function getDefaultGameStatus(gameKey) {
  const resolvedGameKey = resolveGameKey(gameKey);
  if (resolvedGameKey === GAME_KEYS.GUESS_10) return "beta";
  if (resolvedGameKey === GAME_KEYS.SHAPE_TRADERS) return "admin";
  if (resolvedGameKey === GAME_KEYS.COLOR_SCHEME) return "admin";
  return "active";
}

function normalizeGameStatusForStorage(value, fallbackGameKey = null) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "beta") return "beta";
  if (normalized === "admin") return "admin";
  if (normalized === "released" || normalized === "active") return "active";
  return getDefaultGameStatus(fallbackGameKey);
}

function normalizeGameStatusForDisplay(value, fallbackGameKey = null) {
  const storedStatus = normalizeGameStatusForStorage(value, fallbackGameKey);
  return storedStatus === "active" ? "released" : storedStatus;
}

function getGameStatusLabel(value, fallbackGameKey = null) {
  const displayStatus = normalizeGameStatusForDisplay(value, fallbackGameKey);
  if (displayStatus === "beta") return "Beta";
  if (displayStatus === "admin") return "Admin Only";
  return "Released";
}

const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

function normalizeGameKey(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (
    normalized === GAME_KEYS.RUN_THE_NUMBERS ||
    normalized === "run-the-numbers" ||
    normalized === "run_the_numbers"
  ) {
    return GAME_KEYS.RUN_THE_NUMBERS;
  }
  if (
    normalized === GAME_KEYS.GUESS_10 ||
    normalized === "guess-10" ||
    normalized === "red-black" ||
    normalized === "red_black" ||
    normalized === "guess10"
  ) {
    return GAME_KEYS.GUESS_10;
  }
  if (
    normalized === GAME_KEYS.SHAPE_TRADERS ||
    normalized === "shape-traders" ||
    normalized === "shape_traders" ||
    normalized === "shapetraders"
  ) {
    return GAME_KEYS.SHAPE_TRADERS;
  }
  if (
    normalized === GAME_KEYS.COLOR_SCHEME ||
    normalized === "color-scheme" ||
    normalized === "color_scheme" ||
    normalized === "colorscheme"
  ) {
    return GAME_KEYS.COLOR_SCHEME;
  }
  if (
    normalized === GAME_KEYS.FATE_OR_FORTUNE ||
    normalized === "fate-or-fortune" ||
    normalized === "fate_or_fortune" ||
    normalized === "fateorfortune" ||
    normalized === "fof"
  ) {
    return GAME_KEYS.FATE_OR_FORTUNE;
  }
  return null;
}

function resolveGameKey(value) {
  return normalizeGameKey(value) || GAME_KEYS.RUN_THE_NUMBERS;
}

function getGameLabel(value) {
  return GAME_LABELS[resolveGameKey(value)] || "Run the Numbers";
}

function getGameAssetRecord(gameKey) {
  const resolvedGameKey = resolveGameKey(gameKey);
  const record = gameAssetLibraryCache[resolvedGameKey] || DEFAULT_GAME_ASSET_LIBRARY[resolvedGameKey];
  return record ? { ...record } : null;
}

function getResolvedGameStatus(gameKey, user = currentUser) {
  const resolvedGameKey = resolveGameKey(gameKey);
  const record = gameAssetLibraryCache[resolvedGameKey] || DEFAULT_GAME_ASSET_LIBRARY[resolvedGameKey];
  return normalizeGameStatusForStorage(record?.status, resolvedGameKey);
}

function isGameVisibleToUser(gameKey, user = currentUser) {
  const status = getResolvedGameStatus(gameKey, user);
  return status !== "admin" || isAdmin(user);
}

function isGameLockedForPlayer(gameKey) {
  if (isAdmin(currentUser)) return false;
  const record = getGameAssetRecord(gameKey);
  const unlockTier = record?.unlock_tier;
  if (!unlockTier) return false;
  // Use the best available tier across three sources (take the max so a valid
  // high-tier player is never falsely locked out due to DB lag or timing):
  //   1. DB-stored profile tier  (currentProfile.current_rank_tier)
  //   2. Client-computed rank    (currentRankState.currentRank.tier)
  //   3. Last-session cached tier (localStorage rtn:player-tier)
  // If none are available yet (assets arrived before auth), default to locked
  // so genuinely low-tier players can't slip through the brief pre-auth window.
  const profileTier = currentProfile?.current_rank_tier ?? null;
  const stateTier   = currentRankState?.currentRank?.tier ?? null;
  const cachedTier  = (profileTier == null && stateTier == null) ? loadStoredPlayerTier() : null;
  if (profileTier == null && stateTier == null && cachedTier == null) return true; // locked until we know
  const playerTier = Math.max(Number(profileTier ?? 1), Number(stateTier ?? 1), Number(cachedTier ?? 1));
  if (playerTier >= unlockTier) return false;
  const activeContest = getModeContest();
  if (activeContest && contestAllowsGame(activeContest, gameKey)) return false;
  return true;
}

// Like isGameLockedForPlayer but evaluates against a specific target mode
// rather than the currently active mode. Used to block mode switches that
// would leave the player inside a game they can't access in the new mode.
function isGameLockedInMode(gameKey, mode) {
  if (isAdmin(currentUser)) return false;
  const record = getGameAssetRecord(gameKey);
  const unlockTier = record?.unlock_tier;
  if (!unlockTier) return false;
  const profileTier = currentProfile?.current_rank_tier ?? null;
  const stateTier   = currentRankState?.currentRank?.tier ?? null;
  const cachedTier  = (profileTier == null && stateTier == null) ? loadStoredPlayerTier() : null;
  if (profileTier == null && stateTier == null && cachedTier == null) return true;
  const playerTier = Math.max(Number(profileTier ?? 1), Number(stateTier ?? 1), Number(cachedTier ?? 1));
  if (playerTier >= unlockTier) return false;
  const modeContest = getModeContest(mode);
  if (modeContest && contestAllowsGame(modeContest, gameKey)) return false;
  return true;
}

function sanitizeGameAssetColor(value) {
  const normalized = String(value || "").trim();
  if (!normalized) {
    return "";
  }
  if (typeof CSS !== "undefined" && typeof CSS.supports === "function" && CSS.supports("color", normalized)) {
    return normalized;
  }
  return "";
}

function escapeGameAssetField(value) {
  return String(value || "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function getGameAssetPickerColor(value, fallback = "#ffffff") {
  const normalized = String(value || "").trim();
  if (/^#(?:[0-9a-fA-F]{6})$/.test(normalized)) {
    return normalized;
  }
  if (/^#(?:[0-9a-fA-F]{3})$/.test(normalized)) {
    return `#${normalized[1]}${normalized[1]}${normalized[2]}${normalized[2]}${normalized[3]}${normalized[3]}`;
  }
  return fallback;
}

function getGameAdminPresentation(gameKey, statusOverride = null) {
  const resolvedGameKey = resolveGameKey(gameKey);
  const status = normalizeGameStatusForStorage(statusOverride, resolvedGameKey) || getResolvedGameStatus(resolvedGameKey);
  if (status === "beta") {
    return {
      kicker: "New Beta Game",
      pill: "Beta",
      buttonLabel: `Play ${DEFAULT_GAME_ASSET_LIBRARY[resolvedGameKey].label}`,
      cardClass: "game-card-beta"
    };
  }
  if (status === "admin") {
    return {
      kicker: "Admin Preview",
      pill: "Admin",
      buttonLabel: `Open ${DEFAULT_GAME_ASSET_LIBRARY[resolvedGameKey].label}`,
      cardClass: "game-card-shape-traders"
    };
  }
  return {
    kicker: "Original Game",
    pill: "",
    buttonLabel: `Play ${DEFAULT_GAME_ASSET_LIBRARY[resolvedGameKey].label}`,
    cardClass: "game-card-primary"
  };
}

function loadStoredGameAssetLibrary() {
  if (typeof window === "undefined" || !window.localStorage) {
    return {};
  }
  try {
    const raw = window.localStorage.getItem(GAME_ASSET_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch (error) {
    console.warn("[RTN] Unable to parse stored game assets", error);
    return {};
  }
}

function hydrateGameAssetLibrary() {
  const overrides = loadStoredGameAssetLibrary();
  gameAssetLibraryCache = Object.values(GAME_KEYS).reduce((next, gameKey) => {
    const defaults = DEFAULT_GAME_ASSET_LIBRARY[gameKey];
    const override = overrides?.[gameKey];
    next[gameKey] = {
      ...defaults,
      ...(override && typeof override === "object" ? override : {}),
      key: gameKey,
      status: normalizeGameStatusForStorage(override?.status, gameKey),
      label: defaults.label,
      route: defaults.route,
      description: defaults.description,
      card_description: String(override?.card_description || defaults.card_description || "").trim() || defaults.card_description,
      card_background_color: sanitizeGameAssetColor(override?.card_background_color),
      button_color: sanitizeGameAssetColor(override?.button_color),
      button_text_color: sanitizeGameAssetColor(override?.button_text_color),
      unlock_tier: null // always comes from backend, never from localStorage
    };
    return next;
  }, {});
  return gameAssetLibraryCache;
}

function applyBackendGameAssetRows(rows = []) {
  let applied = false;
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const gameKey = normalizeGameKey(row?.id);
    if (!gameKey || !DEFAULT_GAME_ASSET_LIBRARY[gameKey]) return;
    const defaults = DEFAULT_GAME_ASSET_LIBRARY[gameKey];
    const existing = gameAssetLibraryCache[gameKey] || defaults;
    const resolvedLogoUrl = String(row?.logo_url || existing.logo_url || defaults.logo_url || "").trim() || defaults.logo_url;
    const resolvedCardDescription =
      String(row?.card_description || existing.card_description || defaults.card_description || "").trim() ||
      defaults.card_description;
    const resolvedCardBackgroundColor =
      sanitizeGameAssetColor(row?.card_background_color) ||
      sanitizeGameAssetColor(existing.card_background_color);
    const resolvedButtonColor =
      sanitizeGameAssetColor(row?.button_color) ||
      sanitizeGameAssetColor(existing.button_color);
    const resolvedButtonTextColor =
      sanitizeGameAssetColor(row?.button_text_color) ||
      sanitizeGameAssetColor(existing.button_text_color);
    const resolvedUnlockTier = row?.unlock_tier != null ? Number(row.unlock_tier) : (existing.unlock_tier ?? null);
    gameAssetLibraryCache[gameKey] = {
      ...existing,
      key: gameKey,
      status: normalizeGameStatusForStorage(row?.status || existing.status, gameKey),
      label: defaults.label,
      route: defaults.route,
      description: defaults.description,
      logo_url: resolvedLogoUrl,
      card_description: resolvedCardDescription,
      card_background_color: resolvedCardBackgroundColor,
      button_color: resolvedButtonColor,
      button_text_color: resolvedButtonTextColor,
      unlock_tier: resolvedUnlockTier
    };
    applied = true;
  });
  if (applied) {
    persistGameAssetLibrary();
    renderGameLogoTargets();
  }
  return applied;
}

async function refreshGameAssetsFromBackend() {
  if (!supabase || shouldWaitForLiveSupabaseGameAssets()) {
    return false;
  }
  try {
    const { data, error } = await supabase
      .from("games")
      .select("id, name, status, logo_url, card_description, card_background_color, button_color, button_text_color, unlock_tier")
      .order("id", { ascending: true });
    if (error) {
      if (isMissingRelationError(error, "games") || isMissingColumnError(error, "logo_url")) {
        console.warn("[RTN] games branding columns unavailable; using local game asset cache");
        return false;
      }
      throw error;
    }
    return applyBackendGameAssetRows(data);
  } catch (error) {
    console.error("[RTN] Unable to refresh game assets from backend", error);
    return false;
  }
}

async function persistGameAssetRecordToBackend(gameKey) {
  if (!supabase || !currentUser?.id || !gameKey) {
    return false;
  }
  const record = getGameAssetRecord(gameKey) || DEFAULT_GAME_ASSET_LIBRARY[gameKey];
  if (!record) return false;
  const payload = {
    id: gameKey,
    name: DEFAULT_GAME_ASSET_LIBRARY[gameKey].label,
    status: normalizeGameStatusForStorage(record.status, gameKey),
    logo_url: String(record.logo_url || DEFAULT_GAME_ASSET_LIBRARY[gameKey].logo_url || "").trim() || DEFAULT_GAME_ASSET_LIBRARY[gameKey].logo_url,
    card_description: String(record.card_description || DEFAULT_GAME_ASSET_LIBRARY[gameKey].card_description || "").trim() || DEFAULT_GAME_ASSET_LIBRARY[gameKey].card_description,
    card_background_color: sanitizeGameAssetColor(record.card_background_color) || null,
    button_color: sanitizeGameAssetColor(record.button_color) || null,
    button_text_color: sanitizeGameAssetColor(record.button_text_color) || null,
    unlock_tier: Number.isInteger(record.unlock_tier) && record.unlock_tier > 0 ? record.unlock_tier : null
  };
  try {
    const { data, error } = await supabase
      .from("games")
      .upsert(payload, { onConflict: "id" })
      .select("id, name, status, logo_url, card_description, card_background_color, button_color, button_text_color, unlock_tier")
      .maybeSingle();
    if (error) {
      if (isMissingRelationError(error, "games") || isMissingColumnError(error, "logo_url")) {
        console.warn("[RTN] games branding columns unavailable; saved game assets locally only");
        return false;
      }
      throw error;
    }
    if (data) {
      applyBackendGameAssetRows([data]);
    }
    return true;
  } catch (error) {
    console.error("[RTN] Unable to persist game assets to backend", error);
    throw error;
  }
}

function persistGameAssetLibrary() {
  if (typeof window === "undefined" || !window.localStorage) return;
  try {
    const payload = Object.values(GAME_KEYS).reduce((next, gameKey) => {
      const record = gameAssetLibraryCache[gameKey] || DEFAULT_GAME_ASSET_LIBRARY[gameKey];
      next[gameKey] = {
        status: normalizeGameStatusForStorage(record.status, gameKey),
        logo_url: record.logo_url || DEFAULT_GAME_ASSET_LIBRARY[gameKey].logo_url,
        card_description: String(record.card_description || DEFAULT_GAME_ASSET_LIBRARY[gameKey].card_description || "").trim(),
        card_background_color: sanitizeGameAssetColor(record.card_background_color),
        button_color: sanitizeGameAssetColor(record.button_color),
        button_text_color: sanitizeGameAssetColor(record.button_text_color)
      };
      return next;
    }, {});
    window.localStorage.setItem(GAME_ASSET_STORAGE_KEY, JSON.stringify(payload));
  } catch (error) {
    console.warn("[RTN] Unable to persist game assets", error);
  }
}

function shouldWaitForLiveSupabaseGameAssets() {
  if (typeof window === "undefined") {
    return false;
  }
  return Boolean(window.SUPABASE_URL && window.SUPABASE_ANON_KEY) && !window.__RTN_SUPABASE_LIVE_READY;
}

function initHomeGameCardGlitch() {
  if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;

  const CHARSET = "▓▒░█▌▐▀▄|/\\<>=*?#$%&@!";
  const AMP = { intensity: 1.0, burst: true, jitter: 0.35, flicker: 0.3, chroma: 0.45, noise: true, vignette: true, sweep: false };

  const ACCENT = {
    "home-game-card-rtn":   { hex: "#e8a020", r: 232, g: 160, b: 32 },
    "home-game-card-g10":   { hex: "#00e5ff", r: 0,   g: 229, b: 255 },
    "home-game-card-shape": { hex: "#c8ff00", r: 200, g: 255, b: 0 },
    "home-game-card-color": { hex: "#ff2d4a", r: 255, g: 45,  b: 74 },
    "home-game-card-fof":   { hex: "#b07bff", r: 176, g: 123, b: 255 },
    "home-game-card-mm":    { hex: "#2fd06e", r: 47,  g: 208, b: 110 },
  };

  document.querySelectorAll(".home-game-card").forEach((card) => {
    const glyphEl = card.querySelector(".cc-glyph");
    const nameEl  = card.querySelector(".cc-label, .fof-tile-wordmark, .mm-tile-wordmark");
    if (!nameEl) return;

    const glyphTarget = glyphEl ? glyphEl.textContent : null;
    const nameTarget  = nameEl.textContent;

    // Text fields this card scrambles. The glyph is optional — the feature
    // tiles (FOF/MM) have no text glyph, only a wordmark.
    const fields = [];
    if (glyphEl) fields.push({ el: glyphEl, target: glyphTarget });
    fields.push({ el: nameEl, target: nameTarget });

    let accent = ACCENT["home-game-card-rtn"];
    for (const [cls, acc] of Object.entries(ACCENT)) {
      if (card.classList.contains(cls)) { accent = acc; break; }
    }

    // Inject overlay layers
    if (AMP.sweep) {
      const el = document.createElement("div");
      el.className = "hgc-sweep-beam";
      card.appendChild(el);
    }
    if (AMP.noise) {
      const el = document.createElement("div");
      el.className = "hgc-noise-layer";
      card.appendChild(el);
    }
    if (AMP.vignette) {
      const el = document.createElement("div");
      el.className = "hgc-vignette-layer";
      card.appendChild(el);
    }

    // Chromatic aberration text-shadow on glyph (glyph-only, like RTN)
    const c = AMP.chroma;
    if (glyphEl) glyphEl.style.textShadow = `${-2*c}px 0 0 rgba(255,40,80,${(0.7*c).toFixed(2)}), ${2*c}px 0 0 rgba(0,200,255,${(0.7*c).toFixed(2)}), 0 0 ${10+12*c}px ${accent.hex}cc`;

    let isHovered = false;
    let ambientId = null;
    let bootId    = null;
    let jitterId  = null;
    let flickerId = null;

    // ── Ambient glitch + burst ───────────────────────────────────
    function startAmbient() {
      clearInterval(ambientId);
      const rate = Math.max(80, 240 / AMP.intensity);
      ambientId = setInterval(() => {
        if (isHovered) return;
        // burst: occasionally scramble entire string
        if (AMP.burst && Math.random() < 0.06 * AMP.intensity) {
          const scramble = (t) => t.split("").map((ch) => ch === " " ? " " : CHARSET[Math.floor(Math.random() * CHARSET.length)]).join("");
          fields.forEach((f) => { f.el.textContent = scramble(f.target); });
          setTimeout(() => { if (!isHovered) fields.forEach((f) => { f.el.textContent = f.target; }); }, 80 + Math.random() * 120);
          return;
        }
        // single/multi-char flip
        const baseProb = 0.16 * AMP.intensity;
        const flip = (target, el) => {
          if (Math.random() < baseProb) {
            const flips = 1 + Math.floor(Math.random() * Math.max(1, AMP.intensity * 2));
            const arr = target.split("");
            for (let n = 0; n < flips; n++) {
              const i = Math.floor(Math.random() * arr.length);
              if (arr[i] !== " ") arr[i] = CHARSET[Math.floor(Math.random() * CHARSET.length)];
            }
            el.textContent = arr.join("");
            setTimeout(() => { if (!isHovered) el.textContent = target; }, 70 + Math.random() * 90);
          }
        };
        fields.forEach((f) => flip(f.target, f.el));
      }, rate);
    }

    // ── Hover boot: scramble → resolve left-to-right ─────────────
    function startBoot() {
      clearInterval(bootId);
      let frame = 0;
      bootId = setInterval(() => {
        frame++;
        fields.forEach((f) => {
          f.el.textContent = f.target.split("").map((ch, i) => frame > 6 + i ? ch : CHARSET[Math.floor(Math.random() * CHARSET.length)]).join("");
        });
        if (frame > 6 + Math.max(...fields.map((f) => f.target.length))) {
          clearInterval(bootId);
          fields.forEach((f) => { f.el.textContent = f.target; });
        }
      }, 35);
    }

    // ── Horizontal jitter ────────────────────────────────────────
    jitterId = setInterval(() => {
      if (isHovered) return;
      if (Math.random() < 0.35) {
        const jx = (Math.random() - 0.5) * 6 * AMP.jitter;
        if (glyphEl) glyphEl.style.transform = `translateX(${jx}px)`;
        nameEl.style.transform  = `translateX(${jx * 0.4}px)`;
        setTimeout(() => { if (glyphEl) glyphEl.style.transform = ""; nameEl.style.transform = ""; }, 60 + Math.random() * 80);
      }
    }, 220);

    // ── Brightness flicker ───────────────────────────────────────
    flickerId = setInterval(() => {
      if (isHovered) return;
      if (Math.random() < 0.25) {
        const bri = 1 - Math.random() * 0.5 * AMP.flicker;
        fields.forEach((f) => { f.el.style.filter = `brightness(${bri})`; });
        setTimeout(() => { fields.forEach((f) => { f.el.style.filter = ""; }); }, 50 + Math.random() * 80);
      }
    }, 180);

    card.addEventListener("mouseenter", () => {
      isHovered = true;
      startBoot();
    });
    card.addEventListener("mouseleave", () => {
      isHovered = false;
      clearInterval(bootId);
      fields.forEach((f) => { f.el.textContent = f.target; f.el.style.transform = ""; });
    });

    const io = new IntersectionObserver((entries) => {
      entries.forEach((e) => { if (e.isIntersecting) startAmbient(); else clearInterval(ambientId); });
    }, { threshold: 0.1 });
    io.observe(card);

    document.addEventListener("visibilitychange", () => {
      if (document.hidden) clearInterval(ambientId);
      else if (!isHovered) startAmbient();
    });
  });
}

function renderGameLogoTargets() {
  document.querySelectorAll("[data-game-logo-for]").forEach((node) => {
    if (!(node instanceof HTMLImageElement)) return;
    const gameKey = resolveGameKey(node.dataset.gameLogoFor || "");
    const record = getGameAssetRecord(gameKey);
    if (!record) return;
    node.src = record.logo_url || DEFAULT_GAME_ASSET_LIBRARY[gameKey].logo_url;
    node.alt = `${record.label} logo`;
  });

  document.querySelectorAll("[data-game-description-for]").forEach((node) => {
    const gameKey = resolveGameKey(node.dataset.gameDescriptionFor || "");
    const record = getGameAssetRecord(gameKey);
    if (!record) return;
    node.textContent = String(record.card_description || DEFAULT_GAME_ASSET_LIBRARY[gameKey].card_description || "").trim();
  });

  document.querySelectorAll("[data-game-card]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const gameKey = resolveGameKey(node.dataset.gameCard || "");
    const record = getGameAssetRecord(gameKey);
    if (!record) return;
    const presentation = getGameAdminPresentation(gameKey, record.status);
    node.classList.remove("game-card-primary", "game-card-beta", "game-card-shape-traders");
    node.classList.add(presentation.cardClass);
    node.hidden = !isGameVisibleToUser(gameKey);
    const customBackground = sanitizeGameAssetColor(record.card_background_color);
    if (customBackground) {
      node.style.setProperty("--game-card-bg-override", customBackground);
      node.dataset.hasCustomBackground = "true";
    } else {
      node.style.removeProperty("--game-card-bg-override");
      node.dataset.hasCustomBackground = "false";
    }
  });

  document.querySelectorAll("[data-game-kicker-for]").forEach((node) => {
    const gameKey = resolveGameKey(node.dataset.gameKickerFor || "");
    const record = getGameAssetRecord(gameKey);
    if (!record) return;
    const presentation = getGameAdminPresentation(gameKey, record.status);
    node.textContent = presentation.kicker;
  });

  document.querySelectorAll("[data-game-pill-for]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const gameKey = resolveGameKey(node.dataset.gamePillFor || "");
    const record = getGameAssetRecord(gameKey);
    if (!record) return;
    const presentation = getGameAdminPresentation(gameKey, record.status);
    node.hidden = !presentation.pill;
    node.textContent = presentation.pill || "";
  });

  document.querySelectorAll("[data-game-button-for]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const gameKey = resolveGameKey(node.dataset.gameButtonFor || "");
    const record = getGameAssetRecord(gameKey);
    if (!record) return;
    const presentation = getGameAdminPresentation(gameKey, record.status);
    node.textContent = presentation.buttonLabel;
    const customButtonColor = sanitizeGameAssetColor(record.button_color);
    if (customButtonColor) {
      node.style.setProperty("--game-card-button-override", customButtonColor);
      node.dataset.hasCustomButtonColor = "true";
    } else {
      node.style.removeProperty("--game-card-button-override");
      node.dataset.hasCustomButtonColor = "false";
    }
    const customButtonTextColor = sanitizeGameAssetColor(record.button_text_color);
    if (customButtonTextColor) {
      node.style.setProperty("--game-card-button-text-override", customButtonTextColor);
      node.dataset.hasCustomButtonTextColor = "true";
    } else {
      node.style.removeProperty("--game-card-button-text-override");
      node.dataset.hasCustomButtonTextColor = "false";
    }
  });

  document.querySelectorAll(".home-game-card[data-game-id]").forEach((node) => {
    if (!(node instanceof HTMLButtonElement)) return;
    const gameKey = resolveGameKey(node.dataset.gameId || "");
    const visible = isGameVisibleToUser(gameKey);
    node.hidden = !visible;
    if (!visible) return;
    const locked = isGameLockedForPlayer(gameKey);
    node.classList.toggle("is-locked", locked);
    node.disabled = locked;
    const lockLabel = node.querySelector(".hgc-lock-label");
    if (lockLabel) {
      if (locked) {
        const unlockTier = getGameAssetRecord(gameKey)?.unlock_tier;
        lockLabel.textContent = unlockTier ? `UNLOCKS AT TIER ${unlockTier}` : "LOCKED";
      } else {
        lockLabel.textContent = "LOCKED";
      }
    }
  });

  document.querySelectorAll(".drawer-link-game[data-route-target]").forEach((node) => {
    if (!(node instanceof HTMLButtonElement)) return;
    const gameKey = resolveGameKey(node.dataset.routeTarget || "");
    const locked = isGameLockedForPlayer(gameKey);
    node.classList.toggle("is-locked", locked);
    node.disabled = locked;
  });
}

function isMissingColumnError(error, columnName) {
  const message = String(error?.message || error?.details || error?.hint || "");
  return message.includes(columnName) && message.includes("does not exist");
}

function isMissingRelationError(error, relationName) {
  const message = String(error?.message || error?.details || error?.hint || "");
  return message.includes(relationName) && message.includes("does not exist");
}

function isPermissionDeniedError(error) {
  const code = String(error?.code || "");
  const message = String(error?.message || error?.details || error?.hint || "").toLowerCase();
  return code === "42501" || message.includes("permission denied") || message.includes("row-level security");
}

function isMissingFunctionError(error, functionName) {
  const message = String(error?.message || error?.details || error?.hint || "").toLowerCase();
  return message.includes(String(functionName || "").toLowerCase()) && (
    message.includes("could not find the function")
    || message.includes("does not exist")
  );
}

function normalizeContestAllowedGameIds(value) {
  const values = Array.isArray(value) ? value : [];
  const normalized = values
    .map((entry) => normalizeGameKey(entry))
    .filter(Boolean);
  return normalized.length ? Array.from(new Set(normalized)) : [...CONTEST_GAME_KEYS];
}

function contestAllowsGame(contest, gameKey) {
  const allowed = normalizeContestAllowedGameIds(contest?.allowed_game_ids);
  return allowed.includes(resolveGameKey(gameKey));
}

function getContestGamesLabel(contest) {
  const allowed = normalizeContestAllowedGameIds(contest?.allowed_game_ids);
  if (allowed.length === CONTEST_GAME_KEYS.length) {
    return "All games";
  }
  return allowed.map((gameId) => getGameLabel(gameId)).join(" • ");
}

function getGameKeyForRoute(route) {
  if (route === "run-the-numbers") return GAME_KEYS.RUN_THE_NUMBERS;
  if (route === "red-black") return GAME_KEYS.GUESS_10;
  if (route === "shape-traders") return GAME_KEYS.SHAPE_TRADERS;
  if (route === "color-scheme") return GAME_KEYS.COLOR_SCHEME;
  if (route === "fate-or-fortune") return GAME_KEYS.FATE_OR_FORTUNE;
  return null;
}

function canUseCurrentFundsForGame(gameKey) {
  if (!isContestAccountMode(currentAccountMode)) {
    return true;
  }
  const contest = getModeContest(currentAccountMode);
  return !contest || contestAllowsGame(contest, gameKey);
}

function startStopwatch(label) {
  const startedAt = Date.now();
  console.info(`[RTN] ${label} started`);
  return (details = "") => {
    const duration = Date.now() - startedAt;
    const suffix = details ? ` ${details}` : "";
    console.info(`[RTN] ${label} finished in ${duration}ms${suffix}`);
  };
}

if (typeof window !== "undefined") {
  window.addEventListener("error", (event) => {
    const detail = event?.error ?? event?.message ?? "Unknown error";
    console.error("[RTN] Global error", detail);
  });

  window.addEventListener("unhandledrejection", (event) => {
    const reason = event?.reason ?? "Unknown promise rejection";
    console.error("[RTN] Unhandled rejection", reason);
  });

  window.addEventListener("resize", () => {
    applyShapeTradersTradeSheetState();
    applyRtnWagersState();
  });
}

