function isRecoveryRedirectUrl() {
  if (typeof window === "undefined") return false;
  const hash = window.location.hash || "";
  const search = window.location.search || "";
  return hash.includes("type=recovery") || search.includes("type=recovery");
}

const REFERRAL_STORAGE_KEY = "rtn-referral-code";

function sanitizeReferralCode(value) {
  return String(value || "")
    .trim()
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, "")
    .slice(0, 16);
}

// Pull ?ref=CODE off the landing URL and stash it so it survives the signup
// flow. The durable carrier is the auth user_metadata (set at signUp), but we
// also keep it here in case the same browser provisions the profile.
function captureReferralCodeFromUrl() {
  if (typeof window === "undefined") return;
  try {
    const params = new URLSearchParams(window.location.search || "");
    const code = sanitizeReferralCode(params.get("ref"));
    if (code) {
      window.localStorage.setItem(REFERRAL_STORAGE_KEY, code);
    }
  } catch (err) {
    console.warn("[RTN] captureReferralCodeFromUrl failed", err);
  }
}

function getStoredReferralCode() {
  try {
    return window.localStorage.getItem(REFERRAL_STORAGE_KEY) || "";
  } catch {
    return "";
  }
}

function clearStoredReferralCode() {
  try {
    window.localStorage.removeItem(REFERRAL_STORAGE_KEY);
  } catch {
    /* ignore */
  }
}

// True if the Supabase client has a persisted session in localStorage. Used to
// avoid flashing the signup view on reload for an already-authenticated user.
function hasStoredSupabaseSession() {
  try {
    for (let i = 0; i < window.localStorage.length; i += 1) {
      const k = window.localStorage.key(i);
      if (k && /^sb-.*-auth-token$/.test(k)) {
        const v = window.localStorage.getItem(k);
        if (v && v.length > 20) return true;
      }
    }
  } catch {
    /* ignore */
  }
  return false;
}

captureReferralCodeFromUrl();

function buildReferralLink(code) {
  const cleaned = sanitizeReferralCode(code);
  if (!cleaned) return "";
  try {
    const url = new URL(window.location.origin + window.location.pathname);
    url.search = `?ref=${cleaned}`;
    url.hash = "";
    return url.toString();
  } catch {
    return `${window.location.origin}/?ref=${cleaned}`;
  }
}

// Called right after a brand-new profile is provisioned. Credits the referrer
// who owns the code the user signed up under. Safe to call with no code.
async function maybeRecordAffiliateSignup(user) {
  if (!supabase) return;
  try {
    const metaCode = user?.user_metadata?.referred_by;
    const code = sanitizeReferralCode(
      typeof metaCode === "string" && metaCode.trim() ? metaCode : getStoredReferralCode()
    );
    if (!code) return;
    const { data, error } = await supabase.rpc("record_affiliate_signup", {
      _referral_code: code
    });
    if (error) {
      console.warn("[RTN] record_affiliate_signup error", error);
      return;
    }
    console.info("[RTN] record_affiliate_signup result", data);
  } catch (err) {
    console.warn("[RTN] maybeRecordAffiliateSignup failed", err);
  } finally {
    clearStoredReferralCode();
  }
}

// Shows "Invited by <username>" on the Create Account screen when the visitor
// arrived via an affiliate link. Resolves the code through a public RPC since
// the signup page is unauthenticated and cannot read profiles directly.
async function renderSignupAffiliateBanner() {
  const banner = document.getElementById("signup-affiliate-banner");
  const nameEl = document.getElementById("signup-affiliate-name");
  if (!banner || !nameEl) return;

  const code = sanitizeReferralCode(getStoredReferralCode());
  if (!code) {
    banner.hidden = true;
    return;
  }

  // `supabase` is always a Proxy that forwards to an offline stub until the
  // live CDN client finishes loading; the stub's rpc() returns null. Wait for
  // the live client so we hit the real resolve_referral_affiliate RPC.
  if (!window.__RTN_SUPABASE_LIVE_READY) {
    await new Promise((resolve) => {
      let settled = false;
      const done = () => {
        if (settled) return;
        settled = true;
        resolve();
      };
      window.addEventListener("supabase:ready", done, { once: true });
      setTimeout(done, 5000);
    });
  }
  if (!window.__RTN_SUPABASE_LIVE_READY || !supabase) {
    banner.hidden = true;
    return;
  }

  try {
    const { data, error } = await supabase.rpc("resolve_referral_affiliate", {
      _referral_code: code
    });
    if (error || !data?.found || !data?.affiliate_name) {
      banner.hidden = true;
      return;
    }
    nameEl.textContent = data.affiliate_name;
    banner.hidden = false;
  } catch (err) {
    console.warn("[RTN] renderSignupAffiliateBanner failed", err);
    banner.hidden = true;
  }
}

function markAppReady() {
  if (typeof document === "undefined") {
    return;
  }

  if (appReady) {
    console.info("[RTN] markAppReady called but app is already ready");
    return;
  }

  const { body } = document;
  if (body) {
    if (appReadyFallbackTimerId) {
      clearTimeout(appReadyFallbackTimerId);
      appReadyFallbackTimerId = null;
    }
    body.dataset.appState = "ready";
    console.info("[RTN] markAppReady called; UI now visible");
    appReady = true;
  }
}

if (typeof window !== "undefined") {
  appReadyFallbackTimerId = window.setTimeout(() => {
    console.warn("[RTN] App ready fallback timer fired; forcing UI visible");
    markAppReady();
  }, 2500);
}

