function normalizeRankRecord(rank = {}) {
  const themeKey = slugifyThemeKey(rank.theme_key || MAIN_APP_THEME_KEY) || MAIN_APP_THEME_KEY;
  return {
    id: rank.id || null,
    tier: Math.max(1, Number(rank.tier || 1)),
    name: String(rank.name || "Rank").trim(),
    welcome_phrase: String(rank.welcome_phrase || "").trim(),
    required_hands_played: Math.max(0, Math.round(Number(rank.required_hands_played || 0))),
    required_contest_wins: Math.max(0, Math.round(Number(rank.required_contest_wins || 0))),
    required_trades_made: Math.max(0, Math.round(Number(rank.required_trades_made || 0))),
    required_color_scheme_rounds: Math.max(0, Math.round(Number(rank.required_color_scheme_rounds || 0))),
    advancement_bonus_credits: Math.max(0, Math.round(Number(rank.advancement_bonus_credits || 0))),
    icon_url: typeof rank.icon_url === "string" ? rank.icon_url.trim() : "",
    theme_key: themeKey
  };
}

function getFallbackRankLadder() {
  return DEFAULT_RANK_LADDER.map((rank) => normalizeRankRecord(rank));
}

function getRankLadder() {
  return rankLadderCache.length ? rankLadderCache : getFallbackRankLadder();
}

function getRankProgressPercent(currentValue, requiredValue) {
  const current = Math.max(0, Number(currentValue || 0));
  const required = Math.max(0, Number(requiredValue || 0));
  if (required <= 0) return 100;
  return Math.max(0, Math.min(100, (current / required) * 100));
}

function formatRankRequirementValue(value) {
  return Math.max(0, Math.round(Number(value || 0))).toLocaleString();
}

function getRankDisplayName(profile = currentProfile) {
  const fullName = [profile?.first_name, profile?.last_name].filter(Boolean).join(" ").trim();
  return fullName || profile?.first_name || profile?.username || "Player";
}

function interpolateRankWelcome(rank, profile = currentProfile) {
  const playerName = getRankDisplayName(profile);
  return String(rank?.welcome_phrase || "").replace(/\{name\}/g, playerName);
}

function getHomeRankTypingCopy(rank, profile = currentProfile) {
  const copy = interpolateRankWelcome(rank, profile);
  const strippedCopy = copy.replace(/^welcome,\s*[^.!?]+[.!?]\s*/i, "").trim();
  return strippedCopy || copy;
}

function getRankPlayerCount(rank) {
  const tier = Math.max(1, Math.round(Number(rank?.tier || 1)));
  return rankPlayerCountByTier.get(tier) || 0;
}

function rankProfileIconSvg(className = "rlm-player-icon") {
  return `<svg class="${className}" viewBox="0 0 16 16" aria-hidden="true"><circle cx="8" cy="5" r="3"></circle><path d="M2.5 14.5a5.5 5.5 0 0 1 11 0z"></path></svg>`;
}

let rankClaimState = { amount: 0, claimed_tier: 1, current_tier: 1 };

function renderRankLadderAward(rank) {
  const award = Math.max(0, Math.round(Number(rank?.advancement_bonus_credits || 0)));
  if (award <= 0) return "";
  const tier = Number(rank?.tier || 0);
  let trailingHtml = "";
  if (tier <= rankClaimState.claimed_tier) {
    trailingHtml = `<span class="rlm-claim-tag is-claimed">CLAIMED</span>`;
  } else if (tier <= rankClaimState.current_tier) {
    trailingHtml = `<button type="button" class="rlm-claim-btn" data-claim-tier="${tier}">CLAIM +${award.toLocaleString()}</button>`;
  }
  return `<p class="rank-ladder-award"><span class="rlm-award-chip">RANK AWARD</span><span class="rlm-award-value">+${award.toLocaleString()} credits</span>${trailingHtml}</p>`;
}

function renderRankLadderPlayers(rank) {
  const playerCount = rankPlayerCountsLoaded ? getRankPlayerCount(rank) : null;
  const icon = rankProfileIconSvg();
  if (playerCount == null) {
    return `<p class="rank-ladder-player-count is-unavailable">${icon}<span>Player count unavailable</span></p>`;
  }
  return `<p class="rank-ladder-player-count">${icon}<span>${playerCount} player${playerCount === 1 ? "" : "s"} in this rank</span></p>`;
}

function renderRankPlayerCountText(rank, className = "rank-ladder-player-count") {
  const playerCount = rankPlayerCountsLoaded ? getRankPlayerCount(rank) : null;
  const tagName = className.startsWith("home-") ? "span" : "p";
  const text = playerCount == null
    ? "Player count unavailable"
    : `${playerCount} player${playerCount === 1 ? "" : "s"} in this rank`;
  const stateClass = playerCount == null ? " is-unavailable" : "";
  return `<${tagName} class="${className}${stateClass}">${text}</${tagName}>`;
}

function resolveRankState(handsPlayed = 0, contestWins = 0, tradesMade = 0, ladder = getRankLadder(), colorSchemeRounds = 0) {
  const sorted = [...ladder].sort((a, b) => a.tier - b.tier);
  const progressEvents = Math.max(0, Math.round(Number(handsPlayed || 0)));
  const progressWins = Math.max(0, Math.round(Number(contestWins || 0)));
  const progressTrades = Math.max(0, Math.round(Number(tradesMade || 0)));
  const progressRyb = Math.max(0, Math.round(Number(colorSchemeRounds || 0)));
  let currentRank = sorted[0] || normalizeRankRecord(DEFAULT_RANK_LADDER[0]);

  sorted.forEach((rank) => {
    if (
      progressEvents >= rank.required_hands_played &&
      progressWins >= rank.required_contest_wins &&
      progressTrades >= rank.required_trades_made &&
      progressRyb >= (rank.required_color_scheme_rounds || 0)
    ) {
      currentRank = rank;
    }
  });

  const nextRank = sorted.find((rank) => rank.tier > currentRank.tier) || null;
  return {
    ladder: sorted,
    currentRank,
    nextRank,
    totalProgressEvents: progressEvents,
    contestWins: progressWins,
    tradesMade: progressTrades,
    colorSchemeRounds: progressRyb
  };
}

async function loadRankLadder(force = false) {
  if (!force && rankLadderCache.length) {
    return rankLadderCache;
  }

  await loadThemeLibrary(force);

  if (!supabase) {
    rankLadderCache = getFallbackRankLadder();
    return rankLadderCache;
  }

  try {
    const { data, error } = await supabase
      .from("ranks")
      .select("*")
      .order("tier", { ascending: true });
    if (error) throw error;
    rankLadderCache = Array.isArray(data) && data.length
      ? data.map((rank) => normalizeRankRecord(rank))
      : getFallbackRankLadder();
  } catch (error) {
    console.error("[RTN] loadRankLadder error", error);
    rankLadderCache = getFallbackRankLadder();
  }

  return rankLadderCache;
}

async function loadRankPlayerCounts(force = false) {
  if (!force && rankPlayerCountsLoaded) {
    return rankPlayerCountByTier;
  }
  if (!supabase || (!rankPlayerCountsAvailable && !force)) {
    return rankPlayerCountByTier;
  }

  try {
    const { data, error } = await supabase.rpc("get_rank_player_counts");
    if (error) throw error;
    rankPlayerCountByTier = (Array.isArray(data) ? data : []).reduce((map, row) => {
      const tier = Math.max(1, Math.round(Number(row?.rank_tier || row?.tier || 1)));
      map.set(tier, Math.max(0, Math.round(Number(row?.player_count || 0))));
      return map;
    }, new Map());
    rankPlayerCountsLoaded = true;
    rankPlayerCountsAvailable = true;
  } catch (error) {
    if (rankPlayerCountsAvailable) {
      console.warn("[RTN] rank player counts are unavailable", error);
    }
    rankPlayerCountsAvailable = false;
    rankPlayerCountsLoaded = false;
    rankPlayerCountByTier = new Map();
  }

  return rankPlayerCountByTier;
}

async function refreshRankPlayerCounts({ force = false } = {}) {
  await loadRankPlayerCounts(force);
  renderHomeRankLadder();
  if (rankLadderModal && !rankLadderModal.hidden) {
    await renderRankLadderModal();
  }
}

function applyProfileProgressSnapshot(row = null) {
  if (!row || !currentProfile) return;

  currentProfile.run_the_numbers_hands_played_all_time = Math.max(
    0,
    Math.round(
      Number(
        row.run_the_numbers_hands_played_all_time
          ?? currentProfile.run_the_numbers_hands_played_all_time
          ?? 0
      )
    )
  );
  currentProfile.guess10_hands_played_all_time = Math.max(
    0,
    Math.round(
      Number(
        row.guess10_hands_played_all_time
          ?? currentProfile.guess10_hands_played_all_time
          ?? 0
      )
    )
  );
  currentProfile.trades_made_all_time = Math.max(
    0,
    Math.round(Number(row.trades_made_all_time ?? currentProfile.trades_made_all_time ?? 0))
  );
  currentProfile.color_scheme_rounds_played_all_time = Math.max(
    0,
    Math.round(Number(row.color_scheme_rounds_played_all_time ?? currentProfile.color_scheme_rounds_played_all_time ?? 0))
  );
  currentProfile.total_progress_events = Math.max(
    0,
    Math.round(
      Number(
        row.total_progress_events
          ?? row.hands_played_all_time
          ?? currentProfile.total_progress_events
          ?? currentProfile.hands_played_all_time
          ?? 0
      )
    )
  );
  currentProfile.hands_played_all_time = currentProfile.total_progress_events;
  currentProfile.current_rank_tier = Math.max(
    1,
    Math.round(Number(row.current_rank_tier ?? currentProfile.current_rank_tier ?? 1))
  );
  currentProfile.current_rank_id = row.current_rank_id ?? currentProfile.current_rank_id ?? null;
  currentProfile.current_rank = Math.max(
    1,
    Math.round(Number(row.current_rank ?? currentProfile.current_rank ?? 1))
  );
  currentProfile.updated_at = row.updated_at || currentProfile.updated_at || null;
}

async function fetchProfileProgressSummary(userId) {
  if (!userId || !supabase) {
    return {
      runTheNumbersHands: 0,
      guess10Hands: 0,
      tradesMade: 0,
      totalProgressEvents: 0
    };
  }
  try {
    const [
      { count: rtnHandCount, error: rtnCountError },
      { count: guess10HandCount, error: guess10CountError },
      { count: tradeCount, error: tradeCountError }
    ] = await Promise.all([
      supabase
        .from("rtn_live_hands")
        .select("id", { count: "exact", head: true })
        .eq("user_id", userId)
        .neq("status", "active"),
      supabase
        .from("guess10_live_hands")
        .select("id", { count: "exact", head: true })
        .eq("user_id", userId)
        .neq("status", "active"),
      supabase
        .from("shape_trader_trades")
        .select("id", { count: "exact", head: true })
        .eq("user_id", userId)
    ]);
    if (rtnCountError && !isMissingRelationError(rtnCountError, "rtn_live_hands")) throw rtnCountError;
    if (guess10CountError && !isMissingRelationError(guess10CountError, "guess10_live_hands")) throw guess10CountError;
    if (tradeCountError && !isMissingRelationError(tradeCountError, "shape_trader_trades")) throw tradeCountError;

    const runTheNumbersHands = Math.max(0, Number(rtnHandCount || 0));
    const guess10Hands = Math.max(0, Number(guess10HandCount || 0));
    const tradesMade = Math.max(0, Number(tradeCount || 0));
    return {
      runTheNumbersHands,
      guess10Hands,
      tradesMade,
      totalProgressEvents: runTheNumbersHands + guess10Hands + tradesMade
    };
  } catch (error) {
    console.error("[RTN] fetchProfileProgressSummary error", error);
    return {
      runTheNumbersHands: 0,
      guess10Hands: 0,
      tradesMade: 0,
      totalProgressEvents: 0
    };
  }
}

async function incrementProfileHandProgress(handIncrement = 1, gameKey = null) {
  if (!currentUser?.id || currentUser.id === GUEST_USER.id || !supabase) {
    return null;
  }

  try {
    const { data, error } = await supabase.rpc("increment_profile_hands_played", {
      target_user_id: currentUser.id,
      hand_increment: handIncrement,
      target_game_id: resolveGameKey(gameKey) || null
    });
    if (error) throw error;
    const row = Array.isArray(data) ? data[0] : data;
    applyProfileProgressSnapshot(row);
    return row || null;
  } catch (error) {
    console.error("[RTN] incrementProfileHandProgress error", error);
    return null;
  }
}

async function reconcileProfileHandProgress({ force = false } = {}) {
  if (!currentUser?.id || currentUser.id === GUEST_USER.id || !supabase) {
    return null;
  }
  if (!force && reconciledHandsPlayedUserId === currentUser.id) {
    return null;
  }

  try {
    const { data, error } = await supabase.rpc("reconcile_profile_hands_played", {
      target_user_id: currentUser.id
    });
    if (error) throw error;
    const row = Array.isArray(data) ? data[0] : data;
    applyProfileProgressSnapshot(row);
    reconciledHandsPlayedUserId = currentUser.id;
    return row || null;
  } catch (error) {
    console.error("[RTN] reconcileProfileHandProgress error", error);
    return null;
  }
}

