async function refreshCurrentRankState({ force = false } = {}) {
  const previousTier = currentRankState?.currentRank?.tier || null;
  if (!currentUser?.id || currentUser.id === GUEST_USER.id) {
    currentRankState = null;
    reconciledHandsPlayedUserId = null;
    reconciledTradesMadeUserId = null;
    aiThemeSettingsCache = {};
    aiThemeSettingsHydrated = false;
    applyResolvedTheme();
    renderDrawerRankSummary(null);
    typeHomeAboutIntro(homeAboutIntroEl?.dataset.fullCopy || homeAboutIntroEl?.textContent || "");
    renderHomeRankPanel();
    renderHomeRankLadder();
    renderReferralPanel();
    return null;
  }

  const ladder = await loadRankLadder(force);
  await loadAiThemeSettings(force);
  await reconcileProfileHandProgress({ force });
  await reconcileProfileTradeProgress({ force });
  const storedTotalProgressEvents = Number(currentProfile?.total_progress_events ?? currentProfile?.hands_played_all_time);
  let totalProgressEvents = Number.isFinite(storedTotalProgressEvents)
    ? Math.max(0, Math.round(storedTotalProgressEvents))
    : null;
  const contestWins = Math.max(0, Math.round(Number(currentProfile?.contest_wins || 0)));
  const storedTradesMade = Number(currentProfile?.trades_made_all_time);
  let tradesMade = Number.isFinite(storedTradesMade)
    ? Math.max(0, Math.round(storedTradesMade))
    : null;
  if (totalProgressEvents == null || tradesMade == null) {
    const fallbackProgress = await fetchProfileProgressSummary(currentUser.id);
    if (currentProfile) {
      currentProfile.run_the_numbers_hands_played_all_time = fallbackProgress.runTheNumbersHands;
      currentProfile.guess10_hands_played_all_time = fallbackProgress.guess10Hands;
      currentProfile.trades_made_all_time = fallbackProgress.tradesMade;
      currentProfile.total_progress_events = fallbackProgress.totalProgressEvents;
      currentProfile.hands_played_all_time = fallbackProgress.totalProgressEvents;
    }
    totalProgressEvents = fallbackProgress.totalProgressEvents;
    tradesMade = fallbackProgress.tradesMade;
  }
  const csRounds = Math.max(0, Math.round(Number(currentProfile?.color_scheme_rounds_played_all_time || 0)));
  currentRankState = resolveRankState(totalProgressEvents, contestWins, tradesMade, ladder, csRounds);
  savePlayerTier(currentRankState.currentRank?.tier); // cache for next boot's pre-auth lock check
  applyResolvedTheme();
  renderDrawerRankSummary(currentRankState.currentRank);
  typeHomeAboutIntro(homeAboutIntroEl?.dataset.fullCopy || homeAboutIntroEl?.textContent || "");
  renderHomeRankPanel();
  renderHomeRankLadder();
  renderReferralPanel();
  refreshHomeDashboard();
  void refreshRankPlayerCounts();
  void renderRankLadderModal();
  await renderHomeContestPromos();
  if (playerLiveContestListEl && playerEndedContestListEl) {
    await loadPlayerContestList(false);
  }

  const nextTier = currentRankState.currentRank?.tier || 1;
  const announcedTier = getStoredAnnouncedRankTier(currentUser.id);
  // Use the DB-stored profile rank tier as a floor. This prevents the modal
  // from re-firing on a new device where localStorage is empty — the profile
  // already reflects the player's real rank tier in the DB.
  const profileFloor = Number(currentProfile?.current_rank_tier ?? 1);
  const highWaterMark = Math.max(announcedTier ?? 0, profileFloor);

  if (nextTier > highWaterMark) {
    // Genuine advancement past everything we know about — show once and record.
    // The rank-up credit bonus is awarded server-side (award_rank_up_bonus
    // trigger); pull the fresh balance so the readout reflects it immediately.
    let bonusCredits = sumRankAwards(highWaterMark, nextTier, ladder);
    if (bonusCredits <= 0) {
      bonusCredits = Math.max(0, Math.round(Number(currentRankState.currentRank?.advancement_bonus_credits || 0)));
    }
    void refreshNormalModeCreditsFromDb();
    openRankUpModal(currentRankState.currentRank, { bonusCredits });
    setStoredAnnouncedRankTier(nextTier, currentUser.id);
  } else if (announcedTier == null || nextTier > announcedTier) {
    // Silently sync localStorage to catch up (e.g. new device, cleared cache).
    setStoredAnnouncedRankTier(nextTier, currentUser.id);
  }
  return currentRankState;
}

function renderHomeRankPanel() {
  if (!homeRankPanelEl) return;

  if (!currentRankState?.currentRank || !currentUser?.id || currentUser.id === GUEST_USER.id) {
    homeRankPanelEl.hidden = true;
    clearThemeVariables(homeRankPanelEl);
    return;
  }

  const { currentRank } = currentRankState;

  homeRankPanelEl.hidden = false;
  clearThemeVariables(homeRankPanelEl);
  if (homeRankTitleEl) {
    homeRankTitleEl.textContent = `Welcome, ${getRankDisplayName()}`;
  }

  if (homeRankIconEl && homeRankIconFallbackEl) {
    if (currentRank.icon_url) {
      homeRankIconEl.src = currentRank.icon_url;
      homeRankIconEl.alt = `${currentRank.name} icon`;
      homeRankIconEl.hidden = false;
      homeRankIconFallbackEl.hidden = true;
    } else {
      homeRankIconEl.hidden = true;
      homeRankIconFallbackEl.hidden = false;
      homeRankIconFallbackEl.textContent = String(currentRank.tier);
    }
  }
}

let referralCountFetchedForUserId = null;
let referralCopyBtnWired = false;

function wireReferralCopyButton() {
  if (referralCopyBtnWired || !homeReferralCopyBtn) return;
  referralCopyBtnWired = true;
  homeReferralCopyBtn.addEventListener("click", async () => {
    const link = homeReferralLinkInput?.value || "";
    if (!link) return;
    const original = homeReferralCopyBtn.innerHTML;   // preserve inner markup (e.g. the "LINK" span)
    try {
      await navigator.clipboard.writeText(link);
    } catch {
      homeReferralLinkInput?.select?.();
      try {
        document.execCommand("copy");
      } catch {
        /* ignore */
      }
    }
    homeReferralCopyBtn.textContent = "COPIED";
    homeReferralCopyBtn.classList.add("is-copied");
    window.setTimeout(() => {
      homeReferralCopyBtn.innerHTML = original || "COPY";
      homeReferralCopyBtn.classList.remove("is-copied");
    }, 1600);
  });
}

const HAB_COLLAPSE_KEY = "rtn_affiliate_banner_collapsed";
const habBannerEl = document.querySelector(".home-affiliate-banner");
const habToggleBtn = document.getElementById("hab-toggle");

function applyHabCollapsed(collapsed) {
  if (!habBannerEl) return;
  habBannerEl.classList.toggle("is-collapsed", collapsed);
  if (habToggleBtn) {
    habToggleBtn.setAttribute("aria-expanded", String(!collapsed));
    habToggleBtn.setAttribute("aria-label", collapsed ? "Expand announcement" : "Collapse announcement");
  }
}

function wireHabToggle() {
  if (!habToggleBtn || habToggleBtn.dataset.wired) return;
  habToggleBtn.dataset.wired = "1";
  let collapsed = true;   // default collapsed; only expanded if the player chose it ("0")
  try { collapsed = localStorage.getItem(HAB_COLLAPSE_KEY) !== "0"; } catch { /* ignore */ }
  applyHabCollapsed(collapsed);
  habToggleBtn.addEventListener("click", () => {
    const next = !habBannerEl.classList.contains("is-collapsed");
    applyHabCollapsed(next);
    try { localStorage.setItem(HAB_COLLAPSE_KEY, next ? "1" : "0"); } catch { /* ignore */ }
  });
}

function renderReferralPanel() {
  wireHabToggle();
  wireReferralHistoryButton();
  wireCreditsLeaderboardModal();
  wireBankrollHistoryModal();
  void renderHomeLeaderboard();
  void refreshAffiliateNotifications();
  if (!homeReferralLinkInput) return;
  wireReferralCopyButton();

  const signedIn = currentUser?.id && currentUser.id !== GUEST_USER.id;
  const code = signedIn ? sanitizeReferralCode(currentProfile?.referral_code) : "";
  const link = buildReferralLink(code);

  homeReferralLinkInput.value = link;
  homeReferralLinkInput.placeholder = signedIn ? "Generating your link…" : "Sign in to get your link";
  if (homeReferralCopyBtn) {
    homeReferralCopyBtn.disabled = !link;
  }

  if (!signedIn) {
    referralCountFetchedForUserId = null;
    if (homeReferralCountEl) homeReferralCountEl.textContent = "";
    return;
  }

  if (referralCountFetchedForUserId !== currentUser.id) {
    referralCountFetchedForUserId = currentUser.id;
    void refreshReferralSignupCount(currentUser.id);
  }
}

async function refreshReferralSignupCount(userId) {
  if (!supabase || !homeReferralCountEl) return;
  try {
    const { count, error } = await supabase
      .from("affiliate_signups")
      .select("id", { count: "exact", head: true })
      .eq("affiliate_user_id", userId);
    if (error) {
      console.warn("[RTN] refreshReferralSignupCount error", error);
      return;
    }
    if (currentUser?.id !== userId) return;
    const n = Math.max(0, Number(count || 0));
    homeReferralCountEl.textContent = n === 1
      ? "1 sign-up so far — 1,000 credits earned."
      : `${n.toLocaleString()} sign-ups so far — ${(n * 1000).toLocaleString()} credits earned.`;
  } catch (err) {
    console.warn("[RTN] refreshReferralSignupCount failed", err);
  }
}

function formatLeaderboardCredits(value) {
  const n = Math.round(Number(value || 0));
  if (!Number.isFinite(n)) return "0";
  const abs = Math.abs(n);
  const trim = (s) => s.replace(/\.0$/, "");
  if (abs >= 1e9) return trim((n / 1e9).toFixed(1)) + "B";
  if (abs >= 1e6) return trim((n / 1e6).toFixed(1)) + "M";
  if (abs >= 1e4) return Math.round(n / 1e3) + "K"; // 45,000 -> 45K
  return n.toLocaleString();
}

const HOME_LEADERBOARD_MINI_COUNT = 5;
let creditsLeaderboardCache = null;

function buildLeaderboardRow(p, rank, myId, { mini } = {}) {
  const isMe = p.id === myId;
  const medal = rank === 1 ? " hlb-gold" : rank === 2 ? " hlb-silver" : rank === 3 ? " hlb-bronze" : "";
  const ladder = getRankLadder();
  const tierName = ladder.find((r) => r.id === p.current_rank_id || r.tier === p.current_rank_tier)?.name || `Tier ${p.current_rank_tier ?? "—"}`;
  const tierCell = mini ? "" : `<span class="hlb-tier">${escapeAssistantHtml(tierName)}</span>`;
  const uname = escapeAssistantHtml(p.username || "—");
  return `<li class="hlb-row hlb-clickable${isMe ? " is-me" : ""}${medal}" data-bankroll-user="${escapeAssistantHtml(p.id || "")}" data-bankroll-name="${uname}" role="button" tabindex="0" title="View bankroll history">
      <span class="hlb-num">${rank}</span>
      <span class="hlb-name">${uname}</span>
      ${tierCell}
      <span class="hlb-credits">${formatLeaderboardCredits(p.credits)}</span>
    </li>`;
}

async function renderHomeLeaderboard() {
  if (!homeLeaderboardListEl) return;
  const signedIn = currentUser?.id && currentUser.id !== GUEST_USER.id;
  if (!signedIn || !supabase) {
    homeLeaderboardListEl.innerHTML = `<li class="hlb-empty">Sign in to see the leaderboard.</li>`;
    if (homeLeaderboardViewFullBtn) homeLeaderboardViewFullBtn.hidden = true;
    return;
  }
  homeLeaderboardListEl.innerHTML = `<li class="hlb-empty">Loading…</li>`;

  const { data, error } = await supabase.rpc("get_credits_leaderboard");
  if (error || !Array.isArray(data) || !data.length) {
    homeLeaderboardListEl.innerHTML = `<li class="hlb-empty">No players yet.</li>`;
    if (homeLeaderboardViewFullBtn) homeLeaderboardViewFullBtn.hidden = true;
    return;
  }

  creditsLeaderboardCache = data;
  const myId = currentUser?.id;

  homeLeaderboardListEl.innerHTML = data
    .slice(0, HOME_LEADERBOARD_MINI_COUNT)
    .map((p, i) => buildLeaderboardRow(p, i + 1, myId, { mini: true }))
    .join("");

  if (homeLeaderboardViewFullBtn) {
    homeLeaderboardViewFullBtn.hidden = data.length <= HOME_LEADERBOARD_MINI_COUNT;
  }

  // If the full modal is open, keep it in sync.
  if (creditsLeaderboardModal && !creditsLeaderboardModal.hidden) {
    renderCreditsLeaderboardFull();
  }
}

function renderCreditsLeaderboardFull() {
  if (!creditsLeaderboardListEl) return;
  const data = creditsLeaderboardCache;
  if (!Array.isArray(data) || !data.length) {
    creditsLeaderboardListEl.innerHTML = `<li class="hlb-empty">No players yet.</li>`;
    return;
  }
  const myId = currentUser?.id;
  creditsLeaderboardListEl.innerHTML = data
    .map((p, i) => buildLeaderboardRow(p, i + 1, myId, { mini: false }))
    .join("");
}

async function openCreditsLeaderboardModal() {
  if (!creditsLeaderboardModal) return;
  creditsLeaderboardModal.hidden = false;
  document.body.classList.add("modal-open");
  if (!Array.isArray(creditsLeaderboardCache) || !creditsLeaderboardCache.length) {
    creditsLeaderboardListEl.innerHTML = `<li class="hlb-empty">Loading…</li>`;
    if (supabase) {
      const { data } = await supabase.rpc("get_credits_leaderboard");
      if (Array.isArray(data)) creditsLeaderboardCache = data;
    }
  }
  renderCreditsLeaderboardFull();
}

function closeCreditsLeaderboardModal() {
  if (!creditsLeaderboardModal) return;
  creditsLeaderboardModal.hidden = true;
  document.body.classList.remove("modal-open");
}

function wireCreditsLeaderboardModal() {
  if (homeLeaderboardViewFullBtn && !homeLeaderboardViewFullBtn.dataset.wired) {
    homeLeaderboardViewFullBtn.dataset.wired = "1";
    homeLeaderboardViewFullBtn.addEventListener("click", () => { void openCreditsLeaderboardModal(); });
  }
  if (creditsLeaderboardClose && !creditsLeaderboardClose.dataset.wired) {
    creditsLeaderboardClose.dataset.wired = "1";
    creditsLeaderboardClose.addEventListener("click", closeCreditsLeaderboardModal);
  }
  if (creditsLeaderboardOk && !creditsLeaderboardOk.dataset.wired) {
    creditsLeaderboardOk.dataset.wired = "1";
    creditsLeaderboardOk.addEventListener("click", closeCreditsLeaderboardModal);
  }
  if (creditsLeaderboardModal && !creditsLeaderboardModal.dataset.wired) {
    creditsLeaderboardModal.dataset.wired = "1";
    creditsLeaderboardModal.addEventListener("click", (e) => {
      if (e.target === creditsLeaderboardModal) closeCreditsLeaderboardModal();
    });
  }
}

// ── Bankroll history chart (ledger-backed, cross-user) ─────────────────────
let bankrollHistorySeries = [];
let bankrollHistoryPeriod = "all";
let bankrollHistoryFetchToken = 0;
// Account VALUE vs ACTIVITY toggle state for the leaderboard player modal.
let bankrollHistoryView = "value";
let bankrollHistoryUserId = null;
let bankrollHistoryName = "";
let activityHistoryRows = null;      // cached daily rows for the active user/period
let activityHistoryFetchToken = 0;
let activityHistoryChart = null;

function bankrollPeriodStartDate(period) {
  const now = Date.now();
  if (period === "week") return new Date(now - 7 * 864e5);
  if (period === "month") return new Date(now - 30 * 864e5);
  if (period === "90days") return new Date(now - 90 * 864e5);
  if (period === "ytd") { const d = new Date(); return new Date(d.getFullYear(), 0, 1); }
  if (period === "year") return new Date(now - 365 * 864e5);
  return null; // all
}

// Filter a [{time, value}] series to a period and downsample to ~600 points.
function filterDownsampleSeries(series, period) {
  const start = bankrollPeriodStartDate(period);
  let pts = start ? series.filter((p) => p.time >= start) : series.slice();
  const MAX = 600;
  if (pts.length > MAX) {
    const step = pts.length / MAX;
    const sampled = [];
    for (let i = 0; i < MAX; i += 1) sampled.push(pts[Math.floor(i * step)]);
    sampled.push(pts[pts.length - 1]);
    pts = sampled;
  }
  return pts;
}

// Fetch a user's bankroll series into [{time, value}] (ascending).
async function fetchBankrollSeries(userId) {
  if (!supabase || !userId) return [];
  const { data, error } = await supabase.rpc("get_bankroll_series", { p_user_id: userId });
  if (error || !Array.isArray(data)) return [];
  return data
    .map((row) => ({ time: new Date(row.occurred_at), value: Number(row.balance) || 0 }))
    .filter((p) => !Number.isNaN(p.time.getTime()))
    .sort((a, b) => a.time - b.time);
}

async function openBankrollHistoryModal(userId, username) {
  if (!bankrollHistoryModal || !userId) return;
  bankrollHistoryModal.hidden = false;
  document.body.classList.add("modal-open");
  bankrollHistoryUserId = userId;
  bankrollHistoryName = username || "";
  bankrollHistoryView = "value";
  bankrollHistorySeries = [];
  bankrollHistoryPeriod = "all";
  activityHistoryRows = null;
  syncBankrollHistoryPeriodButtons();
  syncBankrollHistoryViewButtons();
  applyBankrollHistoryView();     // shows value wrap, hides activity wrap, sets title

  const token = ++bankrollHistoryFetchToken;
  drawBankrollHistoryChart(); // shows Loading via empty state
  if (!supabase) return;
  const { data, error } = await supabase.rpc("get_bankroll_series", { p_user_id: userId });
  if (token !== bankrollHistoryFetchToken) return; // superseded by a newer open
  if (error || !Array.isArray(data)) {
    bankrollHistorySeries = [];
  } else {
    bankrollHistorySeries = data
      .map((row) => ({ time: new Date(row.occurred_at), value: Number(row.balance) || 0 }))
      .filter((p) => !Number.isNaN(p.time.getTime()))
      .sort((a, b) => a.time - b.time);
  }
  if (bankrollHistoryView === "value") drawBankrollHistoryChart();
}

function syncBankrollHistoryViewButtons() {
  if (!bankrollHistoryModal) return;
  bankrollHistoryModal.querySelectorAll("[data-bh-view]").forEach((btn) => {
    const on = btn.dataset.bhView === bankrollHistoryView;
    btn.classList.toggle("active", on);
    btn.setAttribute("aria-selected", on ? "true" : "false");
  });
}

// Show the canvas for the current view, hide the other, and update the title.
function applyBankrollHistoryView() {
  const isActivity = bankrollHistoryView === "activity";
  if (bankrollValueWrapEl) bankrollValueWrapEl.hidden = isActivity;
  if (bankrollActivityWrapEl) bankrollActivityWrapEl.hidden = !isActivity;
  if (bankrollHistoryTitleEl) {
    const who = bankrollHistoryName ? `${bankrollHistoryName} · ` : "";
    bankrollHistoryTitleEl.textContent = who + (isActivity ? "Account Activity" : "Account Value");
  }
}

function setBankrollHistoryView(view) {
  const next = view === "activity" ? "activity" : "value";
  if (next === bankrollHistoryView) return;
  bankrollHistoryView = next;
  syncBankrollHistoryViewButtons();
  applyBankrollHistoryView();
  if (next === "activity") {
    void drawActivityHistoryChart();
  } else {
    drawBankrollHistoryChart();
  }
}

// Map the shared period buttons to a day-window + display bucket for activity.
function activityPeriodConfig(period) {
  switch (period) {
    case "month":  return { days: 30,   bucket: "day" };
    case "90days": return { days: 90,   bucket: "day" };
    case "year":   return { days: 364,  bucket: "week" };
    // Cap "all" at 730 days: PostgREST returns at most 1000 rows, and this RPC
    // emits one row per day, so a larger window would silently drop older days.
    case "all":    return { days: 730,  bucket: "month" };
    default:       return { days: 30,   bucket: "day" };
  }
}

const ACTIVITY_GAME_SERIES = [
  { key: "rtn", label: "RTN",  color: "#e8a020" },
  { key: "g10", label: "G10",  color: "#00e5ff" },
  { key: "st",  label: "ST",   color: "#c8ff00" },
  { key: "ryb", label: "RYB",  color: "#ff4444" },
  { key: "fof", label: "FOF",  color: "#b07bff" },
];

// Collapse daily rows into day / week / month display buckets.
function bucketActivityRows(rows, mode) {
  if (!Array.isArray(rows) || !rows.length) return [];
  if (mode === "day") {
    return rows.map((r) => ({ label: String(r.d).slice(5), ...pickGameCounts(r) }));
  }
  const groups = new Map();
  const order = [];
  for (const r of rows) {
    let key;
    if (mode === "month") {
      key = String(r.d).slice(0, 7);            // YYYY-MM
    } else {                                     // week: ISO-ish, group by 7-day index from first day
      const first = new Date(rows[0].d + "T00:00:00Z");
      const cur = new Date(r.d + "T00:00:00Z");
      const wk = Math.floor((cur - first) / (7 * 86400000));
      key = String(wk);
    }
    if (!groups.has(key)) { groups.set(key, { label: null, rtn: 0, g10: 0, st: 0, ryb: 0, fof: 0, firstDay: r.d }); order.push(key); }
    const g = groups.get(key);
    g.rtn += Number(r.rtn || 0); g.g10 += Number(r.g10 || 0); g.st += Number(r.st || 0);
    g.ryb += Number(r.ryb || 0); g.fof += Number(r.fof || 0);
  }
  return order.map((key) => {
    const g = groups.get(key);
    g.label = mode === "month" ? key : String(g.firstDay).slice(5);
    return g;
  });
}

function pickGameCounts(r) {
  return {
    rtn: Number(r.rtn || 0), g10: Number(r.g10 || 0), st: Number(r.st || 0),
    ryb: Number(r.ryb || 0), fof: Number(r.fof || 0),
  };
}

async function drawActivityHistoryChart() {
  if (!bankrollActivityCanvas || typeof Chart === "undefined") return;
  const userId = bankrollHistoryUserId;
  if (!userId || !supabase) return;

  const { days, bucket } = activityPeriodConfig(bankrollHistoryPeriod);
  const token = ++activityHistoryFetchToken;

  const { data, error } = await supabase.rpc("get_activity_series", { p_user_id: userId, p_days: days });
  if (token !== activityHistoryFetchToken) return;         // superseded by a newer period/user
  if (bankrollHistoryView !== "activity") return;          // user toggled away mid-fetch
  if (error) console.error("[RTN] get_activity_series error", error.message || error);
  activityHistoryRows = Array.isArray(data) ? data : [];

  const display = bucketActivityRows(activityHistoryRows, bucket);
  const total = display.reduce((s, b) => s + b.rtn + b.g10 + b.st + b.ryb + b.fof, 0);

  if (activityHistoryChart) { activityHistoryChart.destroy(); activityHistoryChart = null; }
  const ctx = bankrollActivityCanvas.getContext("2d");
  if (!ctx) return;

  activityHistoryChart = new Chart(ctx, {
    type: "bar",
    data: {
      labels: display.length ? display.map((b) => b.label) : ["No activity"],
      datasets: ACTIVITY_GAME_SERIES.map((s) => ({
        label: s.label,
        data: display.map((b) => b[s.key] || 0),
        backgroundColor: s.color + "cc",
        borderColor: s.color,
        borderWidth: 0,
        borderRadius: 1,
        stack: "events",
      })),
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: "index", intersect: false },
      animation: { duration: 600, easing: "easeOutQuart" },
      animations: {
        x: { duration: 0 },
        y: { from: (c) => c.chart.scales.y.getPixelForValue(0) },
        base: { from: (c) => c.chart.scales.y.getPixelForValue(0) },
      },
      plugins: {
        legend: {
          display: true,
          labels: { color: "rgba(226, 248, 255, 0.85)", boxWidth: 12, boxHeight: 12, font: { size: 11 } },
        },
        tooltip: { callbacks: { label: (c) => ` ${c.dataset.label}: ${c.parsed.y}` } },
      },
      scales: {
        x: {
          stacked: true,
          ticks: { color: "rgba(168, 168, 112, 0.7)", font: { size: 9 }, maxTicksLimit: 12 },
          grid: { display: false },
          border: { color: "rgba(200, 255, 0, 0.12)" },
        },
        y: {
          stacked: true,
          beginAtZero: true,
          ticks: { color: "rgba(168, 168, 112, 0.7)", font: { size: 9 }, precision: 0 },
          grid: { color: "rgba(200, 255, 0, 0.06)" },
          border: { color: "rgba(200, 255, 0, 0.12)" },
        },
      },
    },
  });

  if (!total) {
    // Empty overlay via the "No activity" label already; nothing else needed.
  }
}

function closeBankrollHistoryModal() {
  if (!bankrollHistoryModal) return;
  bankrollHistoryModal.hidden = true;
  document.body.classList.remove("modal-open");
  if (activityHistoryChart) { activityHistoryChart.destroy(); activityHistoryChart = null; }
}

function syncBankrollHistoryPeriodButtons() {
  if (!bankrollHistoryModal) return;
  bankrollHistoryModal.querySelectorAll("[data-bh-period]").forEach((btn) => {
    btn.classList.toggle("active", btn.dataset.bhPeriod === bankrollHistoryPeriod);
  });
}

function getFilteredBankrollHistory() {
  return filterDownsampleSeries(bankrollHistorySeries, bankrollHistoryPeriod);
}

function drawBankrollHistoryChart() {
  drawBankrollLineChart(bankrollHistoryCanvas, getFilteredBankrollHistory());
}

// Reusable time-series line renderer for [{time, value}] points.
function drawBankrollLineChart(canvas, points) {
  if (!canvas) return;
  const ctx = canvas.getContext("2d");
  if (!ctx) return;

  const width = canvas.clientWidth || 720;
  const height = canvas.clientHeight || 320;
  const dpr = Math.max(1, window.devicePixelRatio || 1);
  canvas.width = Math.round(width * dpr);
  canvas.height = Math.round(height * dpr);
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, width, height);

  if (!points.length) {
    ctx.fillStyle = "rgba(168, 168, 112, 0.7)";
    ctx.font = "600 15px JetBrains Mono, monospace";
    ctx.textAlign = "center";
    ctx.fillText("No bankroll history in this range yet.", width / 2, height / 2);
    return;
  }

  const padding = { top: 22, right: 18, bottom: 34, left: 78 };
  const chartWidth = Math.max(10, width - padding.left - padding.right);
  const chartHeight = Math.max(10, height - padding.top - padding.bottom);
  const values = points.map((p) => p.value);
  let minValue = Math.min(...values);
  let maxValue = Math.max(...values);
  if (minValue === maxValue) { minValue -= 10; maxValue += 10; }
  const range = Math.max(1, maxValue - minValue);

  ctx.strokeStyle = "rgba(200, 255, 0, 0.08)";
  ctx.lineWidth = 1;
  for (let step = 0; step <= 4; step += 1) {
    const y = padding.top + (chartHeight / 4) * step;
    ctx.beginPath();
    ctx.moveTo(padding.left, y);
    ctx.lineTo(width - padding.right, y);
    ctx.stroke();
  }

  ctx.fillStyle = "rgba(168, 168, 112, 0.6)";
  ctx.font = "600 12px JetBrains Mono, monospace";
  ctx.textAlign = "right";
  for (let step = 0; step <= 4; step += 1) {
    const value = Math.round(maxValue - (range / 4) * step);
    const y = padding.top + (chartHeight / 4) * step + 4;
    ctx.fillText(value.toLocaleString(), padding.left - 10, y);
  }

  const coords = points.map((p, index) => {
    const x = padding.left + (points.length === 1 ? chartWidth / 2 : (chartWidth * index) / (points.length - 1));
    const y = padding.top + chartHeight - ((p.value - minValue) / range) * chartHeight;
    return { x, y };
  });

  const gradient = ctx.createLinearGradient(0, padding.top, 0, padding.top + chartHeight);
  gradient.addColorStop(0, "rgba(200, 255, 0, 0.18)");
  gradient.addColorStop(1, "rgba(200, 255, 0, 0)");
  ctx.beginPath();
  coords.forEach(({ x, y }, index) => { if (index === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y); });
  ctx.lineTo(coords[coords.length - 1].x, padding.top + chartHeight);
  ctx.lineTo(coords[0].x, padding.top + chartHeight);
  ctx.closePath();
  ctx.fillStyle = gradient;
  ctx.fill();

  ctx.beginPath();
  coords.forEach(({ x, y }, index) => { if (index === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y); });
  ctx.strokeStyle = "#c8ff00";
  ctx.lineWidth = 2;
  ctx.stroke();

  // Date axis: first + last
  ctx.fillStyle = "rgba(168, 168, 112, 0.6)";
  ctx.font = "600 11px JetBrains Mono, monospace";
  const fmt = (d) => d.toLocaleDateString(undefined, { month: "short", day: "numeric", year: "2-digit" });
  ctx.textAlign = "left";
  ctx.fillText(fmt(points[0].time), padding.left, height - 12);
  ctx.textAlign = "right";
  ctx.fillText(fmt(points[points.length - 1].time), width - padding.right, height - 12);
}

// ── Embedded charts in the Account Chart & Logs view ───────────────────────
const accountBankrollCanvas = document.getElementById("account-bankroll-canvas");
const accountBankrollPeriodsEl = document.getElementById("account-bankroll-periods");
const accountJourneySelect = document.getElementById("account-journey-select");
const accountJourneyCanvas = document.getElementById("account-journey-canvas");

let accountBankrollSeries = [];
let accountBankrollPeriod = "all";
let accountBankrollUserId = null;

async function renderAccountBankrollChart(force = false) {
  if (!accountBankrollCanvas) return;
  const signedIn = currentUser?.id && currentUser.id !== GUEST_USER.id;
  if (!signedIn) {
    accountBankrollSeries = [];
    accountBankrollUserId = null;
    drawBankrollLineChart(accountBankrollCanvas, []);
    return;
  }
  if (force || accountBankrollUserId !== currentUser.id || !accountBankrollSeries.length) {
    accountBankrollSeries = await fetchBankrollSeries(currentUser.id);
    accountBankrollUserId = currentUser.id;
  }
  drawBankrollLineChart(accountBankrollCanvas, filterDownsampleSeries(accountBankrollSeries, accountBankrollPeriod));
}

function wireAccountBankrollPeriods() {
  if (!accountBankrollPeriodsEl || accountBankrollPeriodsEl.dataset.wired) return;
  accountBankrollPeriodsEl.dataset.wired = "1";
  accountBankrollPeriodsEl.addEventListener("click", (e) => {
    const btn = e.target.closest("[data-abh-period]");
    if (!btn) return;
    accountBankrollPeriod = btn.dataset.abhPeriod || "all";
    accountBankrollPeriodsEl.querySelectorAll("[data-abh-period]").forEach((b) => b.classList.toggle("active", b === btn));
    drawBankrollLineChart(accountBankrollCanvas, filterDownsampleSeries(accountBankrollSeries, accountBankrollPeriod));
  });
}

function populateAccountJourneySelect() {
  if (!accountJourneySelect) return;
  const ended = (contestCache || [])
    .filter((c) => getContestStatus(c) === "ended" && getContestEntryById(c.id))
    .sort((a, b) => new Date(b.ends_at || 0) - new Date(a.ends_at || 0));
  const prev = accountJourneySelect.value;
  accountJourneySelect.innerHTML =
    `<option value="">${ended.length ? "Select an ended contest…" : "No ended contests yet"}</option>` +
    ended.map((c) => `<option value="${escapeAssistantHtml(c.id)}">${escapeAssistantHtml(c.title || "Contest")}</option>`).join("");
  if (prev && ended.some((c) => c.id === prev)) {
    accountJourneySelect.value = prev;
  }
}

async function renderAccountJourneyChart(contestId) {
  if (!accountJourneyCanvas) return;
  if (!contestId) { drawContestJourneyChart([], accountJourneyCanvas); return; }
  const contest = getContestById(contestId);
  const entry = getContestEntryById(contestId);
  if (!contest || !entry) { drawContestJourneyChart([], accountJourneyCanvas); return; }
  const points = await loadContestJourneyPoints(contest, entry);
  drawContestJourneyChart(points, accountJourneyCanvas);
}

function wireAccountJourneySelect() {
  if (!accountJourneySelect || accountJourneySelect.dataset.wired) return;
  accountJourneySelect.dataset.wired = "1";
  accountJourneySelect.addEventListener("change", () => {
    void renderAccountJourneyChart(accountJourneySelect.value);
  });
}

function renderAccountAnalyticsCharts() {
  wireAccountBankrollPeriods();
  wireAccountJourneySelect();
  void renderAccountBankrollChart(true);
  populateAccountJourneySelect();
  void renderAccountJourneyChart(accountJourneySelect?.value || "");
}

function wireBankrollHistoryModal() {
  if (bankrollHistoryClose && !bankrollHistoryClose.dataset.wired) {
    bankrollHistoryClose.dataset.wired = "1";
    bankrollHistoryClose.addEventListener("click", closeBankrollHistoryModal);
  }
  if (bankrollHistoryOk && !bankrollHistoryOk.dataset.wired) {
    bankrollHistoryOk.dataset.wired = "1";
    bankrollHistoryOk.addEventListener("click", closeBankrollHistoryModal);
  }
  if (bankrollHistoryModal && !bankrollHistoryModal.dataset.wired) {
    bankrollHistoryModal.dataset.wired = "1";
    bankrollHistoryModal.addEventListener("click", (e) => {
      if (e.target === bankrollHistoryModal) closeBankrollHistoryModal();
      const viewBtn = e.target.closest?.("[data-bh-view]");
      if (viewBtn) {
        setBankrollHistoryView(viewBtn.dataset.bhView || "value");
        return;
      }
      const periodBtn = e.target.closest?.("[data-bh-period]");
      if (periodBtn) {
        bankrollHistoryPeriod = periodBtn.dataset.bhPeriod || "all";
        syncBankrollHistoryPeriodButtons();
        if (bankrollHistoryView === "activity") {
          void drawActivityHistoryChart();
        } else {
          drawBankrollHistoryChart();
        }
      }
    });
  }
  if (accountBankrollHistoryOpenBtn && !accountBankrollHistoryOpenBtn.dataset.wired) {
    accountBankrollHistoryOpenBtn.dataset.wired = "1";
    accountBankrollHistoryOpenBtn.addEventListener("click", () => {
      const uid = currentUser?.id;
      if (!uid || uid === GUEST_USER.id) return;
      const name = currentProfile?.username || "You";
      void openBankrollHistoryModal(uid, name);
    });
  }
  // Delegated: click any leaderboard row to view that player's bankroll.
  [homeLeaderboardListEl, creditsLeaderboardListEl].forEach((listEl) => {
    if (listEl && !listEl.dataset.bhWired) {
      listEl.dataset.bhWired = "1";
      listEl.addEventListener("click", (e) => {
        const row = e.target.closest?.("[data-bankroll-user]");
        if (!row) return;
        void openBankrollHistoryModal(row.dataset.bankrollUser, row.dataset.bankrollName || "");
      });
    }
  });
}

function wireReferralHistoryButton() {
  if (homeReferralHistoryBtn && !homeReferralHistoryBtn.dataset.wired) {
    homeReferralHistoryBtn.dataset.wired = "1";
    homeReferralHistoryBtn.addEventListener("click", () => { void openReferralHistoryModal(); });
  }
  if (referralHistoryClose && !referralHistoryClose.dataset.wired) {
    referralHistoryClose.dataset.wired = "1";
    referralHistoryClose.addEventListener("click", closeReferralHistoryModal);
  }
  if (referralHistoryOk && !referralHistoryOk.dataset.wired) {
    referralHistoryOk.dataset.wired = "1";
    referralHistoryOk.addEventListener("click", closeReferralHistoryModal);
  }
  if (referralHistoryModal && !referralHistoryModal.dataset.wired) {
    referralHistoryModal.dataset.wired = "1";
    referralHistoryModal.addEventListener("click", (e) => {
      if (e.target === referralHistoryModal) closeReferralHistoryModal();
    });
  }
}

async function openReferralHistoryModal() {
  if (!referralHistoryModal) return;
  referralHistoryModal.hidden = false;
  document.body.classList.add("modal-open");
  await renderReferralHistory();
}

function closeReferralHistoryModal() {
  if (!referralHistoryModal) return;
  referralHistoryModal.hidden = true;
  document.body.classList.remove("modal-open");
}

async function renderReferralHistory() {
  if (!referralHistoryListEl) return;
  referralHistoryListEl.innerHTML = `<li class="rhist-empty">Loading…</li>`;
  if (!supabase || !currentUser?.id) {
    referralHistoryListEl.innerHTML = `<li class="rhist-empty">Sign in to view your history.</li>`;
    return;
  }

  const { data, error } = await supabase
    .from("affiliate_signups")
    .select("referred_username, amount_credited, created_at")
    .eq("affiliate_user_id", currentUser.id)
    .order("created_at", { ascending: false });

  if (error || !Array.isArray(data) || !data.length) {
    referralHistoryListEl.innerHTML = `<li class="rhist-empty">Your code has not been used yet — share your link to start earning.</li>`;
    return;
  }

  referralHistoryListEl.innerHTML = data.map((row) => {
    const name = row.referred_username && row.referred_username.trim() ? row.referred_username : "A new player";
    const amount = formatLeaderboardCredits(row.amount_credited);
    return `<li class="rhist-row">
      <div class="rhist-info">
        <span class="rhist-name">${escapeAssistantHtml(name)}</span>
        <span class="rhist-date">${formatMedalAwardDate(row.created_at)}</span>
      </div>
      <span class="rhist-amount">+${amount}</span>
    </li>`;
  }).join("");
}

function buildHomeRankLadderProgressMarkup(rank, classBase = "home-rank-ladder") {
  if (!currentRankState?.currentRank || rank?.tier !== currentRankState.currentRank.tier) return "";
  const { nextRank, totalProgressEvents, contestWins, tradesMade } = currentRankState;
  if (!nextRank) {
    return `
      <span class="${classBase}-progress">
        <span class="${classBase}-progress-complete">Top tier reached</span>
      </span>
    `;
  }

  const progressItems = [
    {
      label: "Progress Events",
      current: totalProgressEvents,
      required: nextRank.required_hands_played
    },
    {
      label: "Wins",
      current: contestWins,
      required: nextRank.required_contest_wins
    },
    {
      label: "Trades",
      current: tradesMade,
      required: nextRank.required_trades_made
    }
  ].filter((item) => item.required > 0);

  if (!progressItems.length) return "";

  return `
    <span class="${classBase}-progress" aria-label="Progress toward ${escapeAssistantHtml(nextRank.name)}">
      ${progressItems.map((item) => `
        <span class="${classBase}-progress-row">
          <span class="${classBase}-progress-label">
            <span>${escapeAssistantHtml(item.label)}</span>
            <span>${formatRankRequirementValue(item.current)} / ${formatRankRequirementValue(item.required)}</span>
          </span>
          <span class="${classBase}-progress-track" aria-hidden="true">
            <span class="${classBase}-progress-fill" style="width: ${getRankProgressPercent(item.current, item.required).toFixed(2)}%;"></span>
          </span>
        </span>
      `).join("")}
    </span>
  `;
}

function renderHomeRankLadder() {
  if (!homeRankLadderPanelEl || !homeRankLadderListEl) return;

  if (!currentRankState?.currentRank || !currentUser?.id || currentUser.id === GUEST_USER.id) {
    homeRankLadderPanelEl.hidden = true;
    homeRankLadderListEl.innerHTML = "";
    if (homeRankLadderCurrentEl) homeRankLadderCurrentEl.textContent = "";
    homeGlitchSection('tier');
    return;
  }

  const ladder = getRankLadder();
  if (!ladder.length) {
    homeRankLadderPanelEl.hidden = true;
    homeRankLadderListEl.innerHTML = "";
    homeGlitchSection('tier');
    return;
  }

  const { currentRank } = currentRankState;
  homeRankLadderPanelEl.hidden = false;
  if (homeRankLadderCurrentEl) {
    homeRankLadderCurrentEl.textContent = `${currentRank.name} · Tier ${currentRank.tier}`;
  }

  homeRankLadderListEl.innerHTML = ladder.map((rank, index) => {
    const isCurrent = rank.tier === currentRank.tier;
    const rankStateClass = isCurrent ? "is-current" : rank.tier < currentRank.tier ? "is-complete" : "is-locked";
    const reqs = buildRankRequirementsCopy(rank);
    return `
      <li
        class="home-rank-ladder-rung ${rankStateClass}"
        style="--rung-index: ${index};"
        role="button"
        tabindex="0"
        data-rank-tier="${escapeAssistantHtml(String(rank.tier))}"
        aria-label="Open full rank ladder"
      >
        <span class="home-rank-ladder-node" aria-hidden="true">${escapeAssistantHtml(String(rank.tier))}</span>
        <span class="home-rank-ladder-copy">
          <span class="home-rank-ladder-name">${escapeAssistantHtml(rank.name)}</span>
          <span class="home-rank-ladder-requirements">${escapeAssistantHtml(reqs)}</span>
        </span>
        ${isCurrent ? '<span class="home-rank-ladder-arrow" aria-hidden="true">←</span>' : ""}
      </li>
    `;
  }).join("");

  homeGlitchSection('tier');
  window.requestAnimationFrame(() => {
    const currentRung = homeRankLadderListEl.querySelector(".home-rank-ladder-rung.is-current");
    const sidebar = document.querySelector(".home-sidebar");
    if (currentRung && sidebar) {
      const rungTop = currentRung.offsetTop;
      const sidebarScroll = rungTop - sidebar.clientHeight / 2;
      sidebar.scrollTop = Math.max(0, sidebarScroll);
    }
  });
}

function buildRankRequirementsCopy(rank) {
  const requirements = [];
  if (rank.required_hands_played > 0) {
    requirements.push(`${formatRankRequirementValue(rank.required_hands_played)} progress events`);
  }
  if (rank.required_contest_wins > 0) {
    requirements.push(`${formatRankRequirementValue(rank.required_contest_wins)} contest victories`);
  }
  if (rank.required_trades_made > 0) {
    requirements.push(`${formatRankRequirementValue(rank.required_trades_made)} trades made`);
  }
  return requirements.length ? requirements.join(" • ") : "No thresholds";
}

function getRankByTier(tier, ladder = getRankLadder()) {
  const targetTier = Math.max(1, Math.round(Number(tier || 1)));
  return ladder.find((rank) => rank.tier === targetTier) || null;
}

// Sum the advancement bonuses for every tier crossed in (fromTier, toTier].
// Mirrors the server-side award_rank_up_bonus trigger for display purposes.
function sumRankAwards(fromTier, toTier, ladder = getRankLadder()) {
  const from = Math.max(0, Math.round(Number(fromTier || 0)));
  const to = Math.max(0, Math.round(Number(toTier || 0)));
  if (to <= from) return 0;
  return ladder.reduce((total, rank) => {
    const tier = Math.max(0, Math.round(Number(rank.tier || 0)));
    if (tier > from && tier <= to) {
      return total + Math.max(0, Math.round(Number(rank.advancement_bonus_credits || 0)));
    }
    return total;
  }, 0);
}

// Pull the authoritative normal-mode balance from the DB and refresh the
// readout. Used after a server-side credit award (rank bonus) lands so the
// player sees it without waiting for the next periodic sync. No-op in contest
// mode, where profiles.credits is not the active ledger.
async function refreshNormalModeCreditsFromDb() {
  if (!supabase || !currentUser?.id || currentUser.id === GUEST_USER.id) return;
  if (typeof isContestAccountMode === "function" && isContestAccountMode()) return;
  try {
    const { data, error } = await supabase
      .from("profiles")
      .select("credits, carter_cash, carter_cash_progress")
      .eq("id", currentUser.id)
      .maybeSingle();
    if (error || !data) return;
    if (currentProfile) {
      currentProfile.credits = data.credits;
    }
    applyAccountSnapshot(data, { resetHistory: false });
  } catch (err) {
    console.warn("[RTN] refreshNormalModeCreditsFromDb failed", err);
  }
}

function getRankThemeLabel(themeKey) {
  return getThemeRecord(themeKey)?.name || humanizeThemeKey(themeKey);
}

function renderThemeSelectOptions(selectEl, selectedKey = "blue") {
  if (!(selectEl instanceof HTMLSelectElement)) return;
  const themes = getThemeLibrary();
  const selected = getThemeRecord(selectedKey)?.key || selectedKey;
  selectEl.innerHTML = "";
  themes.forEach((theme) => {
    const option = document.createElement("option");
    option.value = theme.key;
    option.textContent = theme.name;
    option.selected = theme.key === selected;
    selectEl.appendChild(option);
  });
}

function populateAdminThemeBaseOptions(selectedKey = "blue") {
  if (!(adminThemeBaseSelect instanceof HTMLSelectElement)) return;
  adminThemeBaseSelect.innerHTML = "";
  Object.keys(THEME_CLASS_MAP).forEach((key) => {
    const option = document.createElement("option");
    option.value = key;
    option.textContent = humanizeThemeKey(key);
    option.selected = key === selectedKey;
    adminThemeBaseSelect.appendChild(option);
  });
}

function populateAdminRankThemeOptions(selectedKey = "blue") {
  renderThemeSelectOptions(adminRankThemeSelect, selectedKey);
}

function getThemeFormState() {
  if (!adminThemeForm) {
    return normalizeThemeRecord({
      name: "Untitled Theme",
      key: "untitled-theme",
      base_theme: "blue",
      palette: DEFAULT_CUSTOM_THEME_PALETTE,
      settings: DEFAULT_CUSTOM_THEME_SETTINGS
    });
  }
  const formData = new FormData(adminThemeForm);
  const name = String(formData.get("themeName") || "").trim() || "Untitled Theme";
  const manualKey = String(formData.get("themeKey") || "").trim();
  return normalizeThemeRecord({
    id: String(formData.get("themeId") || "").trim() || null,
    name,
    key: manualKey || slugifyThemeKey(name),
    base_theme: String(formData.get("baseTheme") || "blue").trim(),
    palette: {
      accent: formData.get("accentColor"),
      accentSecondary: formData.get("accentSecondaryColor"),
      accentTertiary: formData.get("accentTertiaryColor"),
      heroButton: formData.get("heroButtonColor"),
      primaryButton: formData.get("primaryButtonColor"),
      actionColor: formData.get("actionColor"),
      primaryButtonDisabled: formData.get("primaryButtonDisabledColor"),
      secondaryButton: formData.get("secondaryButtonColor"),
      secondaryButtonDisabled: formData.get("secondaryButtonDisabledColor"),
      progressStart: formData.get("progressStartColor"),
      progressEnd: formData.get("progressEndColor"),
      gold: formData.get("goldColor"),
      muted: formData.get("mutedColor"),
      success: formData.get("successColor"),
      danger: formData.get("dangerColor"),
      bgStart: formData.get("bgStartColor"),
      bgEnd: formData.get("bgEndColor"),
      panelStart: formData.get("panelStartColor"),
      panelEnd: formData.get("panelEndColor"),
      headerStart: formData.get("headerStartColor"),
      headerEnd: formData.get("headerEndColor")
    },
    settings: {
      glowStrength: formData.get("glowStrength"),
      surfaceContrast: formData.get("surfaceContrast"),
      radiusScale: formData.get("radiusScale"),
      flatSurfaces: formData.get("flatSurfaces") === "on"
    }
  });
}

