async function openGameActivityChart(gameId) {
  if (!currentUser?.id || isGuestRuntimeUser()) return;
  const modal = document.getElementById("game-activity-modal");
  if (!modal) return;

  const GAMES = {
    game_001: { title: "RTN ACTIVITY", subtitle: "Hands per day — last 30 days", unit: "hands", accent: "#e8a020" },
    game_002: { title: "GUESS 10 ACTIVITY", subtitle: "Hands per day — last 30 days", unit: "hands", accent: "#00e5ff" },
    game_003: { title: "SHAPE TRADERS ACTIVITY", subtitle: "Trades per day — last 30 days", unit: "trades", accent: "#c8ff00" },
    game_004: { title: "RYB ACTIVITY", subtitle: "Rounds per day — last 30 days", unit: "rounds", accent: "#ff4444" }
  };
  const game = GAMES[gameId] || GAMES.game_001;

  const titleEl = document.getElementById("game-activity-modal-title");
  const subtitleEl = document.getElementById("game-activity-modal-subtitle");
  if (titleEl) titleEl.textContent = game.title;
  if (subtitleEl) subtitleEl.textContent = game.subtitle;

  modal.hidden = false;
  document.getElementById("game-activity-modal-close")?.focus();

  const canvas = document.getElementById("game-activity-chart");
  if (!canvas) return;

  if (window._gameActivityChart) {
    window._gameActivityChart.destroy();
    window._gameActivityChart = null;
  }

  try {
    // Set cutoff to start of local day 30 days ago so the full local day is included
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    thirtyDaysAgo.setHours(0, 0, 0, 0);
    const cutoff = thirtyDaysAgo.toISOString();
    let rows = [];

    if (gameId === "game_001") {
      const { data, error } = await supabase.from("rtn_live_hands").select("started_at").eq("user_id", currentUser.id).neq("status", "active").gte("started_at", cutoff);
      if (error) console.error("[RTN] activity chart query error (game_001):", error.message, error);
      console.log(`[RTN] activity chart game_001 rows returned: ${(data||[]).length}`);
      rows = (data || []).map(r => r.started_at);
    } else if (gameId === "game_002") {
      const { data, error } = await supabase.from("guess10_live_hands").select("started_at").eq("user_id", currentUser.id).neq("status", "active").gte("started_at", cutoff);
      if (error) console.error("[RTN] activity chart query error (game_002):", error.message, error);
      console.log(`[RTN] activity chart game_002 rows returned: ${(data||[]).length}`);
      rows = (data || []).map(r => r.started_at);
    } else if (gameId === "game_003") {
      const { data, error } = await supabase.from("shape_trader_trades").select("executed_at").eq("user_id", currentUser.id).gte("executed_at", cutoff);
      if (error) console.error("[RTN] activity chart query error (game_003):", error.message, error);
      console.log(`[RTN] activity chart game_003 rows returned: ${(data||[]).length}`);
      rows = (data || []).map(r => r.executed_at);
    } else if (gameId === "game_004") {
      // Broadest possible filter — count every round that exists for this user,
      // regardless of status. roll_1 is NOT filtered on because cs_perform_roll
      // may not write that column, which would silently return zero rows.
      const { data: csData, error: csError } = await supabase
        .from("color_scheme_rounds")
        .select("created_at, status")
        .eq("user_id", currentUser.id)
        .gte("created_at", cutoff);
      if (csError) console.error("[RTN] activity chart query error (game_004):", csError.message, csError);
      console.log(`[RTN] activity chart game_004 rows returned: ${(csData||[]).length}`, (csData||[]).slice(0,3));
      rows = (csData || []).map(r => r.created_at);
    }

    // Use LOCAL dates so "today" matches the player's clock, not UTC.
    const toLocalDateKey = (ts) => {
      const d = ts instanceof Date ? ts : new Date(ts);
      if (!d || isNaN(d.getTime())) return null;
      const y = d.getFullYear();
      const m = String(d.getMonth() + 1).padStart(2, "0");
      const day = String(d.getDate()).padStart(2, "0");
      return `${y}-${m}-${day}`;
    };

    const countsByDay = {};
    for (const ts of rows) {
      const day = ts ? toLocalDateKey(new Date(ts)) : null;
      if (day) countsByDay[day] = (countsByDay[day] || 0) + 1;
    }

    const labels = [];
    const values = [];
    for (let i = 29; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const key = toLocalDateKey(d);
      labels.push(key.slice(5));
      values.push(countsByDay[key] || 0);
    }

    const totalRows = rows.length;
    const totalActivity = values.reduce((a, b) => a + b, 0);
    console.log(`[RTN] activity chart ${gameId}: ${totalRows} raw rows, ${totalActivity} total activity across 30d window`);
    if (subtitleEl) {
      subtitleEl.textContent = totalActivity > 0
        ? game.subtitle
        : `${game.subtitle} — no data found (${totalRows} rows fetched)`;
    }

    const ctx = canvas.getContext("2d");
    window._gameActivityChart = new Chart(ctx, {
      type: "bar",
      data: {
        labels,
        datasets: [{
          data: values,
          backgroundColor: game.accent + "40",
          borderColor: game.accent,
          borderWidth: 1,
          borderRadius: 2
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: (ctx) => ` ${ctx.parsed.y} ${game.unit}`
            }
          }
        },
        scales: {
          x: {
            ticks: { color: "#686850", font: { size: 9, family: "inherit" }, maxTicksLimit: 10 },
            grid: { color: "rgba(255,255,255,0.05)" },
            border: { color: "rgba(255,255,255,0.1)" }
          },
          y: {
            beginAtZero: true,
            ticks: { color: "#686850", font: { size: 9, family: "inherit" }, precision: 0 },
            grid: { color: "rgba(255,255,255,0.05)" },
            border: { color: "rgba(255,255,255,0.1)" }
          }
        }
      }
    });
  } catch (err) {
    console.error("[RTN] game activity chart error", err);
  }
}

function closeGameActivityModal() {
  const modal = document.getElementById("game-activity-modal");
  if (!modal) return;
  modal.hidden = true;
  if (window._gameActivityChart) {
    window._gameActivityChart.destroy();
    window._gameActivityChart = null;
  }
}

async function saveProfile(event) {
  event.preventDefault();
  
  if (!currentUser || currentUser.id === GUEST_USER.id) {
    showToast("Session expired. Please sign in again.", "error");
    return;
  }

  const firstName = profileFirstNameInput?.value.trim() || "";
  const lastName = profileLastNameInput?.value.trim() || "";
  const newPassword = profilePasswordInput?.value || "";

  if (!firstName || !lastName) {
    if (profileMessage) {
      profileMessage.textContent = "First name and last name are required.";
      profileMessage.className = "profile-status-message error";
    }
    return;
  }

  try {
    if (profileSaveButton) profileSaveButton.disabled = true;
    if (profileMessage) {
      profileMessage.textContent = "Saving...";
      profileMessage.className = "profile-status-message";
    }

    // Update profile in database
    const { error: profileError } = await supabase
      .from("profiles")
      .update({
        first_name: firstName,
        last_name: lastName
      })
      .eq("id", currentUser.id);

    if (profileError) throw profileError;

    // Update password if provided
    if (newPassword) {
      const { error: passwordError } = await supabase.auth.updateUser({
        password: newPassword
      });

      if (passwordError) throw passwordError;
    }

    // Success
    if (profileMessage) {
      profileMessage.textContent = "Profile updated successfully!";
      profileMessage.className = "profile-status-message success";
    }
    showToast("Profile updated successfully", "success");
    
    setProfileEditMode(false);
    
    // Clear message after 3 seconds
    setTimeout(() => {
      if (profileMessage) {
        profileMessage.textContent = "";
        profileMessage.className = "profile-status-message";
      }
    }, 3000);
    
  } catch (error) {
    console.error("[RTN] saveProfile error", error);
    if (profileMessage) {
      profileMessage.textContent = "Failed to update profile. Please try again.";
      profileMessage.className = "profile-status-message error";
    }
    showToast("Failed to update profile", "error");
  } finally {
    if (profileSaveButton) profileSaveButton.disabled = false;
  }
}

function displayAuthScreen({ focus = true, replaceHash = false } = {}) {
  currentRoute = "auth";
  applyResolvedTheme();
  showAuthView("login");
  updateAdminVisibility(null);
  updateResetButtonVisibility(null);

  if (typeof document !== "undefined" && document.body) {
    document.body.dataset.appState = "auth";
  }

  if (typeof window !== "undefined") {
    updateHash("auth", { replace: replaceHash });
    setTimeout(() => {
      if (focus && authEmailInput) {
        authEmailInput.focus();
      }
    }, 0);
  }
}

function hideAuthResendAction() {
  if (authResendWrapEl) {
    authResendWrapEl.hidden = true;
  }
  if (authResendConfirmationButton) {
    authResendConfirmationButton.disabled = false;
  }
}

async function handleAuthResendConfirmationRequest() {
  const email = String(authEmailInput?.value || "").trim();
  if (!email) {
    if (authErrorEl) {
      authErrorEl.hidden = false;
      authErrorEl.textContent = "Enter your email address first.";
    }
    hideAuthResendAction();
    authEmailInput?.focus();
    return;
  }

  if (!supabase?.auth || typeof supabase.auth.resend !== "function") {
    showToast("Unable to resend confirmation email", "error");
    return;
  }

  if (authResendConfirmationButton) {
    authResendConfirmationButton.disabled = true;
  }

  try {
    const { error } = await supabase.auth.resend({
      type: "signup",
      email
    });

    if (error) {
      throw error;
    }

    hideAuthResendAction();
    if (authErrorEl) {
      authErrorEl.hidden = false;
      authErrorEl.textContent = "Confirmation email sent. Please check your inbox.";
    }
    showToast("Confirmation email sent", "success");
  } catch (error) {
    console.error("[RTN] handleAuthResendConfirmationRequest error", error);
    if (authErrorEl) {
      authErrorEl.hidden = false;
      authErrorEl.textContent = error?.message || "Unable to resend confirmation email.";
    }
    if (authResendWrapEl) {
      authResendWrapEl.hidden = false;
    }
    showToast("Unable to resend confirmation email", "error");
  } finally {
    if (authResendConfirmationButton) {
      authResendConfirmationButton.disabled = false;
    }
  }
}

function forceAuth(reason, { message, tone = "warning", focus = true } = {}) {
  if (message) {
    showToast(message, tone);
  }
  applySignedOutState(reason, { focusInput: focus });
}

function applySignedOutState(reason = "unknown", { focusInput = true } = {}) {
    console.warn(`[RTN] applySignedOutState invoked (reason=${reason})`);
    const clearFn = typeof window !== "undefined" ? window.clearTimeout : clearTimeout;
    lastSyncedBankroll = null;
    bankrollInitialized = false;
    currentUser = { ...GUEST_USER };
    currentProfile = { ...GUEST_PROFILE };
    dashboardLoaded = false;
    prizesLoaded = false;
    adminPrizesLoaded = false;
    adminContestsLoaded = false;
    adminEditingPrizeId = null;
    adminPrizeCache = [];
    contestCache = [];
    currentContest = null;
    currentContestEntry = null;
    contestLeaderboard = [];
    userContestEntries = [];
    contestEntryMap = new Map();
    contestNotifications = [];
    contestStartNotifications = [];
    contestParticipantCounts = {};
    currentAccountMode = createNormalAccountMode();
    persistentBankrollHistory = [];
    persistentBankrollUserId = null;
    lastProfileSync = Date.now();

  if (dashboardProfileRetryTimer) {
    clearFn(dashboardProfileRetryTimer);
    dashboardProfileRetryTimer = null;
  }

  stats = { hands: 0, wagered: 0, paid: 0 };
  updateStatsUI();

  resetSessionScopedGameplayState({
    reason: `signed-out:${reason}`,
    resetRunTheNumbersStatus: true
  });

  bankroll = INITIAL_BANKROLL;
  handleBankrollChanged();
  updateDashboardCreditsDisplay(0);
  renderContestChip();
  renderContestNotifications();
  carterCash = 0;
  carterCashProgress = 0;
  lastSyncedCarterCash = 0;
  lastSyncedCarterProgress = 0;
  stopCarterCashAnimation();
  updateCarterCashDisplay();
  resetBankrollHistory();
  stopBankrollAnimation();

  if (adminPrizeListEl) {
    adminPrizeListEl.innerHTML = "";
  }
  closeAdminForm({ resetFields: true, restoreFocus: false });

  if (paytableModal && !paytableModal.hidden) {
    closePaytableModal({ restoreFocus: false });
  }
  if (resetModal && !resetModal.hidden) {
    closeResetModal({ restoreFocus: false });
  }
  if (shippingModal && !shippingModal.hidden) {
    closeShippingModal({ restoreFocus: false });
  }
  if (adminPrizeModal && !adminPrizeModal.hidden) {
    closeAdminForm({ resetFields: true, restoreFocus: false });
  }
  if (prizeImageModal && !prizeImageModal.hidden) {
    closePrizeImageModal({ restoreFocus: false });
  }

  setSelectedChip(chipDenominations[0], false);
  closeUtilityPanel();
  closeActiveDrawer();
  clearPlayAreaHeight();
  updateRebetButtonState();
  updatePauseButton();

  if (appShell) {
    appShell.setAttribute("data-hidden", "true");
  }

  authState.lastUserId = null;
  authState.manualSignOutRequested = false;

  displayAuthScreen({ focus: focusInput });
}

async function handleSignOut() {
  authState.manualSignOutRequested = true;
  try {
    const result = await supabase.auth.signOut();
    const error = result?.error ?? null;
    if (error) {
      authState.manualSignOutRequested = false;
      console.error("signOut error", error);
      showToast("Unable to sign out", "error");
      return;
    }

    // Immediately apply signed-out state so the UI updates even if the
    // auth state change event is delayed or not emitted by an offline stub.
    console.info("[RTN] signOut completed, applying signed-out state");
    try {
      applySignedOutState("manual-signout", { focusInput: true });
    } catch (err) {
      console.warn("[RTN] applySignedOutState after signOut failed", err);
    }
  } catch (err) {
    authState.manualSignOutRequested = false;
    console.error("Unexpected error during signOut", err);
    showToast("Unable to sign out", "error");
  }
}

function getHandModeTypeSnapshot(mode = currentAccountMode) {
  return isContestAccountMode(mode) ? "contest" : "normal";
}

function getHandContestIdSnapshot(mode = currentAccountMode) {
  return isContestAccountMode(mode) ? mode.contestId : null;
}

const GUESS10_SERVER_RPC_MISSING = "__guess10_server_rpc_missing__";
const RTN_SERVER_RPC_MISSING = "__rtn_server_rpc_missing__";

function normalizeGuess10ServerResult(result) {
  if (!result || typeof result !== "object" || Array.isArray(result)) {
    return null;
  }
  return result;
}

function normalizeGuess10SelectionValues(category, values = []) {
  const safeValues = Array.isArray(values) ? values.map((value) => String(value ?? "").trim()).filter(Boolean) : [];
  if (category === "color" || category === "suit") {
    return safeValues.map((value) => value.toLowerCase());
  }
  return safeValues.map((value) => value.toUpperCase());
}

function isGuess10ActiveHandConflict(error) {
  const message = String(error?.message || error?.details || error?.hint || "").toLowerCase();
  return message.includes("active guess 10 hand") && message.includes("already");
}

function getGuess10ServerResultBalance(result) {
  const nextBalance = normalizeStoredCreditValue(Number(result?.cash_balance ?? bankroll));
  return Number.isFinite(nextBalance) ? nextBalance : normalizeStoredCreditValue(bankroll);
}

function applyGuess10ServerAccountSnapshot(result) {
  const nextBalance = getGuess10ServerResultBalance(result);
  const nextCarterCash = Math.max(0, Math.round(Number(result?.carter_cash ?? carterCash)));
  const nextCarterCashProgress = normalizeCarterCashProgressValue(
    Number(result?.carter_cash_progress ?? carterCashProgress)
  );
  const nextUpdatedAt = result?.balance_updated_at || null;

  if (isContestAccountMode()) {
    const activeEntry = getModeContestEntry();
    if (activeEntry) {
      applyAuthoritativeAccountSnapshotForMode(currentAccountMode, {
        contestEntry: {
          ...activeEntry,
          current_credits: nextBalance,
          current_carter_cash: nextCarterCash,
          current_carter_cash_progress: nextCarterCashProgress,
          updated_at: nextUpdatedAt || activeEntry.updated_at || null,
          display_name: getContestDisplayName(currentProfile, currentUser?.id),
          participant_email: currentUser?.email || ""
        }
      });
    } else {
      bankroll = nextBalance;
      handleBankrollChanged();
      carterCash = nextCarterCash;
      carterCashProgress = nextCarterCashProgress;
      handleCarterCashChanged();
    }
  } else if (currentProfile) {
    applyAuthoritativeAccountSnapshotForMode(currentAccountMode, {
      normalProfile: {
        ...currentProfile,
        credits: nextBalance,
        carter_cash: nextCarterCash,
        carter_cash_progress: nextCarterCashProgress,
        updated_at: nextUpdatedAt || currentProfile.updated_at || null
      }
    });
  } else {
    bankroll = nextBalance;
    handleBankrollChanged();
    carterCash = nextCarterCash;
    carterCashProgress = nextCarterCashProgress;
    handleCarterCashChanged();
  }

  return nextBalance;
}

function applyRtnServerAccountSnapshot(result) {
  return applyGuess10ServerAccountSnapshot(result);
}

async function invokeRtnServerRpc(functionName, args = {}) {
  if (!supabase || isGuestRuntimeUser()) {
    return RTN_SERVER_RPC_MISSING;
  }

  const { data, error } = await supabase.rpc(functionName, args);
  if (error) {
    if (isMissingRpcError(error)) {
      return RTN_SERVER_RPC_MISSING;
    }
    throw error;
  }

  if (Array.isArray(data)) {
    return data[0] || null;
  }
  return data || null;
}

async function invokeGuess10ServerRpc(functionName, args = {}) {
  if (!supabase || isGuestRuntimeUser()) {
    return GUESS10_SERVER_RPC_MISSING;
  }

  const { data, error } = await supabase.rpc(functionName, args);
  if (error) {
    if (isMissingRpcError(error)) {
      return GUESS10_SERVER_RPC_MISSING;
    }
    throw error;
  }

  if (Array.isArray(data)) {
    return normalizeGuess10ServerResult(data[0] || null);
  }
  return normalizeGuess10ServerResult(data);
}

async function fetchActiveGuess10HandForCurrentUser() {
  if (!supabase || !currentUser?.id || isGuestRuntimeUser()) {
    return null;
  }

  const { data: handRow, error: handError } = await supabase
    .from("guess10_live_hands")
    .select("id, user_id, status, result, mode_type, contest_id, selection_category, selection_values, selection_label, current_pot, current_rung, draw_count, started_at, last_draw_at, ended_at, total_cards, total_wager, total_paid, net, commission_percentage, commission_kept, new_account_value, drawn_cards")
    .eq("user_id", currentUser.id)
    .eq("status", "active")
    .order("started_at", { ascending: false })
    .limit(1)
    .maybeSingle();

  if (handError) {
    if (isMissingRelationError(handError, "guess10_live_hands")) {
      return GUESS10_SERVER_RPC_MISSING;
    }
    throw handError;
  }

  return handRow || null;
}

async function resumeActiveGuess10Hand({ force = false } = {}) {
  if (!supabase || !currentUser?.id || isGuestRuntimeUser()) {
    return null;
  }
  if (redBlackSettlementPending) {
    return null;
  }
  if (!force && redBlackHandActive && redBlackServerHandId) {
    return null;
  }

  const handRow = await fetchActiveGuess10HandForCurrentUser();
  if (handRow === GUESS10_SERVER_RPC_MISSING) {
    return GUESS10_SERVER_RPC_MISSING;
  }
  if (!handRow) {
    return null;
  }

  const { data: drawRows, error: drawError } = await supabase
    .from("guess10_draw_plays")
    .select("draw_index, placed_at, wager_amount, prediction_category, prediction_values, selection_label, multiplier, drawn_card_label, drawn_card_suit, drawn_card_suit_name, drawn_card_color, was_correct, starting_pot, ending_pot")
    .eq("hand_id", handRow.id)
    .order("draw_index", { ascending: true });

  if (drawError) {
    if (isMissingRelationError(drawError, "guess10_draw_plays")) {
      return GUESS10_SERVER_RPC_MISSING;
    }
    throw drawError;
  }

  redBlackServerHandId = handRow.id;
  redBlackHandActive = true;
  redBlackAwaitingDecision = false;
  redBlackSettlementPending = false;
  redBlackBet = roundCurrencyValue(Number(handRow.total_wager || 0));
  redBlackLastBet = redBlackBet;
  redBlackCurrentPot = roundCurrencyValue(Number(handRow.current_pot || redBlackBet));
  redBlackRung = Math.max(0, Math.round(Number(handRow.current_rung || 0)));
  redBlackCategory = String(handRow.selection_category || "color").trim().toLowerCase() || "color";
  redBlackSelectedValues = normalizeGuess10SelectionValues(redBlackCategory, handRow.selection_values);
  clearRedBlackDraws();
  clearRedBlackHistory();

  (Array.isArray(drawRows) ? drawRows : [])
    .sort((a, b) => Number(a?.draw_index || 0) - Number(b?.draw_index || 0))
    .forEach((row) => {
      const card = sanitizeGuess10AssistantCard({
        label: row?.drawn_card_label,
        suit: row?.drawn_card_suit,
        suitName: row?.drawn_card_suit_name,
        color: row?.drawn_card_color
      });
      appendRedBlackCard(card);
      appendRedBlackHistoryEntry({
        card,
        matched: Boolean(row?.was_correct),
        multiplier: roundCurrencyValue(Number(row?.multiplier || 0)),
        selectionLabel: String(row?.selection_label || handRow.selection_label || ""),
        category: String(row?.prediction_category || handRow.selection_category || redBlackCategory).toLowerCase(),
        selectedValues: normalizeGuess10SelectionValues(
          String(row?.prediction_category || handRow.selection_category || redBlackCategory).toLowerCase(),
          row?.prediction_values
        ),
        wagerAmount: roundCurrencyValue(Number(row?.wager_amount || handRow.total_wager || 0)),
        startingPot: roundCurrencyValue(Number(row?.starting_pot || 0)),
        potAfter: roundCurrencyValue(Number(row?.ending_pot || 0))
      });
    });

  renderRedBlackValueSelector();
  renderRedBlackSummary();
  updateRedBlackPaytableHighlight();
  updateRedBlackActionState();

  const commissionRate = getGuess10CommissionRate();
  const selectionLabel = String(handRow.selection_label || getGuess10SelectionLabel());
  if (redBlackRung > 0) {
    setRedBlackStatus(
      `Resumed active hand. ${selectionLabel} is live, pot is ${formatCurrency(redBlackCurrentPot)}, and commission is ${formatPercent(commissionRate)} of winnings.`
    );
  } else {
    setRedBlackStatus(
      `Resumed active hand. ${selectionLabel} is locked in for ${formatCurrency(redBlackBet)}. Draw when you're ready.`
    );
  }

  return handRow;
}

function sanitizeGuess10AssistantCard(card = null) {
  if (!card || typeof card !== "object") {
    return null;
  }
  return {
    label: card.label ?? null,
    suit: card.suit ?? null,
    suitName: card.suitName ?? null,
    color: card.color ?? null,
    stopper: Boolean(card.stopper)
  };
}

function sanitizeStoredDrawnCards(cards = []) {
  if (!Array.isArray(cards)) {
    return [];
  }
  return cards
    .map((card) => sanitizeGuess10AssistantCard(card))
    .filter(Boolean);
}

function buildGuess10DrawPlayRows(handHistory = [], {
  result = null,
  totalPaid = 0,
  commissionKept = 0,
  netHandProfit = 0
} = {}) {
  if (!Array.isArray(handHistory)) {
    return [];
  }
  const normalizedResult = String(result || "").trim().toLowerCase();
  return handHistory.map((entry, index) => {
    const isLastDraw = index === handHistory.length - 1;
    const wagerAmount = roundCurrencyValue(Number(entry?.wagerAmount || 0));
    const explicitCashoutPayout = roundCurrencyValue(Number(entry?.cashoutPayout || 0));
    const explicitCommissionKept = roundCurrencyValue(Number(entry?.commissionKept || 0));
    const explicitNetHandProfit = roundCurrencyValue(Number(entry?.netHandProfit || 0));
    const settledEndingPot =
      normalizedResult === "cashout" && isLastDraw
        ? roundCurrencyValue(explicitCashoutPayout || Number(totalPaid || 0))
        : roundCurrencyValue(Number(entry?.potAfter || 0));
    const computedNetHandProfit =
      normalizedResult === "cashout" && isLastDraw
        ? roundCurrencyValue(explicitNetHandProfit || (settledEndingPot - wagerAmount))
        : isLastDraw
          ? roundCurrencyValue(Number(netHandProfit || 0))
          : 0;
    return {
      draw_index: index + 1,
      placed_at: entry?.placedAt || new Date().toISOString(),
      wager_amount: wagerAmount,
      prediction_category: String(entry?.category || ""),
      prediction_values: Array.isArray(entry?.selectedValues)
        ? entry.selectedValues.map((value) => String(value ?? ""))
        : [],
      selection_label: String(entry?.selectionLabel || ""),
      multiplier: Number.isFinite(Number(entry?.multiplier)) ? Number(entry.multiplier) : 0,
      drawn_card_label: entry?.card?.label ?? null,
      drawn_card_suit: entry?.card?.suit ?? null,
      drawn_card_suit_name: entry?.card?.suitName ?? null,
      drawn_card_color: entry?.card?.color ?? null,
      was_correct: Boolean(entry?.matched),
      starting_pot: roundCurrencyValue(Number(entry?.startingPot || 0)),
      ending_pot: settledEndingPot,
      hand_result: normalizedResult || null,
      cashout_payout: normalizedResult === "cashout" && isLastDraw
        ? roundCurrencyValue(explicitCashoutPayout || Number(totalPaid || 0))
        : 0,
      commission_kept: normalizedResult === "cashout" && isLastDraw
        ? roundCurrencyValue(explicitCommissionKept || Number(commissionKept || 0))
        : 0,
      net_hand_profit: computedNetHandProfit
    };
  });
}

async function insertGuess10DrawPlayRecords(rows = []) {
  if (!Array.isArray(rows) || !rows.length) {
    return true;
  }

  const { error } = await supabase.from("guess10_draw_plays").insert(rows);
  if (error) {
    if (isMissingRelationError(error, "guess10_draw_plays")) {
      console.warn("[RTN] guess10_draw_plays table missing; skipping Guess 10 draw persistence");
      return false;
    }
    throw error;
  }

  return true;
}

// RTN hands are written by start_rtn_hand/draw_rtn_card RPCs → rtn_live_hands.
// G10 hands are written by the guess10 server RPC → guess10_live_hands.

function isRtnActiveHandConflict(error) {
  const message = String(error?.message || error?.details || error?.hint || "").toLowerCase();
  return message.includes("active run the numbers hand") && message.includes("already");
}

function sanitizeRtnServerBetState(betState = []) {
  if (!Array.isArray(betState)) {
    return [];
  }

  return betState.map((entry) => ({
    key: String(entry?.key || ""),
    type: String(entry?.type || ""),
    label: String(entry?.label || entry?.key || "Bet"),
    units: roundCurrencyValue(Number(entry?.units || 0)),
    hits: Math.max(0, Math.round(Number(entry?.hits || 0))),
    paid: roundCurrencyValue(Number(entry?.paid || 0)),
    chips: Array.isArray(entry?.chips)
      ? entry.chips.map((chip) => roundCurrencyValue(Number(chip || 0))).filter((chip) => chip > 0)
      : [],
    metadata: entry?.metadata && typeof entry.metadata === "object" ? { ...entry.metadata } : {}
  })).filter((entry) => entry.key && entry.units > 0);
}

function isRtnRemovableBetType(type) {
  return ["specific-card", "bust-suit", "bust-rank", "bust-joker"].includes(String(type || ""));
}

function isRtnServerIntermission() {
  return Boolean(rtnServerHandId) && !bettingOpen && (!dealing || awaitingManualDeal);
}

function shouldHideBetFromBoard(bet) {
  return Boolean(
    bet
    && bet.type === "specific-card"
    && (Math.max(0, Math.round(Number(bet.hits || 0))) > 0 || roundCurrencyValue(Number(bet.paid || 0)) > 0)
  );
}

function getDisplayedBetUnits(bet) {
  return shouldHideBetFromBoard(bet) ? 0 : roundCurrencyValue(Number(bet?.units || 0));
}

function getDisplayedBetChips(bet) {
  if (shouldHideBetFromBoard(bet)) {
    return [];
  }
  const chips = Array.isArray(bet?.chips) && bet.chips.length ? bet.chips : [bet?.units];
  return chips
    .map((chip) => roundCurrencyValue(Number(chip || 0)))
    .filter((chip) => chip > 0);
}

function isRtnBetInSection(betOrDefinition, section) {
  const type = String(betOrDefinition?.type || "");
  if (section === "specific-card") {
    return type === "specific-card";
  }
  if (section === "bust-card") {
    return type === "bust-suit" || type === "bust-rank" || type === "bust-joker";
  }
  return false;
}

function getVisibleRtnSectionBets(section) {
  return bets.filter((bet) => isRtnBetInSection(bet, section) && getDisplayedBetUnits(bet) > 0);
}

function updateRtnSectionClearButtons() {
  const canUseSectionClear = isRtnServerIntermission();
  const sections = [
    { button: specificCardClearButton, section: "specific-card" },
    { button: bustCardClearButton, section: "bust-card" }
  ];

  sections.forEach(({ button, section }) => {
    if (!(button instanceof HTMLButtonElement)) {
      return;
    }
    const hasVisibleBets = getVisibleRtnSectionBets(section).length > 0;
    button.hidden = !hasVisibleBets || !canUseSectionClear;
    button.disabled = !hasVisibleBets || !canUseSectionClear || rtnSectionClearPending;
    button.setAttribute("aria-hidden", String(!hasVisibleBets || !canUseSectionClear));
    button.setAttribute("aria-disabled", String(button.disabled));
  });
}

function adjustDisplayedBetByAmount(key, amountToRemove) {
  const nextKey = String(key || "");
  const targetAmount = roundCurrencyValue(Number(amountToRemove || 0));
  if (!nextKey || targetAmount <= 0) {
    return 0;
  }

  const bet = bets.find((entry) => String(entry?.key || "") === nextKey);
  if (!bet) {
    return 0;
  }

  const removableAmount = Math.min(roundCurrencyValue(Number(bet.units || 0)), targetAmount);
  if (removableAmount <= 0) {
    return 0;
  }

  let remaining = removableAmount;
  const chips = Array.isArray(bet.chips) ? [...bet.chips] : [];
  for (let index = chips.length - 1; index >= 0 && remaining > 0; index -= 1) {
    const chipValue = roundCurrencyValue(Number(chips[index] || 0));
    if (chipValue <= 0) {
      chips.splice(index, 1);
      continue;
    }
    if (chipValue <= remaining + 0.001) {
      remaining = roundCurrencyValue(remaining - chipValue);
      chips.splice(index, 1);
    }
  }

  bet.units = roundCurrencyValue(Number(bet.units || 0) - removableAmount);
  bet.chips = chips;
  if (bet.units <= 0.001) {
    bets = bets.filter((entry) => entry !== bet);
  }
  return removableAmount;
}

function clearLocalRtnSectionBets(section) {
  const matchingBets = bets.filter((bet) => isRtnBetInSection(bet, section));
  if (!matchingBets.length) {
    return 0;
  }

  const removedTotal = roundCurrencyValue(
    matchingBets.reduce((sum, bet) => sum + Math.max(0, Number(bet.units || 0)), 0)
  );
  bets = bets.filter((bet) => !isRtnBetInSection(bet, section));
  rtnPendingMidHandBetDrafts = rtnPendingMidHandBetDrafts.filter((draft) => !isRtnBetInSection(draft, section));
  if (removedTotal > 0) {
    restoreUnits(removedTotal);
  }
  renderBets();
  syncDisplayedBetStacksFromState({ animate: false });
  return removedTotal;
}

function clearPendingRtnSectionDrafts(section) {
  const draftsToRemove = rtnPendingMidHandBetDrafts.filter((draft) => isRtnBetInSection(draft, section));
  if (!draftsToRemove.length) {
    return { removedTotal: 0, removedKeys: [] };
  }

  let removedTotal = 0;
  const removedKeys = new Set();
  draftsToRemove.forEach((draft) => {
    const amount = roundCurrencyValue(Number(draft?.amount || 0));
    if (amount <= 0) {
      return;
    }
    removedTotal = roundCurrencyValue(removedTotal + adjustDisplayedBetByAmount(draft.key, amount));
    removedKeys.add(String(draft.key || ""));
  });

  rtnPendingMidHandBetDrafts = rtnPendingMidHandBetDrafts.filter((draft) => !isRtnBetInSection(draft, section));
  if (removedTotal > 0) {
    restoreUnits(removedTotal);
  }
  renderBets();
  syncDisplayedBetStacksFromState({ animate: false });
  return { removedTotal, removedKeys: Array.from(removedKeys) };
}

async function clearRtnSectionBets(section) {
  if (rtnSectionClearPending) {
    return;
  }

  const sectionLabel = section === "specific-card" ? "Specific Card Bets" : "Bust Card Bets";

  if (bettingOpen) {
    return;
  }

  if (!isRtnServerIntermission() || !rtnServerHandId) {
    return;
  }

  const { removedKeys: locallyRemovedDraftKeys } = clearPendingRtnSectionDrafts(section);
  const persistedKeys = getVisibleRtnSectionBets(section)
    .map((bet) => String(bet?.key || ""))
    .filter((key) => key && !locallyRemovedDraftKeys.includes(key));

  if (!persistedKeys.length) {
    if (locallyRemovedDraftKeys.length) {
      statusEl.textContent = `${sectionLabel} cleared.`;
    }
    return;
  }

  rtnSectionClearPending = true;
  updateRtnSectionClearButtons();
  try {
    let latestResult = null;
    for (const betKey of persistedKeys) {
      latestResult = await invokeRtnServerRpc("remove_rtn_bet_play", {
        _hand_id: rtnServerHandId,
        _bet_key: betKey
      });
      if (latestResult === RTN_SERVER_RPC_MISSING) {
        throw new Error("RTN bet removal RPC is unavailable.");
      }
      applyRtnServerAccountSnapshot(latestResult);
      currentHandContext = {
        totalCards: Math.max(0, Math.round(Number(latestResult?.total_cards || currentHandContext?.totalCards || 0))),
        nonStopperCount: sanitizeStoredDrawnCards(latestResult?.drawn_cards || currentHandContext?.drawnCards || []).filter((card) => !card?.stopper).length,
        drawnCards: sanitizeStoredDrawnCards(latestResult?.drawn_cards || currentHandContext?.drawnCards || [])
      };
      replaceRtnBetsFromServerState(latestResult?.bet_state || [], { animateStacks: false });
    }

    if (latestResult) {
      statusEl.textContent = `${sectionLabel} cleared.`;
    }
  } catch (error) {
    console.error("[RTN] Unable to clear RTN section bets", error);
    showToast(error?.message || `Unable to clear ${sectionLabel.toLowerCase()}.`, "error");
  } finally {
    rtnSectionClearPending = false;
    updateRtnSectionClearButtons();
  }
}

function getDrawnSpecificCardKeys() {
  const drawnCards = Array.isArray(currentHandContext?.drawnCards) ? currentHandContext.drawnCards : [];
  const drawnKeys = new Set();
  drawnCards.forEach((card) => {
    const rank = String(card?.rank || card?.label || "").trim();
    const suit = String(card?.suit || "").trim();
    if (!rank || !suit || rank === "Joker") {
      return;
    }
    drawnKeys.add(`card-${rank}${suit}`);
  });
  return drawnKeys;
}

function syncDisplayedBetStacksFromState({ animate = false } = {}) {
  clearChipStacks();
  bets.forEach((bet) => {
    getDisplayedBetChips(bet).forEach((chipValue) => {
      addChipToSpot(bet.key, chipValue, { animate });
    });
  });
  updateBetSpotTotals();
  updateRtnSectionClearButtons();
}

function replaceRtnBetsFromServerState(betState = [], { animateStacks = false, forceRebuildStacks = false } = {}) {
  const nextBets = sanitizeRtnServerBetState(betState);
  bets = nextBets;
  renderBets();
  syncDisplayedBetStacksFromState({ animate: animateStacks });
}

// Sanitize metadata values that cannot survive JSON serialization (e.g. Infinity → null).
// The server-side SQL checks for the string "Infinity" when evaluating count bets, so we
// replace JS Infinity with that sentinel string before sending over the wire.
function sanitizeMetadataForServer(metadata) {
  if (!metadata || typeof metadata !== "object") return {};
  const result = {};
  for (const [k, v] of Object.entries(metadata)) {
    if (v === Infinity) result[k] = "Infinity";
    else if (v === -Infinity) result[k] = "-Infinity";
    else result[k] = v;
  }
  return result;
}

function serializeRtnBetPlacements(sourceBets = []) {
  const safeBets = Array.isArray(sourceBets) ? sourceBets : [];
  return safeBets.flatMap((bet) => {
    const definition = getBetDefinition(bet?.key);
    const label = String(bet?.label || definition?.label || bet?.key || "Bet");
    const type = String(bet?.type || definition?.type || "");
    const rawMetadata = bet?.metadata && typeof bet.metadata === "object"
      ? bet.metadata
      : definition?.metadata || {};
    const metadata = sanitizeMetadataForServer(rawMetadata);
    const chips = Array.isArray(bet?.chips) && bet.chips.length
      ? bet.chips
      : [roundCurrencyValue(Number(bet?.units || 0))];

    return chips
      .map((chip) => roundCurrencyValue(Number(chip || 0)))
      .filter((chip) => chip > 0)
      .map((chip) => ({
        key: String(bet?.key || ""),
        type,
        label,
        amount: chip,
        payout: Number(definition?.payout || 0),
        metadata
      }));
  });
}

function serializeRtnMidHandDrafts() {
  return rtnPendingMidHandBetDrafts.map((draft) => ({
    key: String(draft?.key || ""),
    type: String(draft?.type || ""),
    label: String(draft?.label || draft?.key || "Bet"),
    amount: roundCurrencyValue(Number(draft?.amount || 0)),
    payout: Number(draft?.payout || 0),
    metadata: draft?.metadata && typeof draft.metadata === "object" ? { ...draft.metadata } : {}
  })).filter((draft) => draft.key && draft.type && draft.amount > 0);
}

function renderRtnDrawsFromServerState(drawnCards = [], { animateNewCards = false, forceRebuild = false } = {}) {
  const nextCards = sanitizeStoredDrawnCards(drawnCards);
  if (forceRebuild || drawsContainer.children.length > nextCards.length) {
    drawsContainer.innerHTML = "";
    updateRtnCardCount();
    nextCards.forEach((card) => {
      renderDraw(card, { animate: false });
    });
    return;
  }

  const currentCount = drawsContainer.children.length;
  if (currentCount === 0 && nextCards.length > 0) {
    if (!forceRebuild && nextCards.length === 1) {
      renderDraw(nextCards[0], { animate: animateNewCards });
      return;
    }
    nextCards.forEach((card) => {
      renderDraw(card, { animate: false });
    });
    return;
  }

  if (nextCards.length <= currentCount) {
    return;
  }

  nextCards.slice(currentCount).forEach((card) => {
    renderDraw(card, { animate: animateNewCards });
  });
}

async function fetchActiveRtnHandForCurrentUser() {
  if (!supabase || !currentUser?.id || isGuestRuntimeUser()) {
    return null;
  }

  const { data: handRow, error } = await supabase
    .from("rtn_live_hands")
    .select("id, user_id, status, result, mode_type, contest_id, started_at, last_draw_at, ended_at, draw_index, drawn_cards, total_cards, total_wager, total_paid, net, new_account_value, hand_state, stopper_card")
    .eq("user_id", currentUser.id)
    .eq("status", "active")
    .order("started_at", { ascending: false })
    .limit(1)
    .maybeSingle();

  if (error) {
    if (isMissingRelationError(error, "rtn_live_hands")) {
      return RTN_SERVER_RPC_MISSING;
    }
    throw error;
  }

  return handRow || null;
}

async function resumeActiveRtnHand({ force = false } = {}) {
  if (!supabase || !currentUser?.id || isGuestRuntimeUser()) {
    return null;
  }
  if (!force && dealing && rtnServerHandId) {
    return null;
  }

  const handRow = await fetchActiveRtnHandForCurrentUser();
  if (handRow === RTN_SERVER_RPC_MISSING) {
    return RTN_SERVER_RPC_MISSING;
  }
  if (!handRow) {
    return null;
  }

  const { data: betRows, error: betError } = await supabase
    .from("bet_plays")
    .select("rtn_hand_id, bet_key, bet_type, amount, amount_wagered, amount_paid, raw, result_snapshot, placed_at")
    .eq("rtn_hand_id", handRow.id)
    .eq("accepted", true)
    .order("placed_at", { ascending: true });

  if (betError) {
    throw betError;
  }

  const grouped = new Map();
  (Array.isArray(betRows) ? betRows : []).forEach((row) => {
    if (String(row?.result_snapshot?.resolved_reason || row?.result_snapshot?.["resolved_reason"] || "") === "bet_removed") {
      return;
    }
    const key = String(row?.bet_key || "");
    if (!key) return;
    const amount = roundCurrencyValue(Number(row?.amount ?? row?.amount_wagered ?? 0));
    const paid = roundCurrencyValue(Number(row?.amount_paid || 0));
    const hits = Math.max(0, Math.round(Number(row?.result_snapshot?.hits || row?.result_snapshot?.["hits"] || 0)));
    const raw = row?.raw && typeof row.raw === "object" ? row.raw : {};
    if (!grouped.has(key)) {
      grouped.set(key, {
        key,
        type: String(row?.bet_type || raw?.type || ""),
        label: String(raw?.label || key),
        units: 0,
        hits: 0,
        paid: 0,
        chips: [],
        metadata: raw?.metadata && typeof raw.metadata === "object" ? { ...raw.metadata } : {}
      });
    }
    const aggregate = grouped.get(key);
    aggregate.units = roundCurrencyValue(aggregate.units + amount);
    aggregate.paid = roundCurrencyValue(aggregate.paid + paid);
    aggregate.hits += hits;
    aggregate.chips.push(amount);
  });

  rtnServerHandId = handRow.id;
  rtnPendingMidHandBetDrafts = [];
  dealing = false;
  awaitingManualDeal = false;
  setHandPaused(false);
  currentHandContext = {
    totalCards: Math.max(0, Math.round(Number(handRow?.total_cards || 0))),
    nonStopperCount: sanitizeStoredDrawnCards(handRow?.drawn_cards).length,
    drawnCards: sanitizeStoredDrawnCards(handRow?.drawn_cards)
  };
  renderRtnDrawsFromServerState(handRow?.drawn_cards, { animateNewCards: false, forceRebuild: true });
  replaceRtnBetsFromServerState(Array.from(grouped.values()), { animateStacks: false, forceRebuildStacks: true });
  setBettingEnabled(false);
  updateAutoDealToggleUI();
  updatePauseButton();
  updateDealButtonState();
  updateRebetButtonState();

  const paytableId = String(handRow?.hand_state?.paytable_id || handRow?.hand_state?.["paytable_id"] || activePaytable.id);
  setActivePaytable(paytableId, { announce: false });
  statusEl.textContent = "Resumed active Run The Numbers hand. Draw when you're ready.";
  return handRow;
}

async function startRtnHandServer() {
  rtnServerStartPending = true;
  try {
    const result = await invokeRtnServerRpc("start_rtn_hand", {
      _opening_bets: serializeRtnBetPlacements(bets),
      _paytable_id: activePaytable.id,
      _mode_type: getHandModeTypeSnapshot(),
      _contest_id: getHandContestIdSnapshot()
    });

    if (result === RTN_SERVER_RPC_MISSING) {
      return RTN_SERVER_RPC_MISSING;
    }
    if (!result?.hand_id) {
      throw new Error("RTN start hand did not return a hand id.");
    }

    applyRtnServerAccountSnapshot(result);
    rtnServerHandId = result.hand_id;
    rtnPendingMidHandBetDrafts = [];
    replaceRtnBetsFromServerState(result?.bet_state || [], { animateStacks: false });
    renderRtnDrawsFromServerState(result?.drawn_cards || [], { animateNewCards: false });
    return result;
  } finally {
    rtnServerStartPending = false;
  }
}

async function drawRtnCardServer() {
  if (!rtnServerHandId) {
    throw new Error("RTN hand is missing a server hand id.");
  }

  const result = await invokeRtnServerRpc("draw_rtn_card", {
    _hand_id: rtnServerHandId,
    _midhand_bets: serializeRtnMidHandDrafts()
  });

  if (result === RTN_SERVER_RPC_MISSING) {
    return RTN_SERVER_RPC_MISSING;
  }
  return result;
}

function applyTheme(theme) {
  if (!document.body) {
    return;
  }
  ALL_THEME_CLASSES.forEach((className) => {
    document.body.classList.remove(className);
  });
  delete document.body.dataset.themeProfile;
  clearThemeVariables(document.body);
  applyGlobalShellThemeVariables();
  applyAiThemeVariables(aiThemeSettingsCache);
  applyLoginThemeVariables(loginThemeSettingsCache);
  applyLoginThemeContent(loginThemeSettingsCache);
  if (typeof window !== "undefined") {
    window.requestAnimationFrame(() => drawBankrollChart());
  } else {
    drawBankrollChart();
  }
}

function getAdminThemeOverrideStorageKey(userId = currentUser?.id) {
  if (!userId || userId === GUEST_USER.id) {
    return null;
  }
  return `rtn:admin-theme-override:${userId}`;
}

function loadStoredAdminThemeOverride(userId = currentUser?.id) {
  if (typeof window === "undefined" || !window.localStorage) {
    return null;
  }
  const storageKey = getAdminThemeOverrideStorageKey(userId);
  if (!storageKey) {
    return null;
  }
  try {
    const raw = window.localStorage.getItem(storageKey);
    return raw ? slugifyThemeKey(raw) || null : null;
  } catch (error) {
    console.warn("[RTN] unable to load admin theme override", error);
    return null;
  }
}

function persistAdminThemeOverride(themeKey, userId = currentUser?.id) {
  if (typeof window === "undefined" || !window.localStorage) {
    return;
  }
  const storageKey = getAdminThemeOverrideStorageKey(userId);
  if (!storageKey) {
    return;
  }
  try {
    if (themeKey) {
      window.localStorage.setItem(storageKey, String(themeKey));
    } else {
      window.localStorage.removeItem(storageKey);
    }
  } catch (error) {
    console.warn("[RTN] unable to persist admin theme override", error);
  }
}

function syncAdminThemeOverrideForCurrentUser() {
  const userId = currentUser?.id || null;
  if (adminThemeOverrideUserId === userId) {
    return;
  }
  adminThemeOverrideUserId = userId;

  if (!isAdmin()) {
    adminThemeOverrideTheme = null;
    adminThemeOverrideStoredKey = null;
    return;
  }

  const storedKey = loadStoredAdminThemeOverride(userId);
  adminThemeOverrideStoredKey = storedKey;
  adminThemeOverrideTheme = storedKey || null;
}

function getResolvedThemeRecord(route = currentRoute) {
  const gameTheme = getGameThemeRecord(route);
  if (gameTheme) {
    return gameTheme;
  }
  return getMainAppThemeRecord();
}

function refreshAdminThemeOverrideThemeFromLibrary() {
  if (!adminThemeOverrideStoredKey) {
    return;
  }
  const matchingTheme = getThemeLibrary().find((theme) => theme.key === adminThemeOverrideStoredKey) || null;
  if (!matchingTheme) {
    adminThemeOverrideStoredKey = null;
    adminThemeOverrideTheme = null;
    persistAdminThemeOverride(null);
    return;
  }
  adminThemeOverrideTheme = matchingTheme;
}

function updateAdminThemeOverrideUI() {
  if (adminThemeOverrideStatus) {
    adminThemeOverrideStatus.textContent = "";
  }

  if (adminThemeClearOverrideButton) {
    adminThemeClearOverrideButton.disabled = true;
  }

  if (adminThemeUseDefaultsButton) {
    adminThemeUseDefaultsButton.disabled = true;
  }

  document.querySelectorAll("[data-admin-theme-try-on-key]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement)) return;
    button.textContent = "Built In";
    button.disabled = true;
  });
}

function applyResolvedTheme(route = currentRoute) {
  applyTheme();
  updateAdminThemeOverrideUI();
}

function setAdminThemeOverride(theme, { persist = false } = {}) {
  applyResolvedTheme();
}

function initTheme() {
  currentTheme = MAIN_APP_THEME_KEY;
  if (!document.body) {
    return;
  }
  ALL_THEME_CLASSES.forEach((className) => {
    document.body.classList.remove(className);
  });
  delete document.body.dataset.themeProfile;
  clearThemeVariables(document.body);
  clearAiThemeVariables(document.body);
  clearLoginThemeVariables(document.body);
  applyLoginThemeContent(loginThemeSettingsCache);
  applyGlobalShellThemeVariables();
}

const bankrollEl = document.getElementById("bankroll");
const bankrollExactTooltipEl = document.getElementById("bankroll-exact-tooltip");
const bankrollExactValueEl = document.getElementById("bankroll-exact-value");
const carterCashEl = document.getElementById("carter-cash");
const ccExactTooltipEl = document.getElementById("cc-exact-tooltip");
const ccExactValueEl = document.getElementById("cc-exact-value");
const carterCashDeltaEl = document.getElementById("carter-cash-delta");

let _headerExactDismissTimer = null;

function _showHeaderExactTooltip(tooltipEl) {
  if (!tooltipEl) return;
  // Hide any other open tooltip first
  [bankrollExactTooltipEl, ccExactTooltipEl].forEach((el) => {
    if (el && el !== tooltipEl) {
      el.hidden = true;
      el.classList.remove("is-visible");
    }
  });
  clearTimeout(_headerExactDismissTimer);
  tooltipEl.hidden = false;
  // Force reflow for transition
  void tooltipEl.offsetWidth;
  tooltipEl.classList.add("is-visible");
  _headerExactDismissTimer = setTimeout(() => {
    tooltipEl.classList.remove("is-visible");
    setTimeout(() => { tooltipEl.hidden = true; }, 220);
  }, 3000);
}

function _hideHeaderExactTooltips() {
  clearTimeout(_headerExactDismissTimer);
  [bankrollExactTooltipEl, ccExactTooltipEl].forEach((el) => {
    if (!el) return;
    el.classList.remove("is-visible");
    setTimeout(() => { el.hidden = true; }, 220);
  });
}
