async function loadAdminAnalyticsRawRecords({
  startAt = null,
  endAt = new Date(),
  userIds = null
} = {}) {
  const [tradeResult, liveHandResult, csResult] = await Promise.allSettled([
    fetchAdminShapeTraderTradeRecords({ startAt, endAt, userIds }),
    fetchAdminLiveHandsRecords({ startAt, endAt, userIds }),
    fetchAdminColorSchemeRoundRecords({ startAt, endAt, userIds })
  ]);

  const tradeRecords = tradeResult.status === "fulfilled" ? tradeResult.value : [];
  const handRecords  = liveHandResult.status === "fulfilled" ? liveHandResult.value : [];
  const csRecords    = csResult.status === "fulfilled" ? csResult.value : [];

  if (tradeResult.status === "rejected") {
    console.warn("[RTN] admin shape trader raw fetch failed", tradeResult.reason);
  }
  if (liveHandResult.status === "rejected") {
    console.warn("[RTN] admin live hands raw fetch failed", liveHandResult.reason);
  }
  if (csResult.status === "rejected") {
    console.warn("[RTN] admin color scheme rounds fetch failed", csResult.reason);
  }
  if (tradeResult.status === "rejected" && liveHandResult.status === "rejected" && csResult.status === "rejected") {
    throw tradeResult.reason || liveHandResult.reason || new Error("Admin analytics raw fetch failed");
  }

  return {
    handRecords,
    tradeRecords,
    csRecords
  };
}

async function fetchDailyProfitLossRows(userId) {
  const allRows = [];
  const pageSize = 1000;
  let page = 0;
  let hasMore = true;

  while (hasMore) {
    const { data, error } = await supabase
      .from("daily_profit_loss")
      .select("profit_date, mode, pnl_total, pnl_rtn, pnl_g10, pnl_shape_traders, pnl_ryb, pnl_fof")
      .eq("user_id", userId)
      .order("profit_date", { ascending: true })
      .range(page * pageSize, (page + 1) * pageSize - 1);

    if (error) {
      if (isMissingRelationError(error, "daily_profit_loss")) {
        return null;
      }
      throw error;
    }

    const rows = Array.isArray(data) ? data : [];
    allRows.push(...rows);
    hasMore = rows.length === pageSize;
    page += 1;
  }

  // Aggregate across modes, keeping per-mode breakdowns for the contest/normal toggle.
  const agg = {};
  allRows.forEach(row => {
    const key = row.profit_date;
    if (!agg[key]) {
      agg[key] = {
        profit_date: key,
        pnl_total: 0, pnl_rtn: 0, pnl_g10: 0, pnl_shape_traders: 0, pnl_ryb: 0, pnl_fof: 0,
        normal_pnl_total: 0, normal_pnl_rtn: 0, normal_pnl_g10: 0, normal_pnl_shape_traders: 0, normal_pnl_ryb: 0, normal_pnl_fof: 0,
        contest_pnl_total: 0, contest_pnl_rtn: 0, contest_pnl_g10: 0, contest_pnl_shape_traders: 0, contest_pnl_ryb: 0, contest_pnl_fof: 0
      };
    }
    const d = agg[key];
    const isContest = row.mode === "contest";
    d.pnl_total         += Number(row.pnl_total         || 0);
    d.pnl_rtn           += Number(row.pnl_rtn           || 0);
    d.pnl_g10           += Number(row.pnl_g10           || 0);
    d.pnl_shape_traders += Number(row.pnl_shape_traders || 0);
    d.pnl_ryb           += Number(row.pnl_ryb           || 0);
    d.pnl_fof           += Number(row.pnl_fof           || 0);
    if (isContest) {
      d.contest_pnl_total         += Number(row.pnl_total         || 0);
      d.contest_pnl_rtn           += Number(row.pnl_rtn           || 0);
      d.contest_pnl_g10           += Number(row.pnl_g10           || 0);
      d.contest_pnl_shape_traders += Number(row.pnl_shape_traders || 0);
      d.contest_pnl_ryb           += Number(row.pnl_ryb           || 0);
      d.contest_pnl_fof           += Number(row.pnl_fof           || 0);
    } else {
      d.normal_pnl_total         += Number(row.pnl_total         || 0);
      d.normal_pnl_rtn           += Number(row.pnl_rtn           || 0);
      d.normal_pnl_g10           += Number(row.pnl_g10           || 0);
      d.normal_pnl_shape_traders += Number(row.pnl_shape_traders || 0);
      d.normal_pnl_ryb           += Number(row.pnl_ryb           || 0);
      d.normal_pnl_fof           += Number(row.pnl_fof           || 0);
    }
  });
  return Object.values(agg).sort((a, b) => a.profit_date.localeCompare(b.profit_date));
}

function buildHandsChartBuckets(period, startDate, endDate = new Date()) {
  const start = new Date(startDate || endDate);
  const end = new Date(endDate);
  const buckets = [];

  if (period === "hour") {
    start.setSeconds(0, 0);
    const minuteBlock = Math.floor(start.getMinutes() / 5) * 5;
    start.setMinutes(minuteBlock, 0, 0);
    for (let current = new Date(start); current <= end; current = new Date(current.getTime() + 5 * 60 * 1000)) {
      const key = current.toISOString();
      buckets.push({
        key,
        label: formatAnalyticsDate(current, { hour: "numeric", minute: "2-digit" }),
        start: new Date(current),
        end: new Date(current.getTime() + 5 * 60 * 1000)
      });
    }
    return buckets;
  }

  if (period === "day") {
    start.setMinutes(0, 0, 0);
    for (let current = new Date(start); current <= end; current = new Date(current.getTime() + 60 * 60 * 1000)) {
      const key = current.toISOString();
      buckets.push({
        key,
        label: formatAnalyticsDate(current, { hour: "numeric" }),
        start: new Date(current),
        end: new Date(current.getTime() + 60 * 60 * 1000)
      });
    }
    return buckets;
  }

  start.setHours(0, 0, 0, 0);
  const last = new Date(end);
  last.setHours(0, 0, 0, 0);
  for (const current = new Date(start); current <= last; current.setDate(current.getDate() + 1)) {
    const bucketStart = new Date(current);
    const bucketEnd = new Date(current);
    bucketEnd.setDate(bucketEnd.getDate() + 1);
    buckets.push({
      key: bucketStart.toISOString(),
      label: formatAnalyticsDate(bucketStart, { month: "short", day: "numeric" }),
      start: bucketStart,
      end: bucketEnd
    });
  }
  return buckets;
}

async function buildHandsByGameSeries(period, {
  startAt = null,
  endAt = new Date(),
  userIds = null
} = {}) {
  const tradeRecords = await fetchShapeTraderTradeRecords({
    startAt,
    endAt,
    userIds: Array.isArray(userIds) && userIds.length ? userIds : null,
    fields: ["executed_at", "user_id"]
  });

  const records = await fetchGameHandsRecords({
    startAt,
    endAt,
    userIds,
    fields: ["user_id", "created_at", "game_id"]
  });

  const effectiveStart =
    startAt ||
    (records.length > 0 ? new Date(records[0].created_at) : new Date(endAt.getTime() - 29 * 24 * 60 * 60 * 1000));
  const buckets = buildHandsChartBuckets(period, effectiveStart, endAt);
  const seriesMap = new Map(
    [GAME_KEYS.RUN_THE_NUMBERS, GAME_KEYS.GUESS_10, GAME_KEYS.SHAPE_TRADERS].map((gameKey) => [
      gameKey,
      {
        key: gameKey,
        label: getGameLabel(gameKey),
        values: new Array(buckets.length).fill(0)
      }
    ])
  );

  records.forEach((record) => {
    const createdAt = new Date(record.created_at);
    const bucketIndex = buckets.findIndex((bucket) => createdAt >= bucket.start && createdAt < bucket.end);
    if (bucketIndex < 0) return;
    const gameKey = resolveGameKey(record.game_id);
    const series = seriesMap.get(gameKey);
    if (!series) return;
    series.values[bucketIndex] += 1;
  });

  const tradeSeries = {
    key: `${GAME_KEYS.SHAPE_TRADERS}_trades`,
    label: "Shape Traders Trades",
    values: new Array(buckets.length).fill(0)
  };
  tradeRecords.forEach((record) => {
    const executedAt = new Date(record.executed_at);
    const bucketIndex = buckets.findIndex((bucket) => executedAt >= bucket.start && executedAt < bucket.end);
    if (bucketIndex < 0) return;
    tradeSeries.values[bucketIndex] += 1;
  });

  return {
    labels: buckets.map((bucket) => bucket.label),
    datasets: [
      seriesMap.get(GAME_KEYS.RUN_THE_NUMBERS),
      seriesMap.get(GAME_KEYS.GUESS_10),
      tradeSeries
    ].filter(Boolean)
  };
}

function formatBankrollTickLabel(point, fallbackIndex, period = "all") {
  if (point?.label) {
    return String(point.label);
  }
  if (point?.dayKey) {
    const date = createAnalyticsDateFromKey(point.dayKey);
    if (date && !Number.isNaN(date.getTime())) {
      return formatAnalyticsDate(date, { month: "short", day: "numeric" });
    }
  }
  return String(fallbackIndex + 1);
}

function getBankrollPeriodSummaryLabel(period = "month") {
  const labels = {
    week: "Last 7 days",
    month: "Last 30 days",
    "90days": "Last 90 days",
    ytd: "Year to date",
    year: "Last 365 days",
    all: "All time"
  };
  return labels[period] || labels.month;
}

function normalizeBankrollChartGameFilter(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized || normalized === "all") {
    return "all";
  }
  return normalizeGameKey(normalized) || "all";
}

function getBankrollChartBarWidth(period, barSpacing) {
  const widthScaleByPeriod = {
    week: 0.72,
    month: 0.58,
    "90days": 0.46,
    ytd: 0.4,
    year: 0.34,
    all: 0.28
  };
  const maxWidthByPeriod = {
    week: 26,
    month: 18,
    "90days": 14,
    ytd: 12,
    year: 10,
    all: 8
  };
  const widthScale = widthScaleByPeriod[period] || widthScaleByPeriod.month;
  const maxWidth = maxWidthByPeriod[period] || maxWidthByPeriod.month;
  return Math.max(4, Math.min(maxWidth, barSpacing * widthScale));
}

function drawRoundedChartBar(ctx, x, y, width, height, radius, options = {}) {
  if (!ctx || width <= 0 || height <= 0) {
    return;
  }
  const effectiveRadius = Math.max(0, Math.min(radius, width / 2, height / 2));
  const roundTop = options.roundTop !== false;
  const roundBottom = options.roundBottom !== false;
  ctx.beginPath();
  ctx.moveTo(x + (roundTop ? effectiveRadius : 0), y);
  ctx.lineTo(x + width - (roundTop ? effectiveRadius : 0), y);
  if (roundTop) {
    ctx.quadraticCurveTo(x + width, y, x + width, y + effectiveRadius);
  } else {
    ctx.lineTo(x + width, y);
  }
  ctx.lineTo(x + width, y + height - (roundBottom ? effectiveRadius : 0));
  if (roundBottom) {
    ctx.quadraticCurveTo(x + width, y + height, x + width - effectiveRadius, y + height);
  } else {
    ctx.lineTo(x + width, y + height);
  }
  ctx.lineTo(x + (roundBottom ? effectiveRadius : 0), y + height);
  if (roundBottom) {
    ctx.quadraticCurveTo(x, y + height, x, y + height - effectiveRadius);
  } else {
    ctx.lineTo(x, y + height);
  }
  ctx.lineTo(x, y + (roundTop ? effectiveRadius : 0));
  if (roundTop) {
    ctx.quadraticCurveTo(x, y, x + effectiveRadius, y);
  } else {
    ctx.lineTo(x, y);
  }
  ctx.closePath();
  ctx.fill();
}

function hideHomePnlTooltip() {
  if (homePnlTooltip) homePnlTooltip.hidden = true;
}

function showHomePnlTooltip(bar) {
  if (!homePnlTooltip || !homePnlTooltipDateEl || !homePnlTooltipValueEl || !bar) return;
  homePnlTooltipDateEl.textContent = bar.label;
  const v = Number(bar.value || 0);
  homePnlTooltipValueEl.textContent = v >= 0 ? `+${formatCurrency(v)}` : formatSignedCurrency(v);
  homePnlTooltipValueEl.classList.toggle("is-negative", v < 0);
  const wrapperRect = homePnlChartWrapEl?.getBoundingClientRect();
  homePnlTooltip.hidden = false;
  if (!wrapperRect) return;
  const tooltipWidth = homePnlTooltip.offsetWidth || 112;
  const horizontalPadding = 10;
  const minLeft = tooltipWidth / 2 + horizontalPadding;
  const maxLeft = wrapperRect.width - tooltipWidth / 2 - horizontalPadding;
  homePnlTooltip.style.left = `${Math.max(minLeft, Math.min(maxLeft, bar.centerX))}px`;
  homePnlTooltip.style.top = `${Math.max(8, bar.anchorY)}px`;
}

function hideBankrollChartTooltip() {
  if (bankrollChartTooltip) {
    bankrollChartTooltip.hidden = true;
  }
}

function showBankrollChartTooltip(bar) {
  if (!bankrollChartTooltip || !bankrollChartTooltipDateEl || !bankrollChartTooltipValueEl || !bar) {
    return;
  }

  bankrollChartTooltipDateEl.textContent = bar.label;
  bankrollChartTooltipValueEl.textContent = formatSignedCurrency(bar.value);
  bankrollChartTooltipValueEl.classList.toggle("is-negative", Number(bar.value || 0) < 0);

  const wrapperRect = bankrollChartWrapper?.getBoundingClientRect();
  if (!wrapperRect) {
    bankrollChartTooltip.hidden = false;
    return;
  }

  bankrollChartTooltip.hidden = false;
  const tooltipWidth = bankrollChartTooltip.offsetWidth || 112;
  const horizontalPadding = 10;
  const minLeft = tooltipWidth / 2 + horizontalPadding;
  const maxLeft = wrapperRect.width - tooltipWidth / 2 - horizontalPadding;
  const left = Math.max(minLeft, Math.min(maxLeft, bar.centerX));
  const top = Math.max(8, bar.anchorY);
  bankrollChartTooltip.style.left = `${left}px`;
  bankrollChartTooltip.style.top = `${top}px`;
}

function getBankrollChartGameValue(point) {
  if (!point || typeof point !== "object") {
    return 0;
  }
  // Build a mode-aware key resolver: "pnlRtn" → "normalPnlRtn" or "contestPnlRtn" or "pnlRtn"
  const modeKey = (f) => {
    if (bankrollChartModeFilter === "normal" || bankrollChartModeFilter === "contest") {
      return bankrollChartModeFilter + f.charAt(0).toUpperCase() + f.slice(1);
    }
    return f;
  };
  if (bankrollChartGameFilter === GAME_KEYS.RUN_THE_NUMBERS) {
    return roundCurrencyValue(Number(point[modeKey("pnlRtn")] || 0));
  }
  if (bankrollChartGameFilter === GAME_KEYS.GUESS_10) {
    return roundCurrencyValue(Number(point[modeKey("pnlG10")] || 0));
  }
  if (bankrollChartGameFilter === GAME_KEYS.SHAPE_TRADERS) {
    return roundCurrencyValue(Number(point[modeKey("pnlShapeTraders")] || 0));
  }
  if (bankrollChartGameFilter === GAME_KEYS.COLOR_SCHEME) {
    return roundCurrencyValue(Number(point[modeKey("pnlRyb")] || 0));
  }
  if (bankrollChartGameFilter === GAME_KEYS.FATE_OR_FORTUNE) {
    return roundCurrencyValue(Number(point[modeKey("pnlFof")] || 0));
  }
  return roundCurrencyValue(Number(point[modeKey("pnlTotal")] || 0));
}

function getPlayerBankrollPeriodSummaryLabel(period = "year") {
  const labels = {
    hour: "Last hour",
    day: "Last 24 hours",
    week: "Last 7 days",
    month: "Last 30 days",
    "90days": "Last 90 days",
    year: "Last year"
  };
  return labels[period] || labels.year;
}

function updatePlayerBankrollFilterUI() {
  document.querySelectorAll("[data-player-bankroll-period]").forEach((button) => {
    button.classList.toggle(
      "active",
      button instanceof HTMLElement && button.dataset.playerBankrollPeriod === playerBankrollPeriod
    );
  });
}

function getFilteredBankrollHistoryPoints() {
  const fallbackDayKey = formatAnalyticsDateKey(new Date());
  const source = persistentBankrollHistory.length
    ? persistentBankrollHistory
    : [{
        dayKey: fallbackDayKey,
        created_at: new Date().toISOString(),
        pnlTotal: 0,
        pnlRtn: 0,
        pnlG10: 0,
        pnlShapeTraders: 0,
        fallbackIndex: 0
      }];

  const todayKey = formatAnalyticsDateKey(new Date());
  let startDayKey = null;
  if (bankrollChartPeriod === "week") {
    startDayKey = shiftAnalyticsDateKey(todayKey, -6);
  } else if (bankrollChartPeriod === "month") {
    startDayKey = shiftAnalyticsDateKey(todayKey, -29);
  } else if (bankrollChartPeriod === "90days") {
    startDayKey = shiftAnalyticsDateKey(todayKey, -89);
  } else if (bankrollChartPeriod === "year") {
    startDayKey = shiftAnalyticsDateKey(todayKey, -364);
  } else if (bankrollChartPeriod === "ytd") {
    const parts = getAnalyticsDateParts(new Date());
    startDayKey = parts ? `${parts.year}-01-01` : null;
  }
  const filtered = startDayKey
    ? source.filter((point) => !point?.dayKey || point.dayKey >= startDayKey)
    : source;
  const effective = filtered.length
    ? filtered
    : [{
        dayKey: fallbackDayKey,
        created_at: new Date().toISOString(),
        pnlTotal: 0,
        pnlRtn: 0,
        pnlG10: 0,
        pnlShapeTraders: 0,
        fallbackIndex: 0
      }];

  let runningTotal = 0;
  return effective.map((point, index) => {
    const dailyNet = getBankrollChartGameValue(point);
    runningTotal = roundCurrencyValue(runningTotal + dailyNet);
    return {
      ...point,
      dayNet: dailyNet,
      value: runningTotal,
      fallbackIndex: Number(point?.fallbackIndex ?? index)
    };
  });
}

function bankrolChartFilterHasData(points = []) {
  return points.some((point) => Math.abs(Number(point?.dayNet || 0)) > 0.0001);
}

function updateBankrollChartFilterUI() {
  bankrollChartFilterButtons.forEach((button) => {
    button.classList.toggle("active", button.dataset.bankrollPeriod === bankrollChartPeriod);
  });
  bankrollChartGameFilterButtons.forEach((button) => {
    button.classList.toggle("active", normalizeBankrollChartGameFilter(button.dataset.bankrollGame || "all") === bankrollChartGameFilter);
  });
  bankrollChartModeFilterButtons.forEach((button) => {
    button.classList.toggle("active", (button.dataset.bankrollMode || "all") === bankrollChartModeFilter);
  });

  if (!bankrollChartSubhead) return;

  const periodLabels = {
    week: "the last 7 days",
    month: "the last 30 days",
    "90days": "the last 3 months",
    ytd: "year to date",
    year: "the last 365 days",
    all: "all available history"
  };
  const gameLabels = {
    all: "all games",
    [GAME_KEYS.RUN_THE_NUMBERS]: "Run The Numbers",
    [GAME_KEYS.GUESS_10]: "Guess 10",
    [GAME_KEYS.SHAPE_TRADERS]: "Shape Traders"
  };

  bankrollChartSubhead.textContent = `${gameLabels[bankrollChartGameFilter] || gameLabels.all} · ${periodLabels[bankrollChartPeriod] || periodLabels.year} · daily realized P&L`;
}

function updateActivityFilterUI() {
  activityFilterButtons.forEach((button) => {
    button.classList.toggle("active", button.dataset.activityPeriod === activityLeaderboardPeriod);
  });

  if (!mostActiveSubheadEl) return;

  const labels = {
    hour: "Player activity ranked by combined events in the last hour.",
    day: "Player activity ranked by combined events in the last 24 hours.",
    week: "Player activity ranked by combined events in the last 7 days.",
    month: "Player activity ranked by combined events in the last 30 days.",
    year: "Player activity ranked by combined events in the last year."
  };

  mostActiveSubheadEl.textContent = labels[activityLeaderboardPeriod] || labels.week;
}

function easeOutCubic(x) {
  return 1 - Math.pow(1 - x, 3);
}

function waitWhilePaused() {
  if (!handPaused) {
    return Promise.resolve();
  }
  return new Promise((resolve) => {
    pauseResolvers.push(resolve);
  });
}

async function waitForManualDealAdvance() {
  awaitingManualDeal = true;
  setHandPaused(true);
  updateDealButtonState();
  await waitWhilePaused();
  awaitingManualDeal = false;
  updateDealButtonState();
}

async function waitForDealDelay() {
  let remaining = DEAL_DELAY;
  while (remaining > 0) {
    const slice = Math.min(DEAL_DELAY_STEP, remaining);
    await new Promise((resolve) => setTimeout(resolve, slice));
    remaining -= slice;
    if (handPaused) {
      await waitWhilePaused();
    }
  }
}

function drawBankrollChart() {
  if (!bankrollChartCanvas || !bankrollChartCtx) return;

  const historyPoints = getFilteredBankrollHistoryPoints();
  const hasFilterData = bankrolChartFilterHasData(historyPoints);
  bankrollChartHoverBars = [];
  hideBankrollChartTooltip();
  const values = historyPoints.length
    ? historyPoints.map((point) => Number(point?.dayNet ?? 0))
    : [0];
  const padding = {
    top: 12,
    right: 12,
    bottom: 18,
    left: 12
  };

  const rect = bankrollChartCanvas.getBoundingClientRect();
  if (rect.width === 0 || rect.height === 0) return;

  const dpr = window.devicePixelRatio || 1;
  bankrollChartCanvas.width = rect.width * dpr;
  bankrollChartCanvas.height = rect.height * dpr;

  const ctx = bankrollChartCtx;
  ctx.setTransform(1, 0, 0, 1, 0, 0);
  ctx.clearRect(0, 0, bankrollChartCanvas.width, bankrollChartCanvas.height);
  ctx.scale(dpr, dpr);

  const width = rect.width;
  const height = rect.height;
  const chartWidth = Math.max(1, width - padding.left - padding.right);
  const chartHeight = Math.max(1, height - padding.top - padding.bottom);
  const maxAbs = Math.max(...values.map((value) => Math.abs(value)), 1);
  const zeroY = padding.top + chartHeight / 2;
  const totalRealizedValue = roundCurrencyValue(values.reduce((sum, value) => sum + Number(value || 0), 0));
  const summaryBasis = Math.max(1, Math.abs(roundCurrencyValue(bankroll - totalRealizedValue)));
  const summaryPct = (totalRealizedValue / summaryBasis) * 100;
  const isPositive = totalRealizedValue >= 0;
  const positiveColor = "#16a34a";
  const negativeColor = "#f97316";
  const baselineColor = "rgba(148, 163, 184, 0.45)";
  const minorColor = "rgba(148, 163, 184, 0.16)";

  if (bankrollChartTotalEl) {
    bankrollChartTotalEl.textContent = hasFilterData ? formatSignedCurrency(totalRealizedValue) : "—";
  }
  if (bankrollChartChangeEl) {
    if (hasFilterData) {
      const arrow = totalRealizedValue >= 0 ? "▲" : "▼";
      bankrollChartChangeEl.textContent = `${arrow} ${Math.abs(summaryPct).toFixed(2)}% ${getBankrollPeriodSummaryLabel(bankrollChartPeriod)}`;
      bankrollChartChangeEl.classList.toggle("is-negative", !isPositive);
    } else {
      bankrollChartChangeEl.textContent = `No realized P&L data for ${getBankrollPeriodSummaryLabel(bankrollChartPeriod)}`;
      bankrollChartChangeEl.classList.remove("is-negative");
    }
  }
  if (bankrollChartSubhead && !hasFilterData) {
    const gameLabels = {
      all: "all games",
      [GAME_KEYS.RUN_THE_NUMBERS]: "Run The Numbers",
      [GAME_KEYS.GUESS_10]: "Guess 10",
      [GAME_KEYS.SHAPE_TRADERS]: "Shape Traders"
    };
    bankrollChartSubhead.textContent = `No daily realized P&L recorded for ${gameLabels[bankrollChartGameFilter] || gameLabels.all} in this range.`;
  }

  ctx.strokeStyle = minorColor;
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(padding.left, padding.top + chartHeight * 0.2);
  ctx.lineTo(width - padding.right, padding.top + chartHeight * 0.2);
  ctx.moveTo(padding.left, padding.top + chartHeight * 0.8);
  ctx.lineTo(width - padding.right, padding.top + chartHeight * 0.8);
  ctx.stroke();

  ctx.strokeStyle = baselineColor;
  ctx.lineWidth = 1.2;
  ctx.beginPath();
  ctx.moveTo(padding.left, zeroY);
  ctx.lineTo(width - padding.right, zeroY);
  ctx.stroke();

  if (!hasFilterData) {
    return;
  }

  const barSpacing = chartWidth / Math.max(values.length, 1);
  const barWidth = getBankrollChartBarWidth(bankrollChartPeriod, barSpacing);
  const barRadius = Math.min(6, barWidth * 0.36);

  values.forEach((value, index) => {
    const magnitude = Math.min(Math.abs(Number(value || 0)) / maxAbs, 1);
    const barHeight = Math.max(2, magnitude * (chartHeight / 2 - 8));
    const x = padding.left + index * barSpacing + (barSpacing - barWidth) / 2;
    const y = value >= 0 ? zeroY - barHeight : zeroY;
    ctx.fillStyle = value >= 0 ? positiveColor : negativeColor;
    drawRoundedChartBar(ctx, x, y, barWidth, barHeight, barRadius, {
      roundTop: value >= 0,
      roundBottom: value < 0
    });
    bankrollChartHoverBars.push({
      x,
      y,
      width: barWidth,
      height: barHeight,
      centerX: x + barWidth / 2,
      anchorY: y,
      value,
      label: formatBankrollTickLabel(historyPoints[index], index, bankrollChartPeriod)
    });
  });
}

function recordBankrollHistoryPoint() {
  bankrollHistory.push(bankroll);
  if (bankrollHistory.length > MAX_HISTORY_POINTS) {
    bankrollHistory = bankrollHistory.slice(-MAX_HISTORY_POINTS);
  }
  drawBankrollChart();
}

function resetBankrollHistory() {
  bankrollHistory = [bankroll];
  drawBankrollChart();
}

function invalidateAccountChartHistory() {
  persistentBankrollHistory = [];
  persistentBankrollUserId = null;
  if (currentRoute === "activity-log" || chartPanel?.classList.contains("is-open")) {
    void loadPersistentBankrollHistory({ force: true });
  }
}

async function loadPersistentBankrollHistory({ force = false } = {}) {
  if (!currentUser?.id || currentUser.id === GUEST_USER.id || !supabase) {
    persistentBankrollHistory = [];
    persistentBankrollUserId = null;
    updateBankrollChartFilterUI();
    drawBankrollChart();
    return;
  }

  if (!force && persistentBankrollUserId === currentUser.id && persistentBankrollHistory.length) {
    updateBankrollChartFilterUI();
    drawBankrollChart();
    return;
  }

  const todayRange = getAnalyticsDayRange(new Date());
  const todayKey = todayRange.dayKey;
  const liveTodayStart = todayRange.start;
  const liveTodayEnd = todayRange.end;

  try {
    const snapshotRows = await fetchDailyProfitLossRows(currentUser.id);
    const hasSnapshots = Array.isArray(snapshotRows) && snapshotRows.length > 0;

    if (hasSnapshots) {
      // Fetch all sources for today's live data.
      // NOTE: todayRtnLive already covers rtn_live_hands, so we do NOT also
      // pull RTN hands separately here.
      const [todayRtnLive, todayG10Live, todayTrades, todayCsRounds, todayFofRounds] = await Promise.all([
        (async () => {
          const { data } = await supabase
            .from("rtn_live_hands")
            .select("created_at:started_at, net, game_id, contest_id")
            .eq("user_id", currentUser.id)
            .neq("status", "active")
            .gte("started_at", liveTodayStart.toISOString())
            .lte("started_at", liveTodayEnd.toISOString());
          return (Array.isArray(data) ? data : []).map((r) => ({ ...r, game_id: GAME_KEYS.RUN_THE_NUMBERS }));
        })(),
        (async () => {
          const { data } = await supabase
            .from("guess10_live_hands")
            .select("created_at:started_at, net, game_id, contest_id")
            .eq("user_id", currentUser.id)
            .neq("status", "active")
            .gte("started_at", liveTodayStart.toISOString())
            .lte("started_at", liveTodayEnd.toISOString());
          return (Array.isArray(data) ? data : []).map((r) => ({ ...r, game_id: GAME_KEYS.GUESS_10 }));
        })(),
        fetchShapeTraderTradeRecords({
          startAt: liveTodayStart,
          endAt: liveTodayEnd,
          userId: currentUser.id,
          fields: ["executed_at", "trade_side", "net_profit", "contest_id"]
        }),
        (async () => {
          const { data } = await supabase
            .from("color_scheme_rounds")
            .select("created_at, net_profit, contest_id")
            .eq("user_id", currentUser.id)
            .eq("status", "completed")
            .gte("created_at", liveTodayStart.toISOString())
            .lte("created_at", liveTodayEnd.toISOString());
          return Array.isArray(data) ? data : [];
        })(),
        (async () => {
          const { data } = await supabase
            .from("fate_or_fortune_rounds")
            .select("locked_at, net_profit, contest_id")
            .eq("user_id", currentUser.id)
            .eq("status", "resolved")
            .not("locked_at", "is", null)
            .gte("locked_at", liveTodayStart.toISOString())
            .lte("locked_at", liveTodayEnd.toISOString());
          return Array.isArray(data) ? data : [];
        })()
      ]);

      const liveToday = {
        pnlTotal: 0, pnlRtn: 0, pnlG10: 0, pnlShapeTraders: 0, pnlRyb: 0, pnlFof: 0,
        normalPnlTotal: 0, normalPnlRtn: 0, normalPnlG10: 0, normalPnlShapeTraders: 0, normalPnlRyb: 0, normalPnlFof: 0,
        contestPnlTotal: 0, contestPnlRtn: 0, contestPnlG10: 0, contestPnlShapeTraders: 0, contestPnlRyb: 0, contestPnlFof: 0
      };

      // All hands — split by contest_id for mode tracking
      [...todayRtnLive, ...todayG10Live].forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.created_at);
        if (dayKey !== todayKey) return;
        const net = roundCurrencyValue(Number(row?.net || 0));
        const isContest = !!row?.contest_id;
        const gameKey = resolveGameKey(row?.game_id);
        if (gameKey === GAME_KEYS.RUN_THE_NUMBERS) {
          liveToday.pnlRtn = roundCurrencyValue(liveToday.pnlRtn + net);
          if (isContest) liveToday.contestPnlRtn = roundCurrencyValue(liveToday.contestPnlRtn + net);
          else liveToday.normalPnlRtn = roundCurrencyValue(liveToday.normalPnlRtn + net);
        } else if (gameKey === GAME_KEYS.GUESS_10) {
          liveToday.pnlG10 = roundCurrencyValue(liveToday.pnlG10 + net);
          if (isContest) liveToday.contestPnlG10 = roundCurrencyValue(liveToday.contestPnlG10 + net);
          else liveToday.normalPnlG10 = roundCurrencyValue(liveToday.normalPnlG10 + net);
        } else if (gameKey === GAME_KEYS.COLOR_SCHEME) {
          liveToday.pnlRyb = roundCurrencyValue(liveToday.pnlRyb + net);
          if (isContest) liveToday.contestPnlRyb = roundCurrencyValue(liveToday.contestPnlRyb + net);
          else liveToday.normalPnlRyb = roundCurrencyValue(liveToday.normalPnlRyb + net);
        }
      });

      // All realized trades — split by contest_id
      todayTrades.forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.executed_at);
        const rawNetProfit = row?.net_profit;
        if (dayKey !== todayKey || rawNetProfit === null || rawNetProfit === undefined || rawNetProfit === "") return;
        if (!Number.isFinite(Number(rawNetProfit))) return;
        const net = roundCurrencyValue(Number(rawNetProfit));
        const isContest = !!row?.contest_id;
        liveToday.pnlShapeTraders = roundCurrencyValue(liveToday.pnlShapeTraders + net);
        if (isContest) liveToday.contestPnlShapeTraders = roundCurrencyValue(liveToday.contestPnlShapeTraders + net);
        else liveToday.normalPnlShapeTraders = roundCurrencyValue(liveToday.normalPnlShapeTraders + net);
      });

      // Color Scheme rounds — split by contest_id
      todayCsRounds.forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.created_at);
        if (dayKey !== todayKey) return;
        const net = roundCurrencyValue(Number(row?.net_profit || 0));
        const isContest = !!row?.contest_id;
        liveToday.pnlRyb = roundCurrencyValue(liveToday.pnlRyb + net);
        if (isContest) liveToday.contestPnlRyb = roundCurrencyValue(liveToday.contestPnlRyb + net);
        else liveToday.normalPnlRyb = roundCurrencyValue(liveToday.normalPnlRyb + net);
      });

      // Fate or Fortune rounds — realized at lock time, split by contest_id
      todayFofRounds.forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.locked_at);
        if (dayKey !== todayKey) return;
        const net = roundCurrencyValue(Number(row?.net_profit || 0));
        const isContest = !!row?.contest_id;
        liveToday.pnlFof = roundCurrencyValue(liveToday.pnlFof + net);
        if (isContest) liveToday.contestPnlFof = roundCurrencyValue(liveToday.contestPnlFof + net);
        else liveToday.normalPnlFof = roundCurrencyValue(liveToday.normalPnlFof + net);
      });

      liveToday.pnlTotal = roundCurrencyValue(
        liveToday.pnlRtn + liveToday.pnlG10 + liveToday.pnlShapeTraders + liveToday.pnlRyb + liveToday.pnlFof
      );
      liveToday.normalPnlTotal = roundCurrencyValue(
        liveToday.normalPnlRtn + liveToday.normalPnlG10 + liveToday.normalPnlShapeTraders + liveToday.normalPnlRyb + liveToday.normalPnlFof
      );
      liveToday.contestPnlTotal = roundCurrencyValue(
        liveToday.contestPnlRtn + liveToday.contestPnlG10 + liveToday.contestPnlShapeTraders + liveToday.contestPnlRyb + liveToday.contestPnlFof
      );

      const historicalRows = snapshotRows
        .filter((row) => String(row?.profit_date || "") !== todayKey)
        .map((row, index) => ({
          dayKey: String(row?.profit_date || ""),
          created_at: `${row?.profit_date || todayKey}T12:00:00`,
          pnlTotal: roundCurrencyValue(Number(row?.pnl_total || 0)),
          pnlRtn: roundCurrencyValue(Number(row?.pnl_rtn || 0)),
          pnlG10: roundCurrencyValue(Number(row?.pnl_g10 || 0)),
          pnlShapeTraders: roundCurrencyValue(Number(row?.pnl_shape_traders || 0)),
          pnlRyb: roundCurrencyValue(Number(row?.pnl_ryb || 0)),
          pnlFof: roundCurrencyValue(Number(row?.pnl_fof || 0)),
          normalPnlTotal: roundCurrencyValue(Number(row?.normal_pnl_total || 0)),
          normalPnlRtn: roundCurrencyValue(Number(row?.normal_pnl_rtn || 0)),
          normalPnlG10: roundCurrencyValue(Number(row?.normal_pnl_g10 || 0)),
          normalPnlShapeTraders: roundCurrencyValue(Number(row?.normal_pnl_shape_traders || 0)),
          normalPnlRyb: roundCurrencyValue(Number(row?.normal_pnl_ryb || 0)),
          normalPnlFof: roundCurrencyValue(Number(row?.normal_pnl_fof || 0)),
          contestPnlTotal: roundCurrencyValue(Number(row?.contest_pnl_total || 0)),
          contestPnlRtn: roundCurrencyValue(Number(row?.contest_pnl_rtn || 0)),
          contestPnlG10: roundCurrencyValue(Number(row?.contest_pnl_g10 || 0)),
          contestPnlShapeTraders: roundCurrencyValue(Number(row?.contest_pnl_shape_traders || 0)),
          contestPnlRyb: roundCurrencyValue(Number(row?.contest_pnl_ryb || 0)),
          contestPnlFof: roundCurrencyValue(Number(row?.contest_pnl_fof || 0)),
          fallbackIndex: index
        }))
        .filter((row) => row.dayKey);

      const hasTodayActivity = Object.values(liveToday).some((value) => Math.abs(Number(value || 0)) > 0);
      persistentBankrollHistory = hasTodayActivity
        ? [...historicalRows, {
            dayKey: todayKey,
            created_at: new Date().toISOString(),
            ...liveToday,
            fallbackIndex: historicalRows.length
          }]
        : historicalRows;
    } else {
      // No snapshots — build from raw records.
      // NOTE: allRtnLive already covers rtn_live_hands, so we do NOT also
      // pull RTN hands separately here.
      const [allRtnLive, allG10Live, allTrades, allCsRounds, allFofRounds] = await Promise.all([
        (async () => {
          const { data } = await supabase
            .from("rtn_live_hands")
            .select("created_at:started_at, net, contest_id")
            .eq("user_id", currentUser.id)
            .neq("status", "active")
            .order("started_at", { ascending: true });
          return (Array.isArray(data) ? data : []).map((r) => ({ ...r, game_id: GAME_KEYS.RUN_THE_NUMBERS }));
        })(),
        (async () => {
          const { data } = await supabase
            .from("guess10_live_hands")
            .select("created_at:started_at, net, contest_id")
            .eq("user_id", currentUser.id)
            .neq("status", "active")
            .order("started_at", { ascending: true });
          return (Array.isArray(data) ? data : []).map((r) => ({ ...r, game_id: GAME_KEYS.GUESS_10 }));
        })(),
        fetchShapeTraderTradeRecords({
          userId: currentUser.id,
          fields: ["executed_at", "trade_side", "net_profit", "contest_id"]
        }),
        (async () => {
          const { data } = await supabase
            .from("color_scheme_rounds")
            .select("created_at, net_profit, contest_id")
            .eq("user_id", currentUser.id)
            .eq("status", "completed")
            .order("created_at", { ascending: true });
          return Array.isArray(data) ? data : [];
        })(),
        (async () => {
          const { data } = await supabase
            .from("fate_or_fortune_rounds")
            .select("locked_at, net_profit, contest_id")
            .eq("user_id", currentUser.id)
            .eq("status", "resolved")
            .not("locked_at", "is", null)
            .order("locked_at", { ascending: true });
          return Array.isArray(data) ? data : [];
        })()
      ]);

      const allHands = [...allRtnLive, ...allG10Live];

      const dailyTotals = new Map();
      const ensureDay = (dayKey, createdAt) => {
        if (!dailyTotals.has(dayKey)) {
          dailyTotals.set(dayKey, {
            dayKey, created_at: createdAt,
            pnlTotal: 0, pnlRtn: 0, pnlG10: 0, pnlShapeTraders: 0, pnlRyb: 0, pnlFof: 0,
            normalPnlTotal: 0, normalPnlRtn: 0, normalPnlG10: 0, normalPnlShapeTraders: 0, normalPnlRyb: 0, normalPnlFof: 0,
            contestPnlTotal: 0, contestPnlRtn: 0, contestPnlG10: 0, contestPnlShapeTraders: 0, contestPnlRyb: 0, contestPnlFof: 0
          });
        }
        return dailyTotals.get(dayKey);
      };

      // All modes — split by contest_id
      allHands.forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.created_at);
        if (!dayKey) return;
        const bucket = ensureDay(dayKey, row?.created_at || `${dayKey}T12:00:00`);
        const net = roundCurrencyValue(Number(row?.net || 0));
        const isContest = !!row?.contest_id;
        const gameKey = resolveGameKey(row?.game_id);
        if (gameKey === GAME_KEYS.RUN_THE_NUMBERS) {
          bucket.pnlRtn = roundCurrencyValue(bucket.pnlRtn + net);
          if (isContest) bucket.contestPnlRtn = roundCurrencyValue(bucket.contestPnlRtn + net);
          else bucket.normalPnlRtn = roundCurrencyValue(bucket.normalPnlRtn + net);
        } else if (gameKey === GAME_KEYS.GUESS_10) {
          bucket.pnlG10 = roundCurrencyValue(bucket.pnlG10 + net);
          if (isContest) bucket.contestPnlG10 = roundCurrencyValue(bucket.contestPnlG10 + net);
          else bucket.normalPnlG10 = roundCurrencyValue(bucket.normalPnlG10 + net);
        }
      });

      // All realized trades — split by contest_id
      allTrades.forEach((row) => {
        const rawNetProfit = row?.net_profit;
        if (rawNetProfit === null || rawNetProfit === undefined || rawNetProfit === "") return;
        if (!Number.isFinite(Number(rawNetProfit))) return;
        const dayKey = formatAnalyticsDateKey(row?.executed_at);
        if (!dayKey) return;
        const bucket = ensureDay(dayKey, row?.executed_at || `${dayKey}T12:00:00`);
        const net = roundCurrencyValue(Number(rawNetProfit));
        const isContest = !!row?.contest_id;
        bucket.pnlShapeTraders = roundCurrencyValue(bucket.pnlShapeTraders + net);
        if (isContest) bucket.contestPnlShapeTraders = roundCurrencyValue(bucket.contestPnlShapeTraders + net);
        else bucket.normalPnlShapeTraders = roundCurrencyValue(bucket.normalPnlShapeTraders + net);
      });

      // Color Scheme rounds — split by contest_id
      allCsRounds.forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.created_at);
        if (!dayKey) return;
        const bucket = ensureDay(dayKey, row?.created_at || `${dayKey}T12:00:00`);
        const net = roundCurrencyValue(Number(row?.net_profit || 0));
        const isContest = !!row?.contest_id;
        bucket.pnlRyb = roundCurrencyValue(bucket.pnlRyb + net);
        if (isContest) bucket.contestPnlRyb = roundCurrencyValue(bucket.contestPnlRyb + net);
        else bucket.normalPnlRyb = roundCurrencyValue(bucket.normalPnlRyb + net);
      });

      // Fate or Fortune rounds — realized at lock time, split by contest_id
      allFofRounds.forEach((row) => {
        const dayKey = formatAnalyticsDateKey(row?.locked_at);
        if (!dayKey) return;
        const bucket = ensureDay(dayKey, row?.locked_at || `${dayKey}T12:00:00`);
        const net = roundCurrencyValue(Number(row?.net_profit || 0));
        const isContest = !!row?.contest_id;
        bucket.pnlFof = roundCurrencyValue(bucket.pnlFof + net);
        if (isContest) bucket.contestPnlFof = roundCurrencyValue(bucket.contestPnlFof + net);
        else bucket.normalPnlFof = roundCurrencyValue(bucket.normalPnlFof + net);
      });

      persistentBankrollHistory = Array.from(dailyTotals.values())
        .map((row, index) => ({
          ...row,
          pnlTotal: roundCurrencyValue(row.pnlRtn + row.pnlG10 + row.pnlShapeTraders + row.pnlRyb + row.pnlFof),
          normalPnlTotal: roundCurrencyValue(row.normalPnlRtn + row.normalPnlG10 + row.normalPnlShapeTraders + row.normalPnlRyb + row.normalPnlFof),
          contestPnlTotal: roundCurrencyValue(row.contestPnlRtn + row.contestPnlG10 + row.contestPnlShapeTraders + row.contestPnlRyb + row.contestPnlFof),
          fallbackIndex: index
        }))
        .sort((left, right) => String(left.dayKey).localeCompare(String(right.dayKey)));
    }
  } catch (error) {
    console.error("[RTN] loadPersistentBankrollHistory error", error);
    return;
  }

  persistentBankrollUserId = currentUser.id;
  updateBankrollChartFilterUI();
  drawBankrollChart();
  drawHomePnlChart();
}

function ensureBankrollChartLiveRefresh() {
  const refreshIntervalMs = 30000;
  if (bankrollChartLiveRefreshTimerId !== null) {
    return;
  }
  bankrollChartLiveRefreshTimerId = window.setInterval(() => {
    if (
      currentRoute !== "activity-log" ||
      document.visibilityState !== "visible" ||
      !currentUser?.id ||
      currentUser.id === GUEST_USER.id
    ) {
      return;
    }
    void loadPersistentBankrollHistory({ force: true });
  }, refreshIntervalMs);
}

function updatePauseButton() {
  if (!pausePlayButton) return;
  const shouldShow = advancedMode && dealing && autoDealEnabled;
  pausePlayButton.hidden = !shouldShow;
  if (!shouldShow) {
    pausePlayButton.setAttribute("aria-pressed", "false");
    pausePlayButton.textContent = "Pause";
    pausePlayButton.disabled = true;
    return;
  }
  pausePlayButton.disabled = false;
  pausePlayButton.textContent = handPaused ? "Resume" : "Pause";
  pausePlayButton.setAttribute("aria-pressed", String(handPaused));
}

function setHandPaused(paused) {
  if (handPaused === paused) return;
  handPaused = paused;
  if (!handPaused) {
    while (pauseResolvers.length) {
      const resolve = pauseResolvers.shift();
      if (resolve) {
        resolve();
      }
    }
  }
  updatePauseButton();
  refreshBetControls();
  updateDealButtonState();
  if (handPaused) {
    statusEl.textContent = awaitingManualDeal
      ? "Manual deal mode: place specific card or bust bets, then press Deal Next Card."
      : "Dealing paused. Place bust bets or resume play.";
  } else if (dealing) {
    statusEl.textContent = "Dealing...";
  }
}

function setAutoDealEnabled(enabled) {
  autoDealEnabled = enabled;
  updateAutoDealToggleUI();
  updatePauseButton();
  updateDealButtonState();
  if (!dealing) {
    statusEl.textContent = enabled
      ? "Auto Deal is on. Press Deal Hand to run the hand to completion."
      : "Auto Deal is off. Press Deal Hand to reveal one card at a time.";
  }
}

function updateAutoRebetToggleUI() {
  if (autoRebetToggleInput) {
    autoRebetToggleInput.checked = autoRebetEnabled;
    autoRebetToggleInput.setAttribute("aria-checked", String(autoRebetEnabled));
    autoRebetToggleInput.disabled = dealing;
  }
  if (autoRebetToggleWrap) {
    autoRebetToggleWrap.classList.toggle("is-active", autoRebetEnabled);
    autoRebetToggleWrap.classList.toggle("is-disabled", dealing);
  }
}

function setAutoRebetEnabled(enabled) {
  autoRebetEnabled = enabled;
  updateAutoRebetToggleUI();
}

function setAdvancedMode(enabled) {
  if (advancedMode === enabled) return;
  advancedMode = enabled;

  if (advancedBetsSection) {
    if (enabled) {
      advancedBetsSection.hidden = false;
      advancedBetsSection.classList.add("is-open");
      advancedBetsSection.setAttribute("aria-hidden", "false");
    } else {
      advancedBetsSection.classList.remove("is-open");
      advancedBetsSection.setAttribute("aria-hidden", "true");
      advancedBetsSection.hidden = true;
    }
  }

  if (advancedToggleInput) {
    advancedToggleInput.checked = enabled;
    advancedToggleInput.setAttribute("aria-checked", String(enabled));
  }

  if (advancedToggleWrapper) {
    advancedToggleWrapper.classList.toggle("is-active", enabled);
  }

  document.body.classList.toggle("advanced-enabled", enabled);
  if (!enabled) {
    setHandPaused(false);
  }
  refreshBetControls();
  updatePauseButton();
  updateDealButtonState();
}

function stopBankrollAnimation(restoreDisplay = true) {
  if (bankrollAnimationFrame !== null) {
    cancelAnimationFrame(bankrollAnimationFrame);
    bankrollAnimationFrame = null;
  }
  if (bankrollDeltaTimeout !== null) {
    clearTimeout(bankrollDeltaTimeout);
    bankrollDeltaTimeout = null;
  }
  bankrollAnimating = false;
  if (bankrollEl) {
    bankrollEl.classList.remove(
      "bankroll-positive",
      "bankroll-negative",
      "bankroll-neutral",
      "bankroll-pulse"
    );
    if (restoreDisplay) {
      const v = getDisplayedHeaderBankrollValue();
      bankrollEl.textContent = formatCompactHeader(v);
      if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(v);
    }
  }
}

function stopCarterCashAnimation() {
  const clearFn = typeof window !== "undefined" ? window.clearTimeout : clearTimeout;
  if (carterCashDeltaTimeout !== null) {
    clearFn(carterCashDeltaTimeout);
    carterCashDeltaTimeout = null;
  }
  carterCashAnimating = false;
  if (carterCashEl) {
    carterCashEl.classList.remove("carter-cash-pulse");
  }
  if (carterCashDeltaEl) {
    carterCashDeltaEl.classList.remove("visible");
    carterCashDeltaEl.textContent = "";
  }
}

function animateCarterCashGain(amount) {
  if (!carterCashEl || amount <= 0) {
    return;
  }

  stopCarterCashAnimation();

  carterCashAnimating = true;
  carterCashEl.classList.remove("carter-cash-pulse");
  void carterCashEl.offsetWidth;
  carterCashEl.classList.add("carter-cash-pulse");

  if (carterCashDeltaEl) {
    carterCashDeltaEl.textContent = `+${formatCurrency(amount)}`;
    carterCashDeltaEl.classList.add("visible");
  }

  const timeoutFn = typeof window !== "undefined" ? window.setTimeout : setTimeout;
  carterCashDeltaTimeout = timeoutFn(() => {
    if (carterCashEl) {
      carterCashEl.classList.remove("carter-cash-pulse");
    }
    if (carterCashDeltaEl) {
      carterCashDeltaEl.classList.remove("visible");
      carterCashDeltaEl.textContent = "";
    }
    carterCashAnimating = false;
    carterCashDeltaTimeout = null;
  }, 1400);
}

function animateBankrollOutcome(delta) {
  if (!bankrollEl) return;

  stopBankrollAnimation(false);
  const displayedValue = roundCurrencyValue(getDisplayedHeaderBankrollValue());

  if (!Number.isFinite(delta)) {
    bankrollEl.textContent = formatCompactHeader(displayedValue);
    if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(displayedValue);
    return;
  }

  showHandOutcomeToast(delta);

  if (delta === 0) {
    bankrollAnimating = true;
    bankrollEl.classList.remove("bankroll-positive", "bankroll-negative");
    bankrollEl.classList.add("bankroll-neutral", "bankroll-pulse");
    bankrollEl.textContent = formatCompactHeader(displayedValue);
    if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(displayedValue);
    bankrollDeltaTimeout = window.setTimeout(() => {
      if (bankrollEl) {
        const v = getDisplayedHeaderBankrollValue();
        bankrollEl.classList.remove("bankroll-neutral", "bankroll-pulse");
        bankrollEl.textContent = formatCompactHeader(v);
        if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(v);
      }
      bankrollAnimating = false;
      bankrollDeltaTimeout = null;
    }, 1200);
    return;
  }

  const directionClass = delta > 0 ? "bankroll-positive" : "bankroll-negative";

  bankrollAnimating = true;
  bankrollEl.classList.remove(
    delta > 0 ? "bankroll-negative" : "bankroll-positive",
    "bankroll-neutral"
  );
  bankrollEl.classList.add(directionClass, "bankroll-pulse");
  bankrollEl.textContent = formatCompactHeader(displayedValue);
  if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(displayedValue);
  bankrollDeltaTimeout = window.setTimeout(() => {
    if (bankrollEl) {
      const v = getDisplayedHeaderBankrollValue();
      bankrollEl.classList.remove(directionClass, "bankroll-pulse");
      bankrollEl.textContent = formatCompactHeader(v);
      if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(v);
    }
    bankrollAnimating = false;
    bankrollDeltaTimeout = null;
  }, 1400);
}

function clearInsufficientBankrollSignal() {
  if (insufficientBankrollSignalTimeout !== null) {
    clearTimeout(insufficientBankrollSignalTimeout);
    insufficientBankrollSignalTimeout = null;
  }

  bankrollEl?.classList.remove("bankroll-warning", "bankroll-pulse");
  chipBarEl?.classList.remove("insufficient-bankroll");
  chipSelectorEl?.classList.remove("insufficient-bankroll");
  statusEl?.classList.remove("status-warning");
}

function signalInsufficientBankroll(requiredAmount, message) {
  if (statusEl) {
    statusEl.textContent = message;
    statusEl.classList.remove("status-warning");
    void statusEl.offsetWidth;
    statusEl.classList.add("status-warning");
  }

  showToast(
    `Need ${formatCurrency(requiredAmount)} units available for that wager.`,
    "error"
  );

  bankrollEl?.classList.remove("bankroll-positive", "bankroll-negative", "bankroll-neutral");
  bankrollEl?.classList.remove("bankroll-warning", "bankroll-pulse");
  chipBarEl?.classList.remove("insufficient-bankroll");
  chipSelectorEl?.classList.remove("insufficient-bankroll");

  if (bankrollEl) {
    void bankrollEl.offsetWidth;
    bankrollEl.classList.add("bankroll-warning", "bankroll-pulse");
  }

  chipBarEl?.classList.add("insufficient-bankroll");
  chipSelectorEl?.classList.add("insufficient-bankroll");

  insufficientBankrollSignalTimeout = window.setTimeout(() => {
    clearInsufficientBankrollSignal();
  }, 1600);
}

function updateStatsUI() {
  if (handsPlayedEl) {
    handsPlayedEl.textContent = stats.hands.toString();
  }
  if (totalWageredEl) {
    totalWageredEl.textContent = formatCurrency(stats.wagered);
  }
  if (totalPaidEl) {
    totalPaidEl.textContent = formatCurrency(stats.paid);
  }
  const hold = stats.wagered - stats.paid;
  if (holdEl) {
    holdEl.textContent = formatCurrency(hold);
  }
  const edge = stats.wagered > 0 ? (hold / stats.wagered) * 100 : 0;
  if (houseEdgeEl) {
    houseEdgeEl.textContent = `${edge.toFixed(2)}%`;
  }
}

function formatStopper({ label, suit }) {
  return label === "Joker" ? "Joker" : `${label}${suit}`;
}

function snapshotLayout(source) {
  return source.map((entry) => ({
    key: entry.key,
    chips: Array.isArray(entry.chips) ? [...entry.chips] : []
  }));
}

function layoutTotalUnits(layout) {
  return layout.reduce((sum, entry) => {
    const chips = entry.chips ?? [];
    return sum + chips.reduce((inner, value) => inner + value, 0);
  }, 0);
}

function applyBetLayout(layout) {
  bets = [];
  clearChipStacks();
  renderBets();
  const needsAdvanced = layout.some(({ key }) => {
    const definition = getBetDefinition(key);
    return definition && definition.type !== "number";
  });
  if (needsAdvanced) {
    setAdvancedMode(true);
  }
  layout.forEach(({ key, chips = [] }) => {
    chips.forEach((value) => addBet(key, value));
  });
}

function inferPlayAssistantRiskTolerance(text = "") {
  const normalized = String(text).toLowerCase();
  if (!normalized) return null;
  if (/(cautious|conservative|safe|small|low risk)/.test(normalized)) {
    return "cautious";
  }
  if (/(aggressive|high risk|press|bigger|swing|volatile)/.test(normalized)) {
    return "aggressive";
  }
  if (/(balanced|medium risk|moderate|middle)/.test(normalized)) {
    return "balanced";
  }
  return null;
}

function setPlayAssistantRiskTolerance(risk, { announce = false } = {}) {
  if (!PLAY_ASSISTANT_RISK_LABELS[risk]) {
    return;
  }
  playAssistantRiskTolerance = risk;
  updatePlayAssistantContext();
  if (announce) {
    pushPlayAssistantMessage({
      role: "system",
      text: `${PLAY_ASSISTANT_RISK_LABELS[risk]} risk mode saved. I’ll keep that preference in mind for future suggestions.`
    });
  }
}

function getCurrentPlayAssistantGameKey() {
  return getGameKeyForRoute(currentRoute) || GAME_KEYS.RUN_THE_NUMBERS;
}

function isShapeTradersPlayAssistantContext() {
  return getCurrentPlayAssistantGameKey() === GAME_KEYS.SHAPE_TRADERS;
}

function getPlayAssistantConfig(gameKey = getCurrentPlayAssistantGameKey()) {
  return PLAY_ASSISTANT_CONFIG[resolveGameKey(gameKey)] || PLAY_ASSISTANT_CONFIG[GAME_KEYS.RUN_THE_NUMBERS];
}

function updatePlayAssistantUiContent() {
  const config = getPlayAssistantConfig();
  if (playAssistantTitleEl) {
    playAssistantTitleEl.textContent = config.title || "Bankroll Coach";
  }
  playAssistantQuickActionButtons.forEach((button, index) => {
    const action = config.quickActions?.[index];
    if (!action) return;
    button.textContent = action.label || button.textContent;
    button.dataset.playAssistantPrompt = action.prompt || "";
  });
}

function getPlayAssistantBetCatalog() {
  return Array.from(betDefinitions.values()).map((definition) => ({
    key: definition.key,
    type: normalizeBetCatalogType(definition.type),
    label: definition.label,
    payout: definition.payout ?? null,
    payoutDisplay: definition.payoutDisplay ?? null,
    metadata: definition.metadata ?? {}
  }));
}

function calculateSequentialHitProbability(hitCount) {
  if (!Number.isFinite(hitCount) || hitCount <= 0) return 0;
  let probability = 1;
  for (let index = 0; index < hitCount; index += 1) {
    probability *= (4 - index) / (17 - index);
  }
  return probability;
}

function calculateExactHandLengthProbability(totalCards) {
  const length = Math.max(1, Math.round(Number(totalCards) || 0));
  if (length > 41) return 0;
  let probability = 1;
  for (let index = 0; index < length - 1; index += 1) {
    probability *= (40 - index) / (53 - index);
  }
  return probability * (13 / (54 - length));
}

function calculateAtLeastHandLengthProbability(totalCards) {
  const length = Math.max(1, Math.round(Number(totalCards) || 0));
  if (length <= 1) return 1;
  if (length > 41) return 0;
  let probability = 1;
  for (let index = 0; index < length - 1; index += 1) {
    probability *= (40 - index) / (53 - index);
  }
  return probability;
}

function calculateRunTheNumbersHouseEdge(definition, paytable = activePaytable) {
  if (!definition) return null;

  if (definition.type === "number") {
    const steps = Array.isArray(paytable?.steps) ? paytable.steps : [];
    const expectedPayout = steps.reduce(
      (sum, step, index) => sum + safeNumber(step) * calculateSequentialHitProbability(index + 1),
      0
    );
    return 1 - expectedPayout;
  }

  let winProbability = 0;
  switch (definition.type) {
    case "specific-card":
      winProbability = 1 / 53;
      break;
    case "bust-suit":
      winProbability = 3 / 13;
      break;
    case "bust-rank":
      winProbability = 4 / 13;
      break;
    case "bust-joker":
      winProbability = 1 / 13;
      break;
    case "suit-pattern":
      if (definition.metadata?.pattern === "none") {
        winProbability = 10 / 23;
      } else if (definition.metadata?.pattern === "any") {
        winProbability = 13 / 23;
      } else if (definition.metadata?.pattern === "first") {
        winProbability = 13 / 53;
      }
      break;
    case "count":
      if (definition.metadata?.countMax === Infinity) {
        winProbability = calculateAtLeastHandLengthProbability(definition.metadata?.countMin);
      } else {
        winProbability = calculateExactHandLengthProbability(definition.metadata?.countMin);
      }
      break;
    default:
      return null;
  }

  return 1 - ((safeNumber(definition.payout) + 1) * winProbability);
}

function formatAssistantPercent(value, digits = 2) {
  if (!Number.isFinite(Number(value))) return null;
  return Number((Number(value) * 100).toFixed(digits));
}

function getPlayAssistantBetReference() {
  const catalog = Array.from(betDefinitions.values());
  const paytables = PAYTABLES.map((paytable) => ({
    id: paytable.id,
    name: paytable.name,
    steps: [...paytable.steps],
    numberBetHouseEdgePercent: formatAssistantPercent(
      calculateRunTheNumbersHouseEdge({ type: "number" }, paytable),
      3
    )
  }));

  return {
    deck: {
      totalCards: 53,
      liveCards: 40,
      stopperCards: 13
    },
    activePaytable: {
      id: activePaytable.id,
      name: activePaytable.name,
      steps: [...activePaytable.steps],
      numberBetHouseEdgePercent: formatAssistantPercent(
        calculateRunTheNumbersHouseEdge({ type: "number" }, activePaytable),
        3
      )
    },
    paytables,
    bets: catalog.map((definition) => {
      const shared = {
        key: definition.key,
        type: normalizeBetCatalogType(definition.type),
        label: definition.label,
        payout: definition.payout ?? null,
        payoutDisplay: definition.payoutDisplay ?? null,
        metadata: definition.metadata ?? {},
        payoutDependsOnPaytable: definition.type === "number",
        resolutionPool:
          definition.type === "specific-card"
            ? "full-deck"
            : definition.type === "bust-suit" || definition.type === "bust-rank" || definition.type === "bust-joker"
              ? "bust-card-only"
              : null
      };
      if (definition.type === "number") {
        return {
          ...shared,
          houseEdgeByPaytable: paytables.map((paytable) => ({
            id: paytable.id,
            name: paytable.name,
            houseEdgePercent: paytable.numberBetHouseEdgePercent
          }))
        };
      }
      return {
        ...shared,
        houseEdgePercent: formatAssistantPercent(calculateRunTheNumbersHouseEdge(definition), 3)
      };
    })
  };
}

function getGuess10AssistantReference() {
  return {
    deck: {
      totalCards: 52,
      liveCards: 52,
      stopperCards: 0
    },
    predictionCategories: [
      { key: "color", picksAllowed: "exactly 1", multiplierFormula: "2x" },
      { key: "suit", picksAllowed: "1 to 3", multiplierFormula: "4 / selectedSuits" },
      { key: "rank", picksAllowed: "1 to 12", multiplierFormula: "13 / selectedRanks" }
    ],
    commissionByRung: Array.from({ length: RED_BLACK_MAX_RUNGS }, (_, index) => {
      const rung = index + 1;
      return {
        rung,
        commissionPercent: Number((((RED_BLACK_COMMISSION_BY_RUNG[rung] ?? 0) * 100)).toFixed(2))
      };
    }),
    historicalDrawPlayFields: [
      "handId",
      "drawIndex",
      "placedAt",
      "wagerAmount",
      "category",
      "selectedValues",
      "selectionLabel",
      "multiplier",
      "card",
      "matched",
      "startingPot",
      "potAfter"
    ]
  };
}

function getGuess10AssistantTableState() {
  const handStarted = redBlackHandActive || redBlackRung > 0;
  return {
    wagerUnits: redBlackBet,
    currentPotUnits: handStarted ? redBlackCurrentPot : redBlackBet,
    rung: redBlackRung,
    handActive: redBlackHandActive,
    settlementPending: redBlackSettlementPending,
    category: redBlackCategory,
    selectedValues: [...redBlackSelectedValues],
    selectionLabel: getGuess10SelectionLabel(),
    multiplier: Number(getRedBlackPreviewMultiplier().toFixed(2)),
    commissionPercent: Number((getGuess10CommissionRate() * 100).toFixed(2)),
    canDraw: !redBlackSettlementPending && redBlackBet > 0 && isRedBlackSelectionValid(),
    canCashOut: !redBlackSettlementPending && redBlackHandActive && redBlackRung > 0 && redBlackCurrentPot > 0
  };
}

function buildPlayAssistantHandHistoryInsights(records = []) {
  const safeRecords = Array.isArray(records) ? records : [];
  const summarize = (rows) => {
    const handCount = rows.length;
    const totals = rows.reduce(
      (acc, row) => {
        const cards = Math.max(0, Math.round(safeNumber(row?.total_cards)));
        const wager = safeNumber(row?.total_wager);
        const paid = safeNumber(row?.total_paid);
        const net = safeNumber(row?.net);
        const stopperKey = row?.stopper_label === "Joker"
          ? "Joker"
          : [row?.stopper_label, row?.stopper_suit].filter(Boolean).join(" ");
        acc.totalCards += cards;
        acc.totalWager += wager;
        acc.totalPaid += paid;
        acc.totalNet += net;
        if (net > 0) {
          acc.profitable += 1;
        } else if (net < 0) {
          acc.unprofitable += 1;
        } else {
          acc.breakEven += 1;
        }
        if (cards > 8) {
          acc.over8 += 1;
        }
        if (cards > 0) {
          acc.distribution[String(cards)] = (acc.distribution[String(cards)] || 0) + 1;
        }
        if (stopperKey) {
          acc.stopperBreakdown[stopperKey] = (acc.stopperBreakdown[stopperKey] || 0) + 1;
        }
        return acc;
      },
      {
        totalCards: 0,
        totalWager: 0,
        totalPaid: 0,
        totalNet: 0,
        profitable: 0,
        unprofitable: 0,
        breakEven: 0,
        over8: 0,
        distribution: {},
        stopperBreakdown: {}
      }
    );

    return {
      handCount,
      averageCards: handCount ? Number((totals.totalCards / handCount).toFixed(2)) : 0,
      averageWager: handCount ? Number((totals.totalWager / handCount).toFixed(2)) : 0,
      averageReturn: handCount ? Number((totals.totalPaid / handCount).toFixed(2)) : 0,
      averageNet: handCount ? Number((totals.totalNet / handCount).toFixed(2)) : 0,
      profitableHandsCount: totals.profitable,
      profitableHandsPercent: handCount ? Number(((totals.profitable / handCount) * 100).toFixed(2)) : 0,
      losingHandsCount: totals.unprofitable,
      losingHandsPercent: handCount ? Number(((totals.unprofitable / handCount) * 100).toFixed(2)) : 0,
      breakEvenHandsCount: totals.breakEven,
      breakEvenHandsPercent: handCount ? Number(((totals.breakEven / handCount) * 100).toFixed(2)) : 0,
      over8CardsCount: totals.over8,
      over8CardsPercent: handCount ? Number(((totals.over8 / handCount) * 100).toFixed(2)) : 0,
      handLengthDistribution: totals.distribution,
      stopperBreakdown: totals.stopperBreakdown
    };
  };

  const sortedHands = [...safeRecords]
    .sort((a, b) => new Date(b?.created_at || 0).getTime() - new Date(a?.created_at || 0).getTime());
  const recent = sortedHands.slice(0, PLAY_ASSISTANT_HISTORY_LIMIT);

  return {
    allTime: summarize(safeRecords),
    last100: summarize(recent),
    indexedHands: sortedHands.map((row, index) => ({
      handsAgo: index,
      createdAt: row?.created_at || null,
      totalCards: Math.max(0, Math.round(safeNumber(row?.total_cards))),
      stopper: row?.stopper_label === "Joker"
        ? "Joker"
        : [row?.stopper_label, row?.stopper_suit].filter(Boolean).join(" "),
      totalWager: safeNumber(row?.total_wager),
      totalPaid: safeNumber(row?.total_paid),
      net: safeNumber(row?.net)
    })),
    recentHands: recent.slice(0, 20).map((row) => ({
      createdAt: row?.created_at || null,
      totalCards: Math.max(0, Math.round(safeNumber(row?.total_cards))),
      stopper: row?.stopper_label === "Joker"
        ? "Joker"
        : [row?.stopper_label, row?.stopper_suit].filter(Boolean).join(" "),
      totalWager: safeNumber(row?.total_wager),
      totalPaid: safeNumber(row?.total_paid),
      net: safeNumber(row?.net)
    }))
  };
}

function buildRunTheNumbersBetPlayHistoryInsights(records = []) {
  const safeRecords = Array.isArray(records) ? records : [];
  const normalized = safeRecords
    .map((row) => {
      const raw = row?.raw && typeof row.raw === "object" ? row.raw : {};
      const amountWagered = safeNumber(row?.amount_wagered);
      const amountPaid = safeNumber(row?.amount_paid);
      const net = safeNumber(row?.net, amountPaid - amountWagered);
      return {
        createdAt: row?.placed_at || row?.created_at || null,
        handId: row?.hand_id || null,
        betKey: row?.bet_key || raw?.key || "",
        label: raw?.label || row?.bet_key || "Unknown Bet",
        type: raw?.type || null,
        amountWagered,
        amountPaid,
        net,
        outcome: row?.outcome || (amountPaid > 0 ? "W" : amountPaid < amountWagered ? "L" : "P"),
        handNet: safeNumber(row?.hand_net),
        handTotalCards: Math.max(0, Math.round(safeNumber(row?.hand_total_cards))),
        stopper: row?.hand_stopper_label === "Joker"
          ? "Joker"
          : [row?.hand_stopper_label, row?.hand_stopper_suit].filter(Boolean).join(" "),
        raw
      };
    })
    .sort((a, b) => new Date(b.createdAt || 0).getTime() - new Date(a.createdAt || 0).getTime());

  return {
    totalBets: normalized.length,
    recentBets: normalized.slice(0, 100)
  };
}

async function fetchRunTheNumbersBetPlayRecords({ userId, limit = 1000 } = {}) {
  if (!userId || !supabase) return [];
  const allRecords = [];
  const pageSize = 1000;
  let page = 0;
  let hasMore = true;

  while (hasMore && allRecords.length < limit) {
    const { data, error } = await supabase
      .from("bet_plays")
      .select("user_id, hand_id, bet_key, amount_wagered, amount_paid, outcome, net, raw, placed_at")
      .eq("user_id", userId)
      .order("placed_at", { ascending: false })
      .range(page * pageSize, (page + 1) * pageSize - 1);

    if (error) {
      throw error;
    }

    const rows = Array.isArray(data) ? data : [];
    allRecords.push(...rows);
    hasMore = rows.length === pageSize && allRecords.length < limit;
    page += 1;
  }

  return allRecords.slice(0, limit);
}

async function fetchRunTheNumbersBetPlayRecordsByHandIds({ handIds = [] } = {}) {
  if (!supabase || !Array.isArray(handIds) || !handIds.length) {
    return [];
  }

  const allRows = [];
  const chunkSize = 50;

  for (let index = 0; index < handIds.length; index += chunkSize) {
    const chunk = handIds.slice(index, index + chunkSize).map((handId) => String(handId || "")).filter(Boolean);
    if (!chunk.length) {
      continue;
    }

    const { data, error } = await supabase
      .from("bet_plays")
      .select("user_id, hand_id, rtn_hand_id, bet_key, amount_wagered, amount_paid, outcome, net, raw, placed_at")
      .or(`hand_id.in.(${chunk.join(",")}),rtn_hand_id.in.(${chunk.join(",")})`)
      .order("placed_at", { ascending: true });

    if (error) {
      throw error;
    }

    allRows.push(...(Array.isArray(data) ? data : []));
  }

  return allRows;
}

async function fetchGuess10DrawPlayRecords({ handIds = [] } = {}) {
  if (!supabase || !Array.isArray(handIds) || !handIds.length) {
    return [];
  }

  const allRows = [];
  const chunkSize = 50;

  for (let index = 0; index < handIds.length; index += chunkSize) {
    const chunk = handIds.slice(index, index + chunkSize).map((handId) => String(handId || "")).filter(Boolean);
    if (!chunk.length) {
      continue;
    }

    const { data, error } = await supabase
      .from("guess10_draw_plays")
      .select("hand_id, user_id, game_id, draw_index, placed_at, wager_amount, prediction_category, prediction_values, selection_label, multiplier, drawn_card_label, drawn_card_suit, drawn_card_suit_name, drawn_card_color, was_correct, starting_pot, ending_pot, hand_result, cashout_payout, commission_kept, net_hand_profit")
      .in("hand_id", chunk)
      .order("draw_index", { ascending: true });

    if (error) {
      if (isMissingRelationError(error, "guess10_draw_plays")) {
        console.warn("[RTN] guess10_draw_plays table missing; Guess 10 assistant draw history unavailable");
        return [];
      }
      throw error;
    }

    allRows.push(...(Array.isArray(data) ? data : []));
  }

  return allRows;
}

async function loadPlayAssistantHandHistoryInsights({
  force = false,
  gameKey = getCurrentPlayAssistantGameKey()
} = {}) {
  if (!currentUser?.id || currentUser.id === GUEST_USER.id || !supabase) {
    return null;
  }

  const now = Date.now();
  if (
    !force &&
    playAssistantHistoryCache.userId === currentUser.id &&
    playAssistantHistoryCache.gameKey === gameKey &&
    playAssistantHistoryCache.insights &&
    now - playAssistantHistoryCache.fetchedAt < PLAY_ASSISTANT_HISTORY_CACHE_MS
  ) {
    return playAssistantHistoryCache.insights;
  }

  try {
    const records = await fetchGameHandsRecords({
      userIds: [currentUser.id],
      fields: ["id", "user_id", "created_at", "game_id", "total_cards", "stopper_label", "stopper_suit", "total_wager", "total_paid", "net"]
    });
    const gameRecords = records.filter((row) => resolveGameKey(row?.game_id) === gameKey);
    const handHistory = buildPlayAssistantHandHistoryInsights(gameRecords);
    let insights = handHistory;

    if (gameKey === GAME_KEYS.RUN_THE_NUMBERS) {
      const handMap = new Map(gameRecords.map((row) => [String(row?.id || ""), row]));
      const betRecords = await fetchRunTheNumbersBetPlayRecords({ userId: currentUser.id, limit: 2000 });
      const enrichedBetRecords = betRecords
        .map((row) => {
          const hand = handMap.get(String(row?.hand_id || ""));
          if (!hand) return null;
          return {
            ...row,
            hand_total_cards: hand?.total_cards ?? null,
            hand_stopper_label: hand?.stopper_label ?? null,
            hand_stopper_suit: hand?.stopper_suit ?? null,
            hand_net: hand?.net ?? null,
            created_at: hand?.created_at ?? null
          };
        })
        .filter(Boolean);
      insights = {
        ...handHistory,
        betHistory: buildRunTheNumbersBetPlayHistoryInsights(enrichedBetRecords)
      };
    } else if (gameKey === GAME_KEYS.GUESS_10) {
      const orderedHands = [...gameRecords]
        .sort((a, b) => new Date(b?.created_at || 0).getTime() - new Date(a?.created_at || 0).getTime())
        .slice(0, PLAY_ASSISTANT_HISTORY_LIMIT);
      const drawRecords = await fetchGuess10DrawPlayRecords({
        handIds: orderedHands.map((row) => row?.id).filter(Boolean)
      });
      const drawRecordsByHand = new Map();
      drawRecords.forEach((row) => {
        const key = String(row?.hand_id || "");
        if (!key) return;
        const list = drawRecordsByHand.get(key) || [];
        list.push({
          drawIndex: Math.max(1, Math.round(Number(row?.draw_index || list.length + 1))),
          placedAt: row?.placed_at || null,
          wagerAmount: safeNumber(row?.wager_amount),
          category: String(row?.prediction_category || ""),
          selectedValues: Array.isArray(row?.prediction_values)
            ? row.prediction_values.map((value) => String(value ?? ""))
            : [],
          selectionLabel: String(row?.selection_label || ""),
          multiplier: safeNumber(row?.multiplier),
          matched: Boolean(row?.was_correct),
          startingPot: safeNumber(row?.starting_pot),
          potAfter: safeNumber(row?.ending_pot),
          handResult: String(row?.hand_result || "").trim().toLowerCase() || null,
          cashoutPayout: safeNumber(row?.cashout_payout),
          commissionKept: safeNumber(row?.commission_kept),
          netHandProfit: safeNumber(row?.net_hand_profit),
          card: sanitizeGuess10AssistantCard({
            label: row?.drawn_card_label,
            suit: row?.drawn_card_suit,
            suitName: row?.drawn_card_suit_name,
            color: row?.drawn_card_color
          })
        });
        drawRecordsByHand.set(key, list);
      });
      const detailedHands = orderedHands.map((row) => {
        const handId = String(row?.id || "");
        const drawPlays = (drawRecordsByHand.get(handId) || []).sort((a, b) => a.drawIndex - b.drawIndex);
        return {
          handId,
          createdAt: row?.created_at || null,
          totalCards: Math.max(0, Math.round(safeNumber(row?.total_cards))),
          totalWager: safeNumber(row?.total_wager),
          totalPaid: safeNumber(row?.total_paid),
          net: safeNumber(row?.net),
          stopper: row?.stopper_label === "Joker"
            ? "Joker"
            : [row?.stopper_label, row?.stopper_suit].filter(Boolean).join(" "),
          result: safeNumber(row?.total_paid) > 0 ? "cashout" : "loss",
          drawPlays
        };
      });
      insights = {
        ...handHistory,
        detailedHands,
        recentDetailedHands: detailedHands.slice(0, 20)
      };
    }
    playAssistantHistoryCache = {
      userId: currentUser.id,
      gameKey,
      fetchedAt: now,
      insights
    };
    return insights;
  } catch (error) {
    console.warn("[RTN] unable to load play assistant hand history", error);
    return null;
  }
}

function roundShapeTraderAssistantThreshold(value) {
  return roundCurrencyValue(Number(value || 0));
}

function getShapeTraderAssistantRuleStorageKey(
  userId = currentUser?.id || "guest",
  mode = currentAccountMode
) {
  const modeKey = getAccountModeValue(mode) || ACCOUNT_MODE_NORMAL;
  return `${SHAPE_TRADER_ASSISTANT_RULE_STORAGE_PREFIX}:${userId || "guest"}:${modeKey}`;
}

function getLegacyShapeTraderAssistantRuleStorageKey(userId = currentUser?.id || "guest") {
  return `${SHAPE_TRADER_ASSISTANT_RULE_STORAGE_PREFIX}:${userId || "guest"}`;
}

function normalizeShapeTraderAssistantRule(rule) {
  if (!rule || typeof rule !== "object") return null;
  const currentScope = getAccountModeValue(currentAccountMode) || ACCOUNT_MODE_NORMAL;
  const triggerType = String(rule.triggerType || rule.trigger_type || "asset_price").trim().toLowerCase();
  const actionType = String(rule.actionType || rule.action_type || "").trim().toLowerCase();
  const side = rule.side === "sell" ? "sell" : "buy";
  const resolvedActionType =
    actionType === "liquidate_all"
      ? "liquidate_all"
      : actionType === "sell"
        ? "sell"
        : actionType === "buy"
          ? "buy"
          : side;
  const threshold = roundShapeTraderAssistantThreshold(rule.threshold);
  if (!Number.isFinite(threshold) || threshold <= 0) {
    return null;
  }
  const resolvedTriggerType =
    triggerType === "holdings_value" || triggerType === "account_value"
      ? triggerType
      : "asset_price";
  const comparator =
    rule.comparator === "gte" || rule.comparator === "lte"
      ? rule.comparator
      : resolvedTriggerType === "asset_price"
        ? detectShapeTraderAssistantComparator(String(rule.sourcePrompt || ""), resolvedActionType === "sell" ? "sell" : "buy")
      : resolvedActionType === "liquidate_all" || resolvedActionType === "sell" || resolvedTriggerType !== "asset_price"
        ? "gte"
        : "lte";
  const assetId =
    rule.assetId === "any" || SHAPE_TRADERS_ASSETS.some((asset) => asset.id === rule.assetId)
      ? rule.assetId
      : "any";
  const quantityMode =
    resolvedActionType === "liquidate_all"
      ? "all"
      : rule.quantityMode === "fixed"
        ? "fixed"
        : "all";
  const quantity = quantityMode === "fixed"
    ? Math.max(1, Math.round(Number(rule.quantity || 1)))
    : null;
  return {
    id: String(rule.id || `shape-rule-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`),
    accountScope: String(rule.accountScope || rule.account_scope || currentScope),
    side,
    actionType: resolvedActionType,
    triggerType: resolvedTriggerType,
    comparator,
    assetId,
    threshold,
    quantityMode,
    quantity,
    repeat: false,
    enabled: rule.enabled !== false,
    createdAt: String(rule.createdAt || new Date().toISOString()),
    sourcePrompt: String(rule.sourcePrompt || "").trim(),
    lastTriggeredDrawId: Math.max(0, Math.floor(Number(rule.lastTriggeredDrawId || 0))),
    lastFailureDrawId: Math.max(0, Math.floor(Number(rule.lastFailureDrawId || 0))),
    executionCount: Math.max(0, Math.floor(Number(rule.executionCount || 0)))
  };
}

function doesShapeTraderAssistantRuleMatchCurrentMode(rule, mode = currentAccountMode) {
  if (!rule) return false;
  const expectedScope = getAccountModeValue(mode) || ACCOUNT_MODE_NORMAL;
  const ruleScope = String(rule.accountScope || rule.account_scope || "");
  return ruleScope === expectedScope;
}

function summarizeShapeTraderAssistantRule(rule) {
  if (!rule) return "";
  if (rule.actionType === "liquidate_all") {
    const triggerLabel =
      rule.triggerType === "account_value"
        ? `account value reaches ${formatCurrency(rule.threshold)}`
        : rule.triggerType === "holdings_value"
          ? `holdings value reaches ${formatCurrency(rule.threshold)}`
          : `threshold reaches ${formatCurrency(rule.threshold)}`;
    return `Liquidate all holdings when ${triggerLabel}${rule.repeat ? "" : " once"}.`;
  }
  const assetLabel = rule.assetId === "any"
    ? "any asset"
    : getShapeTraderAssetConfig(rule.assetId).label;
  const sideLabel = rule.actionType === "sell" || rule.side === "sell" ? "Sell" : "Buy";
  const thresholdLabel = `${rule.comparator === "gte" ? "at or above" : "at or below"} ${formatCurrency(rule.threshold)}`;
  const quantityValue = Math.max(1, Math.round(Number(rule.quantity || 1)));
  const quantityLabel =
    rule.quantityMode === "fixed"
      ? `${quantityValue} unit${quantityValue === 1 ? "" : "s"}`
      : rule.actionType === "sell"
        ? "full position"
        : "all available cash";
  return `${sideLabel} ${assetLabel} ${thresholdLabel} using ${quantityLabel}${rule.repeat ? "" : " once"}.`;
}

function normalizeShapeTraderAssistantRuleDraft(ruleDraft) {
  if (!ruleDraft || typeof ruleDraft !== "object") return null;
  const rules = Array.isArray(ruleDraft.rules)
    ? ruleDraft.rules.map((rule) => normalizeShapeTraderAssistantRule(rule)).filter(Boolean)
    : [];
  const summaryInput = ruleDraft.summary;
  const summary = Array.isArray(summaryInput)
    ? summaryInput.map((line) => String(line || "").trim()).filter(Boolean)
    : typeof summaryInput === "string" && summaryInput.trim()
      ? [summaryInput.trim()]
      : rules.map((rule) => summarizeShapeTraderAssistantRule(rule));
  return {
    id: String(ruleDraft.id || `shape-rule-draft-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`),
    clearAll: rules.length ? false : Boolean(ruleDraft.clearAll ?? ruleDraft.clear_all),
    rules,
    sourcePrompt: String(ruleDraft.sourcePrompt || "").trim(),
    summary,
    applied: Boolean(ruleDraft.applied)
  };
}

function getShapeTraderAssistantRuleMetaBadges(rule) {
  if (!rule) return [];
  if (rule.actionType === "liquidate_all") {
    return [
      "Portfolio rule",
      "Liquidate all",
      rule.triggerType === "account_value" ? "Account value trigger" : "Holdings value trigger",
      "One-shot"
    ];
  }
  const quantityValue = Math.max(1, Math.round(Number(rule.quantity || 1)));
  return [
    rule.actionType === "sell" ? "Sell rule" : "Buy rule",
    rule.assetId === "any" ? "Any asset" : getShapeTraderAssetConfig(rule.assetId).label,
    rule.quantityMode === "fixed"
      ? `${quantityValue} units`
      : rule.actionType === "sell"
        ? "Full position"
        : "All cash",
    "One-shot"
  ];
}

function ensureShapeTraderAssistantRulesLoaded() {
  const userKey = currentUser?.id || "guest";
  const modeKey = getAccountModeValue(currentAccountMode) || ACCOUNT_MODE_NORMAL;
  const scopedKey = `${userKey}:${modeKey}`;
  if (shapeTradersAssistantRulesLoadedForUser === scopedKey) {
    return;
  }
  shapeTradersAssistantRulesLoadedForUser = scopedKey;
  shapeTradersAssistantLastEvaluatedDrawId = 0;
  shapeTradersAssistantRules = [];
  if (typeof window === "undefined" || !window.localStorage) {
    return;
  }
  try {
    const scopedStorageKey = getShapeTraderAssistantRuleStorageKey(userKey, currentAccountMode);
    const raw = window.localStorage.getItem(scopedStorageKey);
    const legacyRaw = !raw && !isContestAccountMode(currentAccountMode)
      ? window.localStorage.getItem(getLegacyShapeTraderAssistantRuleStorageKey(userKey))
      : null;
    const sourceRaw = raw || legacyRaw;
    if (!raw && legacyRaw) {
      window.localStorage.setItem(scopedStorageKey, legacyRaw);
    }
    const parsed = sourceRaw ? JSON.parse(sourceRaw) : [];
    shapeTradersAssistantRules = Array.isArray(parsed)
      ? parsed.map((rule) => normalizeShapeTraderAssistantRule(rule)).filter(Boolean)
      : [];
  } catch (error) {
    console.warn("[RTN] Unable to load Shape Traders assistant rules", error);
  }
}

function persistShapeTraderAssistantRules() {
  if (typeof window === "undefined" || !window.localStorage) return;
  try {
    window.localStorage.setItem(
      getShapeTraderAssistantRuleStorageKey(),
      JSON.stringify(shapeTradersAssistantRules)
    );
  } catch (error) {
    console.warn("[RTN] Unable to persist Shape Traders assistant rules", error);
  }
}

function setShapeTraderAssistantRules(nextRules) {
  shapeTradersAssistantRules = Array.isArray(nextRules)
    ? nextRules.map((rule) => normalizeShapeTraderAssistantRule(rule)).filter(Boolean)
    : [];
  persistShapeTraderAssistantRules();
  renderPlayAssistantRules();
}

function getShapeTraderAssistantRulesSummary() {
  ensureShapeTraderAssistantRulesLoaded();
  if (!shapeTradersAssistantRules.length) {
    return "You do not have any Shape Traders rules saved yet.";
  }
  const lines = shapeTradersAssistantRules.map((rule, index) => {
    const status = rule.enabled ? "live" : "paused";
    return `- Rule ${index + 1}: ${summarizeShapeTraderAssistantRule(rule)} Status: ${status}.`;
  });
  return `Here are your Shape Traders rules right now:\n${lines.join("\n")}`;
}

function renderPlayAssistantRules() {
  if (!playAssistantRulesEl || !playAssistantRulesListEl || !playAssistantRulesToggleEl || !playAssistantRulesLabelEl) {
    return;
  }
  const shouldShow = isShapeTradersPlayAssistantContext();
  const updateRuleBadge = (count = 0) => {
    if (!playAssistantRuleBadgeEl) return;
    const safeCount = Math.max(0, Math.round(Number(count || 0)));
    const shouldDisplay = safeCount > 0;
    playAssistantRuleBadgeEl.hidden = !shouldDisplay;
    playAssistantRuleBadgeEl.textContent = shouldDisplay ? String(safeCount) : "";
    playAssistantRuleBadgeEl.setAttribute("aria-hidden", shouldDisplay ? "false" : "true");
  };
  if (!shouldShow) {
    playAssistantRulesEl.hidden = true;
    playAssistantRulesEl.setAttribute("aria-hidden", "true");
    playAssistantRulesEl.classList.add("is-collapsed");
    playAssistantRulesListEl.innerHTML = "";
    playAssistantRulesListEl.hidden = true;
    playAssistantRulesLabelEl.textContent = "View Rules (0)";
    playAssistantRulesToggleEl.setAttribute("aria-expanded", "false");
    updateRuleBadge(0);
    return;
  }

  ensureShapeTraderAssistantRulesLoaded();
  const ruleCount = shapeTradersAssistantRules.length;
  playAssistantRulesLabelEl.textContent = `View Rules (${ruleCount})`;
  updateRuleBadge(ruleCount);
  playAssistantRulesEl.classList.toggle("is-collapsed", playAssistantRulesCollapsed);
  playAssistantRulesListEl.hidden = playAssistantRulesCollapsed;
  playAssistantRulesToggleEl.setAttribute("aria-expanded", String(!playAssistantRulesCollapsed));
  playAssistantRulesEl.hidden = false;
  playAssistantRulesEl.setAttribute("aria-hidden", "false");

  if (!shapeTradersAssistantRules.length) {
    playAssistantRulesListEl.innerHTML =
      '<p class="play-assistant-plan-summary">No live rules yet. Ask the assistant to build one, then confirm it.</p>';
    return;
  }

  playAssistantRulesListEl.innerHTML = shapeTradersAssistantRules
    .map((rule) => `
      <article class="play-assistant-rule-card${rule.enabled ? " is-enabled" : " is-disabled"}">
        <p class="play-assistant-rule-summary">${escapeAssistantHtml(summarizeShapeTraderAssistantRule(rule))}</p>
        <div class="play-assistant-rule-meta">
          ${getShapeTraderAssistantRuleMetaBadges(rule)
            .map((badge) => `<span class="play-assistant-rule-pill">${escapeAssistantHtml(badge)}</span>`)
            .join("")}
        </div>
        <div class="play-assistant-rule-actions">
          <button type="button" class="primary" data-shape-rule-toggle="${escapeAssistantHtml(rule.id)}">
            ${rule.enabled ? "Pause" : "Enable"}
          </button>
          <button type="button" data-shape-rule-delete="${escapeAssistantHtml(rule.id)}">Delete</button>
        </div>
      </article>
    `)
    .join("");
}

function detectShapeTraderAssistantAssetId(message = "") {
  const normalized = String(message || "").toLowerCase();
  if (/\bsquare\b/.test(normalized)) return "square";
  if (/\btriangle\b/.test(normalized)) return "triangle";
  if (/\bcircle\b/.test(normalized)) return "circle";
  return "any";
}

function detectShapeTraderAssistantQuantityConfig(message = "", side = "buy") {
  const normalized = String(message || "").toLowerCase();
  const explicitQuantityMatch = normalized.match(/(\d+)\s+(?:unit|units|share|shares)/);
  if (explicitQuantityMatch) {
    return {
      quantityMode: "fixed",
      quantity: Math.max(1, Math.round(Number(explicitQuantityMatch[1] || 1)))
    };
  }
  if (
    side === "buy" &&
    /\b(all cash|all my cash|all available cash|whatever money i have left|whatever cash i have left|max affordable|with whatever money)\b/.test(normalized)
  ) {
    return { quantityMode: "all", quantity: null };
  }
  if (
    side === "sell" &&
    /\b(all holdings|everything|all of it|full position|entire position|sell it|liquidate)\b/.test(normalized)
  ) {
    return { quantityMode: "all", quantity: null };
  }
  return {
    quantityMode: side === "sell" ? "all" : "fixed",
    quantity: side === "sell" ? null : 1
  };
}

function detectShapeTraderAssistantRepeat(message = "") {
  const normalized = String(message || "").toLowerCase();
  if (/\b(one shot|one-shot|once|just once|single time)\b/.test(normalized)) {
    return false;
  }
  return true;
}

function parseShapeTraderAssistantThreshold(message = "", side = "buy") {
  const normalized = String(message || "").toLowerCase();
  const patterns = side === "sell"
    ? [
        /\b(?:sell|exit|liquidate)[\w\s,]*?(?:at or above|above|over|>=|at|hits|hit|reaches|reach|gets to)\s+\$?(\d+(?:\.\d+)?)/,
        /\bas soon as (?:it|the asset|square|triangle|circle) (?:reaches|hits|gets to)\s+\$?(\d+(?:\.\d+)?)/,
        /\bwhen (?:it|the asset|square|triangle|circle) (?:reaches|hits|gets to|is above|is over)\s+\$?(\d+(?:\.\d+)?)/
      ]
    : [
        /\b(?:buy|enter|purchase)[\w\s,]*?(?:at or above|above|over|>=|more than|greater than|breaks above|goes above)\s+\$?(\d+(?:\.\d+)?)/,
        /\b(?:buy|enter|purchase)[\w\s,]*?(?:at or below|below|under|<=|at|less than|dips below|drops below|falls below)\s+\$?(\d+(?:\.\d+)?)/,
        /\bwhen (?:it|the asset|square|triangle|circle) (?:is above|is over|goes above|breaks above|gets above)\s+\$?(\d+(?:\.\d+)?)/,
        /\bwhen (?:it|the asset|square|triangle|circle) (?:dips below|drops below|falls below|is below|is under)\s+\$?(\d+(?:\.\d+)?)/
      ];

  for (const pattern of patterns) {
    const match = normalized.match(pattern);
    if (match) {
      const threshold = roundShapeTraderAssistantThreshold(match[1]);
      if (Number.isFinite(threshold) && threshold > 0) {
        return threshold;
      }
    }
  }
  return null;
}

function detectShapeTraderAssistantComparator(message = "", side = "buy") {
  const normalized = String(message || "").toLowerCase();
  if (side === "sell") {
    return "gte";
  }
  if (
    /\b(?:at or above|above|over|>=|more than|greater than|breaks above|goes above|is above|is over|gets above)\b/.test(normalized)
  ) {
    return "gte";
  }
  return "lte";
}

function buildShapeTraderAssistantRule(side, message = "") {
  const threshold = parseShapeTraderAssistantThreshold(message, side);
  if (!Number.isFinite(threshold) || threshold <= 0) {
    return null;
  }
  const quantityConfig = detectShapeTraderAssistantQuantityConfig(message, side);
  return normalizeShapeTraderAssistantRule({
    side,
    actionType: side,
    triggerType: "asset_price",
    comparator: detectShapeTraderAssistantComparator(message, side),
    assetId: detectShapeTraderAssistantAssetId(message),
    threshold,
    quantityMode: quantityConfig.quantityMode,
    quantity: quantityConfig.quantity,
    repeat: detectShapeTraderAssistantRepeat(message),
    enabled: true,
    sourcePrompt: message
  });
}

function buildShapeTraderPortfolioRuleDraftFromMessage(message = "") {
  const normalized = String(message || "").toLowerCase();
  const wantsLiquidateAll =
    /\b(liquidate all|sell everything|sell all|exit all|close all positions?)\b/.test(normalized);
  if (!wantsLiquidateAll) {
    return null;
  }

  const holdingsMatch = normalized.match(/\bholdings(?: value)? (?:are|is|hits|hit|reach|reaches|gets to|above|over|at)\s+\$?(\d+(?:\.\d+)?)/);
  const accountMatch = normalized.match(/\baccount value (?:is|hits|hit|reach|reaches|gets to|above|over|at)\s+\$?(\d+(?:\.\d+)?)/);
  const threshold = roundShapeTraderAssistantThreshold((holdingsMatch?.[1] || accountMatch?.[1] || ""));
  if (!Number.isFinite(threshold) || threshold <= 0) {
    return null;
  }

  return normalizeShapeTraderAssistantRule({
    side: "sell",
    actionType: "liquidate_all",
    triggerType: holdingsMatch ? "holdings_value" : "account_value",
    assetId: "any",
    threshold,
    quantityMode: "all",
    quantity: null,
    repeat: detectShapeTraderAssistantRepeat(message),
    enabled: true,
    sourcePrompt: message
  });
}

function buildShapeTraderAssistantRuleDraftFromMessage(message = "") {
  const portfolioRule = buildShapeTraderPortfolioRuleDraftFromMessage(message);
  if (portfolioRule) {
    return {
      id: `shape-rule-draft-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      rules: [portfolioRule],
      sourcePrompt: String(message || "").trim(),
      summary: [summarizeShapeTraderAssistantRule(portfolioRule)]
    };
  }
  const buyRule = /\bbuy|purchase|enter\b/i.test(message) ? buildShapeTraderAssistantRule("buy", message) : null;
  const sellRule = /\bsell|exit|liquidate\b/i.test(message) ? buildShapeTraderAssistantRule("sell", message) : null;
  const rules = [buyRule, sellRule].filter(Boolean);
  if (!rules.length) {
    return null;
  }
  return {
    id: `shape-rule-draft-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    rules,
    sourcePrompt: String(message || "").trim(),
    summary: rules.map((rule) => summarizeShapeTraderAssistantRule(rule))
  };
}

function buildLocalShapeTradersAssistantResponse(userMessage, state) {
  const normalized = String(userMessage || "").toLowerCase().trim();
  if (!normalized) {
    return null;
  }

  if (/\b(show|list|what are)\b/.test(normalized) && /\brules?\b/.test(normalized)) {
    return {
      reply: getShapeTraderAssistantRulesSummary(),
      riskTolerance: state.riskTolerance,
      plan: null,
      chart: null,
      ruleDraft: null
    };
  }

  if (/\b(explain|how does|how do i play|rules|what is)\b/.test(normalized) && /\bshape|market|trader\b/.test(normalized)) {
    return {
      reply:
        "Shape Traders prices come from a shared persisted deck that advances on a repeating 15-second cycle. Each reveal applies a printed percentage move: asset cards move one named shape, macro cards move all three shapes together, and every 5 cards the game runs a short data-dump sequence to reveal that batch in order. Trades always fill at the latest persisted market price. If an asset reaches 1000 or more it immediately performs a 10-for-1 split, which divides the price by 10 and multiplies every holder's units by 10. If an asset falls below 1, it is treated as bankrupt, resets back to 100 for the market, and existing holdings in that asset are wiped out. Your account value is always cash plus the current marked value of your holdings.",
      riskTolerance: state.riskTolerance,
      plan: null,
      chart: null,
      ruleDraft: null
    };
  }

  const clearRules = /\b(clear|delete|remove)\b/.test(normalized) && /\b(all )?rules?\b/.test(normalized);
  if (clearRules) {
    return {
      reply: "Confirm if you want me to remove every saved Shape Traders rule.",
      riskTolerance: state.riskTolerance,
      plan: null,
      chart: null,
      ruleDraft: {
        id: `shape-rule-clear-${Date.now()}`,
        clearAll: true,
        rules: [],
        summary: ["Delete all saved Shape Traders rules."]
      }
    };
  }

  const draft = buildShapeTraderAssistantRuleDraftFromMessage(userMessage);
  if (draft?.rules?.length) {
    return {
      reply: `I translated that into ${draft.rules.length} Shape Traders rule${draft.rules.length === 1 ? "" : "s"}.\n${draft.summary.map((line) => `- ${line}`).join("\n")}\n\nConfirm if you want me to activate them.`,
      riskTolerance: state.riskTolerance,
      plan: null,
      chart: null,
      ruleDraft: draft
    };
  }

  return {
    reply:
      "I can help with Shape Traders rules in a few specific formats right now. Try something like: buy Square below 12 and sell it at 18, or buy any asset that dips below 10 with all available cash and sell it when it reaches 20.",
    riskTolerance: state.riskTolerance,
    plan: null,
    chart: null,
    ruleDraft: null
  };
}

async function getPlayAssistantState() {
  const gameKey = getCurrentPlayAssistantGameKey();
  const config = getPlayAssistantConfig(gameKey);
  const handHistory = await loadPlayAssistantHandHistoryInsights({ gameKey });
  if (gameKey === GAME_KEYS.SHAPE_TRADERS) {
    ensureShapeTraderAssistantRulesLoaded();
    return {
      gameKey,
      gameLabel: getGameLabel(gameKey),
      bankroll,
      carterCash,
      riskTolerance: playAssistantRiskTolerance,
      accountMode: {
        key: getAccountModeValue(),
        label: getAccountModeLabel(),
        contest: isContestAccountMode()
          ? {
              id: currentAccountMode.contestId,
              title: getModeContest()?.title ?? "Contest Mode"
            }
          : null
      },
      betting: {
        canPlaceBets: !getShapeTraderWindowState(getShapeTraderCurrentWindowIndex()).tradeLocked,
        dealing: false,
        outstandingUnits: 0,
        availableUnits: bankroll,
        totalExposureUnits: getShapeTraderAccountValue(),
        currentBets: []
      },
      stats: {
        holdingsValue: getShapeTraderHoldingsValue(),
        accountValue: getShapeTraderAccountValue()
      },
      rulesSummary: config.rulesSummary,
      betCatalog: [],
      gameReference: {
        deck: {
          totalCards: (SHAPE_TRADERS_ASSETS.length * SHAPE_TRADERS_MOVEMENTS.length) + SHAPE_TRADERS_MACRO_CARDS.length,
          assetCards: SHAPE_TRADERS_ASSETS.length * SHAPE_TRADERS_MOVEMENTS.length,
          macroCards: SHAPE_TRADERS_MACRO_CARDS.length
        },
        assets: SHAPE_TRADERS_ASSETS.map((asset) => ({
          id: asset.id,
          label: asset.label,
          price: roundCurrencyValue(Number(shapeTradersCurrentPrices[asset.id] || 0)),
          owned: Math.max(0, Math.round(Number(shapeTradersHoldings[asset.id]?.quantity || 0)))
        }))
      },
      tableState: {
        selectedAsset: shapeTradersSelectedAsset,
        prices: { ...shapeTradersCurrentPrices },
        holdings: JSON.parse(JSON.stringify(shapeTradersHoldings)),
        accountValue: getShapeTraderAccountValue(),
        holdingsValue: getShapeTraderHoldingsValue(),
        activeRules: shapeTradersAssistantRules.slice()
      },
      handHistory
    };
  }

  if (gameKey === GAME_KEYS.GUESS_10) {
    const outstanding = Math.max(0, Number(redBlackBet || 0));
    return {
      gameKey,
      gameLabel: getGameLabel(gameKey),
      bankroll,
      carterCash,
      riskTolerance: playAssistantRiskTolerance,
      accountMode: {
        key: getAccountModeValue(),
        label: getAccountModeLabel(),
        contest: isContestAccountMode()
          ? {
              id: currentAccountMode.contestId,
              title: getModeContest()?.title ?? "Contest Mode"
            }
          : null
      },
      betting: {
        canPlaceBets: !redBlackSettlementPending,
        dealing: redBlackSettlementPending,
        outstandingUnits: outstanding,
        availableUnits: bankroll,
        totalExposureUnits: bankroll + outstanding,
        currentBets: outstanding > 0
          ? [{
              key: `guess10-${redBlackCategory}`,
              label: `${getGuess10SelectionLabel()} (${redBlackCategory})`,
              units: outstanding,
              type: redBlackCategory
            }]
          : []
      },
      stats: null,
      rulesSummary: config.rulesSummary,
      betCatalog: [],
      gameReference: getGuess10AssistantReference(),
      tableState: getGuess10AssistantTableState(),
      handHistory
    };
  }

  const outstanding = bets.reduce((sum, bet) => sum + Math.max(0, Number(bet.units ?? 0)), 0);
  return {
    gameKey,
    gameLabel: getGameLabel(gameKey),
    bankroll,
    carterCash,
    riskTolerance: playAssistantRiskTolerance,
    selectedChip,
    activePaytable: {
      id: activePaytable.id,
      name: activePaytable.name,
      steps: [...activePaytable.steps]
    },
    accountMode: {
      key: getAccountModeValue(),
      label: getAccountModeLabel(),
      contest: isContestAccountMode()
        ? {
            id: currentAccountMode.contestId,
            title: getModeContest()?.title ?? "Contest Mode"
          }
        : null
    },
    betting: {
      canPlaceBets: !dealing,
      dealing,
      outstandingUnits: outstanding,
      availableUnits: bankroll,
      totalExposureUnits: bankroll + outstanding,
      currentBets: bets.map((bet) => ({
        key: bet.key,
        label: bet.label,
        units: bet.units,
        type: bet.type
      }))
    },
    stats: {
      hands: stats.hands,
      wagered: stats.wagered,
      paid: stats.paid
    },
    rulesSummary: config.rulesSummary,
    betCatalog: getPlayAssistantBetCatalog(),
    gameReference: getPlayAssistantBetReference(),
    tableState: null,
    handHistory
  };
}

function updatePlayAssistantContext() {
  if (!playAssistantContextEl) return;
  if (isShapeTradersPlayAssistantContext()) {
    ensureShapeTraderAssistantRulesLoaded();
    const liveRules = shapeTradersAssistantRules.filter((rule) => rule.enabled).length;
    playAssistantContextEl.textContent = `${liveRules} live rule${liveRules === 1 ? "" : "s"} · account value ${formatCurrency(getShapeTraderAccountValue())}`;
  } else {
    playAssistantContextEl.textContent = "";
  }
  updatePlayAssistantUiContent();
  renderPlayAssistantRules();
  updatePlayAssistantRuleBadge();
}

function updatePlayAssistantRuleBadge() {
  if (!playAssistantRuleBadgeEl) {
    return;
  }
  const isShapeTraders = isShapeTradersPlayAssistantContext();
  if (isShapeTraders) {
    ensureShapeTraderAssistantRulesLoaded();
  }
  const liveRules = isShapeTraders
    ? shapeTradersAssistantRules.filter((rule) => rule.enabled).length
    : 0;
  const shouldShow = isShapeTraders && liveRules > 0;
  playAssistantRuleBadgeEl.hidden = !shouldShow;
  playAssistantRuleBadgeEl.textContent = shouldShow ? String(Math.min(liveRules, 99)) : "";
}

function escapeAssistantHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function formatAssistantMessageHtml(text) {
  const safeText = String(text ?? "").trim();
  if (!safeText) {
    return "<p></p>";
  }

  const blocks = safeText.split(/\n{2,}/).map((block) => block.trim()).filter(Boolean);
  return blocks
    .map((block) => {
      const lines = block.split("\n").map((line) => line.trim()).filter(Boolean);
      const bulletLines = lines.filter((line) => /^[-*]\s+/.test(line));
      if (bulletLines.length === lines.length && bulletLines.length > 0) {
        const items = bulletLines
          .map((line) => `<li>${escapeAssistantHtml(line.replace(/^[-*]\s+/, ""))}</li>`)
          .join("");
        return `<ul>${items}</ul>`;
      }
      return `<p>${escapeAssistantHtml(block).replace(/\n/g, "<br>")}</p>`;
    })
    .join("");
}

function createPlayAssistantMessageId() {
  return `assistant-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function normalizeAssistantChart(chart) {
  if (!chart || typeof chart !== "object") {
    return null;
  }
  const labels = Array.isArray(chart.labels)
    ? chart.labels.map((label) => String(label ?? ""))
    : [];
  const values = Array.isArray(chart.values)
    ? chart.values.map((value) => Number(value ?? 0))
    : [];
  if (!labels.length || !values.length || labels.length !== values.length || values.some((value) => !Number.isFinite(value))) {
    return null;
  }
  return {
    type: chart.type === "bar" ? "bar" : "line",
    title: String(chart.title || "").trim(),
    subtitle: String(chart.subtitle || "").trim(),
    labels,
    values,
    xLabel: String(chart.xLabel || "").trim(),
    yLabel: String(chart.yLabel || "").trim()
  };
}

function pushPlayAssistantMessage(message) {
  playAssistantThread.push({
    id: message.id || createPlayAssistantMessageId(),
    role: message.role || "assistant",
    text: message.text || "",
    plan: message.plan ? { ...message.plan } : null,
    ruleDraft: message.ruleDraft
      ? normalizeShapeTraderAssistantRuleDraft(message.ruleDraft)
      : null,
    chart: normalizeAssistantChart(message.chart),
    loading: Boolean(message.loading),
    timestamp: Date.now()
  });
  if (playAssistantThread.length > PLAY_ASSISTANT_MAX_HISTORY) {
    playAssistantThread = playAssistantThread.slice(-PLAY_ASSISTANT_MAX_HISTORY);
  }
  renderPlayAssistantThread();
}

function setPlayAssistantLoading(loading) {
  playAssistantRequestInFlight = loading;
  if (playAssistantSendButton) {
    playAssistantSendButton.disabled = loading;
    playAssistantSendButton.classList.toggle("is-loading", loading);
    playAssistantSendButton.setAttribute(
      "aria-label",
      loading ? "Sending message" : "Send message"
    );
  }
  if (playAssistantInput) {
    playAssistantInput.disabled = loading;
  }

  const lastMessage = playAssistantThread[playAssistantThread.length - 1];
  if (loading) {
    if (!lastMessage || !lastMessage.loading) {
      pushPlayAssistantMessage({
        role: "assistant",
        text: "Thinking through your table state...",
        loading: true
      });
    }
    return;
  }

  if (lastMessage?.loading) {
    playAssistantThread.pop();
    renderPlayAssistantThread();
  }
}

function updatePlayAssistantQuickActionsVisibility() {
  if (!playAssistantQuickActionsEl) return;
  const hasStartedConversation = playAssistantThread.some(
    (message) => !message.loading && message.role === "user"
  );
  playAssistantQuickActionsEl.hidden = hasStartedConversation;
  playAssistantQuickActionsEl.classList.toggle("is-hidden", hasStartedConversation);
  playAssistantQuickActionsEl.setAttribute("aria-hidden", String(hasStartedConversation));
}

function drawPlayAssistantChart(canvas, chart) {
  if (!(canvas instanceof HTMLCanvasElement) || !chart) {
    return;
  }

  const rect = canvas.getBoundingClientRect();
  if (!rect.width || !rect.height) {
    return;
  }

  const ctx = canvas.getContext("2d");
  if (!ctx) {
    return;
  }

  const dpr = window.devicePixelRatio || 1;
  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  ctx.setTransform(1, 0, 0, 1, 0, 0);
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.scale(dpr, dpr);

  const width = rect.width;
  const height = rect.height;
  const padding = { top: 18, right: 14, bottom: 28, left: 34 };
  const chartWidth = Math.max(1, width - padding.left - padding.right);
  const chartHeight = Math.max(1, height - padding.top - padding.bottom);
  const baseY = padding.top + chartHeight;
  const values = chart.values;
  const labels = chart.labels;
  const maxVal = Math.max(...values, 1);
  const minVal = chart.type === "bar" ? 0 : Math.min(...values);
  const range = Math.max(1, maxVal - minVal);

  const bodyStyles = getComputedStyle(document.body);
  const rootStyles = getComputedStyle(document.documentElement);
  const cssVar = (name, fallback) => {
    const raw = bodyStyles.getPropertyValue(name) || rootStyles.getPropertyValue(name);
    return raw && raw.trim() ? raw.trim() : fallback;
  };

  const chartBackground = cssVar("--chart-background", "rgba(6, 8, 26, 0.92)");
  const chartBgStart = cssVar("--chart-background-gradient-start", "rgba(255, 99, 224, 0.18)");
  const chartBgEnd = cssVar("--chart-background-gradient-end", "rgba(31, 241, 255, 0.16)");
  const chartGridColor = cssVar("--chart-grid-color", "rgba(31, 241, 255, 0.18)");
  const chartFillColor = cssVar("--chart-fill-color", "rgba(31, 241, 255, 0.18)");
  const chartFillFade = cssVar("--chart-fill-fade", "rgba(31, 241, 255, 0)");
  const chartLineColor = cssVar("--chart-line-color", "#1ff1ff");
  const chartLineShadow = cssVar("--chart-line-shadow", "rgba(139, 109, 255, 0.45)");
  const chartMarkerColor = cssVar("--chart-marker-color", "#ff63e0");
  const chartMarkerStroke = cssVar("--chart-marker-stroke", "rgba(248, 249, 255, 0.85)");
  const chartMarkerShadow = cssVar("--chart-marker-shadow", "rgba(255, 99, 224, 0.6)");
  const chartBaseLine = cssVar("--chart-base-line", "rgba(31, 241, 255, 0.35)");
  const chartAxisColor = cssVar("--chart-axis-color", "rgba(248, 249, 255, 0.85)");

  ctx.fillStyle = chartBackground;
  ctx.fillRect(0, 0, width, height);
  const backgroundGradient = ctx.createLinearGradient(0, 0, width, height);
  backgroundGradient.addColorStop(0, chartBgStart);
  backgroundGradient.addColorStop(1, chartBgEnd);
  ctx.fillStyle = backgroundGradient;
  ctx.fillRect(0, 0, width, height);

  ctx.strokeStyle = chartGridColor;
  ctx.lineWidth = 1;
  ctx.setLineDash([4, 8]);
  for (let i = 0; i <= 4; i += 1) {
    const y = padding.top + (chartHeight * i) / 4;
    ctx.beginPath();
    ctx.moveTo(padding.left, y);
    ctx.lineTo(width - padding.right, y);
    ctx.stroke();
  }
  ctx.setLineDash([]);

  const points = values.map((value, index) => {
    const x =
      values.length === 1
        ? padding.left + chartWidth / 2
        : padding.left + (chartWidth * index) / Math.max(1, values.length - 1);
    const y = padding.top + chartHeight * (1 - (value - minVal) / range);
    return { x, y };
  });

  if (chart.type === "bar") {
    const barWidth = Math.max(10, Math.min(28, chartWidth / Math.max(1, values.length * 1.5)));
    const fillGradient = ctx.createLinearGradient(0, padding.top, 0, baseY);
    fillGradient.addColorStop(0, chartFillColor);
    fillGradient.addColorStop(1, chartFillFade);
    points.forEach((point) => {
      const barHeight = Math.max(2, baseY - point.y);
      ctx.fillStyle = fillGradient;
      ctx.fillRect(point.x - barWidth / 2, point.y, barWidth, barHeight);
      ctx.strokeStyle = chartLineColor;
      ctx.lineWidth = 1.4;
      ctx.strokeRect(point.x - barWidth / 2, point.y, barWidth, barHeight);
    });
  } else if (points.length >= 2) {
    const fillGradient = ctx.createLinearGradient(0, padding.top, 0, baseY);
    fillGradient.addColorStop(0, chartFillColor);
    fillGradient.addColorStop(1, chartFillFade);
    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);
    for (let i = 1; i < points.length; i += 1) {
      ctx.lineTo(points[i].x, points[i].y);
    }
    ctx.lineTo(points[points.length - 1].x, baseY);
    ctx.lineTo(points[0].x, baseY);
    ctx.closePath();
    ctx.fillStyle = fillGradient;
    ctx.fill();

    ctx.beginPath();
    points.forEach((point, index) => {
      if (index === 0) {
        ctx.moveTo(point.x, point.y);
      } else {
        ctx.lineTo(point.x, point.y);
      }
    });
    ctx.strokeStyle = chartLineColor;
    ctx.lineWidth = 2.2;
    ctx.shadowColor = chartLineShadow;
    ctx.shadowBlur = 12;
    ctx.stroke();
    ctx.shadowBlur = 0;
  }

  points.forEach((point) => {
    ctx.beginPath();
    ctx.fillStyle = chartMarkerColor;
    ctx.strokeStyle = chartMarkerStroke;
    ctx.lineWidth = 1.4;
    ctx.shadowColor = chartMarkerShadow;
    ctx.shadowBlur = 8;
    ctx.arc(point.x, point.y, 3.25, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();
    ctx.shadowBlur = 0;
  });

  ctx.strokeStyle = chartBaseLine;
  ctx.lineWidth = 1.4;
  ctx.beginPath();
  ctx.moveTo(padding.left, baseY);
  ctx.lineTo(width - padding.right, baseY);
  ctx.stroke();

  ctx.font = "600 11px 'Play', 'Segoe UI', sans-serif";
  ctx.fillStyle = chartAxisColor;
  ctx.textAlign = "right";
  ctx.textBaseline = "middle";
  for (let i = 0; i <= 4; i += 1) {
    const y = padding.top + (chartHeight * i) / 4;
    const valueLabel = minVal + (range * (4 - i)) / 4;
    ctx.fillText(String(Math.round(valueLabel * 10) / 10), padding.left - 8, y);
  }

  ctx.textAlign = "center";
  ctx.textBaseline = "top";
  const tickStep = Math.max(1, Math.ceil(labels.length / 6));
  points.forEach((point, index) => {
    if (index % tickStep === 0 || index === labels.length - 1) {
      ctx.fillText(labels[index], point.x, baseY + 6);
    }
  });
}

function renderPlayAssistantThread() {
  if (!playAssistantThreadEl) return;
  playAssistantThreadEl.innerHTML = "";

  playAssistantThread.forEach((message) => {
    const article = document.createElement("article");
    article.className = `play-assistant-message${message.loading ? " is-loading" : ""}`;
    article.dataset.role = message.role;

    const roleLabel =
      message.role === "user" ? "You" : message.role === "system" ? "Table Note" : "Assistant";

    article.innerHTML = `
      <div class="play-assistant-message-meta">
        <span>${roleLabel}</span>
        <span>${new Date(message.timestamp).toLocaleTimeString([], {
          hour: "numeric",
          minute: "2-digit"
        })}</span>
      </div>
      <div class="play-assistant-message-body">${formatAssistantMessageHtml(message.text)}</div>
    `;

    if (message.plan?.bets?.length) {
      const planWrap = document.createElement("div");
      planWrap.className = "play-assistant-plan";
      const listItems = message.plan.bets
        .map(
          (bet) =>
            `<li><strong>${escapeAssistantHtml(bet.label || bet.key)}</strong><span>${formatCurrency(
              Number(bet.units || 0)
            )} units</span></li>`
        )
        .join("");
      planWrap.innerHTML = `
        <p class="play-assistant-plan-summary">${escapeAssistantHtml(
          message.plan.summary || "Suggested betting layout"
        )}</p>
        <ul class="play-assistant-plan-list">${listItems}</ul>
        <div class="play-assistant-plan-actions">
          <span class="play-assistant-plan-total">Total ${formatCurrency(
            Number(message.plan.totalUnits || 0)
          )} units</span>
          <button type="button" class="primary play-assistant-apply" data-plan-id="${escapeAssistantHtml(
            message.id
          )}" ${message.plan.applied ? "disabled" : ""}>
            ${message.plan.applied ? "Placed" : "Place these bets"}
          </button>
        </div>
      `;
      article.appendChild(planWrap);
    }

    if (
      isShapeTradersPlayAssistantContext() &&
      message.ruleDraft &&
      (message.ruleDraft.clearAll || message.ruleDraft.rules?.length)
    ) {
      const draftWrap = document.createElement("div");
      draftWrap.className = "play-assistant-rule-draft";
      const listMarkup = message.ruleDraft.clearAll
        ? "<ul><li>Delete all saved Shape Traders rules.</li></ul>"
        : `<ul>${(message.ruleDraft.summary || [])
            .map((line) => `<li>${escapeAssistantHtml(line)}</li>`)
            .join("")}</ul>`;
      draftWrap.innerHTML = `
        <p class="play-assistant-plan-summary">Confirm to activate this rule set.</p>
        ${listMarkup}
        <div class="play-assistant-rule-actions">
          <button type="button" class="primary" data-shape-rule-draft-id="${escapeAssistantHtml(message.id)}">
            ${message.ruleDraft.applied ? "Activated" : "Activate rules"}
          </button>
        </div>
      `;
      const button = draftWrap.querySelector("[data-shape-rule-draft-id]");
      if (button instanceof HTMLButtonElement && message.ruleDraft.applied) {
        button.disabled = true;
      }
      article.appendChild(draftWrap);
    }

    if (message.chart?.labels?.length && message.chart?.values?.length) {
      const chartWrap = document.createElement("div");
      chartWrap.className = "play-assistant-chart";
      chartWrap.innerHTML = `
        <div class="play-assistant-chart-head">
          <strong>${escapeAssistantHtml(message.chart.title || "Chart")}</strong>
          ${message.chart.subtitle ? `<span>${escapeAssistantHtml(message.chart.subtitle)}</span>` : ""}
        </div>
        <canvas class="play-assistant-chart-canvas" aria-label="${escapeAssistantHtml(message.chart.title || "Assistant chart")}"></canvas>
        <div class="play-assistant-chart-meta">
          <span>${escapeAssistantHtml(message.chart.xLabel || "")}</span>
          <span>${escapeAssistantHtml(message.chart.yLabel || "")}</span>
        </div>
      `;
      article.appendChild(chartWrap);
      const canvas = chartWrap.querySelector(".play-assistant-chart-canvas");
      requestAnimationFrame(() => drawPlayAssistantChart(canvas, message.chart));
    }

    playAssistantThreadEl.appendChild(article);
  });

  playAssistantThreadEl.scrollTop = playAssistantThreadEl.scrollHeight;
  updatePlayAssistantQuickActionsVisibility();
}

function togglePlayAssistant(open = !playAssistantOpen) {
  playAssistantOpen = Boolean(open);
  if (typeof document !== "undefined") {
    document.body.classList.toggle("play-assistant-open", playAssistantOpen);
  }
  updatePlayAssistantRuleBadge();
  if (playAssistantPanel) {
    updatePlayAssistantBounds();
    playAssistantPanel.hidden = !playAssistantOpen;
    playAssistantPanel.setAttribute("aria-hidden", String(!playAssistantOpen));
  }
  if (playAssistantToggle) {
    playAssistantToggle.hidden = !PLAY_ASSISTANT_ROUTES.has(currentRoute) || playAssistantOpen;
    playAssistantToggle.setAttribute("aria-expanded", String(playAssistantOpen));
  }
  if (playAssistantOpen && playAssistantInput) {
    playAssistantInput.focus();
  }
}

function updatePlayAssistantVisibility() {
  updatePlayAssistantUiContent();
  const shouldShow = PLAY_ASSISTANT_ROUTES.has(currentRoute);
  if (shouldShow) {
    ensurePlayAssistantThreadMatchesCurrentGame();
    renderPlayAssistantRules();
    seedPlayAssistant();
  }
  updatePlayAssistantRuleBadge();
  if (playAssistantToggle) {
    playAssistantToggle.hidden = !shouldShow || playAssistantOpen;
  }
  if (!shouldShow) {
    togglePlayAssistant(false);
  }
}

function resetPlayAssistantDraft() {
  playAssistantPendingPlanMessageId = null;
  playAssistantPendingRuleDraftMessageId = null;
  if (!playAssistantInput) return;
  playAssistantInput.value = "";
}

function ensurePlayAssistantThreadMatchesCurrentGame() {
  const gameKey = getCurrentPlayAssistantGameKey();
  if (playAssistantThreadGameKey && playAssistantThreadGameKey !== gameKey) {
    playAssistantThread = [];
    playAssistantPendingPlan = null;
    playAssistantPendingRuleDraft = null;
    playAssistantPendingPlanMessageId = null;
    playAssistantPendingRuleDraftMessageId = null;
    renderPlayAssistantThread();
  }
  playAssistantThreadGameKey = gameKey;
}

function serializePlayAssistantMessages() {
  return playAssistantThread
    .filter((message) => !message.loading)
    .slice(-8)
    .map((message) => ({
      role: message.role === "system" ? "assistant" : message.role,
      content: message.text
    }));
}

function getPlayAssistantUserName() {
  if (currentUser?.id && currentUser.id !== GUEST_USER.id) {
    return getContestDisplayName(currentProfile, currentUser.id);
  }
  return getContestDisplayName(GUEST_PROFILE, GUEST_USER.id);
}

function buildPlayAssistantThreadSnapshot() {
  return playAssistantThread
    .filter((message) => !message.loading)
    .slice(-PLAY_ASSISTANT_MAX_HISTORY)
    .map((message) => ({
      id: String(message.id || ""),
      role: String(message.role || "assistant"),
      text: String(message.text || ""),
      timestamp: Number(message.timestamp || Date.now()),
      plan: message.plan
        ? {
            summary: String(message.plan.summary || ""),
            totalUnits: Number(message.plan.totalUnits || 0),
            clearOnly: Boolean(message.plan.clearOnly),
            replaceExisting: Boolean(message.plan.replaceExisting),
            bets: Array.isArray(message.plan.bets)
              ? message.plan.bets.map((bet) => ({
                  key: String(bet.key || ""),
                  label: String(bet.label || ""),
                  units: Number(bet.units || 0)
                }))
              : []
          }
        : null,
      ruleDraft: message.ruleDraft
        ? {
            id: String(message.ruleDraft.id || ""),
            clearAll: Boolean(message.ruleDraft.clearAll),
            summary: Array.isArray(message.ruleDraft.summary)
              ? message.ruleDraft.summary.map((line) => String(line || ""))
              : [],
            ruleCount: Array.isArray(message.ruleDraft.rules) ? message.ruleDraft.rules.length : 0
          }
        : null,
      chart: message.chart
        ? {
            type: String(message.chart.type || "line"),
            title: String(message.chart.title || ""),
            subtitle: String(message.chart.subtitle || "")
          }
        : null
    }));
}

function buildPlayAssistantConversationDetails(userMessage, response) {
  const gameKey = getCurrentPlayAssistantGameKey();
  return {
    route: currentRoute,
    gameId: gameKey,
    userMessage: String(userMessage || ""),
    assistantReply: String(response?.reply || ""),
    riskTolerance: String(response?.riskTolerance || playAssistantRiskTolerance || "balanced"),
    plan: response?.plan
      ? {
          summary: String(response.plan.summary || ""),
          totalUnits: Number(response.plan.totalUnits || 0),
          clearOnly: Boolean(response.plan.clearOnly),
          replaceExisting: Boolean(response.plan.replaceExisting),
          bets: Array.isArray(response.plan.bets)
            ? response.plan.bets.map((bet) => ({
                key: String(bet.key || ""),
                label: String(bet.label || ""),
                units: Number(bet.units || 0)
              }))
            : []
        }
      : null,
    ruleDraft: response?.ruleDraft
      ? {
          id: String(response.ruleDraft.id || ""),
          clearAll: Boolean(response.ruleDraft.clearAll),
          summary: Array.isArray(response.ruleDraft.summary)
            ? response.ruleDraft.summary.map((line) => String(line || ""))
            : [],
          ruleCount: Array.isArray(response.ruleDraft.rules) ? response.ruleDraft.rules.length : 0
        }
      : null,
    chart: response?.chart
      ? {
          type: String(response.chart.type || "line"),
          title: String(response.chart.title || ""),
          subtitle: String(response.chart.subtitle || ""),
          labels: Array.isArray(response.chart.labels) ? response.chart.labels.map((label) => String(label || "")) : [],
          values: Array.isArray(response.chart.values) ? response.chart.values.map((value) => Number(value || 0)) : []
        }
      : null,
    threadMessages: buildPlayAssistantThreadSnapshot()
  };
}

async function persistPlayAssistantConversation({ assistantMessageId, userMessage, response } = {}) {
  if (!supabase || !currentUser?.id || currentUser.id === GUEST_USER.id || !assistantMessageId) {
    return;
  }

  try {
    const payload = {
      user_id: currentUser.id,
      game_id: getCurrentPlayAssistantGameKey(),
      user_name: getPlayAssistantUserName(),
      assistant_message_id: assistantMessageId,
      conversation_details: buildPlayAssistantConversationDetails(userMessage, response),
      actions_performed: []
    };
    const { error } = await supabase.from(PLAY_ASSISTANT_STORAGE_TABLE).insert(payload);
    if (error) {
      throw error;
    }
  } catch (error) {
    console.warn("[RTN] Unable to persist play assistant conversation", error);
  }
}

async function appendPlayAssistantConversationAction(assistantMessageId, action) {
  if (!supabase || !currentUser?.id || currentUser.id === GUEST_USER.id || !assistantMessageId || !action) {
    return;
  }

  try {
    const { data: existingRow, error: fetchError } = await supabase
      .from(PLAY_ASSISTANT_STORAGE_TABLE)
      .select("id, actions_performed")
      .eq("assistant_message_id", assistantMessageId)
      .eq("user_id", currentUser.id)
      .maybeSingle();

    if (fetchError) {
      throw fetchError;
    }
    if (!existingRow?.id) {
      return;
    }

    const existingActions = Array.isArray(existingRow.actions_performed)
      ? existingRow.actions_performed
      : [];
    const nextActions = [
      ...existingActions,
      {
        performedAt: new Date().toISOString(),
        ...action
      }
    ];
    const { error: updateError } = await supabase
      .from(PLAY_ASSISTANT_STORAGE_TABLE)
      .update({ actions_performed: nextActions })
      .eq("id", existingRow.id);

    if (updateError) {
      throw updateError;
    }
  } catch (error) {
    console.warn("[RTN] Unable to append play assistant action", error);
  }
}

function buildAssistantChipBreakdown(units) {
  let remaining = Math.round(Number(units));
  if (!Number.isFinite(remaining) || remaining <= 0) {
    return null;
  }
  const chips = [];
  const ordered = [...new Set([...chipDenominations, ASSISTANT_SHADOW_DENOMINATION])].sort(
    (a, b) => b - a
  );
  ordered.forEach((value) => {
    while (remaining >= value) {
      chips.push(value);
      remaining -= value;
    }
  });
  return remaining === 0 ? chips : null;
}

function normalizeAssistantPlan(plan) {
  if (getCurrentPlayAssistantGameKey() !== GAME_KEYS.RUN_THE_NUMBERS) {
    return null;
  }
  if (!plan || !Array.isArray(plan.bets) || !plan.bets.length) {
    return null;
  }

  const normalizedBets = [];
  for (const candidate of plan.bets) {
    const key = String(candidate?.key || "").trim();
    const definition = getBetDefinition(key);
    const units = Math.round(Number(candidate?.units ?? 0));
    if (!definition || !Number.isFinite(units) || units <= 0) {
      continue;
    }
    const chips = buildAssistantChipBreakdown(units);
    if (!chips) {
      continue;
    }
    normalizedBets.push({
      key,
      label: definition.label,
      units,
      chips
    });
  }

  if (!normalizedBets.length) {
    return null;
  }

  return {
    summary: String(plan.summary || "").trim(),
    replaceExisting: plan.replaceExisting !== false,
    bets: normalizedBets,
    totalUnits: normalizedBets.reduce((sum, bet) => sum + bet.units, 0)
  };
}

function normalizeAssistantBetPhrase(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/\+/g, " plus ")
    .replace(/[^\w\s]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeAssistantSuitName(value = "") {
  const normalized = normalizeAssistantBetPhrase(value);
  if (normalized === "heart" || normalized === "hearts") return "hearts";
  if (normalized === "diamond" || normalized === "diamonds") return "diamonds";
  if (normalized === "club" || normalized === "clubs") return "clubs";
  if (normalized === "spade" || normalized === "spades") return "spades";
  return "";
}

function parseAssistantUnits(value) {
  const raw = String(value || "").trim().toLowerCase().replace(/[$,\s]/g, "");
  if (!raw) return NaN;
  const match = raw.match(/^(\d+(?:\.\d+)?)([km])?$/);
  if (!match) return NaN;
  const base = Number(match[1]);
  if (!Number.isFinite(base)) return NaN;
  const multiplier = match[2] === "m" ? 1000000 : match[2] === "k" ? 1000 : 1;
  return Math.round(base * multiplier);
}

function resolveAssistantBetTarget(targetText) {
  const normalized = normalizeAssistantBetPhrase(targetText);
  if (!normalized) {
    return null;
  }

  for (const definition of betDefinitions.values()) {
    if (normalizeAssistantBetPhrase(definition.label) === normalized) {
      return definition;
    }
  }

  const countPatterns = [
    { pattern: /\b(?:1|one)\s+card\b/, key: "count-1" },
    { pattern: /\b(?:2|two)\s+cards?\b/, key: "count-2" },
    { pattern: /\b(?:3|three)\s+cards?\b/, key: "count-3" },
    { pattern: /\b(?:4|four)\s+cards?\b/, key: "count-4" },
    { pattern: /\b(?:5|five)\s+cards?\b/, key: "count-5" },
    { pattern: /\b(?:6|six)\s+cards?\b/, key: "count-6" },
    { pattern: /\b(?:7|seven)\s+cards?\b/, key: "count-7" },
    {
      pattern:
        /\b(?:8|eight)\s*(?:plus|\+|or more)\s*cards?\b|\b(?:8|eight)\s+cards?\s+(?:or more|plus)\b|\bat least\s+(?:8|eight)\s+cards?\b|\bover\s+7\s+cards?\b/,
      key: "count-8"
    }
  ];
  for (const { pattern, key } of countPatterns) {
    if (pattern.test(normalized)) {
      return getBetDefinition(key) || null;
    }
  }

  const numberMatch = normalized.match(/\b(?:number\s+)?(ace|a|[2-9]|10)\b/);
  if (numberMatch) {
    const rank = numberMatch[1] === "ace" || numberMatch[1] === "a" ? "A" : numberMatch[1];
    return getBetDefinition(`number-${rank}`) || null;
  }

  const specificCardMatch = normalized.match(
    /\b(ace|a|[2-9]|10|jack|queen|king)\s+of\s+(hearts|diamonds|clubs|spades)\b/
  );
  if (specificCardMatch) {
    const rawRank = specificCardMatch[1];
    const suitName = specificCardMatch[2];
    const rank =
      rawRank === "ace" || rawRank === "a"
        ? "A"
        : rawRank === "jack"
          ? "J"
          : rawRank === "queen"
            ? "Q"
            : rawRank === "king"
              ? "K"
              : rawRank;
    const suitMap = {
      hearts: "♥",
      diamonds: "♦",
      clubs: "♣",
      spades: "♠"
    };
    return getBetDefinition(`card-${rank}${suitMap[suitName]}`) || null;
  }

  const suitPatternChecks = [
    { pattern: /\b(?:no|none)\s+(hearts?|diamonds?|clubs?|spades?)\b|\b(hearts?|diamonds?|clubs?|spades?)\s+(?:none|never)\b/, keyPrefix: "suit-none-" },
    { pattern: /\bany\s+(hearts?|diamonds?|clubs?|spades?)\b|\b(hearts?|diamonds?|clubs?|spades?)\s+any\b/, keyPrefix: "suit-any-" },
    { pattern: /\bfirst\s+(hearts?|diamonds?|clubs?|spades?)\b|\b(hearts?|diamonds?|clubs?|spades?)\s+first\b/, keyPrefix: "suit-first-" }
  ];
  for (const { pattern, keyPrefix } of suitPatternChecks) {
    const match = normalized.match(pattern);
    const suitName = normalizeAssistantSuitName(match?.[1] || match?.[2] || "");
    if (suitName) {
      return getBetDefinition(`${keyPrefix}${suitName}`) || null;
    }
  }

  const suitModifierMatch = normalized.match(/\b(no|none|never|any|first)\b/);
  const suitNameMatch = normalized.match(/\b(hearts?|diamonds?|clubs?|spades?)\b/);
  if (suitModifierMatch && suitNameMatch) {
    const suitName = normalizeAssistantSuitName(suitNameMatch[1]);
    const modifier = suitModifierMatch[1];
    const keyPrefix =
      modifier === "any"
        ? "suit-any-"
        : modifier === "first"
          ? "suit-first-"
          : "suit-none-";
    if (suitName) {
      return getBetDefinition(`${keyPrefix}${suitName}`) || null;
    }
  }

  const bustSuitMatch = normalized.match(/\b(?:bust|stop(?:per)?|end)\s+(?:on\s+)?(hearts?|diamonds?|clubs?|spades?)\b/);
  if (bustSuitMatch) {
    const suitName = normalizeAssistantSuitName(bustSuitMatch[1]);
    return suitName ? getBetDefinition(`bust-${suitName}`) || null : null;
  }

  const bustRankMatch = normalized.match(/\b(?:bust|stop(?:per)?|end)\s+(jack|queen|king|joker)\b/);
  if (bustRankMatch) {
    const face = bustRankMatch[1];
    return getBetDefinition(face === "joker" ? "bust-joker" : `bust-${face}`) || null;
  }

  const aliasChecks = [
    { test: /\b(?:8plus|8 plus|8\+)\s*cards?\b/, key: "count-8" },
    { test: /\bjoker\b/, key: "bust-joker" }
  ];
  for (const alias of aliasChecks) {
    if (alias.test.test(normalized)) {
      return getBetDefinition(alias.key) || null;
    }
  }

  return null;
}

function resolveAssistantBetTargets(targetText, state) {
  const normalized = normalizeAssistantBetPhrase(targetText);
  const catalog = Array.isArray(state?.betCatalog) ? state.betCatalog : getPlayAssistantBetCatalog();
  if (!normalized) {
    return [];
  }

  const categoryMatchers = [
    {
      pattern: /\b(?:every|all|each)\s+(?:number|rank)\s+bets?\b|\b(?:every|all|each)\s+numbers?\b|\ball\s+ten\s+numbers?\b/,
      filter: (entry) => entry.type === "number"
    },
    {
      pattern: /\b(?:every|all|each)\s+(?:count|card count)\s+bets?\b|\b(?:every|all|each)\s+counts?\b/,
      filter: (entry) => entry.type === "count"
    },
    {
      pattern: /\b(?:every|all|each)\s+(?:specific\s+card|card)\s+bets?\b|\b(?:every|all|each)\s+specific\s+cards?\b/,
      filter: (entry) => entry.type === "card"
    },
    {
      pattern: /\b(?:every|all|each)\s+(?:bust|stopper|end)\s+bets?\b|\b(?:every|all|each)\s+busts?\b/,
      filter: (entry) => entry.type === "bust"
    },
    {
      pattern: /\b(?:every|all|each)\s+suit\s+bets?\b|\b(?:every|all|each)\s+suits?\b/,
      filter: (entry) => entry.type === "suit"
    }
  ];

  for (const matcher of categoryMatchers) {
    if (matcher.pattern.test(normalized)) {
      return catalog.filter(matcher.filter);
    }
  }

  const single = resolveAssistantBetTarget(targetText);
  return single ? [single] : [];
}

function shuffleAssistantEntries(entries) {
  const copy = [...entries];
  for (let index = copy.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1));
    [copy[index], copy[swapIndex]] = [copy[swapIndex], copy[index]];
  }
  return copy;
}

function parseAssistantRandomSpreadDirective(message, state) {
  const raw = String(message || "").trim();
  const normalized = normalizeAssistantBetPhrase(raw);
  if (!raw || !normalized.includes("random")) {
    return null;
  }
  if (!/\b(?:play|place|bet|put|set|drop|stage|choose|pick)\b/.test(normalized)) {
    return null;
  }

  const countMatch = raw.match(/(?:play|place|bet|put|set|drop|stage|choose|pick)\s+(\d+)/i);
  const perBetMatch = raw.match(/(\d+|one)\s+(?:unit|units|credit|credits)\s+bets?/i);
  const maxPerBetMatch = raw.match(/no more than\s+(\d+|one)\s+(?:unit|units|credit|credits)\s+(?:on|in)\s+any\s+one\s+bet/i);
  const betCount = countMatch ? Math.max(1, Math.round(parseAssistantUnits(countMatch[1]) || 0)) : 0;
  const perBetUnits = perBetMatch
    ? Math.max(1, Math.round(parseAssistantUnits(perBetMatch[1]) || (String(perBetMatch[1]).toLowerCase() === "one" ? 1 : 0)))
    : 1;
  const maxPerBet = maxPerBetMatch
    ? Math.max(1, Math.round(parseAssistantUnits(maxPerBetMatch[1]) || (String(maxPerBetMatch[1]).toLowerCase() === "one" ? 1 : 0)))
    : perBetUnits;

  if (!betCount || !perBetUnits) {
    return null;
  }

  const catalog = Array.isArray(state?.betCatalog) ? state.betCatalog : getPlayAssistantBetCatalog();
  if (!catalog.length) {
    return null;
  }

  let pool = catalog;
  if (/\bnumber\b/.test(normalized)) {
    pool = pool.filter((entry) => entry.type === "number");
  } else if (/\bcount\b/.test(normalized)) {
    pool = pool.filter((entry) => entry.type === "count");
  } else if (/\bbust|stopper|end\b/.test(normalized)) {
    pool = pool.filter((entry) => entry.type === "bust");
  } else if (/\bcard\b/.test(normalized)) {
    pool = pool.filter((entry) => entry.type === "card");
  } else if (/\bsuit\b|\b(?:no|none|any|first)\s+(?:hearts|diamonds|clubs|spades)\b/.test(normalized)) {
    pool = pool.filter((entry) => entry.type === "suit");
  }

  const availableUnits = Math.max(0, Math.round(Number(state?.betting?.availableUnits ?? bankroll)));
  const cappedPerBetUnits = Math.max(1, Math.min(perBetUnits, maxPerBet));
  const affordableCount = Math.max(0, Math.floor(availableUnits / cappedPerBetUnits));
  const selectedCount = Math.min(betCount, pool.length, affordableCount);
  const definitions = shuffleAssistantEntries(pool).slice(0, selectedCount).map((entry) =>
    getBetDefinition(entry.key)
  ).filter(Boolean);

  return {
    requestedCount: betCount,
    selectedCount,
    perBetUnits: cappedPerBetUnits,
    availableUnits,
    definitions
  };
}

function parseAssistantDirective(message, state) {
  const normalized = String(message || "").trim();
  const commandMatch = normalized.match(
    /(?:^|\b)(?:play|place|bet|put|set|drop|stage)\s+\$?([\d,.]+(?:\.\d+)?\s*[km]?)\s*(?:units?)?\s+(?:on\s+)?(.+)$/i
  );
  if (!commandMatch) {
    return null;
  }

  const requestedUnits = parseAssistantUnits(commandMatch[1]);
  const targetText = String(commandMatch[2] || "")
    .replace(/\s+(?:please|pls|for me|thanks?)\s*$/i, "")
    .trim();
  const definitions = resolveAssistantBetTargets(targetText, state);
  const availableUnits = Math.max(0, Math.round(Number(state?.betting?.availableUnits ?? bankroll)));

  return {
    requestedUnits,
    targetText,
    definitions,
    availableUnits
  };
}

function parseAssistantClearDirective(message) {
  const normalized = normalizeAssistantBetPhrase(message);
  if (!normalized) {
    return false;
  }
  return /\b(?:clear|remove|reset|take\s+off)\b/.test(normalized) &&
    /\b(?:bets|bet|table|layout|board|felt|all)\b/.test(normalized);
}

function parseAssistantRequestedHandCount(message, fallback = 20) {
  const normalized = String(message || "").toLowerCase();
  const match = normalized.match(/\blast\s+(\d+)\s+hands?\b/);
  if (!match) {
    return fallback;
  }
  const parsed = Number(match[1]);
  return Number.isFinite(parsed) && parsed > 0 ? Math.max(1, Math.min(200, Math.round(parsed))) : fallback;
}

function buildLocalAssistantChartResponse(userMessage, state) {
  const normalized = String(userMessage || "").toLowerCase();
  const wantsChart = /\b(graph|chart|plot|visuali[sz]e)\b/.test(normalized);
  const mentionsHandLength =
    /\b(hand lengths?|length of each hand|each hand length|cards dealt|total cards)\b/.test(normalized);
  const indexedHands = Array.isArray(state?.handHistory?.indexedHands) ? state.handHistory.indexedHands : [];
  if (!wantsChart || !mentionsHandLength || !indexedHands.length) {
    return null;
  }

  const requestedCount = parseAssistantRequestedHandCount(userMessage, 20);
  const selectedHands = indexedHands.slice(0, requestedCount);
  if (!selectedHands.length) {
    return null;
  }

  const wantsDistribution = /\b(distribution|histogram|frequency|breakdown)\b/.test(normalized);
  if (wantsDistribution) {
    const counts = new Map();
    selectedHands.forEach((hand) => {
      const totalCards = Math.max(0, Math.round(Number(hand?.totalCards || 0)));
      counts.set(totalCards, (counts.get(totalCards) || 0) + 1);
    });
    const sortedEntries = Array.from(counts.entries()).sort((a, b) => a[0] - b[0]);
    return {
      reply: `Here is a bar chart of hand-length frequency across your last ${selectedHands.length} completed hands.`,
      chart: normalizeAssistantChart({
        type: "bar",
        title: `Hand-Length Distribution (${selectedHands.length} Hands)`,
        subtitle: "Counts by total cards dealt",
        labels: sortedEntries.map(([value]) => `${value}`),
        values: sortedEntries.map(([, count]) => count),
        xLabel: "Total cards dealt",
        yLabel: "Hands"
      }),
      riskTolerance: state.riskTolerance,
      plan: null
    };
  }

  const orderedHands = [...selectedHands].reverse();
  return {
    reply: `Here is a ${/\bbar chart\b/.test(normalized) ? "bar" : "line"} chart of total cards dealt for your last ${orderedHands.length} completed hands, ordered from oldest to newest.`,
    chart: normalizeAssistantChart({
      type: /\bbar chart\b/.test(normalized) ? "bar" : "line",
      title: `Hand Lengths Over Last ${orderedHands.length} Hands`,
      subtitle: "Oldest to newest completed hands",
      labels: orderedHands.map((_, index) => `${index + 1}`),
      values: orderedHands.map((hand) => Math.max(0, Math.round(Number(hand?.totalCards || 0)))),
      xLabel: "Hand sequence",
      yLabel: "Cards dealt"
    }),
    riskTolerance: state.riskTolerance,
    plan: null
  };
}

function buildLocalGuess10HistoryResponse(userMessage, state) {
  const normalized = String(userMessage || "").toLowerCase();
  const detailedHands = Array.isArray(state?.handHistory?.detailedHands) ? state.handHistory.detailedHands : [];
  const indexedHands = Array.isArray(state?.handHistory?.indexedHands) ? state.handHistory.indexedHands : [];
  if (!detailedHands.length && !indexedHands.length) {
    return null;
  }

  const asksAboutGuess10History =
    /\b(last|recent)\b/.test(normalized) &&
    /\bhands?\b/.test(normalized) &&
    /\bguess(?:\s|-)?10\b/.test(normalized);
  const asksAboutCorrectGuesses =
    /\bcorrect guesses?\b/.test(normalized) ||
    /\bhow many\b/.test(normalized) && /\b(before busting|before cashing|before cashing out|hits?)\b/.test(normalized);
  const asksAboutOutcome =
    /\bbust(?:ing|ed)?\b/.test(normalized) ||
    /\bcash(?:ing)? out\b/.test(normalized) ||
    /\bcashed out\b/.test(normalized);

  if (!asksAboutGuess10History || !asksAboutCorrectGuesses || !asksAboutOutcome) {
    return null;
  }

  const requestedCount = parseAssistantRequestedHandCount(userMessage, 10);
  const selectedHands = detailedHands.length ? detailedHands.slice(0, requestedCount) : indexedHands.slice(0, requestedCount);
  if (!selectedHands.length) {
    return null;
  }

  const lines = selectedHands.map((hand, index) => {
    const drawPlays = Array.isArray(hand?.drawPlays) ? hand.drawPlays : [];
    const cashedOut =
      String(hand?.result || "").toLowerCase() === "cashout" ||
      Number(hand?.totalPaid || 0) > 0;
    const correctGuesses = drawPlays.length
      ? drawPlays.filter((entry) => entry?.matched).length
      : Math.max(0, Math.round(Number(hand?.totalCards || 0)) - (cashedOut ? 0 : 1));
    const outcome = cashedOut ? "cashed out" : "busted";
    return `- Hand ${index + 1}: ${correctGuesses} correct guess${correctGuesses === 1 ? "" : "es"} before ${outcome}.`;
  });

  return {
    reply: `Here are your last ${selectedHands.length} Guess 10 hands, newest first:\n${lines.join("\n")}`,
    riskTolerance: state.riskTolerance,
    plan: null,
    chart: null
  };
}

function buildLocalGuess10PredictionSequenceResponse(userMessage, state) {
  const normalized = String(userMessage || "").toLowerCase();
  const detailedHands = Array.isArray(state?.handHistory?.detailedHands) ? state.handHistory.detailedHands : [];
  if (!detailedHands.length) {
    return null;
  }

  const asksForPredictionSequence =
    /\bprediction/.test(normalized) &&
    /\b(each card|every card|each draw|draw by draw)\b/.test(normalized);
  if (!asksForPredictionSequence) {
    return null;
  }

  let targetHand = null;
  if (/\blongest hand\b|\bthat hand\b|\b63\b/.test(normalized)) {
    targetHand = [...detailedHands].sort((a, b) => {
      const aHits = Array.isArray(a?.drawPlays) ? a.drawPlays.filter((entry) => entry?.matched).length : 0;
      const bHits = Array.isArray(b?.drawPlays) ? b.drawPlays.filter((entry) => entry?.matched).length : 0;
      if (bHits !== aHits) return bHits - aHits;
      return new Date(b?.createdAt || 0).getTime() - new Date(a?.createdAt || 0).getTime();
    })[0] || null;
  } else if (/\blast hand\b|\bmost recent hand\b|\brecent hand\b/.test(normalized)) {
    targetHand = detailedHands[0] || null;
  }

  if (!targetHand || !Array.isArray(targetHand.drawPlays) || !targetHand.drawPlays.length) {
    return null;
  }

  const lines = targetHand.drawPlays.map((entry) => {
    const cardLabel = entry?.card ? `${entry.card.label || ""}${entry.card.suit || ""}` : "—";
    const categoryLabel = String(entry?.category || "").toUpperCase() || "UNKNOWN";
    const valuesLabel = Array.isArray(entry?.selectedValues) && entry.selectedValues.length
      ? entry.selectedValues.join(", ")
      : "none";
    const resultLabel = entry?.matched ? "hit" : "miss";
    return `- Draw ${entry.drawIndex}: ${categoryLabel} [${valuesLabel}] -> ${cardLabel} (${resultLabel}), pot ${formatCurrency(entry.startingPot || 0)} to ${formatCurrency(entry.potAfter || 0)}.`;
  });

  return {
    reply: `Here is the full prediction sequence for that Guess 10 hand:\n${lines.join("\n")}`,
    riskTolerance: state.riskTolerance,
    plan: null,
    chart: null
  };
}

async function requestPlayAssistantResponse(userMessage) {
  const gameKey = getCurrentPlayAssistantGameKey();
  const state = await getPlayAssistantState();
  const localShapeTradersResponse =
    gameKey === GAME_KEYS.SHAPE_TRADERS ? buildLocalShapeTradersAssistantResponse(userMessage, state) : null;
  const localChartResponse = buildLocalAssistantChartResponse(userMessage, state);
  if (localChartResponse) {
    return localChartResponse;
  }
  const localGuess10HistoryResponse =
    gameKey === GAME_KEYS.GUESS_10 ? buildLocalGuess10HistoryResponse(userMessage, state) : null;
  if (localGuess10HistoryResponse) {
    return localGuess10HistoryResponse;
  }
  const localGuess10PredictionSequenceResponse =
    gameKey === GAME_KEYS.GUESS_10 ? buildLocalGuess10PredictionSequenceResponse(userMessage, state) : null;
  if (localGuess10PredictionSequenceResponse) {
    return localGuess10PredictionSequenceResponse;
  }
  if (gameKey === GAME_KEYS.RUN_THE_NUMBERS && parseAssistantClearDirective(userMessage)) {
    return {
      reply: "Understood. Confirm if you want me to clear all current bets from the felt.",
      riskTolerance: state.riskTolerance,
      plan: {
        summary: "Clear all current bets from the table.",
        replaceExisting: true,
        bets: [],
        totalUnits: 0,
        clearOnly: true
      }
    };
  }
  try {
    const invokePromise = supabase.functions.invoke("play-assistant", {
      body: {
        message: userMessage,
        messages: serializePlayAssistantMessages(),
        state
      }
    });
    const timeoutPromise = new Promise((_, reject) => {
      window.setTimeout(() => {
        reject(new Error("Play assistant request timed out."));
      }, PLAY_ASSISTANT_REQUEST_TIMEOUT_MS);
    });
    const { data, error } = await Promise.race([invokePromise, timeoutPromise]);
    if (error) {
      throw error;
    }
    if (data?.reply) {
      return {
        reply: String(data.reply),
        riskTolerance: data.riskTolerance || state.riskTolerance,
        plan: normalizeAssistantPlan(data.plan),
        chart: normalizeAssistantChart(data.chart),
        ruleDraft: data.ruleDraft || null
      };
    }
  } catch (error) {
    console.warn("[RTN] play assistant fallback", error);
  }

  if (localShapeTradersResponse) {
    return localShapeTradersResponse;
  }

  if (gameKey !== GAME_KEYS.RUN_THE_NUMBERS) {
    return {
      reply:
        "I can help explain Guess 10, your current prediction, and cash-out decisions, but I can't auto-stage Guess 10 actions yet.",
      riskTolerance: state.riskTolerance,
      plan: null,
      chart: null,
      ruleDraft: null
    };
  }

  const explicitDirective = parseAssistantDirective(userMessage, state);
  const randomSpreadDirective = parseAssistantRandomSpreadDirective(userMessage, state);
  if (randomSpreadDirective) {
    const totalRequestedUnits = randomSpreadDirective.selectedCount * randomSpreadDirective.perBetUnits;
    if (randomSpreadDirective.definitions?.length) {
      const adjustedCopy =
        randomSpreadDirective.selectedCount < randomSpreadDirective.requestedCount
          ? ` I could fit ${randomSpreadDirective.selectedCount} bets within your current bankroll and the one-per-bet limit.`
          : "";
      return {
        reply: `Understood. I made a best-guess random draft of ${randomSpreadDirective.selectedCount} bet${randomSpreadDirective.selectedCount === 1 ? "" : "s"} at ${randomSpreadDirective.perBetUnits} unit${randomSpreadDirective.perBetUnits === 1 ? "" : "s"} each for ${totalRequestedUnits} total units.${adjustedCopy} Confirm if you want me to place it on the felt.`,
        riskTolerance: state.riskTolerance,
        chart: null,
        ruleDraft: null,
        plan: normalizeAssistantPlan({
          summary: "Best-guess random layout captured. Confirm and I will stage it on the felt.",
          replaceExisting: true,
          bets: randomSpreadDirective.definitions.map((definition) => ({
            key: definition.key,
            units: randomSpreadDirective.perBetUnits
          }))
        })
      };
    }
  }

  if (explicitDirective) {
    const { requestedUnits, targetText, definitions, availableUnits } = explicitDirective;
    const totalRequestedUnits =
      Array.isArray(definitions) && definitions.length > 0 ? requestedUnits * definitions.length : requestedUnits;

    if (definitions?.length && requestedUnits > 0 && totalRequestedUnits <= availableUnits) {
      const summaryTarget =
        definitions.length === 1
          ? definitions[0].label
          : targetText.replace(/\s+/g, " ").trim() || "that layout";
      return {
        reply:
            definitions.length === 1
              ? `Understood. I drafted exactly ${requestedUnits} units on ${definitions[0].label}. Confirm if you want me to place it on the felt.`
              : `Understood. I made a best-guess draft of ${requestedUnits} units on each target in ${summaryTarget} for ${totalRequestedUnits} units total. Confirm if you want me to place it on the felt.`,
        riskTolerance: state.riskTolerance,
        chart: null,
        ruleDraft: null,
        plan: normalizeAssistantPlan({
          summary:
            definitions.length === 1
              ? "Direct instruction captured. Confirm and I will stage this exact layout on the felt."
              : "Best-guess instruction captured. Confirm and I will stage this layout on the felt.",
          replaceExisting: true,
          bets: definitions.map((definition) => ({ key: definition.key, units: requestedUnits }))
        })
      };
    }

    if (definitions?.length && totalRequestedUnits > availableUnits) {
      const targetLabel =
        definitions.length === 1 ? definitions[0].label : targetText.replace(/\s+/g, " ").trim() || "that layout";
      return {
        reply:
            definitions.length === 1
              ? `I can't place ${requestedUnits} units on ${targetLabel} because only ${availableUnits} units are available right now.`
              : `I can't place ${requestedUnits} units on each target in ${targetLabel} because that needs ${totalRequestedUnits} units and only ${availableUnits} are available right now.`,
        riskTolerance: state.riskTolerance,
        plan: null,
        chart: null,
        ruleDraft: null
      };
    }

  }

  return {
    reply: "The assistant is temporarily unavailable. Try again in a moment.",
    riskTolerance: state.riskTolerance,
    plan: null,
    chart: null,
    ruleDraft: null
  };
}

function applyAssistantPlan(plan, messageId = null) {
  const isClearOnly = Boolean(plan?.clearOnly);
  const normalizedPlan = isClearOnly
    ? {
        summary: String(plan?.summary || "Clear all current bets from the table."),
        replaceExisting: true,
        bets: [],
        totalUnits: 0,
        clearOnly: true
      }
    : normalizeAssistantPlan(plan);
  if (!normalizedPlan) {
    showToast("That assistant plan could not be applied.", "error");
    return false;
  }

  if (currentRoute !== "run-the-numbers") {
    showToast("Open the PLAY table before applying assistant bets.", "error");
    return false;
  }

  if (dealing) {
    pushPlayAssistantMessage({
      role: "system",
      text: "The hand is already in motion. Wait for the table to reopen before I place a new layout."
    });
    return false;
  }

  const outstanding = bets.reduce((sum, bet) => sum + bet.units, 0);
  const available = normalizedPlan.replaceExisting ? bankroll + outstanding : bankroll;
  if (normalizedPlan.totalUnits > available) {
    pushPlayAssistantMessage({
      role: "system",
      text: `This layout needs ${formatCurrency(
        normalizedPlan.totalUnits
      )} units, but only ${formatCurrency(available)} are available right now.`
    });
    return false;
  }

  if (normalizedPlan.replaceExisting && outstanding > 0) {
    restoreUnits(outstanding);
    resetBets();
  }

  if (normalizedPlan.clearOnly) {
    playAssistantPendingPlan = null;
    playAssistantPendingPlanMessageId = null;
    if (messageId) {
      const sourceMessage = playAssistantThread.find((entry) => entry.id === messageId);
      if (sourceMessage?.plan) {
        sourceMessage.plan.applied = true;
        renderPlayAssistantThread();
      }
    }
    if (messageId) {
      void appendPlayAssistantConversationAction(messageId, {
        actionType: "bets_cleared",
        summary: normalizedPlan.summary,
        clearOnly: true,
        replaceExisting: true
      });
    }
    statusEl.textContent = "Assistant cleared all current bets from the table.";
    pushPlayAssistantMessage({
      role: "system",
      text: "Cleared all current bets from the table. The felt is reset and ready for a new layout."
    });
    return true;
  }

  if (normalizedPlan.replaceExisting) {
    applyBetLayout(
      normalizedPlan.bets.map((bet) => ({
        key: bet.key,
        chips: [...bet.chips]
      }))
    );
  } else {
    normalizedPlan.bets.forEach((bet) => {
      bet.chips.forEach((chip) => addBet(bet.key, chip));
    });
  }

  playAssistantPendingPlan = null;
  playAssistantPendingPlanMessageId = null;
  if (messageId) {
    const sourceMessage = playAssistantThread.find((entry) => entry.id === messageId);
    if (sourceMessage?.plan) {
      sourceMessage.plan.applied = true;
      renderPlayAssistantThread();
    }
  }
  if (messageId) {
    void appendPlayAssistantConversationAction(messageId, {
      actionType: "wagers_staged",
      summary: normalizedPlan.summary,
      clearOnly: false,
      replaceExisting: Boolean(normalizedPlan.replaceExisting),
      totalUnits: Number(normalizedPlan.totalUnits || 0),
      wagersPlaced: Array.isArray(normalizedPlan.bets)
        ? normalizedPlan.bets.map((bet) => ({
            key: String(bet.key || ""),
            label: String(bet.label || ""),
            units: Number(bet.units || 0)
          }))
        : []
    });
  }
  statusEl.textContent = `Assistant placed ${formatCurrency(
    normalizedPlan.totalUnits
  )} units on the felt. Review the layout, then deal when you're ready.`;
  pushPlayAssistantMessage({
    role: "system",
    text: `Placed ${formatCurrency(
      normalizedPlan.totalUnits
    )} units on the table. I stopped there so you stay in control of starting the hand.`
  });
  return true;
}

function applyShapeTraderAssistantRuleDraft(ruleDraft, messageId = null) {
  if (getCurrentPlayAssistantGameKey() !== GAME_KEYS.SHAPE_TRADERS || !ruleDraft) {
    return false;
  }

  ensureShapeTraderAssistantRulesLoaded();
  if (ruleDraft.clearAll) {
    setShapeTraderAssistantRules([]);
    pushPlayAssistantMessage({
      role: "system",
      text: "Removed every saved Shape Traders rule."
    });
  } else {
    const nextRules = [...shapeTradersAssistantRules];
    (ruleDraft.rules || []).forEach((rule) => {
      const normalized = normalizeShapeTraderAssistantRule(rule);
      if (normalized) {
        nextRules.push(normalized);
      }
    });
    setShapeTraderAssistantRules(nextRules);
    pushPlayAssistantMessage({
      role: "system",
      text: `Activated ${(ruleDraft.rules || []).length} Shape Traders rule${(ruleDraft.rules || []).length === 1 ? "" : "s"}. I’ll watch each new draw and post fills here.`
    });
  }

  playAssistantPendingRuleDraft = null;
  playAssistantPendingRuleDraftMessageId = null;
  updatePlayAssistantContext();
  if (messageId) {
    const sourceMessage = playAssistantThread.find((entry) => entry.id === messageId);
    if (sourceMessage?.ruleDraft) {
      sourceMessage.ruleDraft.applied = true;
      renderPlayAssistantThread();
    }
  }
  if (messageId) {
    void appendPlayAssistantConversationAction(messageId, {
      actionType: ruleDraft.clearAll ? "rules_cleared" : "rules_saved",
      summary: Array.isArray(ruleDraft.summary)
        ? ruleDraft.summary.join(" ")
        : String(ruleDraft.summary || ""),
      clearAll: Boolean(ruleDraft.clearAll),
      rulesMade: Array.isArray(ruleDraft.rules)
        ? ruleDraft.rules.map((rule) => ({
            side: String(rule.side || rule.actionType || ""),
            assetId: String(rule.assetId || "any"),
            threshold: Number(rule.threshold || 0),
            quantityMode: String(rule.quantityMode || ""),
            quantity: rule.quantity === null || rule.quantity === undefined ? null : Number(rule.quantity || 0),
            repeat: Boolean(rule.repeat)
          }))
        : []
    });
  }
  return true;
}

async function sendPlayAssistantMessage(rawMessage) {
  const userMessage = String(rawMessage || "").trim();
  if (!userMessage || playAssistantRequestInFlight) {
    return;
  }

  const inferredRisk = inferPlayAssistantRiskTolerance(userMessage);
  if (inferredRisk) {
    setPlayAssistantRiskTolerance(inferredRisk);
  }

  if (
    playAssistantPendingPlan &&
    /^\s*(yes|y|apply|place|set it|do it|go ahead|ok|okay)\b/i.test(userMessage)
  ) {
    pushPlayAssistantMessage({ role: "user", text: userMessage });
    const pendingPlanMessageId = playAssistantPendingPlanMessageId;
    resetPlayAssistantDraft();
    applyAssistantPlan(playAssistantPendingPlan, pendingPlanMessageId);
    return;
  }

  if (
    playAssistantPendingRuleDraft &&
    /^\s*(yes|y|activate|enable|do it|go ahead|ok|okay|confirm)\b/i.test(userMessage)
  ) {
    pushPlayAssistantMessage({ role: "user", text: userMessage });
    const pendingRuleDraftMessageId = playAssistantPendingRuleDraftMessageId;
    resetPlayAssistantDraft();
    applyShapeTraderAssistantRuleDraft(playAssistantPendingRuleDraft, pendingRuleDraftMessageId);
    return;
  }

  pushPlayAssistantMessage({ role: "user", text: userMessage });
  resetPlayAssistantDraft();
  setPlayAssistantLoading(true);

  const response = await requestPlayAssistantResponse(userMessage);

  setPlayAssistantLoading(false);

  if (response?.riskTolerance) {
    setPlayAssistantRiskTolerance(response.riskTolerance);
  }

  playAssistantPendingPlan = response?.plan || null;
  playAssistantPendingRuleDraft = response?.ruleDraft || null;
  const assistantMessageId = createPlayAssistantMessageId();
  playAssistantPendingPlanMessageId = response?.plan ? assistantMessageId : null;
  playAssistantPendingRuleDraftMessageId = response?.ruleDraft ? assistantMessageId : null;

  pushPlayAssistantMessage({
    id: assistantMessageId,
    role: "assistant",
    text: response?.reply || "I hit a snag. Please try again in a moment.",
    plan: response?.plan || null,
    ruleDraft: response?.ruleDraft || null,
    chart: response?.chart || null
  });
  void persistPlayAssistantConversation({
    assistantMessageId,
    userMessage,
    response
  });
}

function seedPlayAssistant() {
  ensurePlayAssistantThreadMatchesCurrentGame();
  if (playAssistantThread.length > 0) {
    return;
  }
  updatePlayAssistantContext();
  const config = getPlayAssistantConfig();
  pushPlayAssistantMessage({
    role: "assistant",
    text: config.greeting
  });
}

function summarizeBetResult(bet) {
  if (bet.type === "number") {
    const spokenRank = describeRank(bet.metadata?.rank ?? bet.rank ?? "");
    return bet.hits > 0
      ? `${bet.units}u on ${spokenRank}: <span class="hit">${bet.hits} hits / ${formatCurrency(
          bet.paid
        )}</span>`
      : `${bet.units}u on ${spokenRank}: 0 hits`;
  }

  const profit = bet.paid > 0 ? bet.paid - bet.units : 0;
  const payoutText =
    bet.paid > 0
      ? `<span class="hit">won ${formatCurrency(profit)} · stake returned</span>`
      : "no win";
  return `${bet.label}: ${payoutText}`;
}

function addHistoryEntry(result) {
  recentHandReviews.unshift({
    id: result.id || `hand-review-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    gameKey: result.gameKey || GAME_KEYS.RUN_THE_NUMBERS,
    gameLabel: result.gameLabel || getGameLabel(result.gameKey || GAME_KEYS.RUN_THE_NUMBERS),
    commissionKept: Math.max(0, Number(Number(result.commissionKept || 0).toFixed(2))),
    handHistory: Array.isArray(result.handHistory) ? result.handHistory.map((item) => ({ ...item })) : [],
    drawnCards: Array.isArray(result.drawnCards) ? result.drawnCards.map((card) => ({ ...card })) : [],
    bets: Array.isArray(result.bets) ? result.bets.map((bet) => ({ ...bet })) : [],
    totalWager: Math.max(0, Number(Number(result.totalWager || 0).toFixed(2))),
    totalReturn: Math.max(0, Number(Number(result.totalReturn || 0).toFixed(2))),
    net: Number(Number(result.net || 0).toFixed(2)),
    timestamp: Date.now()
  });
  if (recentHandReviews.length > 8) {
    recentHandReviews = recentHandReviews.slice(0, 8);
  }
  if (currentRoute === "activity-log") {
    void loadActivityLogPage({ force: true });
  }
}

function clearRecentHandHistory() {
  recentHandReviews = [];
  closeHandReviewModal();
}

function renderRecentHandHistory() {
  // Legacy session-only hand history is intentionally hidden now that Activity Log is its own page.
}

function closeHandReviewModal({ restoreFocus = false } = {}) {
  if (!handReviewModal) {
    return;
  }

  handReviewModal.classList.remove("is-open");
  handReviewModal.setAttribute("aria-hidden", "true");
  handReviewModal.hidden = true;

  if (
    (!resetModal || resetModal.hidden) &&
    (!shippingModal || shippingModal.hidden) &&
    (!paytableModal || paytableModal.hidden) &&
    (!adminPrizeModal || adminPrizeModal.hidden) &&
    (!prizeImageModal || prizeImageModal.hidden) &&
    (!numberBetsModal || numberBetsModal.hidden)
  ) {
    document.body.classList.remove("modal-open");
  }

  if (restoreFocus && handReviewModalTrigger instanceof HTMLElement) {
    handReviewModalTrigger.focus();
  }
  handReviewModalTrigger = null;
}

function buildHandReviewField(label, value, options = {}) {
  const toneClass = options.toneClass ? ` ${options.toneClass}` : "";
  return `
    <div class="review-hand-field">
      <span class="review-hand-field-label">${escapeAssistantHtml(label)}</span>
      <span class="review-hand-field-value${toneClass}">${escapeAssistantHtml(value)}</span>
    </div>
  `;
}

function renderColorSchemeReviewCards(entry) {
  const rolls        = Array.isArray(entry.rolls) ? entry.rolls : [];
  const bets         = Array.isArray(entry.bets)  ? entry.bets  : [];
  const ct           = entry.colorTotals || {};
  const netToneClass = entry.net > 0 ? 'review-hand-positive' : entry.net < 0 ? 'review-hand-negative' : 'review-hand-neutral';

  const CS_DOT_HEX = {
    RED: '#d94040', BLUE: '#3a78e0', YELLOW: '#c9a820',
    PURPLE: '#8844cc', GREEN: '#2fa832', ORANGE: '#d06820'
  };

  // ── Summary header panel (rolls + color scores) ────────────────────
  const rollItems = rolls.length
    ? rolls.map((r, i) => {
        const hex = CS_DOT_HEX[r.color] || '#666';
        return `<div class="cs-rv-roll">
          <span class="cs-rv-roll-lbl">ROLL ${i + 1}</span>
          <span class="cs-rv-dot" style="background:${hex};box-shadow:0 0 6px ${hex}66"></span>
          <span class="cs-rv-roll-color">${escapeAssistantHtml(r.color)}</span>
          <span class="cs-rv-roll-num">${r.number || '—'}</span>
        </div>`;
      }).join('')
    : `<span class="cs-rv-na">Roll data unavailable for this round.</span>`;

  const scoreItems = ct.RED !== undefined
    ? ['RED','BLUE','YELLOW','PURPLE','GREEN','ORANGE'].map(c => {
        const hex = CS_DOT_HEX[c] || '#666';
        return `<div class="cs-rv-score">
          <span class="cs-rv-dot cs-rv-dot-sm" style="background:${hex}"></span>
          <span class="cs-rv-score-lbl">${c}</span>
          <span class="cs-rv-score-val">${ct[c]}</span>
        </div>`;
      }).join('')
    : '';

  const grandLine = ct.grandTotal !== undefined
    ? `<div class="cs-rv-grand">
         <span class="cs-rv-grand-lbl">GRAND TOTAL</span>
         <span class="cs-rv-grand-val">${ct.grandTotal}</span>
       </div>`
    : '';

  const summaryPanel = `
    <div class="cs-rv-panel">
      <div class="cs-rv-rolls-row">${rollItems}</div>
      ${scoreItems ? `<div class="cs-rv-scores-row">${scoreItems}</div>${grandLine}` : ''}
    </div>`;

  // ── Bet line cards ─────────────────────────────────────────────────
  const betSection = bets.length ? bets.map(bet => {
    const wager    = Math.max(0, Math.round(Number(bet.amount_wagered || 0)));
    const returned = Math.max(0, Math.round(Number(bet.amount_returned || 0)));
    const net      = returned - wager;
    const won      = bet.outcome === 'W';
    const tone     = won ? 'review-hand-positive' : 'review-hand-negative';
    return `
      <article class="review-hand-card">
        <div class="review-hand-card-topline">
          <span class="review-hand-card-title">${escapeAssistantHtml(csGetBetLabel(bet.bet_key || ''))}</span>
          <span class="review-hand-card-pill ${tone}">${won ? 'WIN' : 'LOSS'}</span>
        </div>
        <div class="review-hand-field-grid review-hand-field-grid-compact">
          ${buildHandReviewField('Wager',  formatCurrency(wager))}
          ${buildHandReviewField('Return', formatCurrency(returned))}
          ${buildHandReviewField('Net',    formatSignedCurrency(net), { toneClass: tone })}
        </div>
      </article>`;
  }).join('') : `<article class="review-hand-card review-hand-card-empty"><p>No bet details saved for this round.</p></article>`;

  const summaryCard = `
    <article class="review-hand-card review-hand-card-sum">
      <div class="review-hand-card-topline">
        <span class="review-hand-card-title review-hand-card-kicker">ROUND TOTAL</span>
      </div>
      <div class="review-hand-field-grid review-hand-field-grid-compact">
        ${buildHandReviewField('Wager',  formatCurrency(entry.totalWager))}
        ${buildHandReviewField('Return', formatCurrency(entry.totalReturn))}
        ${buildHandReviewField('Net',    formatSignedCurrency(entry.net), { toneClass: netToneClass })}
      </div>
    </article>`;

  return summaryPanel + betSection + summaryCard;
}

function renderGuess10ReviewCards(entry) {
  const steps = Array.isArray(entry.handHistory) ? entry.handHistory : [];
  if (!steps.length) {
    return `
      <article class="review-hand-card review-hand-card-empty">
        <p>No round details were saved for this hand.</p>
      </article>
    `;
  }

  return steps
    .map((step, index) => {
      const predictionText = `${step.selectionLabel || "Selection"} · ${
        formatRedBlackMultiplier(step.multiplier || 0) || "0x"
      }`;
      const cardLabel = step?.card ? `${step.card.label || ""}${step.card.suit || ""}` : "—";
      const resultText = step?.matched ? "Hit" : "Miss";
      const resultToneClass = step?.matched ? "review-hand-positive" : "review-hand-negative";
      const potValue = Number(step?.potAfter ?? 0);
      const potToneClass = potValue > 0 ? "review-hand-positive" : "review-hand-negative";
      return `
        <article class="review-hand-card review-hand-round-card">
          <div class="review-hand-card-topline">
            <span class="review-hand-card-kicker">Round ${index + 1}</span>
            <span class="review-hand-card-pill ${resultToneClass}">${escapeAssistantHtml(resultText)}</span>
          </div>
          <div class="review-hand-field-grid">
            ${buildHandReviewField("Prediction", predictionText)}
            ${buildHandReviewField("Card Drawn", cardLabel)}
            ${buildHandReviewField("New Pot", formatCurrency(potValue), { toneClass: potToneClass })}
          </div>
        </article>
      `;
    })
    .join("");
}

function getReviewCardLabel(card) {
  if (!card) return "";
  return [card.label, card.suit || card.suitName].filter(Boolean).join("");
}

function renderClassicDrawnCardsReviewCard(entry) {
  const drawnCards = Array.isArray(entry.drawnCards) ? entry.drawnCards : [];
  if (!drawnCards.length) {
    return "";
  }

  return `
    <article class="review-hand-card review-hand-drawn-card">
      <div class="review-hand-card-topline">
        <span class="review-hand-card-title">Drawn Cards</span>
        <span class="review-hand-card-pill review-hand-neutral">${escapeAssistantHtml(`${drawnCards.length} cards`)}</span>
      </div>
      <p class="review-hand-card-sequence">${escapeAssistantHtml(drawnCards.map(getReviewCardLabel).filter(Boolean).join("  "))}</p>
    </article>
  `;
}

function renderClassicHandReviewCards(entry) {
  const bets = Array.isArray(entry.bets) ? entry.bets : [];
  const drawnCardsCard = renderClassicDrawnCardsReviewCard(entry);
  if (!bets.length) {
    const stopperText = [entry.stopperLabel, entry.stopperSuit].filter(Boolean).join(" ") || "Not saved";
    const netToneClass =
      entry.net > 0 ? "review-hand-positive" : entry.net < 0 ? "review-hand-negative" : "review-hand-neutral";
    return `
      <article class="review-hand-card">
        <div class="review-hand-card-topline">
          <span class="review-hand-card-title">Saved Hand Summary</span>
          <span class="review-hand-card-pill review-hand-neutral">Bet rows unavailable</span>
        </div>
        <div class="review-hand-field-grid review-hand-field-grid-compact">
          ${buildHandReviewField("Stopper", stopperText)}
          ${buildHandReviewField("Wager", formatCurrency(entry.totalWager))}
          ${buildHandReviewField("Return", formatCurrency(entry.totalReturn))}
          ${buildHandReviewField("Net", formatSignedCurrency(entry.net), { toneClass: netToneClass })}
        </div>
      </article>
      ${drawnCardsCard}
    `;
  }

  let sumWager = 0;
  let sumReturn = 0;
  const betRows = bets.map((bet) => {
    const wager = Math.max(0, Math.round(Number(bet.units || 0)));
    const totalReturn = Math.max(0, Math.round(Number(bet.paid || 0)));
    const net = totalReturn - wager;
    const toneClass =
      net > 0 ? "review-hand-positive" : net < 0 ? "review-hand-negative" : "review-hand-neutral";
    sumWager += wager;
    sumReturn += totalReturn;

    return `
      <article class="review-hand-card">
        <div class="review-hand-card-topline">
          <span class="review-hand-card-title">${escapeAssistantHtml(bet.label || bet.key || "Bet")}</span>
        </div>
        <div class="review-hand-field-grid review-hand-field-grid-compact">
          ${buildHandReviewField("Wager", formatCurrency(wager))}
          ${buildHandReviewField("Return", formatCurrency(totalReturn))}
          ${buildHandReviewField("Net", formatSignedCurrency(net), { toneClass })}
        </div>
      </article>
    `;
  });

  const sumNet = sumReturn - sumWager;
  const sumToneClass =
    sumNet > 0 ? "review-hand-positive" : sumNet < 0 ? "review-hand-negative" : "review-hand-neutral";
  const sumRow = `
    <article class="review-hand-card review-hand-card-sum">
      <div class="review-hand-card-topline">
        <span class="review-hand-card-title review-hand-card-kicker">TOTAL</span>
      </div>
      <div class="review-hand-field-grid review-hand-field-grid-compact">
        ${buildHandReviewField("Wager", formatCurrency(sumWager))}
        ${buildHandReviewField("Return", formatCurrency(sumReturn))}
        ${buildHandReviewField("Net", formatSignedCurrency(sumNet), { toneClass: sumToneClass })}
      </div>
    </article>
  `;

  return `${drawnCardsCard}${betRows.join("")}${sumRow}`;
}

function formatActivityLogTimestamp(value) {
  if (!value) return "";
  return formatAnalyticsDate(value, {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit"
  });
}

function mapGameHandRowToActivityEntry(row) {
  const gameKey = resolveGameKey(row?.game_id);
  const fallbackId = row?.created_at || `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  const modeType = String(row?.mode_type || "").trim().toLowerCase();
  return {
    id: `hand:${row?.id || fallbackId}`,
    entryType: "hand",
    handId: String(row?.id || ""),
    gameKey,
    gameLabel: getGameLabel(gameKey),
    createdAt: row?.created_at || new Date().toISOString(),
    modeType: modeType || "normal",
    contestId: row?.contest_id || null,
    totalCards: Math.max(0, Math.round(Number(row?.total_cards || 0))),
    stopperLabel: row?.stopper_label || null,
    stopperSuit: row?.stopper_suit || null,
    totalWager: roundCurrencyValue(Number(row?.total_wager || 0)),
    totalReturn: roundCurrencyValue(Number(row?.total_paid || 0)),
    net: roundCurrencyValue(Number(row?.net || 0)),
    commissionKept: roundCurrencyValue(Number(row?.commission_kept || 0)),
    newAccountValue: roundCurrencyValue(Number(row?.new_account_value || 0)),
    drawnCards: sanitizeStoredDrawnCards(row?.drawn_cards)
  };
}

function mapShapeTraderTradeRowToActivityLogEntry(row) {
  const mapped = mapShapeTraderTradeRowToActivity(row);
  return {
    id: `trade:${mapped.id}`,
    entryType: "trade",
    gameKey: GAME_KEYS.SHAPE_TRADERS,
    gameLabel: getGameLabel(GAME_KEYS.SHAPE_TRADERS),
    createdAt: mapped.createdAt,
    modeType: mapped.contestId ? "contest" : "normal",
    contestId: mapped.contestId || null,
    side: mapped.side,
    assetId: mapped.assetId,
    assetLabel: mapped.assetLabel,
    quantity: mapped.quantity,
    price: mapped.price,
    totalValue: mapped.totalValue,
    netProfit: mapped.netProfit,
    avgPurchasePrice: mapped.avgPurchasePrice ?? null,
    newAccountValue: mapped.accountValue
  };
}

function mapAccountEventRowToActivityLogEntry(row) {
  const eventType = String(row?.event_type || "").trim();
  const amount = roundCurrencyValue(Number(row?.amount || 0));
  const previousBalance = roundCurrencyValue(Number(row?.previous_balance || 0));
  const newBalance = roundCurrencyValue(Number(row?.new_balance || 0));

  return {
    id: `account:${row?.id || `${eventType}:${row?.created_at || Date.now()}`}`,
    entryType: "account",
    gameKey: "account",
    gameLabel: "Account",
    createdAt: row?.created_at || new Date().toISOString(),
    modeType: "normal",
    contestId: null,
    eventType,
    amount,
    previousBalance,
    newAccountValue: newBalance
  };
}

function getActivityEntryModeLabel(entry) {
  if (!entry?.contestId) {
    return "Normal Mode";
  }
  const contest = typeof getContestById === "function" ? getContestById(entry.contestId) : null;
  const contestTitle = String(contest?.title || "").trim();
  return contestTitle ? contestTitle : "Contest Mode";
}

function getFilteredActivityLogEntriesFromState(entries = [], selectedGames = new Set(), tradeFilter = "all") {
  return entries.filter((entry) => {
    if (entry.entryType === "account") {
      return true;
    }
    if (!selectedGames.has(entry.gameKey)) {
      return false;
    }
    if (entry.entryType !== "trade" || entry.gameKey !== GAME_KEYS.SHAPE_TRADERS) {
      return true;
    }
    if (tradeFilter === "all") {
      return true;
    }
    return entry.side === tradeFilter;
  });
}

function getFilteredActivityLogEntries() {
  return getFilteredActivityLogEntriesFromState(
    activityLogEntries,
    activityLogSelectedGames,
    activityLogTradeFilter
  );
}

function updateActivityLogFilterControlsFor(inputs = [], tradeSelect = null, selectedGames = new Set(), tradeFilter = "all") {
  inputs.forEach((input) => {
    if (!(input instanceof HTMLInputElement)) return;
    const gameKey = input.dataset.activityLogFilter || input.dataset.playerActivityLogFilter || "";
    const isActive = selectedGames.has(gameKey);
    input.checked = isActive;
    input.closest(".activity-log-checkbox")?.classList.toggle("is-active", isActive);
  });

  if (tradeSelect) {
    tradeSelect.value = tradeFilter;
    tradeSelect.disabled = !selectedGames.has(GAME_KEYS.SHAPE_TRADERS);
  }
}

function updateActivityLogFilterControls() {
  updateActivityLogFilterControlsFor(
    activityLogFilterInputs,
    activityLogTradeFilterSelect,
    activityLogSelectedGames,
    activityLogTradeFilter
  );
}

function updatePlayerActivityLogFilterControls() {
  updateActivityLogFilterControlsFor(
    playerActivityLogFilterInputs,
    playerActivityLogTradeFilterSelect,
    playerActivityLogSelectedGames,
    playerActivityLogTradeFilter
  );
}

function formatCardSequence(cards = []) {
  return cards
    .map((card) => {
      if (!card || typeof card !== "object") return "";
      if (card.label === "Joker") return "Joker";
      return `${card.label || ""}${card.suit || ""}`;
    })
    .filter(Boolean)
    .join(", ");
}

function getShapeTraderActivitySymbolMarkup(entry) {
  const asset = getShapeTraderAssetConfig(entry.assetId || "square");
  return `<span class="shape-traders-shape-icon shape-${asset.icon}" aria-hidden="true"></span>`;
}

function getActivityLogGameLogoMarkup(gameKey) {
  const record = getGameAssetRecord(gameKey) || DEFAULT_GAME_ASSET_LIBRARY[resolveGameKey(gameKey)] || null;
  if (!record?.logo_url) {
    return "";
  }
  return `<img class="activity-log-game-logo" src="${escapeGameAssetField(record.logo_url)}" alt="${escapeAssistantHtml(record.label || getGameLabel(gameKey))} logo" />`;
}

function accountEventLabel(eventType) {
  switch (String(eventType || "").toLowerCase()) {
    case "rank_up_bonus": return "RANK BONUS";
    case "affiliate_signup": return "AFFILIATE BONUS";
    case "daily_credit_refresh": return "CREDIT REFRESH";
    default: return "ACCOUNT";
  }
}

function buildActivityLogEntriesMarkup(entries = [], { showReviewButtons = true } = {}) {
  return entries.map((entry, _i) => {
    // ── derive shared columns ────────────────────────────────────────────
    let game = "";
    let shortId = "—";
    let modeLabel = "";
    let net = 0;
    let netClass = "is-neutral";
    let netText = "";
    let bal = null;
    let clickAttr = "";
    let isClickable = false;

    if (entry.entryType === "account") {
      game = accountEventLabel(entry.eventType);
      shortId = "—";
      modeLabel = "—";
      net = Number(entry.amount ?? 0);
      netClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      netText = formatSignedCurrency(net);
      bal = entry.newAccountValue ?? null;
    } else if (entry.entryType === "trade") {
      const side = entry.side === "sell" ? "SELL" : "BUY";
      game = `ST·${side}`;
      shortId = entry.id?.split(":")[1]?.slice(-4) || "—";
      modeLabel = (entry.contestId || entry.modeType === "contest") ? "CONTEST" : "NORMAL";
      net = Number(entry.netProfit ?? 0);
      netClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      netText = net >= 0 ? `+${formatCurrency(Math.abs(net))}` : `-${formatCurrency(Math.abs(net))}`;
      bal = entry.newAccountValue ?? null;
      if (showReviewButtons) {
        clickAttr = ` data-activity-trade-entry-id="${escapeAssistantHtml(entry.id || "")}"`;
        isClickable = true;
      }
    } else if (entry.entryType === "ryb_round") {
      game = "RYB";
      shortId = entry.handId?.slice(-4) || entry.id?.split(":")[1]?.slice(-4) || "—";
      modeLabel = (entry.contestId || entry.modeType === "contest") ? "CONTEST" : "NORMAL";
      net = Number(entry.net ?? 0);
      netClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      netText = net >= 0 ? `+${formatCurrency(net)}` : `-${formatCurrency(Math.abs(net))}`;
      bal = entry.newAccountValue ?? null;
      if (showReviewButtons && entry.handId) {
        clickAttr = ` data-hand-review-id="${escapeAssistantHtml(entry.handId)}"`;
        isClickable = true;
      }
    } else if (entry.gameKey === GAME_KEYS.FATE_OR_FORTUNE) {
      // Fate or Fortune (entryType:"hand"). No hand-review modal, so not clickable.
      game = "FOF";
      shortId = entry.handNumber || entry.handId?.slice(-4) || "—";
      modeLabel = (entry.contestId || entry.modeType === "contest") ? "CONTEST" : "NORMAL";
      net = Number(entry.net ?? 0);
      netClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      netText = net >= 0 ? `+${formatCurrency(net)}` : `-${formatCurrency(Math.abs(net))}`;
      bal = entry.newAccountValue ?? null;
    } else {
      // RTN / G10 / COLOR_SCHEME (entryType:"hand")
      game = entry.gameKey === GAME_KEYS.GUESS_10 ? "G10"
           : entry.gameKey === GAME_KEYS.COLOR_SCHEME ? "RYB"
           : "RTN";
      shortId = entry.handNumber || entry.handId?.slice(-4) || "—";
      modeLabel = (entry.contestId || entry.modeType === "contest") ? "CONTEST" : "NORMAL";
      net = Number(entry.net ?? 0);
      netClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      netText = net >= 0 ? `+${formatCurrency(net)}` : `-${formatCurrency(Math.abs(net))}`;
      bal = entry.newAccountValue ?? null;
      if (showReviewButtons && entry.handId) {
        clickAttr = ` data-hand-review-id="${escapeAssistantHtml(entry.handId)}"`;
        isClickable = true;
      }
    }

    const balText = bal && Number(bal) > 0 ? formatCurrency(Number(bal)) : "—";
    const ts = formatActivityLogTimestamp(entry.createdAt);
    const clickableClass = isClickable ? " alr-row-clickable" : "";

    const accountClass = entry.entryType === "account" ? " alr-row-account" : "";
    return `<li class="activity-log-item alr-row${clickableClass}${accountClass}"${clickAttr}${isClickable ? ' tabindex="0" role="button"' : ""}>
      <span class="alr-col alr-col-game">${escapeAssistantHtml(game)}</span>
      <span class="alr-col alr-col-id">#${escapeAssistantHtml(String(shortId))}</span>
      <span class="alr-col alr-col-mode">${escapeAssistantHtml(modeLabel)}</span>
      <span class="alr-col alr-col-net ${netClass}">${escapeAssistantHtml(netText)}</span>
      <span class="alr-col alr-col-bal">${escapeAssistantHtml(balText)}</span>
      <span class="alr-col alr-col-date">${escapeAssistantHtml(ts)}</span>
    </li>`;
  }).join("");
}

function renderActivityLogList({
  listEl,
  loadMoreButton = null,
  entries = [],
  loading = false,
  hasMore = false,
  selectedGames = new Set(),
  tradeFilter = "all",
  updateControls = () => {},
  showReviewButtons = true,
  emptyMessage = "No activity yet. Play a hand or make a trade to start the log.",
  isAppend = false
} = {}) {
  if (!listEl) {
    return;
  }

  updateControls();

  if (loading && !isAppend) {
    listEl.innerHTML = `
      <li class="activity-log-item activity-log-item-empty">
        <p>Loading activity…</p>
      </li>
    `;
    listEl.dataset.renderedCount = "0";
    return;
  }

  const visibleEntries = getFilteredActivityLogEntriesFromState(entries, selectedGames, tradeFilter);

  if (!visibleEntries.length) {
    listEl.innerHTML = `
      <li class="activity-log-item activity-log-item-empty">
        <p>${entries.length ? "No activity matches the selected filters." : emptyMessage}</p>
      </li>
    `;
    listEl.dataset.renderedCount = "0";
    if (loadMoreButton) {
      loadMoreButton.hidden = !hasMore;
      loadMoreButton.disabled = loading;
      loadMoreButton.textContent = "Load More";
    }
    return;
  }

  if (isAppend) {
    const prevCount = parseInt(listEl.dataset.renderedCount || "0", 10);
    const newEntries = visibleEntries.slice(prevCount);
    if (newEntries.length > 0) {
      listEl.insertAdjacentHTML("beforeend", buildActivityLogEntriesMarkup(newEntries, { showReviewButtons }));
    }
    listEl.dataset.renderedCount = String(visibleEntries.length);
  } else {
    listEl.innerHTML = buildActivityLogEntriesMarkup(visibleEntries, { showReviewButtons });
    listEl.dataset.renderedCount = String(visibleEntries.length);
  }

  if (loadMoreButton) {
    loadMoreButton.hidden = !hasMore;
    loadMoreButton.disabled = loading;
    loadMoreButton.textContent = loading ? "Loading…" : "Load More";
  }
}

function renderActivityLogPage({ isAppend = false } = {}) {
  renderActivityLogList({
    listEl: activityLogListEl,
    loadMoreButton: activityLogLoadMoreButton,
    entries: activityLogEntries,
    loading: activityLogLoading,
    hasMore: activityLogHasMore,
    selectedGames: activityLogSelectedGames,
    tradeFilter: activityLogTradeFilter,
    updateControls: updateActivityLogFilterControls,
    showReviewButtons: true,
    isAppend
  });
}

function renderPlayerActivityLogModal() {
  renderActivityLogList({
    listEl: playerActivityLogListEl,
    loadMoreButton: playerActivityLogLoadMoreButton,
    entries: playerActivityLogEntries,
    loading: playerActivityLogLoading,
    hasMore: playerActivityLogHasMore,
    selectedGames: playerActivityLogSelectedGames,
    tradeFilter: playerActivityLogTradeFilter,
    updateControls: updatePlayerActivityLogFilterControls,
    showReviewButtons: false,
    emptyMessage: "No activity has been recorded for this player yet."
  });
}

async function hydrateActivityLogEntrySequences(entries = []) {
  if (!supabase || !Array.isArray(entries) || !entries.length) {
    return entries;
  }

  return entries.map((entry) => {
    if (entry.entryType !== "hand") {
      return entry;
    }
    if (Array.isArray(entry.drawnCards) && entry.drawnCards.length) {
      return {
        ...entry,
        sequenceLabel: formatCardSequence(entry.drawnCards)
      };
    }
    return {
      ...entry,
      sequenceLabel: entry.stopperLabel
        ? entry.stopperLabel === "Joker"
          ? "Stopped on Joker"
          : `Stopped on ${entry.stopperLabel}${entry.stopperSuit ? ` ${entry.stopperSuit}` : ""}`
        : ""
    };
  });
}

async function fetchAdminActivityLogRows(userId, limitCount = 100) {
  if (!supabase || !userId) {
    return [];
  }

  const { data, error } = await supabase.rpc("get_admin_activity_log", {
    target_user_id: userId,
    limit_count: limitCount
  });

  if (error) {
    throw error;
  }

  return Array.isArray(data) ? data : [];
}

function mapColorSchemeRoundToActivityLogEntry(row) {
  const modeType = String(row?.mode_type || (row?.contest_id ? "contest" : "normal")).trim().toLowerCase();
  return {
    id: `ryb:${row?.id || row?.created_at || Date.now()}`,
    entryType: "ryb_round",
    gameKey: GAME_KEYS.COLOR_SCHEME,
    gameLabel: "Color Scheme",
    createdAt: row?.created_at || new Date().toISOString(),
    modeType,
    contestId: row?.contest_id || null,
    totalWager: roundCurrencyValue(Number(row?.total_wager || 0)),
    totalReturn: roundCurrencyValue(Number(row?.total_paid || 0)),
    net: roundCurrencyValue(Number(row?.net || row?.net_profit || 0)),
    newAccountValue: roundCurrencyValue(Number(row?.new_account_value || 0)),
  };
}

function mapAdminActivityLogRowToEntry(row) {
  const entryType = String(row?.entry_type || "").trim().toLowerCase();
  if (entryType === "trade") {
    return mapShapeTraderTradeRowToActivityLogEntry({
      id: row?.id || null,
      executed_at: row?.created_at || null,
      trade_side: row?.trade_side || null,
      shape: row?.shape || null,
      quantity: row?.quantity || null,
      total_value: row?.total_value || null,
      shape_price: row?.shape_price || null,
      net_profit: row?.net_profit || null,
      new_account_value: row?.new_account_value || null,
      contest_id: row?.contest_id || null
    });
  }

  if (entryType === "account") {
    return mapAccountEventRowToActivityLogEntry({
      id: row?.id || null,
      created_at: row?.created_at || null,
      event_type: row?.event_type || null,
      amount: row?.amount || null,
      previous_balance: row?.previous_balance || null,
      new_balance: row?.new_account_value || null
    });
  }

  if (entryType === "ryb_round") {
    return mapColorSchemeRoundToActivityLogEntry({
      id: row?.id || null,
      created_at: row?.created_at || null,
      mode_type: row?.mode_type || null,
      contest_id: row?.contest_id || null,
      total_wager: row?.total_wager || null,
      total_paid: row?.total_paid || null,
      net: row?.net || null,
      new_account_value: row?.new_account_value || null,
    });
  }

  return mapGameHandRowToActivityEntry({
    id: row?.id || null,
    created_at: row?.created_at || null,
    game_id: row?.game_id || null,
    mode_type: row?.mode_type || null,
    contest_id: row?.contest_id || null,
    total_cards: row?.total_cards || null,
    stopper_label: row?.stopper_label || null,
    stopper_suit: row?.stopper_suit || null,
    total_wager: row?.total_wager || null,
    total_paid: row?.total_paid || null,
    net: row?.net || null,
    commission_kept: row?.commission_kept || null,
    new_account_value: row?.new_account_value || null,
    drawn_cards: row?.drawn_cards || null
  });
}

async function loadPlayerActivityLogModal({ force = false, append = false } = {}) {
  if (!playerActivityLogListEl || !activePlayerActivityLogUserId) {
    return;
  }

  if (playerActivityLogLoading) {
    return;
  }

  if (force) {
    playerActivityLogFetchLimit = 100;
  } else if (append) {
    playerActivityLogFetchLimit += 100;
  }

  if (
    !force &&
    !append &&
    playerActivityLogLoadedUserId === activePlayerActivityLogUserId &&
    playerActivityLogEntries.length
  ) {
    renderPlayerActivityLogModal();
    return;
  }

  playerActivityLogLoading = true;
  renderPlayerActivityLogModal();

  try {
    const rows = await fetchAdminActivityLogRows(activePlayerActivityLogUserId, playerActivityLogFetchLimit);
    const contestIds = [...new Set(
      rows
        .map((row) => String(row?.contest_id || "").trim())
        .filter(Boolean)
    )];
    if (contestIds.length) {
      const { data: contestRows, error: contestError } = await supabase
        .from("contests")
        .select("id, title")
        .in("id", contestIds);
      if (!contestError && Array.isArray(contestRows)) {
        contestRows.forEach((contest) => {
          if (!contest?.id) return;
          const existing = getContestById(contest.id);
          if (!existing) {
            contestCache.push(contest);
          }
        });
      }
    }
    playerActivityLogHasMore = rows.length >= playerActivityLogFetchLimit;
    playerActivityLogEntries = await hydrateActivityLogEntrySequences(
      rows.map(mapAdminActivityLogRowToEntry)
    );
    playerActivityLogLoadedUserId = activePlayerActivityLogUserId;
  } catch (error) {
    console.error("[RTN] Unable to load admin player activity log", error);
    showToast("Unable to load player activity log", "error");
    playerActivityLogEntries = [];
    playerActivityLogHasMore = false;
  } finally {
    playerActivityLogLoading = false;
    renderPlayerActivityLogModal();
  }
}

async function loadActivityLogPage({ force = false, append = false } = {}) {
  if (!activityLogListEl) {
    return;
  }

  if (!currentUser?.id || currentUser.id === GUEST_USER.id || !supabase) {
    activityLogEntries = [];
    activityLogLoadedUserId = currentUser?.id || null;
    activityLogLoading = false;
    activityLogHasMore = false;
    renderActivityLogPage();
    return;
  }

  if (activityLogLoading) {
    return;
  }

  if (force) {
    activityLogFetchLimit = 100;
  } else if (append) {
    activityLogFetchLimit += 100;
  }

  if (!force && !append && activityLogLoadedUserId === currentUser.id && activityLogEntries.length) {
    renderActivityLogPage();
    return;
  }

  activityLogLoading = true;
  if (!append) renderActivityLogPage(); // don't wipe existing rows on append

  try {
    const tradesQuery = supabase
      .from("shape_trader_trades")
      .select("*")
      .eq("user_id", currentUser.id)
      .order("executed_at", { ascending: false })
      .limit(activityLogFetchLimit);

    const accountEventsQuery = supabase
      .from("account_events")
      .select("*")
      .eq("user_id", currentUser.id)
      .order("created_at", { ascending: false })
      .limit(activityLogFetchLimit);

    const [
      handRows,
      { data: tradeRows, error: tradeError },
      { data: accountEventRows, error: accountEventError }
    ] = await Promise.all([
      fetchGameHandsRecords({
        userIds: [currentUser.id],
        fields: ["id", "user_id", "created_at", "game_id", "mode_type", "contest_id", "total_cards", "stopper_label", "stopper_suit", "total_wager", "total_paid", "net", "commission_kept", "new_account_value", "drawn_cards"]
      }),
      tradesQuery,
      accountEventsQuery
    ]);

    let normalizedTrades = [];
    if (tradeError) {
      if (!isMissingRelationError(tradeError, "shape_trader_trades")) {
        throw tradeError;
      }
    } else {
      normalizedTrades = (Array.isArray(tradeRows) ? tradeRows : []).map(mapShapeTraderTradeRowToActivityLogEntry);
    }

    let normalizedAccountEvents = [];
    if (accountEventError) {
      if (!isMissingRelationError(accountEventError, "account_events")) {
        throw accountEventError;
      }
    } else {
      normalizedAccountEvents = (Array.isArray(accountEventRows) ? accountEventRows : []).map(mapAccountEventRowToActivityLogEntry);
    }

    const normalizedHands = (Array.isArray(handRows) ? handRows : [])
      .sort((a, b) => new Date(b?.created_at || 0).getTime() - new Date(a?.created_at || 0).getTime())
      .slice(0, activityLogFetchLimit)
      .map(mapGameHandRowToActivityEntry);
    const contestIds = [...new Set(
      [...normalizedHands, ...normalizedTrades, ...normalizedAccountEvents]
        .map((entry) => String(entry?.contestId || "").trim())
        .filter(Boolean)
    )];
    if (contestIds.length) {
      const { data: contestRows, error: contestError } = await supabase
        .from("contests")
        .select("id, title")
        .in("id", contestIds);
      if (!contestError && Array.isArray(contestRows)) {
        contestRows.forEach((contest) => {
          if (!contest?.id) return;
          const existing = getContestById(contest.id);
          if (!existing) {
            contestCache.push(contest);
          }
        });
      }
    }
    activityLogHasMore =
      normalizedHands.length >= activityLogFetchLimit
      || normalizedTrades.length >= activityLogFetchLimit
      || normalizedAccountEvents.length >= activityLogFetchLimit;
    const mergedEntries = [...normalizedHands, ...normalizedTrades, ...normalizedAccountEvents]
      .sort((a, b) => new Date(b.createdAt || 0).getTime() - new Date(a.createdAt || 0).getTime())
      .slice(0, activityLogFetchLimit);
    activityLogEntries = await hydrateActivityLogEntrySequences(mergedEntries);
    activityLogLoadedUserId = currentUser.id;
  } catch (error) {
    console.error("[RTN] Unable to load activity log", error);
    showToast("Unable to load activity log", "error");
    activityLogEntries = [];
    activityLogHasMore = false;
  } finally {
    activityLogLoading = false;
    renderActivityLogPage({ isAppend: append });
    renderHomeSidebarActivity();
  }
}

function openHandReviewModalShell(trigger = null) {
  if (!handReviewModal || !handReviewListEl) {
    return;
  }

  handReviewModalTrigger = trigger instanceof HTMLElement ? trigger : document.activeElement instanceof HTMLElement ? document.activeElement : null;
  handReviewModal.hidden = false;
  handReviewModal.classList.add("is-open");
  handReviewModal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-open");
}

function renderHandReviewModalEntry(entry) {
  if (!handReviewModal || !handReviewListEl) {
    return;
  }

  const isGuess10 = (entry.gameKey || "") === GAME_KEYS.GUESS_10;
  const isColorScheme = (entry.gameKey || "") === GAME_KEYS.COLOR_SCHEME;
  const handLength = Math.max(0, Number(entry.totalCards || (Array.isArray(entry.drawnCards) ? entry.drawnCards.length : 0)));

  if (handReviewSummaryEl) {
    handReviewSummaryEl.textContent = isColorScheme
      ? `Color Scheme · 3 rolls · ${formatCurrency(entry.totalWager)} wagered · ${formatCurrency(entry.totalReturn)} returned · ${formatSignedCurrency(entry.net)} net.`
      : isGuess10
      ? `${entry.gameLabel || "Guess 10"} · ${handLength} cards · ${formatCurrency(entry.totalWager)} wagered · ${formatCurrency(entry.totalReturn)} returned · ${formatSignedCurrency(entry.net)} net · ${formatCurrency(entry.commissionKept || 0)} commission kept.`
      : `Hand length ${handLength}. Total return ${formatCurrency(entry.totalReturn)} units on ${formatCurrency(entry.totalWager)} wagered.`;
  }

  handReviewListEl.innerHTML = isColorScheme
    ? renderColorSchemeReviewCards(entry)
    : isGuess10 ? renderGuess10ReviewCards(entry) : renderClassicHandReviewCards(entry);

  if (handReviewTotalWagerEl) {
    handReviewTotalWagerEl.textContent = formatCurrency(entry.totalWager);
  }
  if (handReviewTotalReturnEl) {
    handReviewTotalReturnEl.textContent = formatCurrency(entry.totalReturn);
  }
  if (handReviewTotalNetEl) {
    handReviewTotalNetEl.textContent = formatSignedValue(entry.net);
    handReviewTotalNetEl.className = `review-hand-total-value ${
      entry.net > 0 ? "review-hand-positive" : entry.net < 0 ? "review-hand-negative" : "review-hand-neutral"
    }`;
  }
  const bal = entry.newAccountValue != null ? Number(entry.newAccountValue) : null;
  if (handReviewBalanceRowEl) handReviewBalanceRowEl.hidden = !(bal && bal > 0);
  if (handReviewTotalBalanceEl && bal && bal > 0) handReviewTotalBalanceEl.textContent = formatCurrency(bal);
}

function renderHandReviewLoadingState(trigger = null) {
  openHandReviewModalShell(trigger);
  if (handReviewSummaryEl) {
    handReviewSummaryEl.textContent = "Loading hand review…";
  }
  if (handReviewListEl) {
    handReviewListEl.innerHTML = `
      <article class="review-hand-card review-hand-card-empty">
        <p>Loading wager details from the database…</p>
      </article>
    `;
  }
  if (handReviewTotalWagerEl) {
    handReviewTotalWagerEl.textContent = "—";
  }
  if (handReviewTotalReturnEl) {
    handReviewTotalReturnEl.textContent = "—";
  }
  if (handReviewTotalNetEl) {
    handReviewTotalNetEl.textContent = "—";
    handReviewTotalNetEl.className = "review-hand-total-value review-hand-neutral";
  }
  if (handReviewBalanceRowEl) handReviewBalanceRowEl.hidden = true;
}

async function fetchHandReviewEntry(reviewId) {
  if (!reviewId || !supabase) {
    return recentHandReviews.find((candidate) => candidate.id === reviewId) || null;
  }

  let handRow = null;
  const { data: rtnHandRow, error: rtnHandError } = await supabase
    .from("rtn_live_hands")
    .select("id, user_id, started_at, mode_type, contest_id, total_cards, total_wager, total_paid, net, commission_kept, new_account_value, drawn_cards, stopper_card")
    .eq("id", reviewId)
    .maybeSingle();

  if (rtnHandError && !isMissingRelationError(rtnHandError, "rtn_live_hands")) {
    throw rtnHandError;
  }

  if (rtnHandRow) {
    handRow = {
      id: rtnHandRow.id,
      user_id: rtnHandRow.user_id,
      created_at: rtnHandRow.started_at,
      game_id: GAME_KEYS.RUN_THE_NUMBERS,
      total_cards: rtnHandRow.total_cards,
      stopper_label: rtnHandRow?.stopper_card?.label || null,
      stopper_suit: rtnHandRow?.stopper_card?.suitName || rtnHandRow?.stopper_card?.suit || null,
      total_wager: rtnHandRow.total_wager,
      total_paid: rtnHandRow.total_paid,
      net: rtnHandRow.net,
      commission_kept: rtnHandRow.commission_kept,
      new_account_value: rtnHandRow.new_account_value,
      drawn_cards: rtnHandRow.drawn_cards
    };
  }

  // Check guess10_live_hands if not found in rtn_live_hands
  if (!handRow) {
    const { data: g10HandRow, error: g10HandError } = await supabase
      .from("guess10_live_hands")
      .select("id, user_id, started_at, mode_type, contest_id, total_cards, total_wager, total_paid, net, commission_kept, new_account_value, drawn_cards")
      .eq("id", reviewId)
      .maybeSingle();

    if (g10HandError && !isMissingRelationError(g10HandError, "guess10_live_hands")) {
      throw g10HandError;
    }
    if (g10HandRow) {
      handRow = {
        id: g10HandRow.id,
        user_id: g10HandRow.user_id,
        created_at: g10HandRow.started_at,
        game_id: GAME_KEYS.GUESS_10,
        total_cards: g10HandRow.total_cards,
        stopper_label: null,
        stopper_suit: null,
        total_wager: g10HandRow.total_wager,
        total_paid: g10HandRow.total_paid,
        net: g10HandRow.net,
        commission_kept: g10HandRow.commission_kept,
        new_account_value: g10HandRow.new_account_value,
        drawn_cards: g10HandRow.drawn_cards
      };
    }
  }

  // CS rounds live in color_scheme_rounds, not rtn_live_hands.
  if (!handRow) {
    const { data: csRound, error: csErr } = await supabase
      .from('color_scheme_rounds')
      .select('id, user_id, created_at, total_wagered, total_returned, net_profit, new_account_value, status')
      .eq('id', reviewId)
      .maybeSingle();
    if (csErr && !isMissingRelationError(csErr, 'color_scheme_rounds')) throw csErr;
    if (csRound) {
      handRow = {
        id: csRound.id,
        user_id: csRound.user_id,
        created_at: csRound.created_at,
        game_id: GAME_KEYS.COLOR_SCHEME,
        total_cards: 0,
        stopper_label: null,
        stopper_suit: null,
        total_wager: csRound.total_wagered || 0,
        total_paid: csRound.total_returned || 0,
        net: csRound.net_profit || 0,
        commission_kept: 0,
        new_account_value: csRound.new_account_value || 0,
        drawn_cards: []
      };
    }
  }

  if (!handRow) {
    return recentHandReviews.find((candidate) => candidate.id === reviewId) || null;
  }

  const gameKey = resolveGameKey(handRow?.game_id);
  const baseEntry = {
    id: String(handRow?.id || reviewId),
    gameKey,
    gameLabel: getGameLabel(gameKey),
    totalCards: Math.max(0, Math.round(Number(handRow?.total_cards || 0))),
    commissionKept: roundCurrencyValue(Number(handRow?.commission_kept || 0)),
    totalWager: roundCurrencyValue(Number(handRow?.total_wager || 0)),
    totalReturn: roundCurrencyValue(Number(handRow?.total_paid || 0)),
    net: roundCurrencyValue(Number(handRow?.net || 0)),
    newAccountValue: handRow?.new_account_value ? roundCurrencyValue(Number(handRow.new_account_value)) : null,
    stopperLabel: handRow?.stopper_label || null,
    stopperSuit: handRow?.stopper_suit || null,
    drawnCards: sanitizeStoredDrawnCards(handRow?.drawn_cards),
    handHistory: [],
    bets: []
  };

  if (gameKey === GAME_KEYS.COLOR_SCHEME) {
    // CS data lives entirely in color_scheme_rounds + color_scheme_bets.
    // reviewId IS the color_scheme_round_id (activity log will source from that table).
    const CS_COLOR_CHAR = { R: 'RED', B: 'BLUE', Y: 'YELLOW' };
    let csBets = [], rolls = [], colorTotals = {};
    if (supabase) {
      const [{ data: betRows }, { data: roundRow }] = await Promise.all([
        supabase.from('color_scheme_bets')
          .select('bet_key, amount_wagered, outcome, amount_returned, net_profit')
          .eq('round_id', reviewId),
        supabase.from('color_scheme_rounds')
          .select('roll_1,roll_2,roll_3,red_total,yellow_total,blue_total,purple_total,green_total,orange_total,primary_score,secondary_score,grand_total,total_wagered,total_returned,net_profit,new_account_value')
          .eq('id', reviewId)
          .maybeSingle()
      ]);
      csBets = betRows || [];
      if (roundRow) {
        // Parse individual roll columns — server stores {color:'R',number:3}
        rolls = [roundRow.roll_1, roundRow.roll_2, roundRow.roll_3]
          .filter(Boolean)
          .map(r => ({ color: CS_COLOR_CHAR[r.color] || r.color, number: Number(r.number || 0) }));
        colorTotals = {
          RED:    Number(roundRow.red_total    || 0),
          YELLOW: Number(roundRow.yellow_total || 0),
          BLUE:   Number(roundRow.blue_total   || 0),
          PURPLE: Number(roundRow.purple_total || 0),
          GREEN:  Number(roundRow.green_total  || 0),
          ORANGE: Number(roundRow.orange_total || 0),
          primaryScore:   Number(roundRow.primary_score   || 0),
          secondaryScore: Number(roundRow.secondary_score || 0),
          grandTotal:     Number(roundRow.grand_total     || 0),
        };
        baseEntry.totalWager       = roundCurrencyValue(Number(roundRow.total_wagered));
        baseEntry.totalReturn      = roundCurrencyValue(Number(roundRow.total_returned));
        baseEntry.net              = roundCurrencyValue(Number(roundRow.net_profit));
        if (roundRow.new_account_value) baseEntry.newAccountValue = roundCurrencyValue(Number(roundRow.new_account_value));

        // Re-derive each bet's outcome from authoritative round color totals.
        // The stored `outcome` in color_scheme_bets can be wrong if a double-settle
        // overwrote winning bets with LOSS. colorTotals from color_scheme_rounds is
        // always correct (it's the source of truth for what the dice actually showed).
        const gt = colorTotals.grandTotal;
        csBets = csBets.map(bet => {
          const won = csIsCurrentlyWinning(bet.bet_key, colorTotals, gt);
          const base = won ? Math.floor(Number(bet.amount_wagered) * (CS_ODDS[bet.bet_key] || 1)) : 0;
          const payout = (won && bet.bet_key === 'TYPE_PRIMARY') ? Math.floor(base * 0.95) : base;
          return {
            ...bet,
            outcome:         won ? 'W' : 'L',
            amount_returned: won ? Number(bet.amount_wagered) + payout : 0,
            net_profit:      won ? payout : -Number(bet.amount_wagered)
          };
        });

        // Fallback: if round totals were never written (mid-settle page refresh),
        // compute them from the re-derived bet data so the modal shows correct values.
        if (!roundRow.total_wagered && csBets.length) {
          baseEntry.totalWager  = roundCurrencyValue(csBets.reduce((s, b) => s + Number(b.amount_wagered || 0), 0));
          baseEntry.totalReturn = roundCurrencyValue(csBets.reduce((s, b) => s + Number(b.amount_returned || 0), 0));
          baseEntry.net         = roundCurrencyValue(baseEntry.totalReturn - baseEntry.totalWager);
        }
      }
    }
    return { ...baseEntry, bets: csBets, rolls, colorTotals };
  }

  if (gameKey === GAME_KEYS.GUESS_10) {
    const drawRows = await fetchGuess10DrawPlayRecords({ handIds: [reviewId] });
    const handHistory = drawRows
      .sort((a, b) => Number(a?.draw_index || 0) - Number(b?.draw_index || 0))
      .map((row) => ({
        selectionLabel: String(row?.selection_label || ""),
        multiplier: roundCurrencyValue(Number(row?.multiplier || 0)),
        matched: Boolean(row?.was_correct),
        potAfter: roundCurrencyValue(Number(row?.ending_pot || 0)),
        card: sanitizeGuess10AssistantCard({
          label: row?.drawn_card_label,
          suit: row?.drawn_card_suit,
          suitName: row?.drawn_card_suit_name,
          color: row?.drawn_card_color
        })
      }));
    return {
      ...baseEntry,
      handHistory,
      drawnCards: baseEntry.drawnCards.length ? baseEntry.drawnCards : handHistory.map((step) => step.card).filter(Boolean)
    };
  }

  const betRows = await fetchRunTheNumbersBetPlayRecordsByHandIds({ handIds: [reviewId] });
  // Aggregate rows with the same bet_key (each chip can be a separate DB record)
  const betMap = new Map();
  for (const row of betRows) {
    const key = row?.bet_key || "";
    const raw = row?.raw && typeof row.raw === "object" ? row.raw : {};
    const label = raw?.label || key || "Bet";
    const wagered = roundCurrencyValue(Number(row?.amount_wagered || 0));
    const paid = roundCurrencyValue(Number(row?.amount_paid || 0));
    if (betMap.has(key)) {
      const existing = betMap.get(key);
      existing.units = roundCurrencyValue(existing.units + wagered);
      existing.paid = roundCurrencyValue(existing.paid + paid);
    } else {
      betMap.set(key, { key, label, units: wagered, paid });
    }
  }
  return {
    ...baseEntry,
    bets: [...betMap.values()]
  };
}

function mergeHandReviewEntryWithFallback(entry, fallbackEntry) {
  if (!entry || !fallbackEntry) {
    return entry;
  }

  const isGuess10 = (entry.gameKey || "") === GAME_KEYS.GUESS_10;
  if (isGuess10) {
    if (!Array.isArray(entry.handHistory) || !entry.handHistory.length) {
      entry.handHistory = Array.isArray(fallbackEntry.handHistory)
        ? fallbackEntry.handHistory.map((step) => ({ ...step }))
        : [];
    }
  } else if (!Array.isArray(entry.bets) || !entry.bets.length) {
    entry.bets = Array.isArray(fallbackEntry.bets)
      ? fallbackEntry.bets.map((bet) => ({ ...bet }))
      : [];
  }

  if (!Array.isArray(entry.drawnCards) || !entry.drawnCards.length) {
    entry.drawnCards = Array.isArray(fallbackEntry.drawnCards)
      ? fallbackEntry.drawnCards.map((card) => ({ ...card }))
      : [];
  }

  return entry;
}

async function openHandReviewModal(reviewId, trigger = null) {
  if (!handReviewModal || !handReviewListEl) {
    return;
  }

  const requestToken = ++handReviewRequestToken;
  const cachedEntry = recentHandReviews.find((candidate) => candidate.id === reviewId);
  if (cachedEntry) {
    openHandReviewModalShell(trigger);
    renderHandReviewModalEntry(cachedEntry);
  } else {
    renderHandReviewLoadingState(trigger);
  }

  try {
    const entry = mergeHandReviewEntryWithFallback(await fetchHandReviewEntry(reviewId), cachedEntry);
    if (requestToken !== handReviewRequestToken) {
      return;
    }
    if (!entry) {
      closeHandReviewModal();
      showToast("That hand review is no longer available.", "error");
      return;
    }
    openHandReviewModalShell(trigger);
    renderHandReviewModalEntry(entry);
    handReviewOkButton?.focus();
  } catch (error) {
    console.error("[RTN] Unable to load hand review", error);
    if (!cachedEntry) {
      closeHandReviewModal();
    }
    showToast("Unable to load hand review", "error");
  }
}

function resetTable(
  message = "Select a chip and place your bets in the betting panel.",
  { clearDraws = false } = {}
) {
  if (clearDraws) {
    drawsContainer.innerHTML = "";
    updateRtnCardCount();
  }
  if (message) {
    statusEl.textContent = message;
  }
  dealing = false;
  awaitingManualDeal = false;
  currentHandContext = null;
  setHandPaused(false);
  setBettingEnabled(true);
  updateAutoDealToggleUI();
  updateDealButtonState();
  updatePauseButton();
  updateRebetButtonState();
}

async function performAccountReset() {
  const contestMode = isContestAccountMode();
  const modeContest = getModeContest();
  const modeEntry = getModeContestEntry();
  const resetCredits = contestMode
    ? normalizeStoredCreditValue(modeEntry?.starting_credits ?? modeContest?.starting_credits ?? 0)
    : INITIAL_BANKROLL;
  const resetCarterCash = contestMode
    ? Math.max(0, Math.round(Number(modeEntry?.starting_carter_cash ?? modeContest?.starting_carter_cash ?? 0)))
    : 0;

  bankroll = resetCredits;
  handleBankrollChanged();
  stats = { hands: 0, wagered: 0, paid: 0 };
  updateStatsUI();
  lastBetLayout = [];
  currentOpeningLayout = [];
  clearRecentHandHistory();
  resetBets();
  stopCarterCashAnimation();
  carterCash = resetCarterCash;
  carterCashProgress = 0;
  updateCarterCashDisplay();
  syncCurrentModeShadowState();
  await persistBankroll();
  if (!contestMode) {
    await ensureProfileSynced({ force: true });
  }
  resetTable("Account reset. Select a chip and place your bets in the betting panel.", {
    clearDraws: true
  });
  resetBankrollHistory();
  closeUtilityPanel();
  showToast(
    contestMode
      ? "Contest mode reset to its starting balance."
      : "Account reset. Bankroll restored to 1,000 units and Carter Cash cleared.",
    "info"
  );
}

function openResetModal() {
  if (!resetModal) {
    void performAccountReset();
    return;
  }
  if (!resetModal.hidden) {
    return;
  }
  updateModeSpecificModalCopy();
  resetModalTrigger = document.activeElement instanceof HTMLElement ? document.activeElement : resetAccountButton;
  resetModal.hidden = false;
  resetModal.classList.add("is-open");
  resetModal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-open");
  resetConfirmButton?.focus();
}

function closeResetModal({ restoreFocus = false } = {}) {
  if (!resetModal) return;
  resetModal.classList.remove("is-open");
  resetModal.setAttribute("aria-hidden", "true");
  resetModal.hidden = true;
  if (
    (!paytableModal || paytableModal.hidden) &&
    (!shippingModal || shippingModal.hidden) &&
    (!adminPrizeModal || adminPrizeModal.hidden) &&
    (!prizeImageModal || prizeImageModal.hidden) &&
    (!contestModal || contestModal.hidden) &&
    (!contestResultsModal || contestResultsModal.hidden) &&
    (!adminContestResultsModal || adminContestResultsModal.hidden) &&
    (!adminContestModal || adminContestModal.hidden)
  ) {
    document.body.classList.remove("modal-open");
  }
  if (restoreFocus && resetModalTrigger instanceof HTMLElement) {
    resetModalTrigger.focus();
  }
  resetModalTrigger = null;
}

