function openShapeTradersModeSwitchModal(nextMode) {
  if (!shapeTradersModeSwitchModal) {
    return Promise.resolve(
      typeof window === "undefined"
        ? true
        : window.confirm("You still have Shape Traders holdings in this mode. Liquidate them at the live market price before switching accounts?")
    );
  }

  if (shapeTradersModeSwitchCopyEl) {
    shapeTradersModeSwitchCopyEl.textContent =
      `You still have open Shape Traders holdings in ${getAccountModeLabel(currentAccountMode)}. Liquidate them at the live market price before switching to ${getAccountModeLabel(nextMode)}.`;
  }

  setShapeTradersModeSwitchProgress({
    visible: false,
    inFlight: false,
    percent: 0,
    status: "Preparing liquidation…"
  });

  shapeTradersModeSwitchModalTrigger =
    document.activeElement instanceof HTMLElement ? document.activeElement : accountModeSelect;
  shapeTradersModeSwitchModal.hidden = false;
  shapeTradersModeSwitchModal.classList.add("is-open");
  shapeTradersModeSwitchModal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-open");
  shapeTradersModeSwitchConfirmButton?.focus();

  return new Promise((resolve) => {
    shapeTradersModeSwitchModal.dataset.pendingResolution = "true";
    shapeTradersModeSwitchModal.dataset.pendingNextMode = getAccountModeValue(nextMode);
    shapeTradersModeSwitchModal._resolve = resolve;
  });
}

function resolveShapeTradersModeSwitchModal(confirmed = false) {
  if (!shapeTradersModeSwitchModal) return;
  const resolve = shapeTradersModeSwitchModal._resolve;
  delete shapeTradersModeSwitchModal._resolve;
  delete shapeTradersModeSwitchModal.dataset.pendingResolution;
  delete shapeTradersModeSwitchModal.dataset.pendingNextMode;
  if (typeof resolve === "function") {
    resolve(Boolean(confirmed));
  }
}

function setShapeTradersModeSwitchProgress({
  visible = false,
  inFlight = false,
  percent = 0,
  status = "Preparing liquidation…"
} = {}) {
  shapeTradersModeSwitchInFlight = Boolean(inFlight);
  if (shapeTradersModeSwitchProgressEl) {
    shapeTradersModeSwitchProgressEl.hidden = !visible;
    shapeTradersModeSwitchProgressEl.classList.toggle("is-indeterminate", visible && inFlight && percent <= 0);
  }
  if (shapeTradersModeSwitchProgressValueEl) {
    shapeTradersModeSwitchProgressValueEl.textContent = `${Math.max(0, Math.min(100, Math.round(Number(percent || 0))))}%`;
  }
  if (shapeTradersModeSwitchProgressFillEl) {
    shapeTradersModeSwitchProgressFillEl.style.width = `${Math.max(0, Math.min(100, Number(percent || 0)))}%`;
    shapeTradersModeSwitchProgressFillEl.parentElement?.setAttribute("aria-valuenow", String(Math.max(0, Math.min(100, Math.round(Number(percent || 0))))));
  }
  if (shapeTradersModeSwitchStatusEl) {
    shapeTradersModeSwitchStatusEl.textContent = String(status || "");
  }
  if (shapeTradersModeSwitchConfirmButton) {
    shapeTradersModeSwitchConfirmButton.disabled = inFlight;
    shapeTradersModeSwitchConfirmButton.textContent = inFlight ? "Liquidating…" : "Liquidate and Switch";
  }
  if (shapeTradersModeSwitchCancelButton) {
    shapeTradersModeSwitchCancelButton.disabled = inFlight;
  }
  if (shapeTradersModeSwitchCloseButton) {
    shapeTradersModeSwitchCloseButton.disabled = inFlight;
  }
}

function closeShapeTradersModeSwitchModal({ restoreFocus = false, confirmed = false, force = false } = {}) {
  if (!shapeTradersModeSwitchModal) return;
  if (shapeTradersModeSwitchInFlight && !force) {
    return;
  }

  resolveShapeTradersModeSwitchModal(confirmed);
  setShapeTradersModeSwitchProgress({
    visible: false,
    inFlight: false,
    percent: 0,
    status: "Preparing liquidation…"
  });

  shapeTradersModeSwitchModal.classList.remove("is-open");
  shapeTradersModeSwitchModal.setAttribute("aria-hidden", "true");
  shapeTradersModeSwitchModal.hidden = true;

  if (
    (!paytableModal || paytableModal.hidden) &&
    (!shippingModal || shippingModal.hidden) &&
    (!resetModal || resetModal.hidden) &&
    (!adminPrizeModal || adminPrizeModal.hidden) &&
    (!prizeImageModal || prizeImageModal.hidden) &&
    (!contestModal || contestModal.hidden) &&
    (!contestResultsModal || contestResultsModal.hidden) &&
    (!adminContestResultsModal || adminContestResultsModal.hidden) &&
    (!adminContestModal || adminContestModal.hidden) &&
    (!outOfCreditsModal || outOfCreditsModal.hidden)
  ) {
    document.body.classList.remove("modal-open");
  }

  if (restoreFocus && shapeTradersModeSwitchModalTrigger instanceof HTMLElement) {
    shapeTradersModeSwitchModalTrigger.focus();
  }
  shapeTradersModeSwitchModalTrigger = null;

  if (typeof resolve === "function") {
    resolve(Boolean(confirmed));
  }
}

async function maybeHandleShapeTraderModeSwitch(nextMode) {
  const modeChanged = getAccountModeValue(nextMode) !== getAccountModeValue(currentAccountMode);
  if (!modeChanged) {
    return true;
  }

  if (!shapeTradersHasOpenHoldings()) {
    return true;
  }

  const confirmed = await openShapeTradersModeSwitchModal(nextMode);
  if (!confirmed) {
    closeShapeTradersModeSwitchModal({ restoreFocus: true, confirmed: false, force: true });
    return false;
  }

  if (shapeTradersModeSwitchCopyEl) {
    shapeTradersModeSwitchCopyEl.textContent =
      `Liquidating open Shape Traders holdings from ${getAccountModeLabel(currentAccountMode)} before switching to ${getAccountModeLabel(nextMode)}.`;
  }
  setShapeTradersModeSwitchProgress({
    visible: true,
    inFlight: true,
    percent: 0,
    status: "Preparing liquidation…"
  });

  await liquidateAllShapeTraderHoldingsWithOptions("Mode switch liquidation", {
    onProgress: ({ percent = 0, label = "Preparing liquidation…" } = {}) => {
      setShapeTradersModeSwitchProgress({
        visible: true,
        inFlight: true,
        percent,
        status: label
      });
    }
  });

  if (shapeTradersHasOpenHoldings()) {
    setShapeTradersModeSwitchProgress({
      visible: true,
      inFlight: false,
      percent: 100,
      status: "Liquidation did not complete. Review your holdings and try again."
    });
    return false;
  }

  setShapeTradersModeSwitchProgress({
    visible: true,
    inFlight: true,
    percent: 100,
    status: `Liquidation complete. Switching to ${getAccountModeLabel(nextMode)}…`
  });
  return true;
}

async function applyAccountModeSelection(nextMode, { resetHistory = true } = {}) {
  currentAccountMode = nextMode;
  saveAccountModeSelection(currentAccountMode);
  syncActiveAccountMode({ forceApply: true, resetHistory });

  // A Fate or Fortune round is funded by the account that was active when it
  // started. Switching account mode mid-round would settle the wager against
  // the wrong ledger, so drop any in-flight round back to idle and re-render
  // the stage on the now-active account. (syncActiveAccountMode already
  // refreshed the FOF balance readout via applyAccountSnapshot.)
  if (typeof fofResetForAccountChange === "function") {
    fofResetForAccountChange();
  }
  if (typeof fofLiveResetForAccountChange === "function") {
    fofLiveResetForAccountChange();
  }

  shapeTradersHoldings = createEmptyShapeTraderHoldings();
  shapeTradersActivity = [];
  shapeTradersActivityLoadedCount = 0;
  shapeTradersActivityHasMore = false;
  renderShapeTraders();

  if (currentUser?.id) {
    await loadShapeTraderPortfolioFromBackend();
    renderShapeTraders();
  }
}

function renderDraw(card, { animate = true } = {}) {
  const cardEl = makeCardElement(card);
  const fragment = document.createDocumentFragment();
  fragment.appendChild(cardEl);
  drawsContainer.appendChild(fragment);
  if (animate) {
    requestAnimationFrame(() => {
      cardEl.classList.add("dealt-in");
      updateRtnCardCount();
    });
  } else {
    cardEl.classList.add("dealt-static");
    updateRtnCardCount();
  }
}

function settleAdvancedBets(stopperCard, context = {}) {
  const nonStopperCount = context.nonStopperCount ?? 0;
  const totalCards = context.totalCards ?? nonStopperCount;
  const drawnCards = Array.isArray(context.drawnCards) ? context.drawnCards : [];

  for (const bet of bets) {
    if (bet.type === "number") {
      continue;
    }

    const definition = getBetDefinition(bet.key);
    if (!definition) {
      continue;
    }

    let payout = 0;
    const { metadata } = definition;

    switch (definition.type) {
      case "bust-suit":
        if (stopperCard.label !== "Joker" && stopperCard.suitName === metadata.suit) {
          payout = definition.payout * bet.units;
        }
        break;
      case "bust-rank":
        if (stopperCard.label === metadata.face) {
          payout = definition.payout * bet.units;
        }
        break;
      case "bust-joker":
        if (stopperCard.label === "Joker") {
          payout = definition.payout * bet.units;
        }
        break;
      case "suit-pattern":
        {
          const suit = metadata.suit;
          const pattern = String(metadata.pattern || "").toLowerCase();
          const matchingCards = drawnCards.filter((card) => card?.suitName === suit);
          const firstCard = drawnCards[0] || null;

          if (pattern === "none" && matchingCards.length === 0) {
            payout = definition.payout * bet.units;
          } else if (pattern === "any" && matchingCards.length > 0) {
            payout = definition.payout * bet.units;
          } else if (pattern === "first" && firstCard?.suitName === suit) {
            payout = definition.payout * bet.units;
          }
        }
        break;
      case "count":
        {
          const min = metadata.countMin ?? 0;
          const max = metadata.countMax ?? min;
          if (max === Infinity) {
            if (totalCards >= min) {
              payout = definition.payout * bet.units;
            }
          } else if (totalCards === max) {
            payout = definition.payout * bet.units;
          }
        }
        break;
      default:
        break;
    }

  if (payout > 0) {
      const totalReturn = roundCurrencyValue(payout + bet.units);
      bet.paid = roundCurrencyValue(bet.paid + totalReturn);
      bankroll = roundCurrencyValue(bankroll + totalReturn);
      handleBankrollChanged();
    }
  }
}

function applyPlaythrough(amount) {
  if (!Number.isFinite(amount) || amount <= 0) {
    return;
  }

  addPendingCarterCashPlaythrough(amount);
  carterCashProgress = normalizeCarterCashProgressValue(carterCashProgress + amount);
  const earned = Math.floor(carterCashProgress / 1000);
  if (earned > 0) {
    carterCash += earned;
    carterCashProgress -= earned * 1000;
    handleCarterCashChanged();
    animateCarterCashGain(earned);
  } else if (!carterCashAnimating) {
    handleCarterCashChanged();
  }

  syncCurrentModeShadowState();
}

function applyShapeTraderCarterCashProgress(netProfit) {
  const realizedMove = Math.abs(Number(netProfit) || 0);
  if (!Number.isFinite(realizedMove) || realizedMove <= 0) {
    return;
  }
  applyPlaythrough(realizedMove);
}

function getResolvedContestHandEndingBankroll(netDelta = 0) {
  if (!isContestAccountMode()) {
    return roundCurrencyValue(bankroll);
  }
  const activeEntry = getModeContestEntry();
  const startingCredits = Number(activeEntry?.current_credits);
  if (!Number.isFinite(startingCredits)) {
    return roundCurrencyValue(bankroll);
  }
  return normalizeStoredCreditValue(roundCurrencyValue(startingCredits + Number(netDelta || 0)));
}

async function endHand(stopperCard, context = {}) {
  setHandPaused(false);
  settleAdvancedBets(stopperCard, context);
  const totalWagerThisHand = bets.reduce((sum, bet) => sum + bet.units, 0);
  const totalPaidThisHand = bets.reduce((sum, bet) => sum + bet.paid, 0);
  const netThisHand = totalPaidThisHand - totalWagerThisHand;
  const resolvedEndingBankroll = getResolvedContestHandEndingBankroll(netThisHand);

  const betSnapshots = bets.map((bet) => ({
    key: bet.key,
    type: bet.type,
    label: bet.label,
    units: bet.units,
    hits: bet.hits,
    paid: bet.paid,
    metadata: bet.metadata ? { ...bet.metadata } : null
  }));

  applyPlaythrough(totalWagerThisHand);

  stats.hands += 1;
  stats.wagered += totalWagerThisHand;
  stats.paid += totalPaidThisHand;
  updateStatsUI();

  statusEl.textContent = `Hand stopped on ${stopperCard.label}${
    stopperCard.label !== "Joker" ? " of " + stopperCard.suit : ""
  }. Place your next bets.`;

  addHistoryEntry({
    gameKey: GAME_KEYS.RUN_THE_NUMBERS,
    gameLabel: getGameLabel(GAME_KEYS.RUN_THE_NUMBERS),
    drawnCards: context.drawnCards || [],
    bets: betSnapshots,
    totalWager: totalWagerThisHand,
    totalReturn: totalPaidThisHand,
    net: netThisHand
  });

  lastBetLayout = currentOpeningLayout.length > 0 ? snapshotLayout(currentOpeningLayout) : [];
  currentOpeningLayout = [];

  bankroll = resolvedEndingBankroll;
  handleBankrollChanged();
  dealing = false;
  awaitingManualDeal = false;
  animateBankrollOutcome(netThisHand);
  recordBankrollHistoryPoint();
  await persistBankroll({
    recordContestHistory: isContestAccountMode(),
    contestHistoryLabel: `Hand ${stats.hands}`,
    contestCreditsValue: resolvedEndingBankroll
  });
  await incrementProfileHandProgress(1, GAME_KEYS.RUN_THE_NUMBERS);
  await ensureProfileSynced({ force: true });
  await refreshGameAssetsFromBackend().catch((err) => console.warn("[RTN] Game asset sync error:", err));
  resetBets();
  setBettingEnabled(true);
  updateAutoDealToggleUI();
  updateAutoRebetToggleUI();
  updateDealButtonState();
  updateRebetButtonState();
  updatePauseButton();

  // Auto Rebet: restore last bet layout so user only needs to hit Deal
  if (autoRebetEnabled && lastBetLayout.length > 0) {
    const totalNeeded = layoutTotalUnits(lastBetLayout);
    if (totalNeeded > 0) {
      if (totalNeeded <= bankroll) {
        applyBetLayout(lastBetLayout);
        handleBankrollChanged();
        updateDealButtonState();
        updateRebetButtonState();
      } else {
        signalInsufficientBankroll(
          totalNeeded,
          `Not enough bankroll to auto-rebet ${formatCurrency(totalNeeded)} units.`
        );
        setAutoRebetEnabled(false);
      }
    }
  }
}

async function processCard(card, context) {
  if (context) {
    context.totalCards = (context.totalCards ?? 0) + 1;
    if (!context.drawnCards) {
      context.drawnCards = [];
    }
    context.drawnCards.push(card);
  }

  renderDraw(card);

  if (card.stopper) {
    await endHand(card, context);
    return true;
  }

  if (context) {
    context.nonStopperCount = (context.nonStopperCount ?? 0) + 1;
  }

  const rank = card.rank;
  const suit = card.suit;
  let totalHitPayout = 0;
  let hitsRecorded = 0;
  const stepPays = currentStepPays();
  bets.forEach((bet) => {
    if (
      bet.type === "number" &&
      bet.metadata?.rank === rank &&
      bet.hits < stepPays.length
    ) {
      const pay = stepPays[bet.hits] * bet.units;
      bet.paid += pay;
      bet.hits += 1;
      bankroll += pay;
      handleBankrollChanged();
      totalHitPayout += pay;
      hitsRecorded += 1;
    } else if (
      bet.type === "specific-card" &&
      bet.metadata?.rank === rank &&
      bet.metadata?.suit === suit &&
      bet.hits === 0
    ) {
      // Specific card bet pays 12 to 1 (wager + 12x payout)
      const definition = getBetDefinition(bet.key);
      const payout = definition?.payout || 12;
      const pay = (payout + 1) * bet.units; // Return wager plus payout
      bet.paid += pay;
      bet.hits += 1;
      bankroll += pay;
      handleBankrollChanged();
      totalHitPayout += pay;
      hitsRecorded += 1;
    }
  });

  renderBets();
  syncDisplayedBetStacksFromState({ animate: false });
  if (hitsRecorded > 0) {
    const spokenRank = describeRank(rank);
    statusEl.textContent = `${spokenRank} hits ${hitsRecorded} bet${
      hitsRecorded > 1 ? "s" : ""
    } for ${formatCurrency(totalHitPayout)} units.`;
  } else {
    statusEl.textContent = `${describeRank(rank)} keeps the action going.`;
  }
  return false;
}

async function dealHandLegacy() {
  if (bets.length === 0 || dealing) return;
  const canStart = await guardAgainstShapeTraderExposureBeforeGameStart(GAME_KEYS.RUN_THE_NUMBERS);
  if (!canStart) {
    return;
  }
  if (!canUseCurrentFundsForGame(GAME_KEYS.RUN_THE_NUMBERS)) {
    const contest = getModeContest(currentAccountMode);
    statusEl.textContent = `This contest bankroll can only be used for ${getContestGamesLabel(contest)}.`;
    showToast(`This contest bankroll can only be used for ${getContestGamesLabel(contest)}.`, "error");
    return;
  }
  currentOpeningLayout = snapshotLayout(bets);
  dealing = true;
  awaitingManualDeal = false;
  pauseResolvers = [];
  currentHandContext = { nonStopperCount: 0, totalCards: 0, drawnCards: [] };
  setHandPaused(false);
  setBettingEnabled(false);
  updateDealButtonState();
  updateRebetButtonState();
  resetBetCounters();
  drawsContainer.innerHTML = "";
  updateRtnCardCount();
  statusEl.textContent = "Dealing...";
  updateAutoDealToggleUI();
  updatePauseButton();

  const deck = createDeck();
  shuffle(deck);

  for (const card of deck) {
    await waitWhilePaused();
    const shouldStop = await processCard(card, currentHandContext);
    if (shouldStop) {
      break;
    }
    if (autoDealEnabled) {
      await waitForDealDelay();
    } else {
      await waitForManualDealAdvance();
    }
  }

  currentHandContext = null;
  awaitingManualDeal = false;
  setHandPaused(false);
  updateAutoDealToggleUI();
  updateDealButtonState();
  updatePauseButton();
}

async function dealHandServer() {
  if (bets.length === 0 || dealing) return;
  // Profile guard — don't start if profile hasn't loaded yet
  if (!currentProfile && !isGuestRuntimeUser()) {
    statusEl.textContent = "Profile loading… please wait a moment.";
    showToast("Profile loading… try again in a moment", "info");
    return;
  }
  const canStart = await guardAgainstShapeTraderExposureBeforeGameStart(GAME_KEYS.RUN_THE_NUMBERS);
  if (!canStart) {
    return;
  }
  if (!canUseCurrentFundsForGame(GAME_KEYS.RUN_THE_NUMBERS)) {
    const contest = getModeContest(currentAccountMode);
    statusEl.textContent = `This contest bankroll can only be used for ${getContestGamesLabel(contest)}.`;
    showToast(`This contest bankroll can only be used for ${getContestGamesLabel(contest)}.`, "error");
    return;
  }

  currentOpeningLayout = snapshotLayout(bets);
  dealing = true;
  awaitingManualDeal = false;
  pauseResolvers = [];
  currentHandContext = { nonStopperCount: 0, totalCards: 0, drawnCards: [] };
  setHandPaused(false);
  setBettingEnabled(false);
  updateDealButtonState();
  updateRebetButtonState();
  statusEl.textContent = "Dealing...";
  updateAutoDealToggleUI();
  updatePauseButton();

  try {
    if (!rtnServerHandId) {
      try {
        const startResult = await startRtnHandServer();
        if (startResult === RTN_SERVER_RPC_MISSING) {
          dealing = false;
          currentHandContext = null;
          setBettingEnabled(true);
          updateDealButtonState();
          updateRebetButtonState();
          showToast("Unable to connect to game server. Please check your connection and try again.", "error");
          return;
        }
      } catch (startError) {
        if (isRtnActiveHandConflict(startError)) {
          const resumedHand = await resumeActiveRtnHand({ force: true });
          if (resumedHand === RTN_SERVER_RPC_MISSING) {
            dealing = false;
            currentHandContext = null;
            setBettingEnabled(true);
            updateDealButtonState();
            updateRebetButtonState();
            showToast("Unable to connect to game server. Please check your connection and try again.", "error");
            return;
          }
          if (!rtnServerHandId) {
            throw startError;
          }
        } else {
          throw startError;
        }
      }
    }

    while (dealing && rtnServerHandId) {
      await waitWhilePaused();
      const drawResult = await drawRtnCardServer();
      if (drawResult === RTN_SERVER_RPC_MISSING) {
        throw new Error("RTN draw RPC is unavailable after hand start.");
      }

      applyRtnServerAccountSnapshot(drawResult);
      replaceRtnBetsFromServerState(drawResult?.bet_state || [], { animateStacks: false });
      renderRtnDrawsFromServerState(drawResult?.drawn_cards || [], { animateNewCards: true });
      rtnPendingMidHandBetDrafts = [];
      if (Array.isArray(drawResult?.rejected_bets) && drawResult.rejected_bets.length) {
        const firstRejected = drawResult.rejected_bets[0];
        showToast(firstRejected?.reason || "One or more mid-hand bets were rejected.", "error");
      }
      currentHandContext = {
        totalCards: Math.max(0, Math.round(Number(drawResult?.total_cards || 0))),
        nonStopperCount: sanitizeStoredDrawnCards(drawResult?.drawn_cards).filter((card) => !card?.stopper).length,
        drawnCards: sanitizeStoredDrawnCards(drawResult?.drawn_cards)
      };

      const drawnCard = sanitizeGuess10AssistantCard(drawResult?.card);
      if (drawResult?.hand_complete) {
        const stopperCard = sanitizeGuess10AssistantCard(drawResult?.stopper_card || drawResult?.card);
        const betSnapshots = bets.map((bet) => ({
          key: bet.key,
          type: bet.type,
          label: bet.label,
          units: bet.units,
          hits: bet.hits,
          paid: bet.paid,
          metadata: bet.metadata ? { ...bet.metadata } : null
        }));
        const totalWagerThisHand = roundCurrencyValue(Number(drawResult?.total_wager || 0));
        const totalPaidThisHand = roundCurrencyValue(Number(drawResult?.total_paid || 0));
        const netThisHand = roundCurrencyValue(Number(drawResult?.net || (totalPaidThisHand - totalWagerThisHand)));

        stats.hands += 1;
        stats.wagered += totalWagerThisHand;
        stats.paid += totalPaidThisHand;
        updateStatsUI();

        statusEl.textContent = stopperCard?.label
          ? `Hand stopped on ${stopperCard.label}${stopperCard.label !== "Joker" && stopperCard.suit ? ` of ${stopperCard.suit}` : ""}. Place your next bets.`
          : "Hand complete. Place your next bets.";

        addHistoryEntry({
          id: drawResult?.hand_id || rtnServerHandId,
          gameKey: GAME_KEYS.RUN_THE_NUMBERS,
          gameLabel: getGameLabel(GAME_KEYS.RUN_THE_NUMBERS),
          drawnCards: sanitizeStoredDrawnCards(drawResult?.drawn_cards),
          bets: betSnapshots,
          totalWager: totalWagerThisHand,
          totalReturn: totalPaidThisHand,
          net: netThisHand
        });

        lastBetLayout = currentOpeningLayout.length > 0 ? snapshotLayout(currentOpeningLayout) : [];
        currentOpeningLayout = [];
        animateBankrollOutcome(netThisHand);
        recordBankrollHistoryPoint();
        await incrementProfileHandProgress(1, GAME_KEYS.RUN_THE_NUMBERS);
        await ensureProfileSynced({ force: true });
        await refreshGameAssetsFromBackend().catch((err) => console.warn("[RTN] Game asset sync error:", err));

        dealing = false;
        awaitingManualDeal = false;
        rtnServerHandId = null;
        currentHandContext = null;
        resetBets();
        setBettingEnabled(true);
        updateAutoDealToggleUI();
        updateAutoRebetToggleUI();
        updateDealButtonState();
        updateRebetButtonState();
        updatePauseButton();

        // Auto Rebet: restore last bet layout so user only needs to tap Deal
        if (autoRebetEnabled && lastBetLayout.length > 0) {
          const totalNeeded = layoutTotalUnits(lastBetLayout);
          if (totalNeeded > 0) {
            if (totalNeeded <= bankroll) {
              applyBetLayout(lastBetLayout);
              handleBankrollChanged();
              updateDealButtonState();
              updateRebetButtonState();
            } else {
              signalInsufficientBankroll(
                totalNeeded,
                `Not enough bankroll to auto-rebet ${formatCurrency(totalNeeded)} units.`
              );
              setAutoRebetEnabled(false);
            }
          }
        }
        return;
      }

      if (drawnCard?.label) {
        statusEl.textContent = `${describeRank(drawnCard.label)} keeps the action going.`;
      }

      if (autoDealEnabled) {
        await waitForDealDelay();
      } else {
        await waitForManualDealAdvance();
      }
    }
  } catch (error) {
    console.error("[RTN] RTN server draw failed", error);
    showToast(error?.message || "Unable to draw the next RTN card", "error");
    dealing = false;
    awaitingManualDeal = false;
    rtnServerHandId = null;
    currentHandContext = null;
    setHandPaused(false);
    setBettingEnabled(true);
    updateAutoDealToggleUI();
    updateDealButtonState();
    updateRebetButtonState();
    updatePauseButton();
  }
}

async function dealHand() {
  return dealHandServer();
}

function placeBet(key) {
  const definition = getBetDefinition(key);
  if (!definition) return;

  // Check if player has zero credits
  if (bankroll === 0) {
    openOutOfCreditsModal();
    return;
  }

  const canUseDuringIntermission =
    isRtnServerIntermission() &&
    isRtnRemovableBetType(definition.type);

  if (!bettingOpen && !canUseDuringIntermission) {
    statusEl.textContent = awaitingManualDeal
      ? `${definition.label} bets cannot be changed once the hand has started. Only specific card and bust bets can be added between cards.`
      : `${definition.label} bets are locked while a hand is in progress.`;
    return;
  }

  if (selectedChip > bankroll) {
    signalInsufficientBankroll(
      selectedChip,
      `Insufficient bankroll for a ${formatCurrency(
        selectedChip
      )}-unit chip. Try a smaller denomination.`
    );
    return;
  }

  const bet = addBet(key, selectedChip);
  if (!bet) return;
  if (dealing && rtnServerHandId && canUseDuringIntermission) {
    rtnPendingMidHandBetDrafts.push({
      key: definition.key,
      type: definition.type,
      label: definition.label,
      amount: selectedChip,
      payout: Number(definition.payout || 0),
      metadata: { ...definition.metadata }
    });
  }
  const totalForBet = formatCurrency(bet.units);
  const spokenLabel =
    definition.type === "number"
      ? describeRank(definition.metadata?.rank ?? definition.label)
      : definition.label;
  statusEl.textContent = `Placed ${formatCurrency(selectedChip)} unit${
    selectedChip !== 1 ? "s" : ""
  } on ${spokenLabel}. Total on ${definition.label}: ${totalForBet} unit${
    bet.units !== 1 ? "s" : ""
  }.`;
}

