// ══════════════════════════════════════════════════════════════
// MONKEY MOONSHINE — admin deck editor + RTP simulator.
// Reads/writes the mm_decks table (authenticated) and Monte-Carlos the
// live engine. The game loads the same decks from mm_decks on boot.
// ══════════════════════════════════════════════════════════════
const MM_FRUIT_NAMES = ['cherry','apple','banana','lemon','peach','dragonfruit','mango','pineapple'];
const MM_SYMBOLS = MM_FRUIT_NAMES.concat(['coconut']);
const MM_EDITOR_ORDER = ['coconut'].concat(MM_FRUIT_NAMES);   // coconut first in the editor
const MM_BASE_PAY = { 3: 1, 4: 3, 5: 10 };
const MM_COLS = 5;
function mmBasePay(len){ return MM_BASE_PAY[Math.min(len, 5)] || 0; }

let _mmDecks = null;          // { wild: { display_name, mult, deck:{}, replace_deck:{} } }
let _mmEditWild = null;
let _mmSimRunning = false;
let _mmSounds = null;         // { name: url|null } from mm_sounds
const MM_SOUNDS_BUCKET = 'mm-sounds';
const MM_SOUND_ORDER = ['shake','rowClunk','lineMatch','wildLand','monkeyWild','extraShake','whoosh','coconutRow','moonshine','uiClick','coin','ambient','music'];
const MM_SOUND_LABELS = {
  shake:'Tree shake / change tree', rowClunk:'Row lands in dirt', lineMatch:'Winning payline drawn',
  wildLand:'Wild fruit lands', monkeyWild:'Monkey wild appears', extraShake:'Extra shake earned',
  whoosh:'Monkey-dot whoosh', coconutRow:'Coconut row lands', moonshine:'MONKEY MOONSHINE banner',
  uiClick:'Open WILD FRUIT menu', coin:'Bet + / − (coin)', ambient:'Ambient bed (loops)', music:'Moonshine music (loops)'
};

function mmStatus(msg){ const el = document.getElementById('admin-mm-status'); if (el) el.textContent = msg || ''; }

async function mmAdminInit(){ if (!_mmDecks) await mmLoadDecks(); if (!_mmSounds) await mmLoadSounds(); }

async function mmLoadDecks(){
  if (!supabase){ mmStatus('No database connection.'); return; }
  mmStatus('Loading decks…');
  const { data, error } = await supabase.from('mm_decks')
    .select('wild,display_name,mult,deck,replace_deck,sort_order').order('sort_order');
  if (error){ mmStatus('Load error: ' + error.message); console.error('[mm] load', error); return; }
  _mmDecks = {};
  (data || []).forEach(r => { _mmDecks[r.wild] = { display_name: r.display_name, mult: r.mult, deck: { ...r.deck }, replace_deck: { ...r.replace_deck } }; });
  const sel = document.getElementById('admin-mm-wild');
  if (sel){
    sel.innerHTML = (data || []).map(r => `<option value="${r.wild}">${r.display_name} ×${r.mult}</option>`).join('');
    if (!_mmEditWild || !_mmDecks[_mmEditWild]) _mmEditWild = (data && data[0]) ? data[0].wild : null;
    sel.value = _mmEditWild;
  }
  mmRenderEditor();
  mmStatus(`Loaded ${Object.keys(_mmDecks).length} decks from mm_decks.`);
}

/* ---- MONKEY MOONSHINE sound uploader (mm_sounds + mm-sounds bucket) ---- */
function mmSoundsStatus(msg){ const el = document.getElementById('admin-mm-sounds-status'); if (el) el.textContent = msg || ''; }

async function mmLoadSounds(){
  if (!supabase){ mmSoundsStatus('No database connection.'); return; }
  mmSoundsStatus('Loading sounds…');
  const { data, error } = await supabase.from('mm_sounds').select('name,url');
  if (error){ mmSoundsStatus('Load error: ' + error.message); console.error('[mm] sounds load', error); return; }
  _mmSounds = {};
  (data || []).forEach(r => { _mmSounds[r.name] = r.url || null; });
  mmRenderSounds();
  const set = Object.values(_mmSounds).filter(Boolean).length;
  mmSoundsStatus(`${set} of ${MM_SOUND_ORDER.length} sounds use a custom file — the rest use the built-in synth.`);
}

function mmRenderSounds(){
  const wrap = document.getElementById('admin-mm-snd-list');
  if (!wrap || !_mmSounds) return;
  wrap.innerHTML = MM_SOUND_ORDER.map(name => {
    const has = !!_mmSounds[name];
    const synthable = MmSynth.hasSynth(name);          // the 11 one-shot SFX (not the ambient/music loops)
    const genPending = !!_mmGenerated[name];
    return `
    <div class="admin-mm-snd-row" data-name="${name}">
      <div class="admin-mm-snd-info">
        <span class="admin-mm-snd-name">${MM_SOUND_LABELS[name] || name}</span>
        <span class="admin-mm-snd-key">${name}</span>
      </div>
      <span class="admin-mm-snd-tag ${has ? 'is-file' : 'is-synth'}">${has ? 'custom file' : 'synth'}</span>
      <div class="admin-mm-snd-actions">
        ${synthable ? `<input type="text" class="admin-mm-snd-prompt" data-role="prompt" placeholder="prompt (optional): deep, punchy, retro, bright, long…" spellcheck="false">` : ''}
        <button type="button" class="admin-mm-snd-btn" data-act="preview" ${(has || synthable) ? '' : 'disabled'}>▶ Preview</button>
        ${synthable ? `<button type="button" class="admin-mm-snd-btn" data-act="synth">♪ Synth</button>` : ''}
        ${synthable ? `<button type="button" class="admin-mm-snd-btn admin-mm-snd-gen" data-act="generate">⚡ New Synth</button>` : ''}
        ${synthable ? `<button type="button" class="admin-mm-snd-btn admin-mm-snd-save" data-act="save" ${genPending ? '' : 'disabled'}>✓ Save</button>` : ''}
        <label class="admin-mm-snd-btn admin-mm-snd-upload">⤴ Upload<input type="file" accept="audio/*" data-act="upload" hidden></label>
        <button type="button" class="admin-mm-snd-btn admin-mm-snd-clear" data-act="clear" ${has ? '' : 'disabled'}>Clear</button>
      </div>
    </div>`;
  }).join('');
}

async function mmSetSoundUrl(name, url){
  const { error } = await supabase.from('mm_sounds').update({ url: url, updated_at: new Date().toISOString() }).eq('name', name);
  if (error) throw error;
  _mmSounds[name] = url || null;
}

async function mmUploadSound(name, file){
  if (!supabase){ mmSoundsStatus('No database connection.'); return; }
  if (!file) return;
  mmSoundsStatus('Uploading “' + name + '”…');
  try {
    const ext = (file.name.split('.').pop() || 'mp3').toLowerCase().replace(/[^a-z0-9]/g, '') || 'mp3';
    const path = name + '-' + Date.now() + '.' + ext;
    const up = await supabase.storage.from(MM_SOUNDS_BUCKET).upload(path, file, { cacheControl: '3600', upsert: false, contentType: file.type || 'audio/mpeg' });
    if (up.error) throw up.error;
    const { data: pub } = supabase.storage.from(MM_SOUNDS_BUCKET).getPublicUrl(path);
    const url = pub && pub.publicUrl;
    if (!url) throw new Error('no public URL');
    await mmSetSoundUrl(name, url);
    mmRenderSounds();
    mmSoundsStatus('Saved “' + name + '”. Reload the game to hear it.');
  } catch (e){ mmSoundsStatus('Upload failed: ' + (e && e.message || e)); console.error('[mm] sound upload', e); }
}

async function mmClearSound(name){
  if (!supabase) return;
  mmSoundsStatus('Clearing “' + name + '”…');
  try { await mmSetSoundUrl(name, null); mmRenderSounds(); mmSoundsStatus('“' + name + '” back to the built-in synth.'); }
  catch (e){ mmSoundsStatus('Clear failed: ' + (e && e.message || e)); }
}

/* ---- MONKEY MOONSHINE synth engine (admin-side twin of the in-game Snd) ----
   Lets the admin preview the built-in procedural synth for each SFX, generate
   fresh randomized variants, and (via renderWav) bake a variant into a WAV
   that gets saved as that sound's custom file. The CURRENT map mirrors the
   game's synth 1:1 so "preview" is faithful; GEN produces tasteful variants. */
const MmSynth = (() => {
  let actx = null;
  function ac(){
    if (!actx){ const AC = window.AudioContext || window.webkitAudioContext; if (!AC) return null; actx = new AC(); }
    return actx;
  }
  function noiseBuf(ctx){
    const b = ctx.createBuffer(1, ctx.sampleRate, ctx.sampleRate); const d = b.getChannelData(0);
    for (let i=0;i<d.length;i++) d[i] = Math.random()*2-1; return b;
  }
  function env(g, st, a, dur, peak){
    g.gain.setValueAtTime(0.0001, st);
    g.gain.linearRampToValueAtTime(peak, st+a);
    g.gain.exponentialRampToValueAtTime(0.0001, st+dur);
  }
  // A scheduler bound to a ctx/dest with a fixed base time, exposing the same
  // beep()/hit() primitives the game uses (times are relative to base).
  function scheduler(ctx, dest, base){
    const nbuf = noiseBuf(ctx);
    function beep(freq, {type='sine',t=0,dur=0.2,peak=0.3,a=0.005,to=null}={}){
      const o=ctx.createOscillator(), g=ctx.createGain(); o.type=type; const st=base+t;
      o.frequency.setValueAtTime(freq, st); if (to) o.frequency.exponentialRampToValueAtTime(Math.max(1,to), st+dur);
      env(g, st, a, dur, peak); o.connect(g); g.connect(dest); o.start(st); o.stop(st+dur+0.06);
    }
    function hit({t=0,dur=0.2,peak=0.3,type='lowpass',freq=800,q=1,to=null}={}){
      const s=ctx.createBufferSource(); s.buffer=nbuf; const f=ctx.createBiquadFilter(); f.type=type; f.frequency.value=freq; f.Q.value=q; const g=ctx.createGain();
      const st=base+t; if (to) f.frequency.exponentialRampToValueAtTime(Math.max(20,to), st+dur);
      env(g, st, 0.004, dur, peak); s.connect(f); f.connect(g); g.connect(dest); s.start(st); s.stop(st+dur+0.06);
    }
    return { beep, hit };
  }
  // Built-in synth, ported 1:1 from games/monkey-moonshine.html.
  const CURRENT = {
    shake:(s)=>{ s.hit({dur:0.5,peak:0.34,type:'highpass',freq:1800,q:0.5}); s.hit({t:0.02,dur:0.42,peak:0.2,type:'bandpass',freq:3200,q:0.8}); s.beep(96,{dur:0.14,peak:0.12,to:58}); },
    rowClunk:(s)=>{ s.beep(150,{dur:0.16,peak:0.32,to:55}); s.hit({dur:0.12,peak:0.4,type:'lowpass',freq:380,q:1}); },
    lineMatch:(s)=>{ [0,4,7,12].forEach((n,i)=> s.beep(523.25*Math.pow(2,n/12),{type:'triangle',t:i*0.05,dur:0.16,peak:0.15})); },
    wildLand:(s)=>{ s.beep(880,{type:'triangle',dur:0.42,peak:0.19}); s.beep(1320,{dur:0.5,t:0.02,peak:0.11}); s.beep(1760,{dur:0.4,t:0.04,peak:0.06}); },
    monkeyWild:(s)=>{ s.beep(380,{type:'sawtooth',dur:0.16,peak:0.15,to:1150}); s.beep(1150,{type:'sawtooth',t:0.15,dur:0.2,peak:0.13,to:520}); s.beep(780,{type:'square',t:0.3,dur:0.12,peak:0.09,to:920}); },
    extraShake:(s)=>{ s.beep(330,{type:'square',dur:0.34,peak:0.12,to:660}); s.beep(660,{t:0.1,dur:0.4,peak:0.12,to:990}); s.beep(990,{type:'triangle',t:0.24,dur:0.3,peak:0.09}); },
    whoosh:(s)=>{ s.hit({dur:0.34,peak:0.3,type:'bandpass',freq:500,q:0.6,to:2600}); s.beep(1500,{t:0.3,dur:0.14,peak:0.13}); },
    coconutRow:(s)=>{ for(let i=0;i<5;i++){ s.beep(210-i*8,{t:i*0.09,dur:0.14,peak:0.3,to:80}); s.hit({t:i*0.09,dur:0.07,peak:0.17,type:'lowpass',freq:700}); } },
    moonshine:(s)=>{ [261.63,329.63,392,523.25].forEach((f,i)=> s.beep(f,{type:'sawtooth',t:i*0.06,dur:1.2,peak:0.1})); s.hit({dur:1.0,peak:0.2,type:'bandpass',freq:300,q:0.4,to:2200}); s.beep(523.25,{type:'triangle',t:0.5,dur:0.9,peak:0.11}); s.beep(784,{type:'triangle',t:0.7,dur:0.7,peak:0.09}); },
    uiClick:(s)=>{ s.beep(1500,{type:'sine',dur:0.035,peak:0.09}); s.beep(840,{type:'triangle',t:0.012,dur:0.05,peak:0.07}); },
    coin:(s)=>{ s.beep(1318.5,{type:'square',dur:0.08,peak:0.11}); s.beep(1975.5,{type:'square',t:0.06,dur:0.17,peak:0.1}); s.beep(2637,{type:'sine',t:0.06,dur:0.14,peak:0.05}); },
  };
  // Approximate tail length per sound, for how long to render offline.
  const DUR = { shake:0.7, rowClunk:0.35, lineMatch:0.55, wildLand:0.65, monkeyWild:0.6, extraShake:0.75, whoosh:0.6, coconutRow:0.75, moonshine:1.8, uiClick:0.2, coin:0.4 };

  // Parametric variant generators. Each picks all random params up-front, then
  // returns a concrete closure, so preview and the later WAV render are identical.
  const R = (a,b)=> a + (b-a)*Math.random();
  const RI = (a,b)=> Math.floor(R(a,b+1));
  const pick = (arr)=> arr[Math.floor(Math.random()*arr.length)];
  const chance = (p)=> Math.random() < p;
  const OSC = ['sine','triangle','square','sawtooth'];
  const NFILT = ['highpass','bandpass','lowpass'];
  // Generators roll structure (layer counts, filter types, sweeps), not just
  // small param jitter, so each New Synth is audibly different.
  const GEN = {
    shake:()=>{
      const layers = RI(1,3), specs = [];
      for (let i=0;i<layers;i++){
        const freq = R(500,5400);
        specs.push({ t:i*R(0,0.05), dur:R(0.18,0.8), peak:R(0.16,0.34),
          type:pick(NFILT), freq, q:R(0.3,5), to: chance(0.55) ? freq*R(0.3,2.8) : null });
      }
      const thump = chance(0.55) ? R(55,150) : null;
      return (s)=>{ specs.forEach(x=> s.hit(x)); if (thump) s.beep(thump,{dur:0.14,peak:0.13,to:thump*0.6}); };
    },
    rowClunk:()=>{ const f=R(75,270), d=R(0.1,0.3), to=f*R(0.2,0.6), type=pick(['sine','triangle','square']), lp=R(200,820), hd=R(0.08,0.22), hp=R(0.26,0.5); return (s)=>{ s.beep(f,{type,dur:d,peak:0.32,to}); s.hit({dur:hd,peak:hp,type:'lowpass',freq:lp,q:R(0.6,2)}); }; },
    lineMatch:()=>{ const root=R(280,780), pats=[[0,4,7,12],[0,3,7,10],[0,5,7,12],[0,4,7,11],[0,2,4,7,11],[0,7,12,16],[0,3,5,7,10]]; let steps=pick(pats).slice(); if (chance(0.4)) steps.reverse(); const type=pick(OSC), sp=R(0.03,0.1), pk=R(0.11,0.2); return (s)=>{ steps.forEach((n,i)=> s.beep(root*Math.pow(2,n/12),{type,t:i*sp,dur:R(0.12,0.22),peak:pk})); }; },
    wildLand:()=>{ const base=R(480,1150), type=pick(['triangle','sine','square']), n=RI(2,4), dur=R(0.3,0.62), spread=R(0.4,0.75); return (s)=>{ for (let i=0;i<n;i++) s.beep(base*(1+i*spread),{type,dur,t:i*R(0.02,0.06),peak:0.2/(i+1)}); }; },
    monkeyWild:()=>{ const a=R(240,540), b=R(780,1500), c=R(560,980), o=pick(['sawtooth','square','triangle']); return (s)=>{ s.beep(a,{type:o,dur:R(0.14,0.22),peak:0.15,to:b}); s.beep(b,{type:o,t:0.15,dur:R(0.16,0.26),peak:0.13,to:a*R(1.1,1.7)}); s.beep(c,{type:'square',t:0.3,dur:0.12,peak:0.09,to:c*R(0.8,1.4)}); }; },
    extraShake:()=>{ const a=R(200,440), r=R(1.35,2.2), type=pick(['square','triangle','sawtooth']); return (s)=>{ s.beep(a,{type,dur:0.34,peak:0.12,to:a*r}); s.beep(a*r,{t:0.1,dur:0.4,peak:0.12,to:a*r*r}); s.beep(a*r*r,{type:'triangle',t:0.24,dur:0.3,peak:0.09}); }; },
    whoosh:()=>{ const f=R(280,780), to=R(1300,3600), q=R(0.3,1.4), dur=R(0.24,0.58), type=pick(['bandpass','highpass']); const tip=chance(0.6)?R(1100,2100):null; return (s)=>{ s.hit({dur,peak:0.3,type,freq:f,q,to}); if (tip) s.beep(tip,{t:dur*0.85,dur:0.14,peak:0.13}); }; },
    coconutRow:()=>{ const start=R(150,285), stepDn=R(4,16), n=RI(4,6), sp=R(0.06,0.13), lp=R(480,880); return (s)=>{ for (let i=0;i<n;i++){ s.beep(Math.max(50,start-i*stepDn),{t:i*sp,dur:0.14,peak:0.3,to:70}); s.hit({t:i*sp,dur:0.07,peak:0.17,type:'lowpass',freq:lp}); } }; },
    moonshine:()=>{ const root=R(196,330), chord=pick([[0,4,7,12],[0,3,7,10],[0,5,9,12],[0,4,7,11]]), type=pick(['sawtooth','square','triangle']); return (s)=>{ chord.forEach((n,i)=> s.beep(root*Math.pow(2,n/12),{type,t:i*R(0.04,0.09),dur:R(1.0,1.4),peak:0.1})); s.hit({dur:1.0,peak:0.2,type:'bandpass',freq:R(230,390),q:0.4,to:2200}); s.beep(root*2,{type:'triangle',t:0.5,dur:0.9,peak:0.11}); if (chance(0.7)) s.beep(root*3,{type:'triangle',t:0.7,dur:0.7,peak:0.09}); }; },
    uiClick:()=>{ const hi=R(1000,2300), lo=R(480,1150), type=pick(['sine','triangle','square']); return (s)=>{ s.beep(hi,{type:'sine',dur:R(0.025,0.05),peak:0.09}); s.beep(lo,{type,t:0.012,dur:R(0.04,0.07),peak:0.07}); }; },
    coin:()=>{ const a=R(1000,1600), r=R(1.3,1.7), type=pick(['square','triangle']); return (s)=>{ s.beep(a,{type,dur:0.08,peak:0.11}); s.beep(a*r,{type,t:0.06,dur:0.17,peak:0.1}); s.beep(a*r*r,{type:'sine',t:0.06,dur:0.14,peak:0.05}); }; },
  };

  // Turn a free-text prompt into tone modifiers. Keyword-driven (no audio model):
  // words nudge pitch / length / loudness / brightness / oscillator shape.
  function parsePrompt(prompt){
    const s = (prompt || '').toLowerCase();
    if (!s.trim()) return null;
    const has = (...w)=> w.some(x => s.includes(x));
    let pitch = 1, dur = 1, peak = 1, bright = 1, q = 1, osc = null;
    // pitch
    if (has('high','bright','sharp','treble','squeak','tiny','chirp','shrill','whistle','ping')) pitch *= 1.5;
    if (has('low','deep','bass','sub','rumble','heavy','fat','boom','thud','dark','earthy')) pitch *= 0.6;
    // length
    if (has('long','sustain','drawn','stretch','slow','drone','epic','big','wind','breeze','swell','wash','ambient','flow')) dur *= 1.85;
    if (has('short','quick','snappy','tight','punchy','stab','blip','tick','clip','pop','click','pluck')) dur *= 0.55;
    // loudness
    if (has('loud','strong','bold','aggressive','intense','powerful','slam')) peak *= 1.4;
    if (has('soft','gentle','quiet','subtle','faint','delicate','light','calm','whisper')) peak *= 0.6;
    // brightness (filter / partial frequency)
    if (has('bright','crisp','metallic','glass','glassy','shiny','sparkle','shimmer','clang','tinny','sizzle','ice')) bright *= 1.9;
    if (has('muffled','warm','dark','dull','round','underwater','mellow','wooden','muddy','soft')) bright *= 0.5;
    // resonance / texture: tonal-whistly vs broadband-airy (matters most for noise SFX)
    if (has('tonal','resonant','whistle','ring','ringing','sing','vocal','laser','beam','pure','pitched')) q *= 3;
    if (has('airy','air','hiss','breath','wind','breeze','noisy','rush','static','white','broad','leaves','rustle','wash')) q *= 0.4;
    // oscillator flavor (tonal parts)
    if (has('retro','8-bit','8bit','chiptune','chip','arcade','game','nes','pixel','videogame')) osc = 'square';
    else if (has('buzzy','gritty','harsh','saw','rough','dirty','growl','grind','buzz')) osc = 'sawtooth';
    else if (has('pure','clean','sine','pad','smooth','flute')) osc = 'sine';
    else if (has('woody','hollow','triangle','mellow','warm','soft')) osc = 'triangle';
    pitch  = Math.max(0.35, Math.min(2.6, pitch));
    dur    = Math.max(0.4,  Math.min(2.5, dur));
    peak   = Math.max(0.4,  Math.min(1.8, peak));
    bright = Math.max(0.4,  Math.min(2.4, bright));
    q      = Math.max(0.2,  Math.min(6,   q));
    return { pitch, dur, peak, bright, q, osc };
  }
  // Wrap a scheduler so every beep/hit is scaled by the prompt modifiers.
  function applyMods(sch, m){
    if (!m) return sch;
    return {
      beep(freq, opts = {}){
        sch.beep(freq * m.pitch, {
          ...opts,
          type: m.osc || opts.type,
          dur: (opts.dur == null ? 0.2 : opts.dur) * m.dur,
          peak: Math.min(0.5, (opts.peak == null ? 0.3 : opts.peak) * m.peak),
          to: opts.to != null ? opts.to * m.pitch : null,
        });
      },
      hit(opts = {}){
        sch.hit({
          ...opts,
          dur: (opts.dur == null ? 0.2 : opts.dur) * m.dur,
          peak: Math.min(0.6, (opts.peak == null ? 0.3 : opts.peak) * m.peak),
          freq: (opts.freq == null ? 800 : opts.freq) * m.bright,
          q: (opts.q == null ? 1 : opts.q) * (m.q || 1),
          to: opts.to != null ? opts.to * m.bright : null,
        });
      },
    };
  }

  function playFn(fn, mods){
    const ctx = ac(); if (!ctx || !fn) return; if (ctx.state === 'suspended') ctx.resume();
    const g = ctx.createGain(); g.gain.value = 0.9; g.connect(ctx.destination);
    const s = applyMods(scheduler(ctx, g, ctx.currentTime + 0.03), mods);
    try { fn(s); } catch(e){ console.error('[mm] synth play', e); }
  }
  async function renderWav(fn, seconds, mods){
    const OAC = window.OfflineAudioContext || window.webkitOfflineAudioContext; if (!OAC || !fn) return null;
    const sr = 44100, len = Math.ceil(sr * (seconds || 1.5));
    const oac = new OAC(1, len, sr);
    const g = oac.createGain(); g.gain.value = 0.9; g.connect(oac.destination);
    const s = applyMods(scheduler(oac, g, 0), mods);
    try { fn(s); } catch(e){ console.error('[mm] synth render', e); }
    const buf = await oac.startRendering();
    return audioBufferToWavBlob(buf);
  }
  function audioBufferToWavBlob(buf){
    const sr = buf.sampleRate, n = buf.length, data = buf.getChannelData(0);
    const ab = new ArrayBuffer(44 + n*2); const view = new DataView(ab); let p = 0;
    const ws = (str)=>{ for (let i=0;i<str.length;i++) view.setUint8(p++, str.charCodeAt(i)); };
    const w32 = (v)=>{ view.setUint32(p, v, true); p += 4; };
    const w16 = (v)=>{ view.setUint16(p, v, true); p += 2; };
    ws('RIFF'); w32(36 + n*2); ws('WAVE'); ws('fmt '); w32(16); w16(1); w16(1); w32(sr); w32(sr*2); w16(2); w16(16); ws('data'); w32(n*2);
    for (let i=0;i<n;i++){ const v = Math.max(-1, Math.min(1, data[i])); view.setInt16(p, v < 0 ? v*0x8000 : v*0x7FFF, true); p += 2; }
    return new Blob([ab], { type: 'audio/wav' });
  }
  return {
    hasSynth: (name)=> !!CURRENT[name],
    previewSynth: (name)=> playFn(CURRENT[name], null),
    // Generate a variant biased by an optional text prompt; plays it and
    // returns { fn, mods } so the exact same sound can be re-rendered on Save.
    generate: (name, prompt)=>{ const mk = GEN[name]; if (!mk) return null; const fn = mk(); const mods = parsePrompt(prompt); playFn(fn, mods); return { fn, mods }; },
    playVariant: (variant)=>{ if (variant) playFn(variant.fn, variant.mods); },
    renderWav,
    durOf: (name)=> DUR[name] || 1,
  };
})();

const _mmGenerated = {};   // name -> last generated variant closure (pending save)

let _mmPreviewAudio = null;
function mmPreviewSound(name){
  if (_mmGenerated[name]){ MmSynth.playVariant(_mmGenerated[name]); return; }  // audition the pending roll
  const url = _mmSounds && _mmSounds[name];
  if (url){
    try { if (_mmPreviewAudio) _mmPreviewAudio.pause(); _mmPreviewAudio = new Audio(url); _mmPreviewAudio.play().catch(() => {}); } catch (e){}
    return;
  }
  MmSynth.previewSynth(name);   // no custom file → play the built-in synth
}

function mmGenerateSynth(name){
  const row = document.querySelector('.admin-mm-snd-row[data-name="' + name + '"]');
  const promptEl = row && row.querySelector('[data-role="prompt"]');
  const prompt = promptEl ? promptEl.value : '';
  const variant = MmSynth.generate(name, prompt);   // generates a fresh variant and plays it
  if (!variant){ mmSoundsStatus('“' + name + '” has no procedural synth to vary.'); return; }
  _mmGenerated[name] = variant;
  const saveBtn = row && row.querySelector('[data-act="save"]');
  if (saveBtn) saveBtn.disabled = false;
  mmSoundsStatus(prompt.trim()
    ? 'New “' + name + '” synth from “' + prompt.trim() + '” — Preview again, roll another, or Save to use it.'
    : 'New “' + name + '” synth generated — Preview again, roll another, or Save to use it in the game.');
}

async function mmSaveGeneratedSynth(name){
  const variant = _mmGenerated[name];
  if (!variant){ mmSoundsStatus('Generate a synth for “' + name + '” first.'); return; }
  mmSoundsStatus('Rendering “' + name + '” synth to a file…');
  try {
    const secs = MmSynth.durOf(name) * ((variant.mods && variant.mods.dur) || 1) + 0.3;
    const blob = await MmSynth.renderWav(variant.fn, secs, variant.mods);
    if (!blob) throw new Error('render unsupported in this browser');
    delete _mmGenerated[name];
    await mmUploadSound(name, new File([blob], name + '-synth.wav', { type: 'audio/wav' }));
  } catch (e){
    _mmGenerated[name] = variant;   // keep the variant so they can retry
    mmSoundsStatus('Save failed: ' + (e && e.message || e));
    console.error('[mm] save synth', e);
  }
}

// delegated handlers (the list element is static in index.html)
(function mmWireSoundHandlers(){
  const list = document.getElementById('admin-mm-snd-list');
  if (!list) return;
  list.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-act]'); const row = e.target.closest('.admin-mm-snd-row');
    if (!btn || !row) return;
    const name = row.dataset.name;
    const act = btn.dataset.act;
    if (act === 'preview') mmPreviewSound(name);
    else if (act === 'synth') MmSynth.previewSynth(name);
    else if (act === 'generate') mmGenerateSynth(name);
    else if (act === 'save') void mmSaveGeneratedSynth(name);
    else if (act === 'clear') mmClearSound(name);
  });
  list.addEventListener('change', (e) => {
    const inp = e.target.closest('input[data-act="upload"]'); const row = e.target.closest('.admin-mm-snd-row');
    if (!inp || !row) return;
    if (inp.files && inp.files[0]) mmOpenTrimTool(row.dataset.name, inp.files[0]);   // decode → trim → save
    inp.value = '';
  });
})();

/* ══════ MONKEY MOONSHINE upload clip/trim tool ══════
   Decodes the chosen file, shows a waveform with draggable start/end handles,
   previews just the selection, and saves the trimmed region as a WAV (or
   uploads the whole file untouched). Fully client-side (Web Audio). */
let _mmTrimCtx = null;
function mmTrimAudioCtx(){ if (!_mmTrimCtx){ const AC = window.AudioContext || window.webkitAudioContext; _mmTrimCtx = AC ? new AC() : null; } return _mmTrimCtx; }
let _mmTrim = null;     // active session { name, file, buf, startFrac, endFrac, src, raf, els }
let _mmTrimUI = null;   // cached overlay DOM + element refs

function mmFmtTime(sec){ sec = Math.max(0, sec || 0); const m = Math.floor(sec/60); const s = sec - m*60; return m + ':' + (s < 10 ? '0' : '') + s.toFixed(2); }

function mmBufferToWavBlob(buf){
  const numCh = Math.min(2, buf.numberOfChannels), sr = buf.sampleRate, n = buf.length;
  const chans = []; for (let c=0;c<numCh;c++) chans.push(buf.getChannelData(c));
  const blockAlign = numCh * 2, dataLen = n * blockAlign;
  const ab = new ArrayBuffer(44 + dataLen); const view = new DataView(ab); let p = 0;
  const ws = (str)=>{ for (let i=0;i<str.length;i++) view.setUint8(p++, str.charCodeAt(i)); };
  const w32 = (v)=>{ view.setUint32(p, v, true); p += 4; };
  const w16 = (v)=>{ view.setUint16(p, v, true); p += 2; };
  ws('RIFF'); w32(36 + dataLen); ws('WAVE'); ws('fmt '); w32(16); w16(1); w16(numCh); w32(sr); w32(sr*blockAlign); w16(blockAlign); w16(16); ws('data'); w32(dataLen);
  for (let i=0;i<n;i++){ for (let c=0;c<numCh;c++){ const v = Math.max(-1, Math.min(1, chans[c][i])); view.setInt16(p, v < 0 ? v*0x8000 : v*0x7FFF, true); p += 2; } }
  return new Blob([ab], { type: 'audio/wav' });
}
function mmSliceBuffer(ctx, buf, startSec, endSec){
  const sr = buf.sampleRate;
  const s = Math.max(0, Math.floor(startSec*sr));
  const e = Math.min(buf.length, Math.floor(endSec*sr));
  const len = Math.max(1, e - s);
  const out = ctx.createBuffer(buf.numberOfChannels, len, sr);
  for (let c=0;c<buf.numberOfChannels;c++) out.getChannelData(c).set(buf.getChannelData(c).subarray(s, e));
  return out;
}

function mmTrimDrawWave(){
  const t = _mmTrim; if (!t || !t.buf) return;
  const canvas = t.els.canvas, wrap = t.els.wave;
  const dpr = Math.max(1, window.devicePixelRatio || 1);
  const w = wrap.clientWidth || 600, h = wrap.clientHeight || 130;
  canvas.width = Math.round(w*dpr); canvas.height = Math.round(h*dpr);
  const ctx = canvas.getContext('2d'); ctx.setTransform(dpr,0,0,dpr,0,0); ctx.clearRect(0,0,w,h);
  const data = t.buf.getChannelData(0), n = data.length, mid = h/2;
  ctx.strokeStyle = 'rgba(255,255,255,.08)'; ctx.beginPath(); ctx.moveTo(0, mid); ctx.lineTo(w, mid); ctx.stroke();
  ctx.strokeStyle = 'rgba(47,208,110,.6)'; ctx.lineWidth = 1; ctx.beginPath();
  for (let x=0;x<w;x++){
    const from = Math.floor(x/w*n), to = Math.floor((x+1)/w*n);
    let mn = 1, mx = -1;
    for (let i=from;i<to;i++){ const v = data[i]; if (v<mn) mn = v; if (v>mx) mx = v; }
    if (mn > mx){ mn = 0; mx = 0; }
    ctx.moveTo(x+0.5, mid - mx*mid*0.92); ctx.lineTo(x+0.5, mid - mn*mid*0.92);
  }
  ctx.stroke();
}
function mmTrimSync(){
  const t = _mmTrim; if (!t || !t.buf) return; const dur = t.buf.duration, el = t.els;
  el.shadeL.style.width = (t.startFrac*100) + '%';
  el.shadeR.style.width = ((1 - t.endFrac)*100) + '%';
  el.hStart.style.left = (t.startFrac*100) + '%';
  el.hEnd.style.left = (t.endFrac*100) + '%';
  el.tStart.textContent = mmFmtTime(t.startFrac*dur);
  el.tEnd.textContent = mmFmtTime(t.endFrac*dur);
  el.tLen.textContent = mmFmtTime((t.endFrac - t.startFrac)*dur);
}
function mmTrimStop(){
  const t = _mmTrim; if (!t) return;
  if (t.src){ try { t.src.stop(); } catch(e){} t.src = null; }
  if (t.raf){ cancelAnimationFrame(t.raf); t.raf = null; }
  if (t.els && t.els.playhead) t.els.playhead.style.display = 'none';
}
function mmTrimPlay(){
  const t = _mmTrim, ctx = mmTrimAudioCtx(); if (!t || !t.buf || !ctx) return;
  mmTrimStop(); if (ctx.state === 'suspended') ctx.resume();
  const dur = t.buf.duration, s = t.startFrac*dur, e = t.endFrac*dur, len = Math.max(0.02, e - s);
  const src = ctx.createBufferSource(); src.buffer = t.buf; src.connect(ctx.destination);
  src.start(0, s, len); t.src = src;
  const startedAt = ctx.currentTime, ph = t.els.playhead; ph.style.display = 'block';
  const tick = ()=>{
    if (!_mmTrim || _mmTrim.src !== src){ return; }
    const elapsed = ctx.currentTime - startedAt;
    if (elapsed >= len){ mmTrimStop(); return; }
    ph.style.left = ((t.startFrac + elapsed/dur)*100) + '%';
    t.raf = requestAnimationFrame(tick);
  };
  t.raf = requestAnimationFrame(tick);
}
async function mmTrimSave(){
  const t = _mmTrim, ctx = mmTrimAudioCtx(); if (!t || !t.buf || !ctx) return;
  mmTrimStop();
  const dur = t.buf.duration, name = t.name;
  t.els.status.textContent = 'Encoding clip…';
  try {
    const clip = mmSliceBuffer(ctx, t.buf, t.startFrac*dur, t.endFrac*dur);
    const file = new File([mmBufferToWavBlob(clip)], name + '-clip.wav', { type: 'audio/wav' });
    mmTrimClose();
    await mmUploadSound(name, file);
  } catch (err){ t.els.status.textContent = 'Clip failed: ' + (err && err.message || err); console.error('[mm] trim save', err); }
}
async function mmTrimUseFull(){
  const t = _mmTrim; if (!t) return; mmTrimStop();
  const name = t.name, file = t.file; mmTrimClose();
  await mmUploadSound(name, file);
}
function mmTrimClose(){ mmTrimStop(); if (_mmTrimUI) _mmTrimUI.ov.classList.remove('is-open'); _mmTrim = null; }

function mmTrimUI(){
  if (_mmTrimUI) return _mmTrimUI;
  const ov = document.createElement('div'); ov.className = 'mm-trim-overlay';
  ov.innerHTML =
    '<div class="mm-trim-panel" role="dialog" aria-modal="true">' +
      '<p class="mm-trim-title" id="mm-trim-title">Trim clip</p>' +
      '<p class="mm-trim-sub" id="mm-trim-sub"></p>' +
      '<div class="mm-trim-wave-wrap" id="mm-trim-wave">' +
        '<canvas class="mm-trim-canvas" id="mm-trim-canvas"></canvas>' +
        '<div class="mm-trim-shade left" id="mm-trim-shade-l"></div>' +
        '<div class="mm-trim-shade right" id="mm-trim-shade-r"></div>' +
        '<div class="mm-trim-handle" id="mm-trim-h-start"></div>' +
        '<div class="mm-trim-handle" id="mm-trim-h-end"></div>' +
        '<div class="mm-trim-playhead" id="mm-trim-playhead"></div>' +
      '</div>' +
      '<div class="mm-trim-times"><span>Start <b id="mm-trim-t-start">0:00.00</b></span>' +
        '<span>Length <b id="mm-trim-t-len">0:00.00</b></span>' +
        '<span>End <b id="mm-trim-t-end">0:00.00</b></span></div>' +
      '<div class="mm-trim-actions"><span class="mm-trim-status" id="mm-trim-status"></span>' +
        '<button type="button" class="admin-mm-snd-btn" data-trim="play">▶ Play selection</button>' +
        '<button type="button" class="admin-mm-snd-btn" data-trim="full">Use full file</button>' +
        '<button type="button" class="admin-mm-snd-btn admin-mm-snd-save" data-trim="save">✓ Save clip</button>' +
        '<button type="button" class="admin-mm-snd-btn admin-mm-snd-clear" data-trim="cancel">Cancel</button></div>' +
    '</div>';
  document.body.appendChild(ov);
  const q = (s)=> ov.querySelector(s);
  const els = { wave:q('#mm-trim-wave'), canvas:q('#mm-trim-canvas'), shadeL:q('#mm-trim-shade-l'), shadeR:q('#mm-trim-shade-r'),
    hStart:q('#mm-trim-h-start'), hEnd:q('#mm-trim-h-end'), playhead:q('#mm-trim-playhead'),
    title:q('#mm-trim-title'), sub:q('#mm-trim-sub'), tStart:q('#mm-trim-t-start'), tEnd:q('#mm-trim-t-end'), tLen:q('#mm-trim-t-len'), status:q('#mm-trim-status') };
  _mmTrimUI = { ov, els };
  ov.addEventListener('click', (e)=>{
    if (e.target === ov){ mmTrimClose(); return; }
    const b = e.target.closest('[data-trim]'); if (!b) return;
    const a = b.dataset.trim;
    if (a === 'play') mmTrimPlay();
    else if (a === 'save') void mmTrimSave();
    else if (a === 'full') void mmTrimUseFull();
    else if (a === 'cancel') mmTrimClose();
  });
  // Drag the nearest handle (works for both handles + clicking anywhere on the wave)
  const wrap = els.wave; let active = null;
  const fracAt = (e)=>{ const r = wrap.getBoundingClientRect(); return Math.max(0, Math.min(1, (e.clientX - r.left)/r.width)); };
  const setFrac = (which, f)=>{
    const t = _mmTrim; if (!t) return; const gap = 0.004;
    if (which === 'start') t.startFrac = Math.max(0, Math.min(f, t.endFrac - gap));
    else t.endFrac = Math.min(1, Math.max(f, t.startFrac + gap));
    mmTrimSync();
  };
  wrap.addEventListener('pointerdown', (e)=>{
    const t = _mmTrim; if (!t || !t.buf) return;
    const f = fracAt(e);
    active = Math.abs(f - t.startFrac) <= Math.abs(f - t.endFrac) ? 'start' : 'end';
    setFrac(active, f); try { wrap.setPointerCapture(e.pointerId); } catch(_){}
  });
  wrap.addEventListener('pointermove', (e)=>{ if (active) setFrac(active, fracAt(e)); });
  const endDrag = ()=>{ active = null; };
  wrap.addEventListener('pointerup', endDrag); wrap.addEventListener('pointercancel', endDrag);
  return _mmTrimUI;
}

async function mmOpenTrimTool(name, file){
  const ctx = mmTrimAudioCtx();
  if (!ctx){ await mmUploadSound(name, file); return; }   // no Web Audio → plain upload
  const ui = mmTrimUI();
  ui.els.title.textContent = 'Trim “' + (MM_SOUND_LABELS[name] || name) + '”';
  ui.els.sub.textContent = file.name + ' — decoding…';
  ui.els.status.textContent = '';
  ui.ov.classList.add('is-open');
  _mmTrim = { name, file, buf:null, startFrac:0, endFrac:1, src:null, raf:null, els:ui.els };
  try {
    const ab = await file.arrayBuffer();
    const buf = await ctx.decodeAudioData(ab.slice(0));
    if (!_mmTrim) return;   // cancelled while decoding
    _mmTrim.buf = buf;
    ui.els.sub.textContent = file.name + ' — ' + mmFmtTime(buf.duration) + ' · ' + buf.numberOfChannels + 'ch · ' + Math.round(buf.sampleRate/1000) + 'kHz · drag the green handles, preview, then Save clip';
    mmTrimDrawWave(); mmTrimSync();
  } catch (err){
    if (_mmTrim) ui.els.sub.textContent = 'Could not decode this file — use “Use full file” to upload it as-is.';
    console.error('[mm] trim decode', err);
  }
}

function mmPct(v, total){ return total > 0 ? (v / total * 100).toFixed(1) + '%' : '0.0%'; }

function mmRenderEditor(){
  const body = document.getElementById('admin-mm-editor-body');
  const sel = document.getElementById('admin-mm-wild');
  const multInput = document.getElementById('admin-mm-mult');
  if (!body || !_mmDecks) return;
  const wild = sel ? sel.value : _mmEditWild;
  _mmEditWild = wild;
  const d = _mmDecks[wild];
  if (!d){ body.innerHTML = ''; return; }
  if (multInput) multInput.value = d.mult;
  const regTotal = MM_SYMBOLS.reduce((s, x) => s + (d.deck[x] || 0), 0);
  const repTotal = MM_SYMBOLS.reduce((s, x) => s + (d.replace_deck[x] || 0), 0);
  body.innerHTML = MM_EDITOR_ORDER.map(sym => `
    <tr>
      <td class="mm-sym">${sym}${sym === 'coconut' ? ' <span class="mm-note">(monkey in repl.)</span>' : ''}</td>
      <td><input type="number" min="0" step="1" class="mm-wt" data-kind="deck" data-sym="${sym}" value="${d.deck[sym] || 0}"></td>
      <td class="mm-pct" data-pct="deck-${sym}">${mmPct(d.deck[sym] || 0, regTotal)}</td>
      <td><input type="number" min="0" step="1" class="mm-wt" data-kind="replace_deck" data-sym="${sym}" value="${d.replace_deck[sym] || 0}"></td>
      <td class="mm-pct" data-pct="replace_deck-${sym}">${mmPct(d.replace_deck[sym] || 0, repTotal)}</td>
    </tr>`).join('');
}

function mmUpdatePcts(){
  const d = _mmDecks && _mmDecks[_mmEditWild]; if (!d) return;
  const regTotal = MM_SYMBOLS.reduce((s, x) => s + (d.deck[x] || 0), 0);
  const repTotal = MM_SYMBOLS.reduce((s, x) => s + (d.replace_deck[x] || 0), 0);
  MM_SYMBOLS.forEach(sym => {
    const r = document.querySelector(`[data-pct="deck-${sym}"]`); if (r) r.textContent = mmPct(d.deck[sym] || 0, regTotal);
    const p = document.querySelector(`[data-pct="replace_deck-${sym}"]`); if (p) p.textContent = mmPct(d.replace_deck[sym] || 0, repTotal);
  });
}

document.getElementById('admin-mm-editor-body')?.addEventListener('input', e => {
  const t = e.target;
  if (!(t instanceof HTMLInputElement) || !t.classList.contains('mm-wt')) return;
  const d = _mmDecks && _mmDecks[_mmEditWild]; if (!d) return;
  d[t.dataset.kind][t.dataset.sym] = Math.max(0, Math.round(parseFloat(t.value) || 0));
  mmUpdatePcts();
});
document.getElementById('admin-mm-mult')?.addEventListener('input', e => {
  const d = _mmDecks && _mmDecks[_mmEditWild]; if (!d) return;
  d.mult = Math.max(1, Math.round(parseFloat(e.target.value) || 1));
});
document.getElementById('admin-mm-wild')?.addEventListener('change', () => mmRenderEditor());
document.getElementById('admin-mm-reset-rep')?.addEventListener('click', () => {
  const d = _mmDecks && _mmDecks[_mmEditWild]; if (!d) return;
  const C = d.deck.coconut || 0;
  const F = MM_FRUIT_NAMES.reduce((s, f) => s + (d.deck[f] || 0), 0);
  const M = (3 * C + 4 * F) > 0 ? Math.round(C * F / (3 * C + 4 * F)) : 0;
  MM_FRUIT_NAMES.forEach(f => d.replace_deck[f] = d.deck[f] || 0);
  d.replace_deck.coconut = M;
  mmRenderEditor();
  mmStatus(`Replacement deck reset to ¼-odds (monkey wt ${M}).`);
});
document.getElementById('admin-mm-save')?.addEventListener('click', async () => {
  const wild = _mmEditWild;
  const d = _mmDecks && _mmDecks[wild];
  if (!d || !supabase) return;
  const btn = document.getElementById('admin-mm-save'); if (btn) btn.disabled = true;
  mmStatus(`Saving ${wild}…`);
  const { error } = await supabase.from('mm_decks')
    .update({ deck: d.deck, replace_deck: d.replace_deck, mult: d.mult, updated_at: new Date().toISOString() })
    .eq('wild', wild);
  if (btn) btn.disabled = false;
  if (error){ mmStatus('Save error: ' + error.message); console.error('[mm] save', error); return; }
  mmStatus(`Saved ${wild} to mm_decks — the game will use it on next load.`);
});

// ---- sim engine (mirrors the live game) ----
function mmBuildTable(deck){ const names = [], cum = []; let total = 0; for (const s of MM_SYMBOLS){ const c = deck[s] || 0; if (c <= 0) continue; total += c; names.push(s); cum.push(total); } return { names, cum, total }; }
function mmDraw(t){ const r = Math.random() * t.total; for (let i = 0; i < t.cum.length; i++){ if (r < t.cum[i]) return t.names[i]; } return t.names[t.names.length - 1]; }
function mmShakes(m){ if (m >= 6) return 3; if (m >= 3) return 2; if (m >= 1) return 1; return 0; }
function mmScore(grid, rows, wild, mult){
  const seqs = [];
  for (let r = 0; r < rows; r++){ const s = []; for (let c = 0; c < MM_COLS; c++) s.push([r, c]); seqs.push(s); }
  for (let c = 0; c < MM_COLS; c++){ const s = []; for (let r = 0; r < rows; r++) s.push([r, c]); seqs.push(s); }
  for (let k = -(rows - 1); k <= MM_COLS - 1; k++){ const s = []; for (let r = 0; r < rows; r++){ const c = r + k; if (c >= 0 && c < MM_COLS) s.push([r, c]); } if (s.length >= 3) seqs.push(s); }
  for (let k = 0; k <= (rows - 1) + (MM_COLS - 1); k++){ const s = []; for (let r = 0; r < rows; r++){ const c = k - r; if (c >= 0 && c < MM_COLS) s.push([r, c]); } if (s.length >= 3) seqs.push(s); }
  let win = 0;
  for (const cells of seqs){
    const vals = cells.map(([r, c]) => grid[r][c]); const cand = [];
    for (const F of MM_FRUIT_NAMES){ const isM = v => v != null && v !== 'coconut' && (v === F || v === wild || v === 'monkey'); let i = 0;
      while (i < vals.length){ if (isM(vals[i])){ let j = i; while (j < vals.length && isM(vals[j])) j++; const len = j - i;
        if (len >= 3){ let rF = false, hW = false; for (let k = i; k < j; k++){ if (vals[k] === F) rF = true; if (F === wild && vals[k] === 'monkey') rF = true; if (vals[k] === wild) hW = true; } if (rF) cand.push({ len, mult: hW ? mult : 1, i, j }); } i = j; } else i++; } }
    cand.sort((a, b) => (b.len - a.len) || (b.mult - a.mult)); const used = new Set();
    for (const c of cand){ let ov = false; for (let k = c.i; k < c.j; k++){ if (used.has(k)){ ov = true; break; } } if (ov) continue; for (let k = c.i; k < c.j; k++) used.add(k); win += mmBasePay(c.len) * c.mult; }
  }
  return win;
}
function mmPlayRound(dT, rT, wild, mult){
  let rows = 3; const grid = []; for (let r = 0; r < 3; r++){ const row = []; for (let c = 0; c < MM_COLS; c++) row.push(mmDraw(dT)); grid.push(row); }
  const raid = []; for (let r = 0; r < 3; r++){ let a = true; for (let c = 0; c < MM_COLS; c++){ if (grid[r][c] !== 'coconut'){ a = false; break; } } if (a) raid.push(r); }
  const moon = raid.length > 0;
  if (moon){ let mk = 0, ex = 0, gr = 0; for (const r of raid) for (let c = 0; c < MM_COLS; c++){ let dd = mmDraw(rT); if (dd === 'coconut') dd = 'monkey'; if (dd === 'monkey') mk++; grid[r][c] = dd; }
    let nt = mmShakes(mk); if (nt > gr){ ex += nt - gr; gr = nt; } let mt = mk;
    while (ex > 0){ ex--; const row = []; for (let c = 0; c < MM_COLS; c++){ let dd = mmDraw(rT); if (dd === 'coconut') dd = 'monkey'; row.push(dd); } grid.push(row); rows = grid.length; let bm = 0; for (const v of row) if (v === 'monkey') bm++; mt += bm; nt = mmShakes(mt); if (nt > gr){ ex += nt - gr; gr = nt; } } }
  return { win: mmScore(grid, rows, wild, mult), moon };
}
function mmRunSim(){
  if (_mmSimRunning || !_mmDecks) return;
  const roundsInput = document.getElementById('admin-mm-rounds');
  const N = Math.max(1000, Math.min(2000000, parseInt(roundsInput.value) || 100000));
  roundsInput.value = N;
  const wilds = Object.keys(_mmDecks);
  const acc = {}; wilds.forEach(w => acc[w] = { pay: 0, hits: 0, moon: 0, moonPay: 0, done: 0, dT: mmBuildTable(_mmDecks[w].deck), rT: mmBuildTable(_mmDecks[w].replace_deck) });
  _mmSimRunning = true;
  const runBtn = document.getElementById('admin-mm-run'); if (runBtn) runBtn.disabled = true;
  const results = document.getElementById('admin-mm-sim-results');
  results.innerHTML = `<div class="admin-mm-simmsg">Simulating ${N.toLocaleString()} rounds × ${wilds.length} decks…</div>`;
  const CHUNK = 5000; let wi = 0;
  const step = () => {
    const w = wilds[wi]; const a = acc[w]; const mult = _mmDecks[w].mult;
    const end = Math.min(N, a.done + CHUNK);
    for (; a.done < end; a.done++){ const r = mmPlayRound(a.dT, a.rT, w, mult); a.pay += r.win; if (r.win > 0) a.hits++; if (r.moon){ a.moon++; a.moonPay += r.win; } }
    if (a.done >= N) wi++;
    if (wi < wilds.length) setTimeout(step, 0);
    else mmRenderSim(acc, N);
  };
  setTimeout(step, 20);
}
function mmRenderSim(acc, N){
  const results = document.getElementById('admin-mm-sim-results');
  const p = x => (x * 100).toFixed(2) + '%';
  const rows = Object.keys(_mmDecks).map(w => {
    const a = acc[w]; const d = _mmDecks[w];
    const coco = (d.deck.coconut || 0) / MM_SYMBOLS.reduce((s, x) => s + (d.deck[x] || 0), 0);
    const rtp = a.pay / N;
    return { w, mult: d.mult, coco, rtp, moon: a.moon / N, ret: a.moon ? a.moonPay / a.moon : 0, hit: a.hits / N, ok: rtp >= 0.93 && rtp <= 0.96 };
  });
  results.innerHTML = `<table class="admin-mm-tbl admin-mm-sim-tbl"><thead><tr>
    <th>deck</th><th>coco%</th><th>RTP</th><th>HE</th><th>moon%</th><th>ret/moon</th><th>hit%</th></tr></thead><tbody>` +
    rows.map(r => `<tr>
      <td class="mm-sym">${r.w} <span class="mm-note">×${r.mult}</span></td>
      <td>${(r.coco * 100).toFixed(1)}%</td>
      <td class="${r.ok ? 'mm-ok' : 'mm-bad'}">${p(r.rtp)}</td>
      <td>${p(1 - r.rtp)}</td>
      <td>${(r.moon * 100).toFixed(1)}%</td>
      <td>${r.ret.toFixed(2)}×</td>
      <td>${(r.hit * 100).toFixed(1)}%</td>
    </tr>`).join('') + `</tbody></table>`;
  _mmSimRunning = false;
  const runBtn = document.getElementById('admin-mm-run'); if (runBtn) runBtn.disabled = false;
}
document.getElementById('admin-mm-run')?.addEventListener('click', mmRunSim);

