let activePlayerBankrollUserId = null;
let activePlayerBankrollName = "";
let activePlayerBankrollSeriesMode = "pnl";
let playerHandsChartInstance = null;
let playerHandsPeriod = "year";
let activePlayerHandsUserId = null;
let activePlayerHandsName = "";
let pnlRankLeaderboardPeriod = "week";
const ANALYTICS_TIME_ZONE = "America/Denver";

function formatAnalyticsDate(dateInput, options = {}) {
  const date = dateInput instanceof Date ? dateInput : new Date(dateInput);
  if (Number.isNaN(date.getTime())) return "";
  return date.toLocaleString("en-US", {
    timeZone: ANALYTICS_TIME_ZONE,
    ...options
  });
}

function formatAnalyticsDateKey(dateInput) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: ANALYTICS_TIME_ZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(dateInput instanceof Date ? dateInput : new Date(dateInput));
  const values = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  return `${values.year}-${values.month}-${values.day}`;
}

function getAnalyticsDateParts(dateInput) {
  const date = dateInput instanceof Date ? dateInput : new Date(dateInput);
  if (Number.isNaN(date.getTime())) return null;
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: ANALYTICS_TIME_ZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(date);
  const values = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  const year = Number(values.year);
  const month = Number(values.month);
  const day = Number(values.day);
  if (!year || !month || !day) {
    return null;
  }
  return { year, month, day };
}

function getAnalyticsTimeZoneOffsetMs(dateInput) {
  const date = dateInput instanceof Date ? dateInput : new Date(dateInput);
  if (Number.isNaN(date.getTime())) return 0;
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: ANALYTICS_TIME_ZONE,
    timeZoneName: "shortOffset"
  }).formatToParts(date);
  const zoneName = parts.find((part) => part.type === "timeZoneName")?.value || "GMT";
  const match = zoneName.match(/^GMT([+-])(\d{1,2})(?::?(\d{2}))?$/i);
  if (!match) {
    return 0;
  }
  const sign = match[1] === "-" ? -1 : 1;
  const hours = Number(match[2] || 0);
  const minutes = Number(match[3] || 0);
  return sign * ((hours * 60) + minutes) * 60 * 1000;
}

function createAnalyticsDateAtTime(year, month, day, hour = 0, minute = 0, second = 0, millisecond = 0) {
  const utcGuess = Date.UTC(year, month - 1, day, hour, minute, second, millisecond);
  const offsetMs = getAnalyticsTimeZoneOffsetMs(new Date(utcGuess));
  return new Date(utcGuess - offsetMs);
}

function createAnalyticsDateFromKey(dayKey) {
  const [year, month, day] = String(dayKey || "").split("-").map((value) => Number(value || 0));
  if (!year || !month || !day) {
    return null;
  }
  return createAnalyticsDateAtTime(year, month, day, 12, 0, 0, 0);
}

function shiftAnalyticsDateKey(dayKey, days) {
  const baseDate = createAnalyticsDateFromKey(dayKey);
  if (!baseDate) {
    return "";
  }
  const shifted = new Date(baseDate.getTime() + days * 24 * 60 * 60 * 1000);
  return formatAnalyticsDateKey(shifted);
}

function getAnalyticsDayRange(dateInput) {
  const parts = getAnalyticsDateParts(dateInput);
  if (!parts) {
    return {
      dayKey: "",
      start: null,
      end: null
    };
  }
  const dayKey = `${String(parts.year).padStart(4, "0")}-${String(parts.month).padStart(2, "0")}-${String(parts.day).padStart(2, "0")}`;
  const start = createAnalyticsDateAtTime(parts.year, parts.month, parts.day, 0, 0, 0, 0);
  const nextDayKey = shiftAnalyticsDateKey(dayKey, 1);
  const nextDayDate = createAnalyticsDateFromKey(nextDayKey);
  return {
    dayKey,
    start,
    end: nextDayDate ? createAnalyticsDateAtTime(
      Number(nextDayKey.slice(0, 4)),
      Number(nextDayKey.slice(5, 7)),
      Number(nextDayKey.slice(8, 10)),
      0,
      0,
      0,
      0
    ) : null
  };
}
let activePlayerBreakdownUserId = null;
let activePlayerBreakdownName = "";
let playerBreakdownPeriod = "year";
let analyticsPlayerBreakdownRequestId = 0;
const analyticsProfileCache = new Map();
const ANALYTICS_ACTIVITY_PAGE_SIZE = 10;

function buildRealizedPnlBucketsFromRawRecords(
  handRecords = [],
  tradeRecords = [],
  csRecords = []
) {
  const buckets = new Map();
  const ensureDay = (dayKey, createdAt) => {
    if (!buckets.has(dayKey)) {
      buckets.set(dayKey, {
        dayKey,
        created_at: createdAt,
        pnlTotal: 0,
        pnlRtn: 0,
        pnlG10: 0,
        pnlShapeTraders: 0,
        pnlRyb: 0
      });
    }
    return buckets.get(dayKey);
  };

  handRecords.forEach((hand) => {
    const dayKey = formatAnalyticsDateKey(hand?.created_at);
    if (!dayKey) return;
    const bucket = ensureDay(dayKey, String(hand?.created_at || `${dayKey}T12:00:00`));
    const net = roundCurrencyValue(Number(hand?.net || 0));
    const gameKey = resolveGameKey(hand?.game_id);
    if (gameKey === GAME_KEYS.RUN_THE_NUMBERS) {
      bucket.pnlRtn = roundCurrencyValue(bucket.pnlRtn + net);
    } else if (gameKey === GAME_KEYS.GUESS_10) {
      bucket.pnlG10 = roundCurrencyValue(bucket.pnlG10 + net);
    }
  });

  // All realized trades including contest — just require a valid net_profit
  tradeRecords.forEach((trade) => {
    const rawNetProfit = trade?.net_profit;
    if (rawNetProfit === null || rawNetProfit === undefined || rawNetProfit === "") return;
    if (!Number.isFinite(Number(rawNetProfit))) return;
    const dayKey = formatAnalyticsDateKey(trade?.executed_at);
    if (!dayKey) return;
    const bucket = ensureDay(dayKey, String(trade?.executed_at || `${dayKey}T12:00:00`));
    bucket.pnlShapeTraders = roundCurrencyValue(
      bucket.pnlShapeTraders + roundCurrencyValue(Number(rawNetProfit))
    );
  });

  // Color Scheme rounds — all modes including contest
  csRecords.forEach((round) => {
    const rawNetProfit = round?.net_profit;
    if (rawNetProfit === null || rawNetProfit === undefined || rawNetProfit === "") return;
    const dayKey = formatAnalyticsDateKey(round?.created_at);
    if (!dayKey) return;
    const bucket = ensureDay(dayKey, String(round?.created_at || `${dayKey}T12:00:00`));
    bucket.pnlRyb = roundCurrencyValue(
      bucket.pnlRyb + roundCurrencyValue(Number(rawNetProfit))
    );
  });

  return Array.from(buckets.values())
    .map((bucket, index) => ({
      ...bucket,
      pnlTotal: roundCurrencyValue(bucket.pnlRtn + bucket.pnlG10 + bucket.pnlShapeTraders + bucket.pnlRyb),
      fallbackIndex: index
    }))
    .sort((left, right) => String(left.dayKey).localeCompare(String(right.dayKey)));
}

