  adminPnlTooltipDateEl.textContent = bar.label;
  adminPnlTooltipValueEl.textContent = formatSignedCurrency(bar.value);
  adminPnlTooltipValueEl.classList.toggle("is-negative", Number(bar.value || 0) < 0);

