const homeSidebarActivityEl = document.getElementById("home-sidebar-activity");
const homePnlTotalEl = document.getElementById("home-pnl-total");
const homePnlChartCanvas = document.getElementById("home-pnl-chart");
let homePnlChartPeriod = "week";
let homePnlChartGame = "all";
let homePnlMode = "all";
let homePnlCtx = homePnlChartCanvas ? homePnlChartCanvas.getContext("2d") : null;
let homePnlHoverBars = [];

if (homePnlChartCanvas) {
  homePnlChartCanvas.addEventListener("mousemove", (event) => {
    const rect = homePnlChartCanvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const hit = homePnlHoverBars.find((bar) => x >= bar.x && x <= bar.x + bar.width && y >= bar.y && y <= bar.y + bar.height);
    if (hit) { showHomePnlTooltip(hit); } else { hideHomePnlTooltip(); }
  });
  homePnlChartCanvas.addEventListener("mouseleave", () => { hideHomePnlTooltip(); });
}

function renderHomePlayerHero() {
  if (!currentProfile) { homeGlitchSection('hero'); return; }
  const setEl = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };
  const firstName = currentProfile.first_name || "";
  const lastName = currentProfile.last_name || "";
  const fullName = [firstName, lastName].filter(Boolean).join("\n");
  const nameEl = document.getElementById("hph-name");
  if (nameEl) {
    const rankNum = Number(currentProfile.current_rank || 1);
    const rankBadge = `<button type="button" class="hph-rank-badge-btn" data-action="open-platform-rankings" aria-label="View platform rankings">#${rankNum}</button>`;
    nameEl.innerHTML = firstName
      ? `${escapeAssistantHtml(firstName)}${rankBadge}<br><span style="color:#c8c0a8">${escapeAssistantHtml(lastName)}</span>`
      : escapeAssistantHtml(fullName || "—");
  }

  const rawUsername = currentProfile.username || "";
  const displayHandle = rawUsername.includes("@")
    ? rawUsername.split("@")[0]
    : rawUsername;
  const username = displayHandle ? `@${displayHandle}` : "";
  const memberYear = currentUser?.created_at
    ? `member since ${new Date(currentUser.created_at).getFullYear()}`
    : "";
  setEl("hph-sub", [username, memberYear].filter(Boolean).join(" · "));

  const contestWins = Math.max(0, Math.round(Number(currentProfile.contest_wins || 0)));
  const rankTier = Math.max(1, Math.round(Number(currentProfile.current_rank_tier || currentProfile.current_rank || 1)));
  const rankName = currentRankState?.currentRank?.name || `Tier ${rankTier}`;
  const totalPlays = Math.max(0, Math.round(Number(currentProfile.total_progress_events || 0)));
  const fmtCount = (n) => n >= 1000 ? (n / 1000).toFixed(1).replace(/\.0$/, "") + "k" : String(n);

  const badgesEl = document.getElementById("hph-badges");
  if (badgesEl) {
    const badges = [
      { text: rankName.toUpperCase(), accent: true, action: "open-rank-modal", label: "View full rank ladder" },
      { text: `TIER ${rankTier}`, action: "open-rank-modal", label: "View full rank ladder" },
      { text: `${contestWins} WIN${contestWins === 1 ? "" : "S"}`, action: "open-wins-modal", label: "View contest awards" },
      { text: `${fmtCount(totalPlays)} PLAY${totalPlays === 1 ? "" : "S"}`, static: true, label: "Total qualifying plays across all games" },
    ];
    badgesEl.innerHTML = badges.map(b =>
      b.static
        ? `<span class="hph-badge hph-badge-static" title="${b.label}" aria-label="${b.label}">${escapeAssistantHtml(b.text)}</span>`
        : `<button type="button" class="hph-badge${b.accent ? " hph-badge-accent" : ""} hph-badge-btn" data-action="${b.action}" aria-label="${b.label}">${escapeAssistantHtml(b.text)}</button>`
    ).join("");
  }
  homeGlitchSection('hero');
}

function renderHomeStatCards() {
  if (!currentProfile) { homeGlitchSection('stats'); return; }

  const rtnHands = Math.max(0, Math.round(Number(currentProfile.run_the_numbers_hands_played_all_time || 0)));
  const g10Hands = Math.max(0, Math.round(Number(currentProfile.guess10_hands_played_all_time || 0)));
  const stTrades = Math.max(0, Math.round(Number(currentProfile.trades_made_all_time || 0)));
  const rybRounds = Math.max(0, Math.round(Number(currentProfile.color_scheme_rounds_played_all_time || 0)));
  const totalHands = Math.max(0, Math.round(Number(currentProfile.total_progress_events || currentProfile.hands_played_all_time || rtnHands + g10Hands + rybRounds)));
  const rankTier = Math.max(1, Math.round(Number(currentProfile.current_rank_tier || currentProfile.current_rank || 1)));
  const rankName = currentRankState?.currentRank?.name || `Tier ${rankTier}`;

  const fmt = (n) => n >= 1000 ? (n / 1000).toFixed(1).replace(/\.0$/, "") + "k" : String(n);
  const setEl = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };

  setEl("hsb-rtn", fmt(rtnHands));
  setEl("hsb-g10", fmt(g10Hands));
  setEl("hsb-st", fmt(stTrades));
  setEl("hsb-ryb", fmt(rybRounds));

  // Rank — show current_rank from profiles
  const rankNum = Number(currentProfile.current_rank || 1);
  setEl("hsb-rank", `#${rankNum}`);
  setEl("hsb-rank-sub", rankName.toUpperCase());
  homeGlitchSection('stats');
}

function renderHomeSystemBlock() {
  const modeEl = document.getElementById("hss-mode");
  const sessionEl = document.getElementById("hss-session");
  if (modeEl) {
    modeEl.textContent = getAccountModeLabel().toUpperCase();
  }
  if (sessionEl) {
    sessionEl.textContent = currentUser && currentUser.id !== (typeof GUEST_USER !== "undefined" ? GUEST_USER.id : null) ? "ACTIVE" : "GUEST";
  }
}

function formatHomeSidebarTimestamp(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  if (isNaN(d.getTime())) return "";
  const mo = String(d.getMonth() + 1).padStart(2, "0");
  const dy = String(d.getDate()).padStart(2, "0");
  const hr = String(d.getHours()).padStart(2, "0");
  const mn = String(d.getMinutes()).padStart(2, "0");
  return `${mo}/${dy} ${hr}:${mn}`;
}

function openHomeTradeDetailModal(entry) {
  const modal = document.getElementById("home-trade-detail-modal");
  const rowsEl = document.getElementById("home-trade-detail-rows");
  if (!modal || !rowsEl) return;

  const side = entry.side === "sell" ? "SELL" : "BUY";
  const pl = entry.netProfit === null || entry.netProfit === undefined ? null : Number(entry.netProfit);
  const plText = pl === null ? "—" : pl >= 0 ? `+${formatCurrency(Math.abs(pl))}` : `-${formatCurrency(Math.abs(pl))}`;
  const plClass = pl === null ? "" : pl > 0 ? " is-win" : pl < 0 ? " is-loss" : "";

  const isSell = entry.side === "sell";
  const avgPrice = entry.avgPurchasePrice;
  const avgPriceText = avgPrice !== null && avgPrice !== undefined ? formatCurrency(avgPrice) : "—";

  const rows = [
    ["TYPE", side],
    ["ASSET", escapeAssistantHtml(entry.assetLabel || entry.assetId || "—")],
    ["QTY", formatCurrency(entry.quantity || 0)],
    isSell ? ["AVG PURCHASE PRICE", avgPriceText] : null,
    [isSell ? "SELL PRICE" : "BUY PRICE", formatCurrency(entry.price || 0)],
    ["TOTAL VALUE", formatCurrency(entry.totalValue || 0)],
    ["P/L", plText, plClass],
    ["ACCOUNT VALUE", formatCurrency(entry.newAccountValue || 0)],
    ["TIME", formatHomeSidebarTimestamp(entry.createdAt)],
  ].filter(Boolean);

  rowsEl.innerHTML = rows.map(([k, v, cls = ""]) =>
    `<div class="htd-row">
      <span class="htd-key">${k}</span>
      <span class="htd-val${escapeAssistantHtml(cls)}">${v}</span>
    </div>`
  ).join("");

  modal.hidden = false;
  document.getElementById("home-trade-detail-close")?.focus();
}

function closeHomeTradeDetailModal() {
  const modal = document.getElementById("home-trade-detail-modal");
  if (modal) modal.hidden = true;
}

(function wireHomeTradeDetailModal() {
  const closeBtn = document.getElementById("home-trade-detail-close");
  if (closeBtn) closeBtn.addEventListener("click", closeHomeTradeDetailModal);
  const modal = document.getElementById("home-trade-detail-modal");
  if (modal) {
    modal.addEventListener("click", (e) => { if (e.target === modal) closeHomeTradeDetailModal(); });
    modal.addEventListener("keydown", (e) => { if (e.key === "Escape") closeHomeTradeDetailModal(); });
  }
})();

function renderHomeSidebarActivity() {
  if (!homeSidebarActivityEl) { homeGlitchSection('activity'); return; }
  const entries = activityLogEntries.slice(0, 25);
  if (!entries.length) {
    homeSidebarActivityEl.innerHTML = '<li class="home-sb-activity-empty">No activity yet.</li>';
    homeGlitchSection('activity');
    return;
  }
  homeSidebarActivityEl.innerHTML = entries.map((entry, idx) => {
    let label = "";
    let resultClass = "is-neutral";
    let resultText = "";
    let isTrade = false;
    let suppressReview = false;

    if (entry.gameKey === GAME_KEYS.FATE_OR_FORTUNE) {
      // FOF rounds have no hand-review modal, so render non-clickable.
      suppressReview = true;
      const handNum = entry.handNumber || entry.handId?.slice(-4) || "—";
      label = `FOF · <b>#${escapeAssistantHtml(String(handNum))}</b>`;
      const net = Number(entry.net ?? 0);
      resultClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      resultText = net >= 0 ? `+${formatCurrency(net)}` : `-${formatCurrency(Math.abs(net))}`;
    } else if (entry.gameKey === GAME_KEYS.RUN_THE_NUMBERS || entry.gameKey === GAME_KEYS.GUESS_10 || entry.gameKey === GAME_KEYS.COLOR_SCHEME) {
      const gameShort = entry.gameKey === GAME_KEYS.RUN_THE_NUMBERS ? "RTN" : entry.gameKey === GAME_KEYS.GUESS_10 ? "G10" : "RYB";
      const handNum = entry.handNumber || entry.handId?.slice(-4) || "—";
      label = `${escapeAssistantHtml(gameShort)} · <b>#${escapeAssistantHtml(String(handNum))}</b>`;
      const net = Number(entry.net ?? 0);
      resultClass = net > 0 ? "is-win" : net < 0 ? "is-loss" : "is-neutral";
      resultText = net >= 0 ? `+${formatCurrency(net)}` : `-${formatCurrency(Math.abs(net))}`;
    } else if (entry.entryType === "trade") {
      isTrade = true;
      const side = entry.side === "sell" ? "SELL" : "BUY";
      label = `ST · <b>${escapeAssistantHtml(side)}</b>`;
      const pl = Number(entry.netProfit ?? 0);
      resultClass = pl > 0 ? "is-win" : pl < 0 ? "is-loss" : "is-neutral";
      resultText = pl >= 0 ? `+${formatCurrency(Math.abs(pl))}` : `-${formatCurrency(Math.abs(pl))}`;
    } else {
      label = `<b>${escapeAssistantHtml(accountEventLabel(entry.eventType))}</b>`;
      resultText = formatSignedCurrency(entry.amount || 0);
      resultClass = "is-neutral";
    }

    const handId = (entry.handId && !suppressReview) ? entry.handId : null;
    const ts = formatHomeSidebarTimestamp(entry.createdAt);
    const isClickable = handId || isTrade;
    const dataAttrs = handId ? ` data-hand-review-id="${escapeAssistantHtml(handId)}"` : "";
    const tradeAttr = isTrade ? ` data-activity-idx="${idx}"` : "";
    const modeLabel = entry.entryType !== "account"
      ? ((entry.contestId || entry.modeType === "contest") ? "CONTEST" : "NORMAL")
      : "";
    const modeBadge = modeLabel ? ` <span class="home-sb-act-mode">${modeLabel}</span>` : "";

    const acctClass = entry.entryType === "account" ? " is-account" : "";
    return `<li class="home-sb-activity-item${isClickable ? " is-clickable" : ""}${acctClass}"${dataAttrs}${tradeAttr}${isClickable ? ' tabindex="0" role="button"' : ""}>
      <span class="home-sb-act-left">${label}${modeBadge}</span>
      <span class="home-sb-act-right ${resultClass}">${escapeAssistantHtml(resultText)}</span>
      <span class="home-sb-act-time">${escapeAssistantHtml(ts)}</span>
    </li>`;
  }).join("");

  homeSidebarActivityEl.querySelectorAll("[data-hand-review-id]").forEach((item) => {
    const activate = () => {
      const handId = item.dataset.handReviewId;
      if (handId && typeof openHandReviewModal === "function") openHandReviewModal(handId);
    };
    item.addEventListener("click", activate);
    item.addEventListener("keydown", (e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); activate(); } });
  });

  homeSidebarActivityEl.querySelectorAll("[data-activity-idx]").forEach((item) => {
    const activate = () => {
      const idx = Number(item.dataset.activityIdx);
      const entry = activityLogEntries[idx];
      if (entry) openHomeTradeDetailModal(entry);
    };
    item.addEventListener("click", activate);
    item.addEventListener("keydown", (e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); activate(); } });
  });
  homeGlitchSection('activity');
}

function getHomePnlFilteredPoints() {
  const fallbackDayKey = formatAnalyticsDateKey(new Date());
  const source = persistentBankrollHistory.length
    ? persistentBankrollHistory
    : [{ dayKey: fallbackDayKey, pnlTotal: 0 }];
  const todayKey = formatAnalyticsDateKey(new Date());
  let startDayKey = null;
  if (homePnlChartPeriod === "week") startDayKey = shiftAnalyticsDateKey(todayKey, -6);
  else if (homePnlChartPeriod === "month") startDayKey = shiftAnalyticsDateKey(todayKey, -29);
  else if (homePnlChartPeriod === "90days") startDayKey = shiftAnalyticsDateKey(todayKey, -89);
  const periodFiltered = startDayKey ? source.filter((p) => !p?.dayKey || p.dayKey >= startDayKey) : source;
  // Build a mode-aware key resolver: "pnlRtn" → "normalPnlRtn" or "contestPnlRtn" or "pnlRtn"
  const modeKey = (f) => {
    if (homePnlMode === "normal" || homePnlMode === "contest") {
      return homePnlMode + f.charAt(0).toUpperCase() + f.slice(1);
    }
    return f;
  };
  if (homePnlChartGame === "all") {
    if (homePnlMode === "all") return periodFiltered;
    return periodFiltered.map((p) => ({ ...p, pnlTotal: Number(p?.[modeKey("pnlTotal")] ?? 0) }));
  }
  return periodFiltered.map((p) => ({ ...p, pnlTotal: Number(p?.[modeKey(homePnlChartGame)] ?? 0) }));
}

function drawHomePnlChart() {
  if (!homePnlChartCanvas || !homePnlCtx) { homeGlitchSection('pnl'); return; }
  const points = getHomePnlFilteredPoints();
  const values = points.map((p) => Number(p?.pnlTotal ?? p?.dayNet ?? 0));
  const totalPnl = roundCurrencyValue(values.reduce((s, v) => s + v, 0));

  if (homePnlTotalEl) {
    homePnlTotalEl.textContent = totalPnl >= 0 ? `+${formatCurrency(totalPnl)}` : formatSignedCurrency(totalPnl);
    homePnlTotalEl.className = "home-sb-pnl-total" + (totalPnl > 0 ? " is-positive" : totalPnl < 0 ? " is-negative" : "");
  }

  const rect = homePnlChartCanvas.getBoundingClientRect();
  if (!rect.width || !rect.height) return;
  const dpr = window.devicePixelRatio || 1;
  homePnlChartCanvas.width = rect.width * dpr;
  homePnlChartCanvas.height = rect.height * dpr;
  const ctx = homePnlCtx;
  ctx.setTransform(1, 0, 0, 1, 0, 0);
  ctx.clearRect(0, 0, homePnlChartCanvas.width, homePnlChartCanvas.height);
  ctx.scale(dpr, dpr);

  const w = rect.width;
  const h = rect.height;
  const pad = { top: 6, right: 4, bottom: 4, left: 4 };
  const chartW = Math.max(1, w - pad.left - pad.right);
  const chartH = Math.max(1, h - pad.top - pad.bottom);
  const maxAbs = Math.max(...values.map(Math.abs), 1);
  const zeroY = pad.top + chartH / 2;
  const n = values.length;
  const barSpacing = 2;
  const barW = n > 1 ? Math.max(2, (chartW - barSpacing * (n - 1)) / n) : chartW;

  homePnlHoverBars = [];
  values.forEach((val, i) => {
    const x = pad.left + i * (barW + barSpacing);
    const barH = Math.max(1, (Math.abs(val) / maxAbs) * (chartH / 2 - 2));
    const y = val >= 0 ? zeroY - barH : zeroY;
    ctx.fillStyle = val >= 0 ? "#c8ff00" : "#ff6b6b";
    ctx.globalAlpha = 0.85;
    ctx.fillRect(x, y, barW, barH);
    ctx.globalAlpha = 1;

    // Hit-test region (full column height for easy hover)
    const pt = points[i];
    const label = formatBankrollTickLabel(pt, i, homePnlChartPeriod);
    homePnlHoverBars.push({
      x, y: 0, width: barW + barSpacing, height: h,
      centerX: x + barW / 2,
      anchorY: Math.max(y - 6, 4),
      value: val,
      label
    });
  });

  // zero line
  ctx.strokeStyle = "rgba(200, 255, 0, 0.25)";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(pad.left, zeroY);
  ctx.lineTo(w - pad.right, zeroY);
  ctx.stroke();
  homeGlitchSection('pnl');
}

// ── Home RECENT ACTIVITY chart ───────────────────────────────────────────
// Stacked daily-events bar chart for the last 30 days, one segment per game
// (RTN hands, G10 hands, ST trades, RYB rounds). Replaces the per-game spark
// stat cards. Reuses the same per-game queries as openGameActivityChart but
// fetches all four at once. Data is cached for the session to avoid refetching
// on every refreshHomeDashboard() pass.
let _homeActivityData = null;
let _homeActivityUserId = null;
let _homeActivityFetching = false;

async function drawHomeActivityChart(force = false) {
  const canvas = document.getElementById("home-activity-chart");
  if (!canvas || typeof Chart === "undefined") return;

  // Signed-out / guest: nothing meaningful to plot. Drop any cached user data.
  if (!currentUser?.id || (typeof isGuestRuntimeUser === "function" && isGuestRuntimeUser())) {
    _homeActivityData = null;
    _homeActivityUserId = null;
    if (window._homeActivityChart) { window._homeActivityChart.destroy(); window._homeActivityChart = null; }
    const subEl = document.getElementById("hra-sub");
    if (subEl) subEl.textContent = "SIGN IN TO TRACK DAILY ACTIVITY";
    return;
  }

  // Cache is per-user: a different signed-in user must refetch, never reuse.
  if (_homeActivityUserId !== currentUser.id) {
    _homeActivityData = null;
  }

  if (_homeActivityData && !force) {
    _renderHomeActivityChart(canvas, _homeActivityData);
    return;
  }
  if (_homeActivityFetching) return;
  _homeActivityFetching = true;

  try {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - 29);
    cutoffDate.setHours(0, 0, 0, 0);
    const cutoff = cutoffDate.toISOString();
    const uid = currentUser.id;

    const [rtn, g10, st, ryb, fof] = await Promise.all([
      supabase.from("rtn_live_hands").select("started_at").eq("user_id", uid).neq("status", "active").gte("started_at", cutoff),
      supabase.from("guess10_live_hands").select("started_at").eq("user_id", uid).neq("status", "active").gte("started_at", cutoff),
      supabase.from("shape_trader_trades").select("executed_at").eq("user_id", uid).gte("executed_at", cutoff),
      supabase.from("color_scheme_rounds").select("created_at").eq("user_id", uid).gte("created_at", cutoff),
      supabase.from("fate_or_fortune_rounds").select("created_at").eq("user_id", uid).eq("status", "resolved").gte("created_at", cutoff),
    ]);
    [rtn, g10, st, ryb, fof].forEach((r, i) => {
      if (r?.error) console.error(`[RTN] home activity query error (${["rtn","g10","st","ryb","fof"][i]}):`, r.error.message);
    });

    // Bucket by LOCAL date so "today" matches the player's clock.
    const toKey = (ts) => {
      const d = new Date(ts);
      if (isNaN(d.getTime())) return null;
      const y = d.getFullYear();
      const m = String(d.getMonth() + 1).padStart(2, "0");
      const day = String(d.getDate()).padStart(2, "0");
      return `${y}-${m}-${day}`;
    };
    const bucket = (rows, field) => {
      const c = {};
      for (const r of (rows || [])) { const k = toKey(r[field]); if (k) c[k] = (c[k] || 0) + 1; }
      return c;
    };

    const rtnC = bucket(rtn?.data, "started_at");
    const g10C = bucket(g10?.data, "started_at");
    const stC = bucket(st?.data, "executed_at");
    const rybC = bucket(ryb?.data, "created_at");
    const fofC = bucket(fof?.data, "created_at");

    const labels = [];
    const keys = [];
    for (let i = 29; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const k = toKey(d);
      keys.push(k);
      labels.push(k.slice(5));
    }

    _homeActivityData = {
      labels,
      datasets: [
        { label: "RTN hands",  data: keys.map((k) => rtnC[k] || 0), color: "#e8a020" },
        { label: "G10 hands",  data: keys.map((k) => g10C[k] || 0), color: "#00e5ff" },
        { label: "ST trades",  data: keys.map((k) => stC[k]  || 0), color: "#c8ff00" },
        { label: "RYB rounds", data: keys.map((k) => rybC[k] || 0), color: "#ff4444" },
        { label: "FOF rounds", data: keys.map((k) => fofC[k] || 0), color: "#b07bff" },
      ],
    };
    // If the user switched while this fetch was in flight, discard the result.
    if (currentUser?.id !== uid) {
      _homeActivityData = null;
      _homeActivityUserId = null;
      return;
    }
    _homeActivityUserId = uid;
    _renderHomeActivityChart(canvas, _homeActivityData);
  } catch (err) {
    console.error("[RTN] home activity chart error", err);
  } finally {
    _homeActivityFetching = false;
  }
}

function _renderHomeActivityChart(canvas, data) {
  if (typeof Chart === "undefined") return;
  if (window._homeActivityChart) { window._homeActivityChart.destroy(); window._homeActivityChart = null; }

  const total = data.datasets.reduce((s, ds) => s + ds.data.reduce((a, b) => a + b, 0), 0);
  const subEl = document.getElementById("hra-sub");
  if (subEl) subEl.textContent = total > 0
    ? "DAILY GAME EVENTS · LAST 30 DAYS"
    : "DAILY GAME EVENTS · LAST 30 DAYS · NO ACTIVITY YET";

  const ctx = canvas.getContext("2d");
  window._homeActivityChart = new Chart(ctx, {
    type: "bar",
    data: {
      labels: data.labels,
      datasets: data.datasets.map((ds) => ({
        label: ds.label,
        data: ds.data,
        backgroundColor: ds.color + "cc",
        borderColor: ds.color,
        borderWidth: 0,
        borderRadius: 1,
        stack: "events",
      })),
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: "index", intersect: false },
      // Bars sprout upward from the zero baseline instead of sweeping in from
      // the left: freeze the horizontal animation and start both the top (y)
      // and bottom (base) of every (stacked) segment at the y=0 pixel.
      animation: { duration: 760, easing: "easeOutQuart" },
      animations: {
        x: { duration: 0 },
        y: { from: (ctx) => ctx.chart.scales.y.getPixelForValue(0) },
        base: { from: (ctx) => ctx.chart.scales.y.getPixelForValue(0) },
      },
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: { label: (c) => ` ${c.dataset.label}: ${c.parsed.y}` },
        },
      },
      scales: {
        x: {
          stacked: true,
          ticks: { color: "#686850", font: { size: 9, family: "inherit" }, maxTicksLimit: 10 },
          grid: { display: false },
          border: { color: "rgba(255,255,255,0.1)" },
        },
        y: {
          stacked: true,
          beginAtZero: true,
          ticks: { color: "#686850", font: { size: 9, family: "inherit" }, precision: 0 },
          grid: { color: "rgba(255,255,255,0.05)" },
          border: { color: "rgba(255,255,255,0.1)" },
        },
      },
    },
  });
}

// ── Home init overlay + coordinated glitch reveal ────────────────────────
const HOME_INIT_SECTIONS = ['hero', 'stats', 'tier', 'activity', 'pnl'];
// Stagger order: left-col top-to-bottom, then sidebar top-to-bottom
const HOME_REVEAL_ORDER = ['hero', 'stats', 'tier', 'activity', 'pnl'];
const SCRAMBLE_GLYPHS = '╔╗╚╝║═╠╣╦╩╬█▓▒░▄▀◆◇■□▪▫⬡⬢';

let _homeInitReady = new Set();
let _homeInitComplete = false;
let _homeInitTimeout = null;
let _hioScrambleId = null;

function homeGlitchSection(sectionId) {
  // No-op: sections are always visible, no coordinated reveal needed
}

function _homeHomeRevealAll() {
  if (_homeInitComplete) return;
  _homeInitComplete = true;
  if (_homeInitTimeout) { clearTimeout(_homeInitTimeout); _homeInitTimeout = null; }
  if (_hioScrambleId) { clearInterval(_hioScrambleId); _hioScrambleId = null; }

  // Ensure body & any remaining unloaded sections are visible
  document.body.removeAttribute('data-home-loading');
  HOME_REVEAL_ORDER.forEach(sectionId => {
    const el = document.querySelector(`[data-home-section="${sectionId}"]`);
    if (!el) return;
    if (el.hasAttribute('data-home-loading')) {
      el.removeAttribute('data-home-loading');
      el.classList.remove('is-glitch-enter');
      void el.offsetWidth;
      el.classList.add('is-glitch-enter');
    }
  });

  // Dismiss overlay
  const overlay = document.getElementById('home-init-overlay');
  if (overlay && !overlay.hidden) {
    overlay.classList.add('is-exiting');
    overlay.addEventListener('animationend', () => overlay.setAttribute('hidden', ''), { once: true });
  }
}

function homeResetLoadingStates() {
  // No-op: sections render directly as data arrives, no blocking state
}

function _homeStartScramble() {
  const el = document.getElementById('home-init-label');
  if (!el) return;
  const target = '// CASINO FLOOR INITIALIZING';
  let tick = 0;
  const totalTicks = 36; // ~2.2s at 60ms intervals
  _hioScrambleId = setInterval(() => {
    const t = tick / totalTicks;
    el.textContent = target.split('').map((ch, i) => {
      if (ch === '/' || ch === ' ') return ch;
      const resolveAt = 0.35 + (i / target.length) * 0.55;
      return t >= resolveAt ? ch : SCRAMBLE_GLYPHS[Math.floor(Math.random() * SCRAMBLE_GLYPHS.length)];
    }).join('');
    if (tick++ >= totalTicks) {
      el.textContent = target;
      clearInterval(_hioScrambleId);
      _hioScrambleId = null;
    }
  }, 60);
}

