const CS_PIP_LAYOUTS = [
  [],
  [[.5,.5]],
  [[.25,.25],[.75,.75]],
  [[.25,.25],[.5,.5],[.75,.75]],
  [[.25,.25],[.75,.25],[.25,.75],[.75,.75]],
  [[.25,.25],[.75,.25],[.5,.5],[.25,.75],[.75,.75]],
  [[.25,.25],[.75,.25],[.28,.5],[.72,.5],[.25,.75],[.75,.75]],
];

const CS_BZ_COLORS = {
  RED:'255,68,68',BLUE:'68,136,255',YELLOW:'255,204,0',
  PURPLE:'204,68,255',GREEN:'51,238,102',ORANGE:'255,136,51',
  COLOR_TIE:'160,160,150',TYPE_PRIMARY:'200,200,192',TYPE_SECONDARY:'170,150,200',
  TYPE_TIE:'160,160,150',
  PUR_LO:'204,68,255',PUR_MID:'204,68,255',PUR_HI:'204,68,255',
  GRN_LO:'51,238,102',GRN_MID:'51,238,102',GRN_HI:'51,238,102',
  ORG_LO:'255,136,51',ORG_MID:'255,136,51',ORG_HI:'255,136,51',
  BLU_1:'68,136,255',BLU_2:'68,136,255',BLU_3:'68,136,255',BLU_4:'68,136,255',BLU_5:'68,136,255',BLU_6:'68,136,255',BLU_7P:'68,136,255',
  RED_1:'255,68,68',RED_2:'255,68,68',RED_3:'255,68,68',RED_4:'255,68,68',RED_5:'255,68,68',RED_6:'255,68,68',RED_7P:'255,68,68',
  YEL_1:'255,204,0',YEL_2:'255,204,0',YEL_3:'255,204,0',YEL_4:'255,204,0',YEL_5:'255,204,0',YEL_6:'255,204,0',YEL_7P:'255,204,0',
  TOT_A:'180,180,160',TOT_B:'180,180,160',TOT_C:'180,180,160',TOT_D:'180,180,160',TOT_E:'180,180,160',TOT_F:'180,180,160',
};

function csEl(id) { return document.getElementById(id); }

function csGetBetLabel(key) {
  const MAP = {
    RED:'Red (Primary)', BLUE:'Blue (Primary)', YELLOW:'Yellow (Primary)',
    PURPLE:'Purple (Secondary)', GREEN:'Green (Secondary)', ORANGE:'Orange (Secondary)',
    COLOR_TIE:'Color Tie', TYPE_PRIMARY:'Type: Primary', TYPE_SECONDARY:'Type: Secondary', TYPE_TIE:'Type Tie',
    PUR_LO:'Purple Low (1-16)', PUR_MID:'Purple Mid (17-30)', PUR_HI:'Purple High (31+)',
    GRN_LO:'Green Low (1-16)', GRN_MID:'Green Mid (17-30)', GRN_HI:'Green High (31+)',
    ORG_LO:'Orange Low (1-16)', ORG_MID:'Orange Mid (17-30)', ORG_HI:'Orange High (31+)',
    BLU_1:'Blue = 1', BLU_2:'Blue = 2', BLU_3:'Blue = 3', BLU_4:'Blue = 4', BLU_5:'Blue = 5', BLU_6:'Blue = 6', BLU_7P:'Blue ≥ 7',
    RED_1:'Red = 1', RED_2:'Red = 2', RED_3:'Red = 3', RED_4:'Red = 4', RED_5:'Red = 5', RED_6:'Red = 6', RED_7P:'Red ≥ 7',
    YEL_1:'Yellow = 1', YEL_2:'Yellow = 2', YEL_3:'Yellow = 3', YEL_4:'Yellow = 4', YEL_5:'Yellow = 5', YEL_6:'Yellow = 6', YEL_7P:'Yellow ≥ 7',
    TOT_A:'Total 1-10', TOT_B:'Total 11-20', TOT_C:'Total 21-36', TOT_D:'Total 37-52', TOT_E:'Total 53-75', TOT_F:'Total 76+',
  };
  return MAP[key] || key;
}

function csMakeFaceTex(THREE, faceColor, pipColor, pips, label) {
  const sz = 256;
  const c = document.createElement('canvas');
  c.width = c.height = sz;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#000000'; ctx.fillRect(0,0,sz,sz);
  ctx.fillStyle = faceColor;
  ctx.beginPath(); ctx.roundRect(5,5,sz-10,sz-10,sz*0.1); ctx.fill();
  if (label) {
    ctx.fillStyle = 'rgba(0,0,0,0.55)';
    ctx.font = `900 ${sz*0.48}px 'Courier New',monospace`;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText(label, sz/2, sz/2+3);
  } else {
    ctx.fillStyle = pipColor;
    pips.forEach(([u,v]) => { ctx.beginPath(); ctx.arc(u*sz,v*sz,sz*0.088,0,Math.PI*2); ctx.fill(); });
  }
  return new THREE.CanvasTexture(c);
}

function csMakeColorDie(THREE) {
  return CS_COLS.map(col => csMakeFaceTex(THREE, col.top, col.dark, [], col.name[0]));
}
function csMakeNumberDie(THREE) {
  return [1,6,2,5,3,4].map(n => csMakeFaceTex(THREE, '#ffffff', '#111111', CS_PIP_LAYOUTS[n], null));
}

function csCalcOutcome(rolls) {
  const totals = {RED:0,BLUE:0,YELLOW:0,PURPLE:0,GREEN:0,ORANGE:0};
  const formulas = {RED:[],BLUE:[],YELLOW:[],PURPLE:[],GREEN:[],ORANGE:[]};
  let i = 0;
  while (i < rolls.length) {
    const c = rolls[i].color; let j = i;
    while (j < rolls.length && rolls[j].color === c) j++;
    const group = rolls.slice(i, j);
    const val = group.reduce((acc,r) => acc * r.number, 1);
    totals[c] += val;
    formulas[c].push(group.length > 1 ? group.map(r=>r.number).join('×') : String(group[0].number));
    i = j;
  }
  const MIX = {'BLUE-RED':'PURPLE','RED-BLUE':'PURPLE','BLUE-YELLOW':'GREEN','YELLOW-BLUE':'GREEN','RED-YELLOW':'ORANGE','YELLOW-RED':'ORANGE'};
  for (let p = 0; p < rolls.length - 1; p++) {
    const a = rolls[p], b = rolls[p+1];
    if (a.color === b.color) continue;
    const sec = MIX[a.color+'-'+b.color]; if (!sec) continue;
    const val = a.number * b.number;
    totals[sec] += val; formulas[sec].push(a.number+'×'+b.number);
  }
  return { totals, formulas };
}

function csIsCurrentlyWinning(betId, totals, grandTotal) {
  const primarySum = totals.RED+totals.BLUE+totals.YELLOW;
  const secondarySum = totals.PURPLE+totals.GREEN+totals.ORANGE;
  const allColors = {RED:totals.RED,BLUE:totals.BLUE,YELLOW:totals.YELLOW,PURPLE:totals.PURPLE,GREEN:totals.GREEN,ORANGE:totals.ORANGE};
  const maxVal = Math.max(...Object.values(allColors));
  const winners = Object.keys(allColors).filter(k => allColors[k]===maxVal);
  const winningColor = winners.length===1 ? winners[0] : 'COLOR_TIE';
  let winningType;
  if (primarySum>secondarySum) winningType='TYPE_PRIMARY';
  else if (secondarySum>primarySum) winningType='TYPE_SECONDARY';
  else winningType='TYPE_TIE';
  if (['RED','BLUE','YELLOW','PURPLE','GREEN','ORANGE','COLOR_TIE'].includes(betId)) return betId===winningColor;
  if (['TYPE_PRIMARY','TYPE_SECONDARY','TYPE_TIE'].includes(betId)) return betId===winningType;
  if (betId.startsWith('PUR_')) { const v=totals.PURPLE; return (betId==='PUR_LO'&&v>=1&&v<=16)||(betId==='PUR_MID'&&v>=17&&v<=30)||(betId==='PUR_HI'&&v>=31); }
  if (betId.startsWith('GRN_')) { const v=totals.GREEN;  return (betId==='GRN_LO'&&v>=1&&v<=16)||(betId==='GRN_MID'&&v>=17&&v<=30)||(betId==='GRN_HI'&&v>=31); }
  if (betId.startsWith('ORG_')) { const v=totals.ORANGE; return (betId==='ORG_LO'&&v>=1&&v<=16)||(betId==='ORG_MID'&&v>=17&&v<=30)||(betId==='ORG_HI'&&v>=31); }
  if (betId.startsWith('BLU_')) { const v=totals.BLUE;   return (betId==='BLU_1'&&v===1)||(betId==='BLU_2'&&v===2)||(betId==='BLU_3'&&v===3)||(betId==='BLU_4'&&v===4)||(betId==='BLU_5'&&v===5)||(betId==='BLU_6'&&v===6)||(betId==='BLU_7P'&&v>=7); }
  if (betId.startsWith('RED_')) { const v=totals.RED;    return (betId==='RED_1'&&v===1)||(betId==='RED_2'&&v===2)||(betId==='RED_3'&&v===3)||(betId==='RED_4'&&v===4)||(betId==='RED_5'&&v===5)||(betId==='RED_6'&&v===6)||(betId==='RED_7P'&&v>=7); }
  if (betId.startsWith('YEL_')) { const v=totals.YELLOW; return (betId==='YEL_1'&&v===1)||(betId==='YEL_2'&&v===2)||(betId==='YEL_3'&&v===3)||(betId==='YEL_4'&&v===4)||(betId==='YEL_5'&&v===5)||(betId==='YEL_6'&&v===6)||(betId==='YEL_7P'&&v>=7); }
  if (betId.startsWith('TOT_')) { const v=grandTotal;    return (betId==='TOT_A'&&v>=1&&v<=10)||(betId==='TOT_B'&&v>=11&&v<=20)||(betId==='TOT_C'&&v>=21&&v<=36)||(betId==='TOT_D'&&v>=37&&v<=52)||(betId==='TOT_E'&&v>=53&&v<=75)||(betId==='TOT_F'&&v>=76); }
  return false;
}

function csRenderFormula(parts) {
  if (!parts.length) return '—';
  return parts.length===1 ? parts[0] : parts.join('+');
}

function csUpdateLiveBetGlow(totals, grandTotal) {
  document.querySelectorAll('.cs-bet-zone').forEach(z => {
    const id = z.dataset.bet;
    z.classList.toggle('cs-live-win', csIsCurrentlyWinning(id, totals, grandTotal));
  });
}

function csClearLiveBetGlow() {
  document.querySelectorAll('.cs-bet-zone').forEach(z => z.classList.remove('cs-live-win'));
}

function csShowOutcome(rolls) {
  const { totals, formulas } = csCalcOutcome(rolls);

  // Update hidden compat spans (for formula lookups by csRenderRankedColors)
  const pairs = [
    ['Red','RED','#ff4444'],['Blue','BLUE','#4488ff'],['Yellow','YELLOW','#ffdd00'],
    ['Purple','PURPLE','#cc44ff'],['Green','GREEN','#33ee66'],['Orange','ORANGE','#ff8833'],
  ];
  pairs.forEach(([id, key]) => {
    const vEl = csEl('cs-v'+id), fEl = csEl('cs-f'+id);
    if (vEl) vEl.textContent = String(totals[key]);
    if (fEl) fEl.textContent = csRenderFormula(formulas[key]);
  });

  const primarySub = totals.RED+totals.BLUE+totals.YELLOW;
  const secondarySub = totals.PURPLE+totals.GREEN+totals.ORANGE;
  const grandTotal = primarySub+secondarySub;

  // Giant grand total
  const vT = csEl('cs-vTotal');
  if (vT) vT.textContent = grandTotal || '—';
  const fT = csEl('cs-fTotal');
  if (fT) fT.textContent = grandTotal ? '1°'+primarySub+' + 2°'+secondarySub : '';

  // Subtotals
  const vPS = csEl('cs-vPrimarySub');
  if (vPS) vPS.textContent = primarySub || '0';
  const vSS = csEl('cs-vSecondarySub');
  if (vSS) vSS.textContent = secondarySub || '0';

  // Winner highlight on subtotal blocks
  const sbP = csEl('cs-subBlockPrimary'), sbS = csEl('cs-subBlockSecondary');
  if (sbP) sbP.classList.toggle('cs-winner', primarySub > secondarySub);
  if (sbS) sbS.classList.toggle('cs-winner', secondarySub > primarySub);
  const arP = csEl('cs-subArrowP'), arS = csEl('cs-subArrowS');
  if (arP) arP.style.display = primarySub > secondarySub ? '' : 'none';
  if (arS) arS.style.display = secondarySub > primarySub ? '' : 'none';

  // Ranked color list
  csRenderRankedColors(totals, grandTotal);

  csUpdateLiveBetGlow(totals, grandTotal);
}

function csResetOutcome() {
  // Reset giant total
  const vT = csEl('cs-vTotal'); if (vT) vT.textContent='—';
  const fT = csEl('cs-fTotal'); if (fT) fT.textContent='';
  // Reset subtotals
  const vPS = csEl('cs-vPrimarySub'); if (vPS) vPS.textContent='—';
  const vSS = csEl('cs-vSecondarySub'); if (vSS) vSS.textContent='—';
  const sbP = csEl('cs-subBlockPrimary'); if (sbP) sbP.classList.remove('cs-winner');
  const sbS = csEl('cs-subBlockSecondary'); if (sbS) sbS.classList.remove('cs-winner');
  const arP = csEl('cs-subArrowP'); if (arP) arP.style.display='none';
  const arS = csEl('cs-subArrowS'); if (arS) arS.style.display='none';
  // Reset ranked list
  const rl = csEl('cs-ocRankedList');
  if (rl) rl.innerHTML = '<div class="cs-oc-waiting">ROLL TO SEE LIVE TOTALS</div>';
  const sc = csEl('cs-ocScoringCount'); if (sc) sc.textContent='';
  // Reset hidden compat spans
  ['Red','Blue','Yellow','Purple','Green','Orange'].forEach(id => {
    const vEl = csEl('cs-v'+id); if (vEl) vEl.textContent='';
    const fEl = csEl('cs-f'+id); if (fEl) fEl.textContent='';
  });
}

function csSetBetState(state) {
  _csBetState = state;
  const badge = csEl('cs-betStateBadge');
  if (badge) { badge.className='cs-bet-state-badge cs-'+state; badge.textContent=state.toUpperCase(); }
  const locked = state !== 'open';
  document.querySelectorAll('.cs-bet-zone').forEach(z => z.classList.toggle('cs-locked', locked));
  const clearBtn = csEl('cs-clearBetsBtn');
  if (clearBtn) clearBtn.disabled = locked;
  _csChipButtons.forEach(c => { c.disabled = locked; });
  if (!locked) csClearLiveBetGlow();
  // REBET is only valid on a fresh empty board — force-hide + disable whenever round locks
  // (never auto-show here; only New Round handler reveals it)
  if (locked) { const bRebetLock=csEl('cs-rebetBtn'); if(bRebetLock){bRebetLock.disabled=true;bRebetLock.style.display='none';} }
}

function csRenderBank() {
  if (bankrollEl) {
    const v = getDisplayedHeaderBankrollValue();
    bankrollEl.textContent = formatCompactHeader(v);
    if (bankrollExactValueEl) bankrollExactValueEl.textContent = formatCurrency(v);
  }
}

function csAddChipToZone(betId, value) {
  const zone = csEl('cs-bz-' + betId);
  if (!zone) return;
  const stackEl = zone.querySelector('.chip-stack');
  if (!stackEl) return;
  const chip = document.createElement('div');
  chip.className = 'chip';
  chip.dataset.value = value;
  chip.dataset.tone = String(getRunTheNumbersChipRackToneIndex(value));
  chip.textContent = String(value);
  chip.setAttribute('aria-hidden', 'true');
  chip.style.setProperty('--stack-index', stackEl.children.length);
  chip.classList.add(`denom-${value}`);
  stackEl.appendChild(chip);
  requestAnimationFrame(() => chip.classList.add('chip-enter'));
}

function csClearChipStacks() {
  document.querySelectorAll('.cs-bet-zone').forEach(zone => {
    const stackEl = zone.querySelector('.chip-stack');
    if (stackEl) stackEl.innerHTML = '';
  });
}

function csRenderChipRack() {
  const el = document.getElementById('cs-chipSelector');
  if (!el) return;
  el.innerHTML = chipDenominations.map((value) =>
    `<button class="${'chip-choice' + (value === selectedChip ? ' active' : '')}" type="button" data-value="${value}" data-tone="${getRunTheNumbersChipRackToneIndex(value)}"
      role="radio" aria-checked="${value === selectedChip ? 'true' : 'false'}">${value}</button>`
  ).join('');
  _csChipButtons = Array.from(el.querySelectorAll('.chip-choice'));
  _csChipButtons.forEach(btn => {
    btn.addEventListener('click', () => {
      if (btn.disabled) return;
      const val = Number(btn.dataset.value);
      if (Number.isFinite(val)) setSelectedChip(val);
      csUpdateChipRackUI();
    });
  });
  csUpdateChipRackUI();
}

function csUpdateChipRackUI() {
  _csChipButtons.forEach(btn => {
    const val = Number(btn.dataset.value);
    const isSelected = val === selectedChip;
    btn.classList.toggle('active', isSelected);
    btn.setAttribute('aria-checked', isSelected ? 'true' : 'false');
  });
}

function csRenderBetZone(betId) {
  const stake = _csBets[betId]||0;
  const el = csEl('cs-stake-'+betId);
  const zone = csEl('cs-bz-'+betId);
  if (!el||!zone) return;
  el.textContent = stake>0 ? stake : '';
  zone.classList.toggle('cs-has-bet', stake>0);
}

function csRenderTotalWagered() {
  const el = csEl('cs-totalWagered');
  if (el) el.textContent = Object.values(_csBets).reduce((a,b)=>a+b,0);
}

function csFillTrackSlot(rollNum, col, numVal, rolls) {
  const MIX = {'BLUE-RED':'PURPLE','RED-BLUE':'PURPLE','BLUE-YELLOW':'GREEN','YELLOW-BLUE':'GREEN','RED-YELLOW':'ORANGE','YELLOW-RED':'ORANGE'};
  const slot = csEl('cs-rts-'+rollNum);
  const empty = csEl('cs-rts-empty-'+rollNum);
  const cont = csEl('cs-rts-content-'+rollNum);
  const dot = csEl('cs-rts-dot-'+rollNum);
  const cname = csEl('cs-rts-cname-'+rollNum);
  const num = csEl('cs-rts-num-'+rollNum);
  const sec = csEl('cs-rts-sec-'+rollNum);
  if (!slot) return;
  slot.style.setProperty('--slot-color', col.dot);
  if (dot) { dot.style.background=col.dot; dot.style.boxShadow='0 0 5px '+col.dot+'99'; }
  if (cname) { cname.textContent=col.name; cname.style.color=col.dot; }
  if (num) num.textContent = numVal;
  const secParts = [];
  const idx = rollNum-1;
  if (idx>0) {
    const prev=rolls[idx-1];
    if (prev.color!==col.name) { const k=prev.color+'-'+col.name; if(MIX[k]) secParts.push(MIX[k][0]+':'+prev.number+'×'+numVal+'='+(prev.number*numVal)); }
  }
  if (idx<rolls.length-1) {
    const next=rolls[idx+1];
    if (next&&next.color!==col.name) { const k=col.name+'-'+next.color; if(MIX[k]) secParts.push(MIX[k][0]+':'+numVal+'×'+next.number+'='+(numVal*next.number)); }
  }
  if (sec) sec.textContent = secParts.length ? secParts.join('  ') : '';
  if (empty) empty.style.display='none';
  if (cont) cont.classList.add('show');
  slot.classList.remove('cs-active-slot'); slot.classList.add('cs-settled-slot');
  const nextSlot = csEl('cs-rts-'+(rollNum+1));
  if (nextSlot) nextSlot.classList.add('cs-active-slot');
}

function csResetTracker() {
  for (let i=1;i<=3;i++) {
    const slot=csEl('cs-rts-'+i); const empty=csEl('cs-rts-empty-'+i); const cont=csEl('cs-rts-content-'+i);
    if (!slot) continue;
    slot.classList.remove('cs-settled-slot','cs-active-slot'); slot.style.removeProperty('--slot-color');
    if (empty) empty.style.display='';
    if (cont) cont.classList.remove('show');
  }
  const first = csEl('cs-rts-1'); if (first) first.classList.add('cs-active-slot');
}

function csAddHistogramBar(roundNum, total, totals) {
  const allCols = {RED:totals.RED,BLUE:totals.BLUE,YELLOW:totals.YELLOW,PURPLE:totals.PURPLE,GREEN:totals.GREEN,ORANGE:totals.ORANGE};
  const maxColVal = Math.max(...Object.values(allCols));
  const winColors = maxColVal > 0 ? Object.keys(allCols).filter(k => allCols[k] === maxColVal) : [];
  _csHistoryData.push({roundNum, total, totals, winColors});
  csRenderHistogram();
}

function _csRenderHistBars(chart, maxTotal) {
  const COLOR_HEX = {RED:'#ff4444',BLUE:'#4488ff',YELLOW:'#ffdd00',PURPLE:'#cc44ff',GREEN:'#33ee66',ORANGE:'#ff8833'};
  const COLOR_NAMES = ['RED','BLUE','YELLOW','PURPLE','GREEN','ORANGE'];
  chart.innerHTML = '';
  [..._csHistoryData].reverse().forEach(d => {
    const isCurrent = d.roundNum === _csHistoryData.length;
    const wrap = document.createElement('div');
    wrap.className = 'cs-hist-bar-wrap' + (isCurrent ? ' cs-hist-current' : '');
    const rnLabel = document.createElement('div');
    rnLabel.className = 'cs-hist-rnd-label';
    rnLabel.textContent = 'R' + String(d.roundNum).padStart(2,'0');
    const track = document.createElement('div');
    track.className = 'cs-hist-bar-track';
    const bar = document.createElement('div');
    bar.className = 'cs-hist-bar';
    bar.style.width = Math.max(2, Math.round((d.total / maxTotal) * 100)) + '%';
    COLOR_NAMES.forEach(col => {
      const val = d.totals[col] || 0;
      if (!val) return;
      const seg = document.createElement('div');
      seg.className = 'cs-hist-seg';
      seg.style.width = ((val / d.total) * 100) + '%';
      seg.style.background = COLOR_HEX[col];
      seg.dataset.col = col;
      seg.addEventListener('mouseenter', function(e) {
        const tip = csEl('cs-histTooltip');
        if (!tip) return;
        const dotEl = csEl('cs-htDot'), nameEl = csEl('cs-htName'), ptsEl = csEl('cs-htPts');
        if (dotEl) dotEl.style.background = COLOR_HEX[col];
        if (nameEl) { nameEl.textContent = col; nameEl.style.color = COLOR_HEX[col]; }
        if (ptsEl) { ptsEl.textContent = val; ptsEl.style.color = COLOR_HEX[col]; }
        tip.style.display = 'block';
        chart.classList.add('cs-hovering');
        this.classList.add('cs-active');
      });
      seg.addEventListener('mousemove', function(e) {
        const tip = csEl('cs-histTooltip');
        if (tip) { tip.style.left = (e.clientX + 14) + 'px'; tip.style.top = (e.clientY - 40) + 'px'; }
      });
      seg.addEventListener('mouseleave', function() {
        const tip = csEl('cs-histTooltip');
        if (tip) tip.style.display = 'none';
        chart.classList.remove('cs-hovering');
        this.classList.remove('cs-active');
      });
      bar.appendChild(seg);
    });
    if (d.winColors && d.winColors.length) {
      bar.querySelectorAll('.cs-hist-seg').forEach(s => {
        if (!d.winColors.includes(s.dataset.col)) s.classList.add('cs-default-dim');
      });
    }
    track.appendChild(bar);
    const totalLabel = document.createElement('div');
    totalLabel.className = 'cs-hist-total-label';
    totalLabel.textContent = d.total;
    wrap.appendChild(rnLabel); wrap.appendChild(track); wrap.appendChild(totalLabel);
    chart.appendChild(wrap);
  });
  chart.scrollTop = 0;
}

function _csRenderMiniHist() {
  const barsTrack = csEl('cs-mini-hist-bars');
  const lblsTrack = csEl('cs-mini-hist-lbls');
  if (!barsTrack || !lblsTrack) return;
  const COLOR_HEX = {RED:'#ff4444',BLUE:'#4488ff',YELLOW:'#ffdd00',PURPLE:'#cc44ff',GREEN:'#33ee66',ORANGE:'#ff8833'};
  const COLOR_NAMES = ['RED','BLUE','YELLOW','PURPLE','GREEN','ORANGE'];
  const maxTotal = Math.max(..._csHistoryData.map(d => d.total), 1);
  barsTrack.innerHTML = '';
  lblsTrack.innerHTML = '';
  // Reverse so most recent round appears as the LEFTMOST bar
  const displayData = [..._csHistoryData].reverse();
  displayData.forEach(d => {
    const isCurrent = d.roundNum === _csHistoryData.length;
    const maxColorVal = Math.max(...COLOR_NAMES.map(c => d.totals[c] || 0));
    const winningColors = COLOR_NAMES.filter(c => (d.totals[c] || 0) === maxColorVal && maxColorVal > 0);

    // Bar column — height is the proportional value, sits at bottom via align-items:flex-end
    const col = document.createElement('div');
    col.className = 'cs-mini-bar-col' + (isCurrent ? ' cs-mini-bar-current' : '');
    const heightPct = Math.max(6, Math.round((d.total / maxTotal) * 100));
    col.style.height = heightPct + '%';

    const bar = document.createElement('div');
    bar.className = 'cs-mini-bar';
    COLOR_NAMES.forEach(color => {
      const val = d.totals[color] || 0;
      if (!val) return;
      const seg = document.createElement('div');
      seg.className = 'cs-mini-seg' + (winningColors.includes(color) ? '' : ' cs-mini-dim');
      seg.style.height = ((val / d.total) * 100) + '%';
      seg.style.background = COLOR_HEX[color];
      bar.appendChild(seg);
    });
    col.appendChild(bar);
    barsTrack.appendChild(col);

    // Label — separate strip below bars, same order
    const lbl = document.createElement('div');
    lbl.className = 'cs-mini-bar-lbl' + (isCurrent ? ' cs-mini-bar-current' : '');
    lbl.textContent = d.total;
    lblsTrack.appendChild(lbl);
  });
  // Most recent is on the left — scroll to the start; sync label scroll
  barsTrack.scrollLeft = 0;
  lblsTrack.scrollLeft = 0;
  barsTrack.onscroll = () => { lblsTrack.scrollLeft = barsTrack.scrollLeft; };
}

function csRenderHistogram() {
  const chart = csEl('cs-histChart');
  if (!chart) return;
  const empty = csEl('cs-histEmpty');
  if (empty) empty.remove();

  const maxTotal = Math.max(..._csHistoryData.map(d => d.total), 1);

  const countEl = csEl('cs-histCount'); if (countEl) countEl.textContent = _csHistoryData.length;
  const peakEl = csEl('cs-histPeak'); if (peakEl) peakEl.textContent = maxTotal;

  _csRenderHistBars(chart, maxTotal);

  _csRenderMiniHist();

  // Also render into modal chart (kept in sync for mobile)
  const modalChart = csEl('cs-histChart-modal');
  if (modalChart) {
    const emptyModal = csEl('cs-histEmpty-modal');
    if (emptyModal) emptyModal.remove();
    const cntM = csEl('cs-histCount-modal'); if (cntM) cntM.textContent = _csHistoryData.length;
    const pkM  = csEl('cs-histPeak-modal');  if (pkM)  pkM.textContent  = maxTotal;
    _csRenderHistBars(modalChart, maxTotal);
  }
}

function csRenderRankedColors(totals, grandTotal) {
  const list = csEl('cs-ocRankedList');
  if (!list) return;

  const COLOR_HEX = {RED:'#ff4444',BLUE:'#4488ff',YELLOW:'#ffdd00',PURPLE:'#cc44ff',GREEN:'#33ee66',ORANGE:'#ff8833'};
  const isPrimary = {RED:true,BLUE:true,YELLOW:true,PURPLE:false,GREEN:false,ORANGE:false};

  const entries = Object.entries(totals)
    .filter(([,v]) => v > 0)
    .sort(([,a],[,b]) => b - a);

  const maxVal = entries.length ? entries[0][1] : 0;

  list.innerHTML = '';
  entries.forEach(([col, val], i) => {
    const fKey = col.charAt(0) + col.slice(1).toLowerCase();
    const fEl = csEl('cs-f'+fKey);
    const formula = fEl ? fEl.textContent : '';
    const row = document.createElement('div');
    row.className = 'cs-oc-rank-row' + (val === maxVal ? ' cs-color-winner' : '');
    if (val === maxVal) row.style.borderLeftColor = COLOR_HEX[col];
    row.innerHTML = `
      <span class="cs-oc-rank-val" style="color:${COLOR_HEX[col]}">${val}</span>
      <div class="cs-oc-rank-dot" style="background:${COLOR_HEX[col]};box-shadow:0 0 5px ${COLOR_HEX[col]}"></div>
      <span class="cs-oc-rank-name" style="color:${COLOR_HEX[col]}">${col}</span>
      <span class="cs-oc-rank-tag">${isPrimary[col]?'PRIMARY':'SECONDARY'}</span>
      <span class="cs-oc-rank-formula">${formula && formula !== '—' ? formula : ''}</span>
    `;
    list.appendChild(row);
  });

  const sc = csEl('cs-ocScoringCount');
  if (sc) sc.textContent = entries.length + ' SCORING';
  if (!entries.length) {
    list.innerHTML = '<div class="cs-oc-waiting">NO SCORES YET</div>';
  }
}

