// ── BLOOM — admin sim ────────────────────────────────────────────────
// Single-round event log calls the SQL RPC (authoritative). Stress test
// runs the JS twin `bloomSimulateOne` in-browser to avoid HTTP per sim,
// mirroring the FOF pattern. The two implementations must stay in sync —
// changes to the SQL `bloom_simulate_round` should be mirrored here.
let _bloomInited = false;
let _bloomStressVol = 1000;
let _bloomLastResult = null;
let _bloomRefData = null;        // { flowers, cardEffects, regions }
let _bloomRefDataLoading = null; // in-flight promise

function adminBloomInit() {
  if (_bloomInited) return;
  _bloomInited = true;

  const runBtn   = document.getElementById("admin-bloom-run");
  const copyBtn  = document.getElementById("admin-bloom-copy");
  const stressBtn = document.getElementById("admin-bloom-stress-run");

  if (runBtn)   runBtn.addEventListener("click", () => { void adminBloomRunSingle(); });
  if (copyBtn)  copyBtn.addEventListener("click", () => { adminBloomCopyJson(); });
  if (stressBtn) stressBtn.addEventListener("click", () => { void adminBloomRunStress(); });

  const masterBtn = document.getElementById("admin-bloom-run-master");
  if (masterBtn) masterBtn.addEventListener("click", () => { void runBloomMasterMatrix(); });

  const newCardBtn = document.getElementById("admin-bloom-card-new");
  if (newCardBtn) newCardBtn.addEventListener("click", () => { void bloomCreateCardFlow(); });

  document.querySelectorAll('[data-bloom-vol]').forEach(btn => {
    btn.addEventListener("click", () => {
      document.querySelectorAll('[data-bloom-vol]').forEach(b => b.classList.remove("active"));
      btn.classList.add("active");
      _bloomStressVol = parseInt(btn.dataset.bloomVol, 10) || 1000;
    });
  });

  document.querySelectorAll('.admin-bloom-subtab').forEach(btn => {
    btn.addEventListener("click", () => adminBloomSwitchSubtab(btn.dataset.bloomSubtab));
  });

  // Warm the ref-data cache in the background — sim and editors both need it.
  void loadAdminBloomRefData().catch(err => console.warn("[bloom] ref preload failed", err));
}

function adminBloomSwitchSubtab(target) {
  document.querySelectorAll('.admin-bloom-subtab').forEach(b => {
    b.classList.toggle('active', b.dataset.bloomSubtab === target);
  });
  document.querySelectorAll('.admin-bloom-subtab-content').forEach(c => { c.hidden = true; });
  const el = document.getElementById(`admin-bloom-${target}-content`);
  if (el) el.hidden = false;
  if (target === 'cards' || target === 'regions' || target === 'flowers' || target === 'anims') {
    void (async () => {
      try {
        await loadAdminBloomRefData();
        if (target === 'cards')   renderBloomCardsEditor();
        if (target === 'regions') renderBloomRegionsEditor();
        if (target === 'flowers') renderBloomFlowersEditor();
        if (target === 'anims')   await loadAndRenderBloomAnims();
      } catch (err) {
        const status = document.getElementById('admin-bloom-status');
        if (status) status.textContent = "Failed to load ref data: " + (err.message || err);
      }
    })();
  }
}

// Mulberry32 PRNG (same algorithm as fofRng / public.bloom_rng_next).
function bloomRng(seed) {
  let s = (seed | 0) || 1;
  return function() {
    s = (s + 0x6D2B79F5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// Expand a region's deck_composition {card: count} into a flat array of slugs.
function bloomBuildDeck(deckComposition) {
  const out = [];
  if (!deckComposition) return out;
  for (const [card, count] of Object.entries(deckComposition)) {
    const n = parseInt(count, 10) || 0;
    for (let i = 0; i < n; i++) out.push(card);
  }
  return out;
}

// Inverse: tally a flat deck array back into a {card: count} composition.
function bloomDeckArrToComp(deckArr) {
  const out = {};
  if (!deckArr) return out;
  for (const c of deckArr) out[c] = (out[c] || 0) + 1;
  return out;
}

// Pure JS port of public.bloom_simulate_round. Returns only the fields the
// stress test needs (no per-draw event log) for speed. `deck` is a flat array
// of card slugs (built once per region by the caller). `flowers` must be the
// ordered list from loadAdminBloomRefData (sort_order ascending).
function bloomSimulateOne(deck, flowers, cardEffects, seed) {
  if (seed == null || !Number.isFinite(seed)) seed = Math.floor(Math.random() * 1e9);
  const rng = bloomRng(seed);
  const deckSize = deck.length;
  const nF = flowers.length;
  const scores = new Int32Array(nF);
  const slugs = new Array(nF);
  const targets = new Int32Array(nF);
  for (let i = 0; i < nF; i++) {
    slugs[i]   = flowers[i].slug;
    targets[i] = flowers[i].bloom_target | 0;
  }
  const MAX_DRAWS = 500;

  let winnerIdx = -1;
  let draw = 0;
  while (winnerIdx < 0 && draw < MAX_DRAWS) {
    draw++;
    let pickIdx = (rng() * deckSize) | 0;
    if (pickIdx >= deckSize) pickIdx = deckSize - 1;
    const eff = cardEffects[deck[pickIdx]];

    let bestScore = -1, bestIdx = -1;
    for (let i = 0; i < nF; i++) {
      const delta = (eff[slugs[i]] | 0);
      let s = scores[i] + delta;
      if (s < 0) s = 0;
      scores[i] = s;
      if (s >= targets[i] && s > bestScore) {
        bestScore = s;
        bestIdx = i;
      }
    }
    if (bestIdx >= 0) winnerIdx = bestIdx;
  }

  let viaSafetyCap = false;
  if (winnerIdx < 0) {
    viaSafetyCap = true;
    winnerIdx = 0;
    for (let i = 1; i < nF; i++) if (scores[i] > scores[winnerIdx]) winnerIdx = i;
  }

  const finalScores = {};
  for (let i = 0; i < nF; i++) finalScores[slugs[i]] = scores[i];
  return {
    seed,
    winner: {
      slug: flowers[winnerIdx].slug,
      name: flowers[winnerIdx].name,
      finalScore: scores[winnerIdx],
      viaSafetyCap,
    },
    totalDraws: draw,
    finalScores,
  };
}

// Load + cache flowers / cards / regions. Single request burst, then reused.
async function loadAdminBloomRefData() {
  if (_bloomRefData) return _bloomRefData;
  if (_bloomRefDataLoading) return _bloomRefDataLoading;

  _bloomRefDataLoading = (async () => {
    const [flowersRes, cardsRes, regionsRes] = await Promise.all([
      supabase.from("bloom_flowers").select("flower,display_name,bloom_target,sort_order").order("sort_order"),
      supabase.from("bloom_cards").select("card,display_name,effects,sort_order").order("sort_order"),
      supabase.from("bloom_regions").select("region,display_name,identity,hero_flower,deck_composition,sort_order").order("sort_order"),
    ]);
    if (flowersRes.error) throw flowersRes.error;
    if (cardsRes.error)   throw cardsRes.error;
    if (regionsRes.error) throw regionsRes.error;

    const flowers = (flowersRes.data || []).map(r => ({
      slug: r.flower,
      name: r.display_name,
      bloom_target: r.bloom_target,
      sort_order: r.sort_order,
    }));

    // cardOrder: sorted list of {slug, name, sort_order} — drives editor rows
    // cardEffects: { slug: {flower: int} } — drives the sim
    const cardOrder = (cardsRes.data || []).map(c => ({
      slug: c.card,
      name: c.display_name,
      sort_order: c.sort_order,
    }));
    const cardEffects = {};
    for (const c of cardsRes.data || []) cardEffects[c.card] = { ...(c.effects || {}) };

    // regions: { slug: { ..., deckComp } } — editor mutates deckComp directly
    // regionOrder: sorted list of {slug, name, identity, hero_flower}
    const regions = {};
    const regionOrder = [];
    for (const r of regionsRes.data || []) {
      regions[r.region] = {
        slug: r.region,
        name: r.display_name,
        identity: r.identity,
        hero_flower: r.hero_flower,
        deckComp: { ...(r.deck_composition || {}) },
      };
      regionOrder.push({
        slug: r.region,
        name: r.display_name,
        identity: r.identity,
        hero_flower: r.hero_flower,
      });
    }
    _bloomRefData = { flowers, cardOrder, cardEffects, regionOrder, regions };
    return _bloomRefData;
  })();

  try {
    return await _bloomRefDataLoading;
  } finally {
    _bloomRefDataLoading = null;
  }
}

async function adminBloomRunSingle() {
  const statusEl  = document.getElementById("admin-bloom-status");
  const summaryEl = document.getElementById("admin-bloom-summary");
  const outEl     = document.getElementById("admin-bloom-log-output");
  const regionSel = document.getElementById("admin-bloom-region");
  const seedInput = document.getElementById("admin-bloom-seed");
  if (!outEl) return;

  const region = regionSel && regionSel.value ? regionSel.value : null;
  const rawSeed = seedInput && seedInput.value !== "" ? Number(seedInput.value) : null;
  const seed = Number.isFinite(rawSeed) ? rawSeed : null;

  if (statusEl) statusEl.textContent = "Running…";
  summaryEl && (summaryEl.innerHTML = "");
  outEl.textContent = "";

  try {
    const { data, error } = await supabase.rpc("bloom_simulate_round", {
      p_region: region,
      p_seed:   seed,
    });
    if (error) throw error;
    _bloomLastResult = data;

    if (summaryEl) {
      const w = data.winner || {};
      const r = data.region || {};
      const finals = data.finalScores || {};
      const rows = Object.entries(finals).map(([slug, score]) => {
        const isWinner = slug === w.slug;
        return `<tr${isWinner ? ' style="font-weight:bold"' : ''}><td>${slug}</td><td style="text-align:right">${score}</td></tr>`;
      }).join("");
      summaryEl.innerHTML = `
        <div><strong>${(r.name || '').toUpperCase()}</strong> · deck ${r.deckSize} · seed ${data.seed}</div>
        <div>Winner: <strong>${(w.name || '').toUpperCase()}</strong> — final score ${w.finalScore} in ${data.totalDraws} draws${w.viaSafetyCap ? ' (safety cap)' : ''}</div>
        <table style="margin-top:6px;font-size:12px"><thead><tr><th style="text-align:left">Flower</th><th style="text-align:right">Final</th></tr></thead><tbody>${rows}</tbody></table>
      `;
    }
    outEl.textContent = JSON.stringify(data, null, 2);
    if (statusEl) statusEl.textContent = "";
  } catch (err) {
    if (statusEl) statusEl.textContent = "Error: " + (err.message || err);
    console.error("[bloom] sim failed", err);
  }
}

function adminBloomCopyJson() {
  if (!_bloomLastResult) return;
  navigator.clipboard.writeText(JSON.stringify(_bloomLastResult, null, 2)).catch(() => {});
}

async function adminBloomRunStress() {
  const statusEl  = document.getElementById("admin-bloom-status");
  const resultsEl = document.getElementById("admin-bloom-stress-results");
  const regionSel = document.getElementById("admin-bloom-stress-region");
  if (!resultsEl) return;

  if (statusEl) statusEl.textContent = "Loading reference data…";
  resultsEl.innerHTML = "";
  let ref;
  try {
    ref = await loadAdminBloomRefData();
  } catch (err) {
    if (statusEl) statusEl.textContent = "Failed to load ref data: " + (err.message || err);
    console.error("[bloom] ref load failed", err);
    return;
  }

  const allRegions = Object.keys(ref.regions);
  const regions = (regionSel && regionSel.value && regionSel.value !== "all")
    ? [regionSel.value]
    : allRegions;
  const runs = _bloomStressVol;
  const totalSims = regions.length * runs;

  if (statusEl) statusEl.textContent = `Running ${totalSims.toLocaleString()} sims (in-browser)…`;
  // Yield to the renderer so "Running…" paints before we start the tight loop.
  await new Promise(r => setTimeout(r, 0));

  const t0 = performance.now();
  const tally = {};
  try {
    for (const region of regions) {
      const regionEntry = ref.regions[region];
      if (!regionEntry) continue;
      // Build the deck once per region; mutations to deckComp via the
      // Regions editor are picked up on the next stress run automatically.
      const deck = bloomBuildDeck(regionEntry.deckComp);
      if (deck.length === 0) continue;
      const t = { _runs: 0, _totalDraws: 0 };
      for (let i = 0; i < runs; i++) {
        const result = bloomSimulateOne(deck, ref.flowers, ref.cardEffects);
        const w = result.winner.slug;
        t[w] = (t[w] || 0) + 1;
        t._runs       += 1;
        t._totalDraws += result.totalDraws;
      }
      tally[region] = t;
    }
    const elapsedMs = performance.now() - t0;
    const elapsedSec = (elapsedMs / 1000).toFixed(2);
    const simsPerSec = elapsedMs > 0 ? Math.round(totalSims / (elapsedMs / 1000)).toLocaleString() : "—";

    const flowerOrder = ref.flowers.map(f => f.slug);
    const headerCols  = ref.flowers.map(f => `<th style="text-align:right">${f.name}</th>`).join("");
    const rows = regions.map(region => {
      const t = tally[region];
      const regionName = ref.regions[region]?.name || region;
      if (!t) return `<tr><td>${regionName}</td><td colspan="${flowerOrder.length + 1}">(no data)</td></tr>`;
      const cells = flowerOrder.map(slug => {
        const n = t[slug] || 0;
        const pct = t._runs ? ((n / t._runs) * 100).toFixed(1) : "0.0";
        return `<td style="text-align:right">${pct}%<br><span style="opacity:.6">(${n})</span></td>`;
      }).join("");
      const avgDraws = t._runs ? (t._totalDraws / t._runs).toFixed(1) : "—";
      return `<tr><td><strong>${regionName}</strong></td>${cells}<td style="text-align:right">${avgDraws}</td></tr>`;
    }).join("");

    resultsEl.innerHTML = `
      <div>Completed ${totalSims.toLocaleString()} sims in ${elapsedSec}s (${simsPerSec} sims/sec)</div>
      <table style="margin-top:8px;font-size:12px;border-collapse:collapse">
        <thead><tr><th style="text-align:left">Region</th>${headerCols}<th style="text-align:right">Avg draws</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>
    `;
    if (statusEl) statusEl.textContent = "";
  } catch (err) {
    if (statusEl) statusEl.textContent = "Error: " + (err.message || err);
    console.error("[bloom] stress failed", err);
  }
}

// ── BLOOM — Cards editor ─────────────────────────────────────────────
function bloomFlash(msg) {
  const el = document.getElementById('admin-bloom-status');
  if (!el) return;
  el.textContent = msg;
  setTimeout(() => { if (el.textContent === msg) el.textContent = ''; }, 1800);
}

function bloomEffectSlider(cardSlug, flowerSlug, flowerName, value) {
  const v = Number.isFinite(value) ? value : 0;
  return `
    <div class="admin-fof-slider-row" data-bloom-card="${cardSlug}" data-bloom-flower="${flowerSlug}">
      <label>${flowerName}</label>
      <input type="range" min="-50" max="50" step="1" value="${v}">
      <span class="admin-fof-val">${v}</span>
    </div>
  `;
}

function bloomSlugify(name) {
  return String(name || '').toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function renderBloomCardsEditor() {
  const el = document.getElementById('admin-bloom-cards-grid');
  if (!el || !_bloomRefData) return;
  const { cardOrder, cardEffects, flowers } = _bloomRefData;
  el.innerHTML = cardOrder.map(card => {
    const eff = cardEffects[card.slug] || {};
    const sliders = flowers.map(f =>
      bloomEffectSlider(card.slug, f.slug, f.name, eff[f.slug] ?? 0)
    ).join('');
    return `
      <div class="admin-fof-char-card" data-bloom-card-card="${card.slug}">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
          <input type="text" data-bloom-card-name="${card.slug}" value="${card.name.replace(/"/g, '&quot;')}"
                 style="flex:1;font-weight:700;font-size:14px;padding:4px 6px;background:transparent;border:1px solid #333;color:inherit;font-family:inherit">
          <span style="opacity:.4;font-size:10px;font-family:'JetBrains Mono',monospace">${card.slug}</span>
        </div>
        ${sliders}
        <div class="admin-fof-char-actions">
          <button type="button" class="admin-fof-reset" data-bloom-card-reset="${card.slug}">Reset</button>
          <button type="button" class="admin-fof-save primary" data-bloom-card-save="${card.slug}">Save</button>
          <button type="button" class="admin-fof-reset" data-bloom-card-delete="${card.slug}"
                  style="margin-left:auto;color:#c33;border-color:#c33">Delete</button>
        </div>
      </div>
    `;
  }).join('');
  attachBloomCardEditorHandlers();
}

function attachBloomCardEditorHandlers() {
  document.querySelectorAll('[data-bloom-card][data-bloom-flower] input[type=range]').forEach(input => {
    input.addEventListener('input', (e) => {
      const row = e.target.closest('[data-bloom-card][data-bloom-flower]');
      const cardSlug = row.dataset.bloomCard;
      const flowerSlug = row.dataset.bloomFlower;
      const val = parseInt(e.target.value, 10) || 0;
      if (!_bloomRefData.cardEffects[cardSlug]) _bloomRefData.cardEffects[cardSlug] = {};
      _bloomRefData.cardEffects[cardSlug][flowerSlug] = val;
      row.querySelector('.admin-fof-val').textContent = String(val);
      const cardEl = row.closest('.admin-fof-char-card');
      if (cardEl) cardEl.classList.add('dirty');
    });
  });
  document.querySelectorAll('[data-bloom-card-name]').forEach(input => {
    input.addEventListener('input', (e) => {
      const slug = e.target.dataset.bloomCardName;
      const entry = _bloomRefData.cardOrder.find(c => c.slug === slug);
      if (entry) entry.name = e.target.value;
      const cardEl = e.target.closest('.admin-fof-char-card');
      if (cardEl) cardEl.classList.add('dirty');
    });
  });
  document.querySelectorAll('[data-bloom-card-save]').forEach(btn => {
    btn.addEventListener('click', () => { void bloomSaveCard(btn.dataset.bloomCardSave); });
  });
  document.querySelectorAll('[data-bloom-card-reset]').forEach(btn => {
    btn.addEventListener('click', () => { void bloomReloadEditors(); });
  });
  document.querySelectorAll('[data-bloom-card-delete]').forEach(btn => {
    btn.addEventListener('click', () => { void bloomDeleteCardFlow(btn.dataset.bloomCardDelete); });
  });
}

async function bloomSaveCard(slug) {
  if (!_bloomRefData) return;
  const effects = _bloomRefData.cardEffects[slug];
  const entry   = _bloomRefData.cardOrder.find(c => c.slug === slug);
  if (!effects || !entry) return;
  const displayName = (entry.name || '').trim();
  if (!displayName) { bloomFlash(`Name cannot be empty`); return; }
  bloomFlash(`Saving ${slug}…`);
  const { error } = await supabase
    .from('bloom_cards')
    .update({ effects, display_name: displayName, updated_at: new Date().toISOString() })
    .eq('card', slug);
  if (error) { bloomFlash(`Save error: ${error.message}`); console.error('[bloom] save card', error); return; }
  const cardEl = document.querySelector(`[data-bloom-card-card="${slug}"]`);
  if (cardEl) cardEl.classList.remove('dirty');
  bloomFlash(`Saved ${slug}`);
}

async function bloomDeleteCardFlow(slug) {
  if (!_bloomRefData) return;
  const entry = _bloomRefData.cardOrder.find(c => c.slug === slug);
  const name  = entry?.name || slug;
  if (!window.confirm(`Delete card "${name}" (${slug})?\n\nThis also removes it from every region's deck composition. Cannot be undone.`)) return;
  bloomFlash(`Deleting ${slug}…`);
  const { error } = await supabase.rpc('bloom_delete_card', { p_card: slug });
  if (error) { bloomFlash(`Delete error: ${error.message}`); console.error('[bloom] delete card', error); return; }
  await bloomReloadEditors();
  bloomFlash(`Deleted ${slug}`);
}

async function bloomCreateCardFlow() {
  if (!_bloomRefData) {
    try { await loadAdminBloomRefData(); }
    catch (err) { bloomFlash(`Load error: ${err.message || err}`); return; }
  }
  const nameRaw = window.prompt('New card name:', '');
  if (nameRaw == null) return;
  const name = nameRaw.trim();
  if (!name) { bloomFlash('Name required'); return; }
  const slug = bloomSlugify(name);
  if (!slug) { bloomFlash('Could not derive slug from name'); return; }
  if (_bloomRefData.cardEffects[slug]) {
    bloomFlash(`Slug "${slug}" already exists`); return;
  }
  // Default effects: 0 for every known flower.
  const effects = {};
  for (const f of _bloomRefData.flowers) effects[f.slug] = 0;
  // Sort order: end of list.
  const maxOrder = _bloomRefData.cardOrder.reduce((m, c) => Math.max(m, c.sort_order | 0), 0);
  bloomFlash(`Creating ${slug}…`);
  const { error } = await supabase
    .from('bloom_cards')
    .insert({
      card: slug,
      display_name: name,
      effects,
      sort_order: maxOrder + 1,
    });
  if (error) { bloomFlash(`Create error: ${error.message}`); console.error('[bloom] create card', error); return; }
  await bloomReloadEditors();
  bloomFlash(`Created ${slug}`);
}

// ── BLOOM — Regions editor ───────────────────────────────────────────
function bloomCountSlider(regionSlug, cardSlug, cardName, value) {
  const v = Number.isFinite(value) ? value : 0;
  return `
    <div class="admin-fof-slider-row" data-bloom-region="${regionSlug}" data-bloom-region-card="${cardSlug}">
      <label>${cardName}</label>
      <input type="range" min="0" max="50" step="1" value="${v}">
      <span class="admin-fof-val">${v}</span>
    </div>
  `;
}

function bloomDeckTotal(deckComp) {
  let n = 0;
  for (const k in deckComp) n += deckComp[k] | 0;
  return n;
}

function renderBloomRegionsEditor() {
  const el = document.getElementById('admin-bloom-regions-grid');
  if (!el || !_bloomRefData) return;
  const { regionOrder, regions, cardOrder } = _bloomRefData;
  el.innerHTML = regionOrder.map(region => {
    const entry = regions[region.slug];
    const comp = entry?.deckComp || {};
    const total = bloomDeckTotal(comp);
    const sliders = cardOrder.map(card =>
      bloomCountSlider(region.slug, card.slug, card.name, comp[card.slug] ?? 0)
    ).join('');
    return `
      <div class="admin-fof-char-card" data-bloom-region-card="${region.slug}">
        <h3>${region.name.toUpperCase()}
          <span style="float:right;font-size:11px;opacity:.7">DECK: <strong data-bloom-region-total="${region.slug}">${total}</strong></span>
        </h3>
        <div style="font-size:11px;opacity:.6;margin:-4px 0 8px">${region.identity || ''}${region.hero_flower ? ' · hero: ' + region.hero_flower : ''}</div>
        ${sliders}
        <div class="admin-fof-char-actions">
          <button type="button" class="admin-fof-reset" data-bloom-region-reset="${region.slug}">Reset</button>
          <button type="button" class="admin-fof-save primary" data-bloom-region-save="${region.slug}">Save</button>
        </div>
      </div>
    `;
  }).join('');
  attachBloomRegionEditorHandlers();
}

function attachBloomRegionEditorHandlers() {
  document.querySelectorAll('[data-bloom-region][data-bloom-region-card] input[type=range]').forEach(input => {
    input.addEventListener('input', (e) => {
      const row = e.target.closest('[data-bloom-region][data-bloom-region-card]');
      const regionSlug = row.dataset.bloomRegion;
      const cardSlug   = row.dataset.bloomRegionCard;
      const val = parseInt(e.target.value, 10) || 0;
      const entry = _bloomRefData.regions[regionSlug];
      if (!entry) return;
      if (val > 0) entry.deckComp[cardSlug] = val;
      else         delete entry.deckComp[cardSlug];
      row.querySelector('.admin-fof-val').textContent = String(val);
      const totalEl = document.querySelector(`[data-bloom-region-total="${regionSlug}"]`);
      if (totalEl) totalEl.textContent = String(bloomDeckTotal(entry.deckComp));
      const cardEl = row.closest('.admin-fof-char-card');
      if (cardEl) cardEl.classList.add('dirty');
    });
  });
  document.querySelectorAll('[data-bloom-region-save]').forEach(btn => {
    btn.addEventListener('click', () => { void bloomSaveRegion(btn.dataset.bloomRegionSave); });
  });
  document.querySelectorAll('[data-bloom-region-reset]').forEach(btn => {
    btn.addEventListener('click', () => { void bloomReloadEditors(); });
  });
}

async function bloomSaveRegion(slug) {
  if (!_bloomRefData) return;
  const entry = _bloomRefData.regions[slug];
  if (!entry) return;
  bloomFlash(`Saving ${slug}…`);
  const { error } = await supabase
    .from('bloom_regions')
    .update({ deck_composition: entry.deckComp, updated_at: new Date().toISOString() })
    .eq('region', slug);
  if (error) { bloomFlash(`Save error: ${error.message}`); console.error('[bloom] save region', error); return; }
  const cardEl = document.querySelector(`[data-bloom-region-card="${slug}"]`);
  if (cardEl) cardEl.classList.remove('dirty');
  bloomFlash(`Saved ${slug}`);
}

async function bloomReloadEditors() {
  _bloomRefData = null;
  _bloomRefDataLoading = null;
  try {
    await loadAdminBloomRefData();
    renderBloomCardsEditor();
    renderBloomRegionsEditor();
    renderBloomFlowersEditor();
  } catch (err) {
    bloomFlash(`Reload error: ${err.message || err}`);
  }
}

// ── BLOOM — Flowers editor (rename only; slugs are FKs) ──────────────
