// ── BLOOM — game state machine (player flow, mirror of FOF) ─────────
const bloomGame = {
  state: 'idle',            // 'idle' | 'selecting' | 'resolving' | 'resolved'
  roundId: null,
  region: null,             // { slug, name, identity, hero_flower }
  candidates: [],           // [{ flower, name, accent_color, bloom_target, win_pct, is_hero }]
  wagers: {},               // { flower_slug: amount, ... } — multi-flower wagers
  resolution: null,         // payload from bloom_lock_round
};

// Sum of all chip stacks across every flower's wager spot.
function bloomTotalWager() {
  let t = 0;
  for (const k in bloomGame.wagers) t += Number(bloomGame.wagers[k]) || 0;
  return t;
}

async function bloomRouteOpen() {
  try { bloomTeardownStages(); } catch (e) { /* noop on first open */ }
  bloomGame.state = 'idle';
  bloomGame.roundId = null;
  bloomGame.region = null;
  bloomGame.candidates = [];
  bloomGame.wagers = {};
  bloomGame.resolution = null;
  bloomRefreshBalance();
  // Preload ref data so the deck preview can render as soon as a round
  // is started AND the idle view's region-pick tiles can populate. Re-
  // renders the stage once the ref lands so both views catch up.
  loadAdminBloomRefData()
    .then(() => {
      if (bloomGame.state === 'idle' || bloomGame.state === 'selecting') {
        bloomRenderStage();
      }
    })
    .catch(err => console.warn('[bloom] ref preload failed', err));
  bloomRenderStage();
}

function bloomRefreshBalance() {
  const el = document.getElementById('bloom-page-balance-val');
  if (!el) return;
  const credits = currentProfile?.credits;
  el.textContent = (credits == null) ? '—' : '$' + Number(credits).toFixed(2);
}

function bloomRenderStage() {
  const stage = document.getElementById('bloom-stage');
  if (!stage) return;
  stage.dataset.state = bloomGame.state;
  if (bloomGame.state === 'idle')           stage.innerHTML = bloomViewIdle();
  // Selecting, resolving and resolved all share the same shell —
  // the race plays out in-place on the selection screen. Tiles
  // hide/show their wager-spot vs. score-readout via the state attr.
  else if (bloomGame.state === 'selecting') stage.innerHTML = bloomViewSelecting();
  else if (bloomGame.state === 'resolving') stage.innerHTML = bloomViewSelecting();
  else if (bloomGame.state === 'resolved')  stage.innerHTML = bloomViewSelecting();
  bloomAttachStageHandlers();
}

function bloomViewIdle() {
  // Region tiles + a Random option. Click one to deal that region.
  // Slugs come from _bloomRefData (preloaded in bloomRouteOpen). If the
  // ref hasn't loaded yet we just show the random button; the ref
  // preload re-renders this view once it lands.
  const ref = _bloomRefData;
  // Each region is its own field-guide profile card (rendered into the
  // slot by BloomRegionCards in bloomAttachStageHandlers). The card already
  // carries the region name, palette and specimen, so no separate label.
  const tiles = (ref && ref.regionOrder ? ref.regionOrder : []).map(r => `
    <button type="button" class="bloom-region-pick" data-bloom-region="${r.slug}" aria-label="${r.name || r.slug}">
      <div class="bloom-region-pick-card" data-bloom-pick-card="${r.slug}"></div>
    </button>
  `).join('');
  return `
    <div class="fof-idle bloom-idle">
      <div class="fof-idle-headline">Pick your region.</div>
      <p class="fof-idle-sub">Five flowers, one bloom target. Weather cards drive the race. Pick a specific region or roll random.</p>
      <div class="bloom-region-pick-grid">
        ${tiles}
        <button type="button" class="bloom-region-pick is-random" data-bloom-region="" aria-label="Random region">
          <div class="bloom-region-pick-card bloom-random-card">
            <span class="bloom-random-glyph">⚄</span>
            <span class="bloom-random-name">RANDOM</span>
            <span class="bloom-random-sub">server picks for you</span>
          </div>
        </button>
      </div>
    </div>
  `;
}

function bloomFlowerCard(c) {
  const accent     = c.accent_color || '#888';
  const name       = (c.name || '').toUpperCase();
  const winPct     = Number(c.win_pct) * 100;
  const payout     = (c.win_pct > 0) ? (1 / Number(c.win_pct)).toFixed(2) : '—';
  const heroCls    = c.is_hero ? 'is-hero' : '';
  const wagerAmt   = Number((bloomGame.wagers || {})[c.flower] || 0);
  const wagerCls   = wagerAmt > 0 ? 'has-wager' : '';
  const potential  = (winPct > 0 && wagerAmt > 0) ? (wagerAmt / Number(c.win_pct)).toFixed(0) : null;
  const hasWagerCls = wagerAmt > 0 ? 'has-wager' : '';
  const inRace = bloomGame.state === 'resolving' || bloomGame.state === 'resolved';
  const emptyWagerText = inRace ? '$0' : 'TAP TO BET';
  const wagerText = wagerAmt > 0 ? '$' + wagerAmt : emptyWagerText;
  // Pct slot is dual-purpose:
  //   selecting → win probability
  //   resolving → live race score (driven by bloomPlayEvents)
  //   resolved  → final score from the resolution payload
  let pctValue;
  if (bloomGame.state === 'selecting') {
    pctValue = Number.isFinite(winPct) ? winPct.toFixed(1) : null;
  } else if (bloomGame.state === 'resolving') {
    pctValue = '0';
  } else {
    const finalScores = (bloomGame.resolution?.round_details?.finalScores) || {};
    // Show the true final score — don't clamp. Winners that hit
    // their target on a high-effect draw can finish well over 100%
    // and the recap should reflect that, not flatten everyone to 100.
    const s = Number(finalScores[c.flower]) || 0;
    pctValue = String(s);
  }
  const pctText = pctValue == null ? '—' : pctValue + '%';
  return `
    <div class="bloom-pick-tile ${heroCls} ${hasWagerCls}" data-bloom-flower="${c.flower}" style="--bloom-accent:${accent}">
      <div class="bloom-pick-stage">
        <div class="bloom-pick-vbar">
          <div class="bloom-pick-vbar-fill" data-bloom-flower-bar="${c.flower}" style="background:${accent}"></div>
        </div>
        <div class="bloom-pick-flower" data-bloom-select-host="${c.flower}"></div>
      </div>
      <div class="bloom-pick-meta">
        <div class="bloom-pick-name" style="color:${accent}">${name}</div>
        <div class="bloom-pick-odds">
          <span class="bloom-pick-pct" data-bloom-flower-pct="${c.flower}">${pctText}</span>
          <span class="bloom-pick-payout">${payout}x payout</span>
        </div>
      </div>
      <button type="button" class="bloom-wager-spot ${wagerCls}" data-bloom-wager-spot="${c.flower}" aria-label="Stack a chip on ${name}">
        <span class="bloom-wager-spot-amount">${wagerText}</span>
        <span class="bloom-wager-spot-potential${potential ? '' : ' is-empty'}">${potential ? '→ $' + potential : '&nbsp;'}</span>
      </button>
    </div>
  `;
}

function bloomViewSelecting() {
  const region = bloomGame.region || {};
  const cards = bloomGame.candidates.map(c => bloomFlowerCard(c)).join('');
  const state = bloomGame.state;
  const subTitle = (state === 'selecting')
    ? '// STACK CHIPS ON ANY FLOWER · BET MULTIPLE TO HEDGE'
    : '// RACE IN PROGRESS';
  const resolved = state === 'resolved' ? bloomViewResolvedBanner() : '';
  return `
    <div class="bloom-selecting" data-bloom-state="${state}">
      <div class="bloom-layout">
        <div class="bloom-region-panel">
          <div class="bloom-region-label">// REGION</div>
          <div class="bloom-region-name">${(region.name || '').toUpperCase()}</div>
          <div class="bloom-region-image" id="bloom-region-image"
               data-bloom-region-species="${region.hero_flower || ''}"></div>
          <div class="bloom-region-identity">${region.identity || ''}</div>
          <div class="bloom-region-hero">Hero flower: ${region.hero_flower || '—'}</div>
          <div class="bloom-weather-banner" id="bloom-weather-banner"></div>
          ${resolved}
        </div>
        <div class="bloom-right-col">
          <div class="bloom-flower-panel">
            <div class="bloom-flower-label">${subTitle}</div>
            <div class="bloom-pick-row">${cards}</div>
          </div>
          <div class="bloom-history-panel">
            <div class="bloom-history-label">${state === 'selecting' ? '// DECK' : '// EVENT LOG'}</div>
            ${state === 'selecting'
              ? `<div class="bloom-card-history" id="bloom-card-history" aria-label="Cards in the deck"></div>`
              : `<div class="fof-event-log" id="bloom-event-log" aria-label="Cards drawn this round"></div>`}
          </div>
        </div>
      </div>
    </div>
  `;
}

function bloomViewResolvedBanner() {
  const r = bloomGame.resolution || {};
  const won = r.round_winner === 'hero';
  const headline = won ? '★ BLOOMED' : 'WITHERED';
  const profit = Number(r.net_profit) || 0;
  const profitDisplay = (profit >= 0 ? '+$' : '-$') + Math.abs(profit).toFixed(2);
  const winnerName = (bloomGame.candidates.find(c => c.flower === r.winner_flower)?.name) || r.winner_flower || '—';
  return `
    <div class="bloom-resolved-banner ${won ? 'won' : 'lost'}">
      <div class="bloom-resolved-headline">${headline}</div>
      <div class="bloom-resolved-row"><span>Winner</span><strong>${(winnerName || '').toUpperCase()}</strong></div>
      <div class="bloom-resolved-row"><span>Wagered</span><strong>$${Number(r.total_wagered).toFixed(2)}</strong></div>
      <div class="bloom-resolved-row"><span>Returned</span><strong>$${Number(r.total_returned).toFixed(2)}</strong></div>
      <div class="bloom-resolved-row"><span>Net</span><strong>${profitDisplay}</strong></div>
      <button type="button" class="fof-btn fof-btn-primary" id="bloom-again-btn">⬡ START NEW ROUND</button>
    </div>
  `;
}

function bloomViewResolving() {
  // 5 flower SVG containers in a row over a biome backdrop. Each column is
  // a 2-section layout (svg wrap + meta block) with the meta absolutely
  // pinned to the bottom so all seeds line up on the same baseline
  // regardless of how the species name wraps. Weather name surfaces in
  // the biome's top-right corner; per-flower +N / -N toasts float above
  // the seed; progress bars adopt the growth-row visual treatment.
  const region = bloomGame.region || {};
  // Each flower lives in its own bg-col card (built dynamically by
  // bloom-growth.js / buildBiomeCard during bloomPlayEvents). The shell
  // here just provides the row container + a weather overlay layer that
  // floats above the cards.
  return `
    <div class="bloom-resolving">
      <div class="bloom-resolving-header">
        <div class="bloom-header-slot bloom-header-slot-left">
          <div class="bloom-header-kicker">REGION</div>
          <div class="bloom-resolving-region">${(region.name || '').toUpperCase()}</div>
        </div>
        <div class="bloom-header-slot bloom-header-slot-weather">
          <div class="bloom-header-kicker">WEATHER</div>
          <div class="bloom-weather-card">
            <div class="bloom-weather-card-fx" id="bloom-card-overlay"></div>
            <div class="bloom-weather-card-name" id="bloom-weather-label">—</div>
          </div>
        </div>
        <div class="bloom-header-slot bloom-header-slot-right">
          <div class="bloom-header-kicker">YOUR PICK</div>
          <div class="bloom-resolving-picked"><strong>$${bloomTotalWager()} STACKED</strong></div>
        </div>
      </div>
      <div class="bloom-grow-stage" id="bloom-grow-stage">
        <div class="bloom-grow-row" id="bloom-growth-row"></div>
      </div>
      <div class="fof-event-log" id="bloom-event-log"></div>
    </div>
  `;
}

function bloomViewResolved() {
  const r = bloomGame.resolution || {};
  const won  = r.round_winner === 'hero';
  const tone = won ? 'win' : 'loss';
  const headline = won ? 'BLOOMED!' : 'WITHERED';
  const profitNum = Number(r.net_profit) || 0;
  const profitDisplay = (profitNum >= 0 ? '+$' : '-$') + Math.abs(profitNum).toFixed(2);
  const winnerName = (bloomGame.candidates.find(c => c.flower === r.winner_flower)?.name) || r.winner_flower;
  // Per-stack breakdown: { flower → wager } from the resolution payload.
  const stacks = r.wagers || {};
  const stackRows = Object.keys(stacks).map(slug => {
    const cand = bloomGame.candidates.find(c => c.flower === slug);
    const name = (cand?.name || slug).toUpperCase();
    const amt = Number(stacks[slug]).toFixed(2);
    const isWinner = slug === r.winner_flower;
    return `<tr${isWinner ? ' class="bloom-stack-won"' : ''}><td>${name}${isWinner ? ' ★' : ''}</td><td>$${amt}</td></tr>`;
  }).join('');
  return `
    <div class="fof-resolved fof-resolved-${tone}">
      <div class="fof-resolved-headline">${headline}</div>
      <table class="fof-resolved-table">
        <tr><td>Region</td><td>${(bloomGame.region?.name || r.region || '').toUpperCase()}</td></tr>
        <tr><td>Bloomed</td><td>${(winnerName || '').toUpperCase()}</td></tr>
        <tr><td>Total wagered</td><td>$${Number(r.total_wagered).toFixed(2)}</td></tr>
        <tr><td>Returned</td><td>$${Number(r.total_returned).toFixed(2)}</td></tr>
        <tr><td>Net</td><td><strong>${profitDisplay}</strong></td></tr>
        <tr><td>New balance</td><td>$${Number(r.new_balance).toFixed(2)}</td></tr>
      </table>
      ${stackRows ? `<table class="fof-resolved-table" style="margin-top:8px"><thead><tr><th colspan="2">Your stacks</th></tr></thead><tbody>${stackRows}</tbody></table>` : ''}
      <button type="button" class="fof-btn fof-btn-primary" id="bloom-again-btn">START NEW ROUND</button>
    </div>
  `;
}

function bloomAttachStageHandlers() {
  const startBtn = document.getElementById('bloom-start-btn');
  if (startBtn) startBtn.addEventListener('click', () => { void bloomStartRound(); });

  // Region-pick tiles on the idle view. Empty data-bloom-region ('')
  // means "random" — bloomStartRound omits p_region and the server
  // picks for you.
  document.querySelectorAll('[data-bloom-region]').forEach(btn => {
    btn.addEventListener('click', () => {
      const slug = btn.dataset.bloomRegion || null;
      void bloomStartRound(slug);
    });
  });

  const againBtn = document.getElementById('bloom-again-btn');
  if (againBtn) againBtn.addEventListener('click', () => { void bloomStartRound(); });

  // Render the field-guide region card into the region image slot,
  // keyed by the bloom DB region slug (BloomRegionCards maps it to
  // its own region id internally).
  const regionImage = document.getElementById('bloom-region-image');
  if (regionImage && window.BloomRegionCards && window.BloomRegionCards.renderCard) {
    const dbSlug = (bloomGame.region && bloomGame.region.slug) || '';
    try { window.BloomRegionCards.renderCard(dbSlug, regionImage); }
    catch (e) { /* noop */ }
  }

  // Idle region picker — render each region's field-guide card into its
  // pick slot so the player chooses from the actual profile cards.
  if (window.BloomRegionCards && window.BloomRegionCards.renderCard) {
    document.querySelectorAll('[data-bloom-pick-card]').forEach(el => {
      try { window.BloomRegionCards.renderCard(el.dataset.bloomPickCard, el); }
      catch (e) { /* noop */ }
    });
  }

  // Deck preview during 'selecting': lay cards out in 5 columns matching
  // the flower row. Each card is parked under the flower it helps most
  // (highest effect delta), so the player can scan each column to see
  // exactly which cards favor that flower.
  if (bloomGame.state === 'selecting') {
    const historyEl = document.getElementById('bloom-card-history');
    const slug = (bloomGame.region && bloomGame.region.slug) || '';
    const ref  = _bloomRefData;
    if (historyEl && ref && ref.regions && ref.regions[slug]) {
      const deck = ref.regions[slug].deckComp || {};
      const nameBySlug = {};
      (ref.cardOrder || []).forEach(c => { nameBySlug[c.slug] = c.name || c.slug; });
      const candidates = bloomGame.candidates || [];
      const cardsByFlower = {};
      candidates.forEach(c => { cardsByFlower[c.flower] = []; });

      Object.keys(deck)
        .filter(k => Number(deck[k]) > 0)
        .forEach(card => {
          const effects = (ref.cardEffects && ref.cardEffects[card]) || {};
          // Find the candidate flower with the highest delta — that's
          // the card's "primary beneficiary". Ties break to the LAST
          // tied candidate (>=) so cards distribute across columns
          // rather than piling up on the first-listed flower.
          let bestFlower = candidates[0]?.flower;
          let bestDelta  = -Infinity;
          candidates.forEach(c => {
            const d = Number(effects[c.flower] || 0);
            if (d >= bestDelta) {
              bestDelta  = d;
              bestFlower = c.flower;
            }
          });
          if (bestFlower && cardsByFlower[bestFlower]) {
            cardsByFlower[bestFlower].push({ card, count: Number(deck[card]) });
          }
        });

      historyEl.classList.add('is-deck-grid');
      historyEl.innerHTML = candidates.map(c => {
        const cards = (cardsByFlower[c.flower] || [])
          .sort((a, b) => (nameBySlug[a.card] || a.card).localeCompare(nameBySlug[b.card] || b.card))
          .map(({ card, count }) => bloomBuildCardChip(
            card,
            nameBySlug[card],
            (ref.cardEffects && ref.cardEffects[card]) || {},
            { mode: 'deck', count }
          )).join('');
        return `<div class="bloom-deck-col" data-flower="${c.flower}">${cards}</div>`;
      }).join('');
    }
  } else {
    // Race / resolved — make sure the deck-grid class doesn't linger
    // when the row should be a horizontal scroll of live draws.
    const historyEl = document.getElementById('bloom-card-history');
    if (historyEl) historyEl.classList.remove('is-deck-grid');
  }

  // Per-tile wager spots — click adds one chip of the currently selected
  // denomination (from the global chip rack) to wagers[flower]. Cap the
  // total across all stacks at currentProfile.credits.
  document.querySelectorAll('[data-bloom-wager-spot]').forEach(spot => {
    spot.addEventListener('click', () => {
      const slug = spot.dataset.bloomWagerSpot;
      const denom = Number(selectedChip) || 0;
      if (!slug || denom <= 0) return;
      const cap = Number(currentProfile?.credits ?? Infinity);
      const remaining = Math.max(0, cap - bloomTotalWager());
      if (remaining <= 0) return;
      const add = Math.min(denom, remaining);
      bloomGame.wagers[slug] = Number(bloomGame.wagers[slug] || 0) + add;
      bloomRenderStage();
    });
  });

  // Mount FlowerMorphs into each tile's [data-bloom-select-host] slot.
  // Initial stage depends on state: selecting → 10 (bloomed preview),
  // resolving → 0 (seed, animates up via bloomPlayEvents), resolved →
  // bloomScoreToStage of the final score (held).
  // Re-render rebuilds the HTML so we tear down + remount each time;
  // bloomPlayEvents then reads from _bloomMorphs to drive the race.
  bloomTeardownMorphs();
  if (window.FlowerMorphs && window.FlowerMorphs.Mount &&
      (bloomGame.state === 'selecting' || bloomGame.state === 'resolving' || bloomGame.state === 'resolved')) {
    const finalScores = (bloomGame.resolution && bloomGame.resolution.round_details && bloomGame.resolution.round_details.finalScores) || {};
    for (const c of bloomGame.candidates) {
      const host = document.querySelector(`[data-bloom-select-host="${c.flower}"]`);
      if (!host) continue;
      let initialStage = 10;            // selecting: bloomed preview
      let initialScore = 0;
      if (bloomGame.state === 'resolving') {
        initialStage = 0;                // seed; race grows from here
        initialScore = 0;
      } else if (bloomGame.state === 'resolved') {
        initialScore = Number(finalScores[c.flower] ?? 0);
        initialStage = bloomScoreToStage(initialScore);
      }
      try {
        const m = window.FlowerMorphs.Mount({
          container: host,
          species:   bloomBundleSpeciesId(c.flower),
          stage:     initialStage,
          baseline:  false,
        });
        _bloomMorphs.push({
          slug:         c.flower,
          morph:        m,
          currentStage: initialStage,
          prevScore:    initialScore,
        });
      } catch (e) { console.warn('[bloom] morph mount failed', c.flower, e); }
    }

    // Resolved state re-render: backfill the vbar height + score text
    // from the final scores so the post-race state sticks.
    if (bloomGame.state === 'resolved') {
      for (const slug of Object.keys(finalScores)) {
        const s = Number(finalScores[slug]) || 0;
        const bar = document.querySelector(`[data-bloom-flower-bar="${slug}"]`);
        // vbar stays capped at 100% visually so it doesn't overflow
        // the tile; text shows the true % so a 113% winner reads honestly.
        if (bar) bar.style.height = Math.min(100, s) + '%';
        const pct = document.querySelector(`[data-bloom-flower-pct="${slug}"]`);
        if (pct) pct.textContent = s + '%';
      }
      // Persist the winner gold glow across the resolved re-render.
      const winnerSlug = bloomGame.resolution && bloomGame.resolution.winner_flower;
      if (winnerSlug) {
        const tile = document.querySelector(`[data-bloom-flower="${winnerSlug}"]`);
        if (tile) tile.classList.add('bloom-winner');
      }
      // Backfill the draw event log from the saved events so the
      // log survives the resolving → resolved re-render. Number draws
      // forward (1..N), then emit newest-first so the last card sits
      // on top — matching the live prepend order.
      const logEl = document.getElementById('bloom-event-log');
      const events = (bloomGame.resolution?.round_details?.events) || [];
      if (logEl && events.length) {
        const lines = [];
        let turnNum = 0;
        for (const ev of events) {
          if (ev.type !== 'DRAW') continue;
          turnNum += 1;
          lines.push(bloomDrawLineHTML(ev, turnNum));
        }
        logEl.innerHTML = lines.reverse().join('');
        logEl.scrollTop = 0;
      }
    }
  }

  // Persistent chip rack — visible across selecting / resolving /
  // resolved so the user always sees their denominations + can drive
  // the round forward with the rack's primary button.
  const chipBar = document.getElementById('bloom-chipBar');
  if (chipBar) {
    chipBar.hidden = bloomGame.state === 'idle';
    chipBar.dataset.bloomRackState = bloomGame.state;
  }
  if (bloomGame.state !== 'idle') {
    bloomEnsureChipRack();
    bloomUpdateBeginBtn();
  }
}

// One-time wiring for the persistent chip rack at the bottom of
// #bloom-view. Populates the chip selector, attaches handlers to the
// Edit / Clear / Begin buttons, and registers chip-click handlers that
// set the GLOBAL `selectedChip` (RTN semantics — chip click chooses
// denomination, tile click stacks one of that denomination).
let _bloomChipRackWired = false;
function bloomEnsureChipRack() {
  bloomRenderChipRackButtons();
  if (_bloomChipRackWired) return;
  _bloomChipRackWired = true;

  const editBtn = document.getElementById('bloom-chipRackEdit');
  if (editBtn) editBtn.addEventListener('click', () => {
    if (typeof openChipEditorModal === 'function') openChipEditorModal();
  });

  const clearBtn = document.getElementById('bloom-clearBetsBtn');
  if (clearBtn) clearBtn.addEventListener('click', () => {
    bloomGame.wagers = {};
    bloomRenderStage();
  });

  const beginBtn = document.getElementById('bloom-begin-btn');
  if (beginBtn) beginBtn.addEventListener('click', () => {
    // Single button drives the round forward — its action depends on
    // bloomGame.state. bloomUpdateBeginBtn keeps the label in sync.
    if (bloomGame.state === 'selecting') return void bloomBeginRound();
    if (bloomGame.state === 'resolving') return bloomDrawNext();
    if (bloomGame.state === 'resolved')  return void bloomStartRound();
  });

  const autoToggle = document.getElementById('bloom-autoDrawToggle');
  if (autoToggle) {
    autoToggle.checked = !!bloomGame.autoDraw;
    autoToggle.addEventListener('change', () => {
      bloomGame.autoDraw = !!autoToggle.checked;
      // If the user flips auto on mid-race, kick off the timer right
      // away. If they flip it off, kill the timer. Selecting state just
      // arms the flag for the next round.
      if (bloomGame.state === 'resolving') {
        if (bloomGame.autoDraw) bloomStartAutoDraw();
        else bloomStopAutoDraw();
      }
      bloomUpdateBeginBtn();
    });
  }
}

// ── Auto-draw — fires one bloomDrawNext every BLOOM_AUTO_DRAW_MS while
// bloomGame.autoDraw is true and the round is resolving. Self-stops when
// the queue empties or the state transitions out of 'resolving'.
const BLOOM_AUTO_DRAW_MS = 500;
let _bloomAutoDrawTimer = null;
function bloomStopAutoDraw() {
  if (_bloomAutoDrawTimer) {
    clearInterval(_bloomAutoDrawTimer);
    _bloomAutoDrawTimer = null;
  }
}
function bloomStartAutoDraw() {
  if (bloomGame.state !== 'resolving') return;
  bloomStopAutoDraw();
  // Fire one immediately for snappy feedback, then continue on cadence.
  bloomDrawNext();
  if (bloomGame.state === 'resolving') {
    _bloomAutoDrawTimer = setInterval(() => {
      if (bloomGame.state !== 'resolving' || !bloomGame.autoDraw) {
        bloomStopAutoDraw();
        return;
      }
      bloomDrawNext();
    }, BLOOM_AUTO_DRAW_MS);
  }
}

function bloomRenderChipRackButtons() {
  const el = document.getElementById('bloom-chipSelector');
  if (!el || !Array.isArray(chipDenominations)) return;
  el.innerHTML = chipDenominations.map(value => `
    <button type="button" class="chip-choice${value === selectedChip ? ' active' : ''}"
      data-value="${value}"
      data-tone="${typeof getRunTheNumbersChipRackToneIndex === 'function' ? getRunTheNumbersChipRackToneIndex(value) : 0}"
      role="radio"
      aria-checked="${value === selectedChip ? 'true' : 'false'}">${value}</button>
  `).join('');
  el.querySelectorAll('.chip-choice').forEach(btn => {
    btn.addEventListener('click', () => {
      const val = Number(btn.dataset.value);
      if (!Number.isFinite(val) || val <= 0) return;
      if (typeof setSelectedChip === 'function') setSelectedChip(val);
      bloomUpdateChipRackActiveClass();
    });
  });
}

function bloomUpdateChipRackActiveClass() {
  document.querySelectorAll('#bloom-chipSelector .chip-choice').forEach(btn => {
    const isSel = Number(btn.dataset.value) === selectedChip;
    btn.classList.toggle('active', isSel);
    btn.setAttribute('aria-checked', isSel ? 'true' : 'false');
  });
}

function bloomUpdateBeginBtn() {
  const beginBtn   = document.getElementById('bloom-begin-btn');
  if (!beginBtn) return;
  const clearBtn   = document.getElementById('bloom-clearBetsBtn');
  const editBtn    = document.getElementById('bloom-chipRackEdit');
  const autoWrap   = document.getElementById('bloom-autoDrawWrap');
  const autoToggle = document.getElementById('bloom-autoDrawToggle');
  const state      = bloomGame.state;
  // Keep the AUTO toggle in sync with the game's autoDraw flag.
  if (autoToggle) autoToggle.checked = !!bloomGame.autoDraw;
  if (state === 'selecting') {
    const total = bloomTotalWager();
    const ok = total > 0 && total <= (Number(currentProfile?.credits ?? 0));
    beginBtn.disabled = !ok;
    beginBtn.textContent = '\u2B22 BEGIN ROUND';
    if (clearBtn) { clearBtn.hidden = false; clearBtn.disabled = false; }
    if (editBtn)  { editBtn.hidden  = false; editBtn.disabled  = false; }
    if (autoWrap) autoWrap.hidden = false;
  } else if (state === 'resolving') {
    // Deck is reshuffled before every draw server-side, so there's no
    // "cards remaining" — only a finite event queue for THIS resolved
    // round. Showing a count would imply the deck depletes, which it
    // doesn't. Just say DRAW CARD.
    const queue = bloomGame.eventQueue || [];
    const remaining = queue.length - (bloomGame.eventIndex || 0);
    beginBtn.disabled = remaining <= 0;
    beginBtn.textContent = remaining > 0 ? '\u25B6 DRAW CARD' : 'WAIT\u2026';
    if (clearBtn) clearBtn.hidden = true;
    if (editBtn)  editBtn.hidden  = true;
    // Toggle stays visible mid-race so the user can flip off / on the
    // auto-draw without waiting for the round to finish.
    if (autoWrap) autoWrap.hidden = false;
  } else if (state === 'resolved') {
    beginBtn.disabled = false;
    beginBtn.textContent = '\u21BB NEW ROUND';
    if (clearBtn) clearBtn.hidden = true;
    if (editBtn)  editBtn.hidden  = true;
    if (autoWrap) autoWrap.hidden = true;
  }
}

async function bloomStartRound(regionSlug) {
  // Reset any leftover state from a prior round so a "New Round" click
  // from the resolved screen lands cleanly without an idle-page bounce.
  // bloomGame.autoDraw is the user's persistent preference — DON'T
  // reset it. If they had AUTO armed last round, it stays armed.
  bloomStopAutoDraw();
  bloomGame.resolution = null;
  bloomGame.eventQueue = [];
  bloomGame.eventIndex = 0;
  const stage = document.getElementById('bloom-stage');
  if (stage) stage.innerHTML = '<div class="fof-loading">Dealing region…</div>';
  try {
    // p_region empty/null → server picks uniform-random
    const rpcArgs = {};
    if (regionSlug && typeof regionSlug === 'string') rpcArgs.p_region = regionSlug;
    const { data, error } = await supabase.rpc('bloom_start_round', rpcArgs);
    if (error) throw error;
    bloomGame.roundId    = data.round_id;
    bloomGame.region     = data.region;
    bloomGame.candidates = data.candidates || [];
    bloomGame.wagers     = {};
    bloomGame.state      = 'selecting';
    bloomRenderStage();
  } catch (e) {
    if (stage) stage.innerHTML = `<div class="fof-err">Failed to start round: ${e.message || e}</div>`;
  }
}

async function bloomBeginRound() {
  // Build the wager map: drop zero/empty stacks, coerce to numbers.
  const wagers = {};
  for (const k in bloomGame.wagers) {
    const v = Number(bloomGame.wagers[k]);
    if (Number.isFinite(v) && v > 0) wagers[k] = v;
  }
  const totalWager = Object.values(wagers).reduce((s, v) => s + v, 0);
  if (!totalWager) return;

  bloomGame.state = 'resolving';
  bloomRenderStage();
  try {
    const { data, error } = await supabase.rpc('bloom_lock_round', {
      p_round_id: bloomGame.roundId,
      p_wagers:   wagers,
    });
    if (error) throw error;
    bloomGame.resolution = data;
    // Queue the events; the user advances them with the DRAW button —
    // unless the AUTO toggle was armed, in which case start the timer
    // right away.
    bloomGame.eventQueue = (data.round_details && data.round_details.events) || [];
    bloomGame.eventIndex = 0;
    bloomUpdateBeginBtn();
    if (bloomGame.autoDraw) bloomStartAutoDraw();
  } catch (e) {
    const stage = document.getElementById('bloom-stage');
    if (stage) stage.innerHTML = `<div class="fof-err">Lock failed: ${e.message || e}</div>`;
  }
}

// Advance the race by exactly one event. Bound to the chip-rack DRAW
// button while bloomGame.state === 'resolving'.
function bloomDrawNext() {
  if (bloomGame.state !== 'resolving') return;
  const queue = bloomGame.eventQueue || [];
  if (bloomGame.eventIndex >= queue.length) return;
  const ev = queue[bloomGame.eventIndex++];
  bloomApplyEvent(ev);
  const done = bloomGame.eventIndex >= queue.length;
  if (done) {
    // Race over — kill the auto-draw timer (the user's autoDraw flag
    // PERSISTS across rounds, so the next BEGIN ROUND will auto-draw
    // again if they had AUTO armed). Credit the player + flip to
    // resolved (re-renders the stage so the recap banner + winner glow
    // + final scores show).
    bloomStopAutoDraw();
    if (currentProfile && bloomGame.resolution) {
      currentProfile.credits = Number(bloomGame.resolution.new_balance);
    }
    bloomRefreshBalance();
    bloomGame.state = 'resolved';
    bloomRenderStage();
  } else {
    bloomUpdateBeginBtn();
  }
}

// Build one FOF-style event-log line for a BLOOM card draw: turn marker,
// weather card name, and its per-candidate-flower deltas. Tone reflects
// whether the card net-helped the flowers the player stacked chips on.
function bloomDrawLineHTML(ev, turnNum) {
  const card = ev.card || '';
  const name = (ev.cardName || card || '').toUpperCase();
  const ref  = _bloomRefData;
  const effects = (ref && ref.cardEffects && ref.cardEffects[card]) || ev.effects || {};
  const cands = bloomGame.candidates || [];

  const fx = cands.map(c => {
    const d = Number(effects[c.flower]) || 0;
    if (!d) return '';
    const cls = d > 0 ? 'bloom-evt-up' : 'bloom-evt-down';
    const label = (c.name || c.flower || '').toUpperCase();
    return `<span class="${cls}">${label} ${d > 0 ? '+' : ''}${d}</span>`;
  }).filter(Boolean).join('');

  const wagers = bloomGame.wagers || {};
  let net = 0;
  for (const slug of Object.keys(wagers)) {
    if (Number(wagers[slug]) > 0) net += Number(effects[slug]) || 0;
  }
  const tone = net > 0 ? 'good' : (net < 0 ? 'bad' : 'neutral');

  return `<div class="fof-evt fof-evt-draw fof-evt-tone-${tone} bloom-evt">`
    + `<span class="bloom-evt-turn">[${turnNum}]</span>`
    + `<span class="bloom-evt-card">${name}</span>`
    + (fx ? `<span class="bloom-evt-fx">${fx}</span>` : '')
    + `</div>`;
}

// Apply a single DRAW / BLOOM / SAFETY_CAP_VICTORY event in-place.
// Mirrors what the old auto-play loop did, minus the setTimeout.
function bloomApplyEvent(ev) {
  if (!ev) return;
  const weatherEl = document.getElementById('bloom-weather-banner');
  const logEl = document.getElementById('bloom-event-log');

  if (ev.type === 'DRAW') {
    if (weatherEl) {
      weatherEl.textContent = (ev.cardName || ev.card || '').toUpperCase();
      weatherEl.classList.add('visible');
    }

    if (logEl) {
      const turnNum = logEl.childElementCount + 1;
      const tpl = document.createElement('template');
      tpl.innerHTML = bloomDrawLineHTML(ev, turnNum).trim();
      const line = tpl.content.firstElementChild;
      if (line) {
        logEl.prepend(line);
        logEl.scrollTop = 0;
      }
    }

    const scores = ev.scoresAfter || {};
    for (const se of _bloomMorphs) {
      const newScore = Number(scores[se.slug] ?? se.prevScore);
      const newStage = bloomScoreToStage(newScore);
      const pctEl = document.querySelector(`[data-bloom-flower-pct="${se.slug}"]`);
      if (pctEl) pctEl.textContent = `${newScore}%`;
      const barEl = document.querySelector(`[data-bloom-flower-bar="${se.slug}"]`);
      if (barEl) barEl.style.height = Math.min(100, newScore) + '%';
      if (se.morph && newStage !== se.currentStage) {
        try { se.morph.setStage(newStage); } catch (e) { /* noop */ }
        se.currentStage = newStage;
      }
      se.prevScore = newScore;
    }
  } else if (ev.type === 'BLOOM' || ev.type === 'SAFETY_CAP_VICTORY') {
    if (weatherEl) weatherEl.classList.remove('visible');
    const slot = document.querySelector(`[data-bloom-flower="${ev.winnerFlower}"]`);
    if (slot) slot.classList.add('bloom-winner');
  }
}

// ── BLOOM — playback helpers ────────────────────────────────────────
// Score (0..bloom_target) → FlowerMorphs stage (0..10). Clean 10-points-
// per-stage progression, with stage 10 (BLOOM) reserved for the exact
// winning moment at 100 so the climax lands at the right beat.
//   0-9 SEED · 10-19 SEED CRACK · 20-29 SPROUT · 30-39 FIRST LEAVES ·
//   40-49 FOLIAGE · 50-59 BUD INIT · 60-69 BUD GROWS · 70-79 BUD SWELLS ·
//   80-89 COLOR PEEK · 90-99 CRACKING · 100 BLOOM
function bloomScoreToStage(score) {
  const s = Number(score) || 0;
  if (s >= 100) return 10;
  if (s <= 0)   return 0;
  return Math.min(9, Math.floor(s / 10));
}

// Build a full 5:7 weather-card HTML string for one card. Delegates to
// the BloomWeatherCards bundle so the visual is shared across deck
// preview / live draws / resolved history. Falls back to a minimal
// inline chip if the bundle isn't loaded yet.
function bloomBuildCardChip(card, displayName, effects, opts) {
  opts = opts || {};
  if (window.BloomWeatherCards && window.BloomWeatherCards.buildCardHTML) {
    return window.BloomWeatherCards.buildCardHTML(card, displayName, effects, {
      mode:       opts.mode || 'draw',
      count:      opts.count,
      candidates: bloomGame.candidates || [],
    });
  }
  return '<div class="bwc-card is-' + (opts.mode || 'draw') + '">' +
    (displayName || card || '').toUpperCase() + '</div>';
}

// Map DB flower slug → bundle species id (only differs when the DB slug
// doesn't match what `assets/bloom/bloom-flowers.js` knows).
const BLOOM_SPECIES_MAP = {
  cactus_bloom: 'cactus_blossom',
  frost_lily:   'arctic_poppy',
  plumeria:     'orchid',
};
function bloomBundleSpeciesId(flowerSlug) {
  return BLOOM_SPECIES_MAP[flowerSlug] || flowerSlug;
}

// DB region slug → biome-backgrounds.css biome id. The bundle ships 5
// preset .biome-{id} classes (sky gradient + soil band + thin stripe);
// applying one to the stage gives the full backdrop in one class swap.
const BLOOM_REGION_TO_BIOME = {
  desert:           'desert',
  tundra:           'tundra',
  tropical_island:  'tropical',
  rainforest:       'rainforest',
  temperate_forest: 'forest',
};
function bloomRegionBiomeId(slug) {
  return BLOOM_REGION_TO_BIOME[slug] || 'forest';
}

// Each bundle species has its NATIVE biome (used in the flower-selection
// preview cards so each candidate is shown in the habitat that matches
// it — arctic poppy in tundra, hibiscus in tropical, etc.). For the
// actual round, the round's REGION biome still applies to every flower.
const BLOOM_SPECIES_TO_BIOME = {
  arctic_poppy:   'tundra',
  hydrangea:      'forest',
  hibiscus:       'tropical',
  cactus_blossom: 'desert',
  orchid:         'rainforest',
};
function bloomSpeciesBiomeId(speciesId) {
  return BLOOM_SPECIES_TO_BIOME[speciesId] || 'forest';
}

// Unified FlowerMorphs handles — same DOM hosts across selecting /
// resolving / resolved so the race plays out in-place. Each entry:
//   { slug, morph, currentStage, prevScore }
// Populated by bloomAttachStageHandlers after each render; consumed by
// bloomPlayEvents to drive transitions during the race.
let _bloomMorphs = [];
function bloomTeardownMorphs() {
  for (const m of _bloomMorphs) {
    try { m.morph && m.morph.destroy(); } catch (e) { /* noop */ }
  }
  _bloomMorphs = [];
}

// Card slug → BloomWeather event ID. The bundle's 10 weather events:
//   arctic_wind, late_freeze, monsoon, perfect_conditions,
//   torrential_downpour, dense_mist, drought, dry_heat, coastal_fog,
//   morning_dew. Same heuristic as the bloom_animations seed file;
//   admin can override per-card later via the Anims editor.
const BLOOM_CARD_TO_WEATHER = {
  sunny_day:          'drought',
  dry_heat:           'dry_heat',
  heat_wave:          'dry_heat',
  drought:            'drought',
  gentle_rain:        'torrential_downpour',
  flooding:           'monsoon',
  thunderstorm:       'monsoon',
  late_freeze:        'late_freeze',
  hailstorm:          'late_freeze',
  windstorm:          'arctic_wind',
  cool_breeze:        'arctic_wind',
  morning_dew:        'morning_dew',
  tropical_humidity:  'coastal_fog',
  overcast:           'dense_mist',
  perfect_conditions: 'perfect_conditions',
};

// Shared region + weather instance handles (still used by bloomPlayEvents
// for the optional weather overlay). The flower morphs are tracked in
// the unified _bloomMorphs list declared above.
let _bloomRegionInst = null;
let _bloomWeatherInst = null;

// Backwards-compat shim — old code paths called bloomTeardownStages.
// Now dispatches to the unified bloomTeardownMorphs and clears region /
// weather handles.
function bloomTeardownStages() {
  bloomTeardownMorphs();
  if (_bloomRegionInst)  { try { _bloomRegionInst.destroy(); } catch (e) {} _bloomRegionInst  = null; }
  if (_bloomWeatherInst) { try { _bloomWeatherInst.destroy(); } catch (e) {} _bloomWeatherInst = null; }
}

// Play a weather overlay (rendered by window.BloomWeather) for the duration
// of one draw. Old BloomWeather instance is destroyed before mounting the
// next so timers don't leak. `intensity` defaults to 1; could be derived
// from card effect magnitude later for variable drama.
function bloomPlayWeatherForCard(cardSlug, container, durationMs, intensity) {
  if (!container || !window.BloomWeather) return;
  const eventId = BLOOM_CARD_TO_WEATHER[cardSlug] || 'perfect_conditions';
  // Destroy the prior instance so its animation timers go away.
  if (_bloomWeatherInst) {
    try { _bloomWeatherInst.destroy(); } catch (e) { /* noop */ }
    _bloomWeatherInst = null;
  }
  try {
    _bloomWeatherInst = new window.BloomWeather.BloomWeather({
      container,
      event:     eventId,
      intensity: intensity == null ? 1 : intensity,
    });
  } catch (e) { console.warn('[bloom] weather mount failed', eventId, e); return; }

  // Auto-tear down after the draw beat so the next overlay can take over
  // (BloomWeather is built around continuously looping animations, so we
  // have to time-bound it ourselves).
  const inst = _bloomWeatherInst;
  setTimeout(() => {
    if (inst === _bloomWeatherInst) {
      try { inst.destroy(); } catch (e) { /* noop */ }
      _bloomWeatherInst = null;
    }
  }, durationMs);
}

// (manual draw flow lives in bloomDrawNext + bloomApplyEvent above —
// the old auto-play bloomPlayEvents loop is gone.)

// ── BLOOM — Master Matrix (compute & save per-region win %) ────────
async function runBloomMasterMatrix() {
  const sizeInput = document.getElementById('admin-bloom-master-size');
  const status    = document.getElementById('admin-bloom-master-status');
  const matrixEl  = document.getElementById('admin-bloom-master-matrix');
  const sampleSize = Math.max(1000, Math.floor(Number(sizeInput?.value) || 1000000));

  if (status) status.textContent = "Loading reference data…";
  let ref;
  try { ref = await loadAdminBloomRefData(); }
  catch (err) { if (status) status.textContent = "Failed to load ref data: " + (err.message || err); return; }

  const regionSlugs = ref.regionOrder.map(r => r.slug);
  const totalSims = regionSlugs.length * sampleSize;
  const confirmMsg = `Run ${regionSlugs.length} regions × ${sampleSize.toLocaleString()} sims each (~${totalSims.toLocaleString()} total) and write pct_<region> columns to bloom_flowers?`;
  if (!window.confirm(confirmMsg)) { if (status) status.textContent = ""; return; }

  // tally[regionSlug][flowerSlug] = winCount
  const tally = {};
  const t0 = performance.now();
  for (const region of regionSlugs) {
    tally[region] = {};
    for (const f of ref.flowers) tally[region][f.slug] = 0;

    const entry = ref.regions[region];
    const deck = bloomBuildDeck(entry.deckComp);
    if (deck.length === 0) continue;

    if (status) status.textContent =
      `${region.toUpperCase()} — ${sampleSize.toLocaleString()} sims… elapsed ${((performance.now()-t0)/1000).toFixed(1)}s`;
    await new Promise(r => setTimeout(r, 20));

    for (let i = 0; i < sampleSize; i++) {
      const result = bloomSimulateOne(deck, ref.flowers, ref.cardEffects);
      tally[region][result.winner.slug] += 1;
    }
  }

  const elapsedSec = ((performance.now() - t0) / 1000).toFixed(1);
  if (status) status.textContent = `Sims done in ${elapsedSec}s. Writing to DB…`;

  // Render the matrix preview while we write
  const headerCols = regionSlugs.map(r => `<th>${r}</th>`).join('');
  const rows = ref.flowers.map(f => {
    const cells = regionSlugs.map(r => {
      const wins = tally[r][f.slug] || 0;
      const pct  = (wins / sampleSize) * 100;
      return `<td>${pct.toFixed(2)}%<br><span style="opacity:.5">(${wins.toLocaleString()})</span></td>`;
    }).join('');
    return `<tr><td class="rowhdr">${f.name}</td>${cells}</tr>`;
  }).join('');
  if (matrixEl) {
    matrixEl.innerHTML = `
      <table class="admin-fof-matrix-table">
        <thead><tr><th>Flower</th>${headerCols}</tr></thead>
        <tbody>${rows}</tbody>
      </table>
    `;
  }

  // Write: one update() per flower, all five pct_* columns at once
  const writtenAt = new Date().toISOString();
  for (const f of ref.flowers) {
    const updates = {
      odds_sample_size: sampleSize,
      odds_computed_at: writtenAt,
    };
    for (const region of regionSlugs) {
      updates[`pct_${region}`] = (tally[region][f.slug] || 0) / sampleSize;
    }
    const { error } = await supabase
      .from('bloom_flowers')
      .update(updates)
      .eq('flower', f.slug);
    if (error) {
      if (status) status.textContent = `DB write failed on ${f.slug}: ${error.message}`;
      return;
    }
  }

  if (status) status.textContent =
    `Master Matrix saved. ${totalSims.toLocaleString()} sims in ${elapsedSec}s.`;
}

// ── BLOOM — Animations editor ────────────────────────────────────────
// Slot list is derived live from _bloomRefData (regions / cards / flowers).
// Schema: bloom_animations (kind, subject, variant, clip_data JSONB).
//   kind = 'region_bg'    → variant = 'default'
//   kind = 'card_overlay' → variant = 'default'
//   kind = 'flower'       → variant = one of BLOOM_FLOWER_VARIANTS
const BLOOM_FLOWER_VARIANTS = [
  { v: 'stage_1',            label: 'Stage 1 (0-20) swell',   loop: true  },
  { v: 'transition_1_2',     label: 'Transition 1 → 2',        loop: false },
  { v: 'stage_2',            label: 'Stage 2 (20-40) swell',  loop: true  },
  { v: 'transition_2_3',     label: 'Transition 2 → 3',        loop: false },
  { v: 'stage_3',            label: 'Stage 3 (40-60) swell',  loop: true  },
  { v: 'transition_3_4',     label: 'Transition 3 → 4',        loop: false },
  { v: 'stage_4',            label: 'Stage 4 (60-80) swell',  loop: true  },
  { v: 'transition_4_5',     label: 'Transition 4 → 5',        loop: false },
  { v: 'stage_5',            label: 'Stage 5 (80-90) swell',  loop: true  },
  { v: 'transition_5_6',     label: 'Transition 5 → 6',        loop: false },
  { v: 'stage_6',            label: 'Stage 6 (90-100) swell', loop: true  },
  { v: 'transition_6_bloom', label: 'Bloom!',                  loop: false },
];

let _bloomAnimRows = [];           // [{ kind, subject, variant, clip_data }]
let _bloomAnimEditing = null;      // { kind, subject, variant }
let _bloomAnimsInited = false;

function bloomAnimGet(kind, subject, variant) {
  return _bloomAnimRows.find(r =>
    r.kind === kind && r.subject === subject && r.variant === variant
  ) || null;
}

async function loadAndRenderBloomAnims() {
  if (!_bloomAnimsInited) {
    _bloomAnimsInited = true;
    document.querySelectorAll('[data-bloom-anim-close]').forEach(el => {
      el.addEventListener('click', () => adminBloomAnimCloseModal());
    });
    const saveBtn  = document.getElementById('admin-bloom-anim-save-btn');
    const clearBtn = document.getElementById('admin-bloom-anim-clear-btn');
    const urlInput = document.getElementById('admin-bloom-anim-url');
    if (saveBtn)  saveBtn.addEventListener('click', () => void adminBloomAnimSave());
    if (clearBtn) clearBtn.addEventListener('click', () => void adminBloomAnimClear());
    if (urlInput) urlInput.addEventListener('input',  () => adminBloomAnimUpdatePreview(urlInput.value));
  }
  const status = document.getElementById('admin-bloom-anim-status');
  if (status) status.textContent = 'Loading clips…';
  const { data, error } = await supabase
    .from('bloom_animations')
    .select('kind, subject, variant, clip_data, updated_at');
  if (error) {
    if (status) status.textContent = `Error: ${error.message}`;
    return;
  }
  _bloomAnimRows = Array.isArray(data) ? data : [];
  if (status) status.textContent = '';
  renderBloomAnimsGrid();
}

function bloomAnimCellHtml(kind, subject, variant) {
  const row = bloomAnimGet(kind, subject, variant);
  const set = !!(row?.clip_data?.url);
  const cls = set ? 'admin-fof-anim-cell admin-fof-anim-cell-set'
                  : 'admin-fof-anim-cell admin-fof-anim-cell-empty';
  const label = set ? '●' : '○';
  const title = set ? row.clip_data.url : 'No clip — click to set';
  return `<button type="button" class="${cls}"
    data-bloom-anim-kind="${kind}"
    data-bloom-anim-subject="${subject}"
    data-bloom-anim-variant="${variant}"
    title="${title.replace(/"/g, '&quot;')}">${label}</button>`;
}

function renderBloomAnimsGrid() {
  const wrap = document.getElementById('admin-bloom-anims-grid');
  if (!wrap || !_bloomRefData) return;
  const { regionOrder, cardOrder, flowers } = _bloomRefData;

  // ── Region backgrounds (one per region) ──────────────────
  const regionRows = regionOrder.map(r =>
    `<tr><td class="admin-fof-anim-rowhdr">${r.name.toUpperCase()}</td><td>${bloomAnimCellHtml('region_bg', r.slug, 'default')}</td></tr>`
  ).join('');

  // ── Card overlays (one per card) ─────────────────────────
  const cardRows = cardOrder.map(c =>
    `<tr><td class="admin-fof-anim-rowhdr">${c.name.toUpperCase()}</td><td>${bloomAnimCellHtml('card_overlay', c.slug, 'default')}</td></tr>`
  ).join('');

  // ── Flower stages + transitions (12 variants × N flowers) ─
  const flowerHeader = '<th>Variant</th>' +
    flowers.map(f => `<th>${f.name.toUpperCase()}</th>`).join('');
  const flowerRows = BLOOM_FLOWER_VARIANTS.map(({ v, label }) => {
    const cells = flowers.map(f =>
      `<td>${bloomAnimCellHtml('flower', f.slug, v)}</td>`
    ).join('');
    return `<tr><td class="admin-fof-anim-rowhdr">${label}</td>${cells}</tr>`;
  }).join('');

  wrap.innerHTML = `
    <h3 style="margin-top:0">Region backgrounds</h3>
    <table class="admin-fof-anim-table">
      <thead><tr><th>Region</th><th>Clip</th></tr></thead>
      <tbody>${regionRows}</tbody>
    </table>

    <h3 style="margin-top:24px">Card overlays (~1s, no loop)</h3>
    <table class="admin-fof-anim-table">
      <thead><tr><th>Card</th><th>Clip</th></tr></thead>
      <tbody>${cardRows}</tbody>
    </table>

    <h3 style="margin-top:24px">Flower stages &amp; transitions</h3>
    <p class="admin-cs-hint" style="margin-top:0">Stage cells should <strong>loop</strong> (swell idle). Transition cells should <strong>play once</strong> (one-shot when score crosses the next threshold).</p>
    <table class="admin-fof-anim-table">
      <thead><tr>${flowerHeader}</tr></thead>
      <tbody>${flowerRows}</tbody>
    </table>

    <div class="admin-fof-anim-legend" style="margin-top:16px">
      <span><span class="admin-fof-anim-cell admin-fof-anim-cell-set">●</span> = clip set</span>
      <span><span class="admin-fof-anim-cell admin-fof-anim-cell-empty">○</span> = empty — click to add</span>
    </div>
  `;
  wrap.querySelectorAll('.admin-fof-anim-cell').forEach(btn => {
    btn.addEventListener('click', () => {
      adminBloomAnimOpenModal(
        btn.dataset.bloomAnimKind,
        btn.dataset.bloomAnimSubject,
        btn.dataset.bloomAnimVariant
      );
    });
  });
}

function adminBloomAnimOpenModal(kind, subject, variant) {
  _bloomAnimEditing = { kind, subject, variant };
  const row = bloomAnimGet(kind, subject, variant);
  const d = row?.clip_data || {};
  const titleEl = document.getElementById('admin-bloom-anim-modal-title');
  if (titleEl) {
    const variantLabel = (kind === 'flower')
      ? (BLOOM_FLOWER_VARIANTS.find(x => x.v === variant)?.label || variant)
      : kind.replace('_', ' ');
    titleEl.textContent = `${subject.toUpperCase()} — ${variantLabel}`;
  }
  const url   = document.getElementById('admin-bloom-anim-url');
  const dur   = document.getElementById('admin-bloom-anim-duration');
  const loop  = document.getElementById('admin-bloom-anim-loop');
  const notes = document.getElementById('admin-bloom-anim-notes');
  if (url)   url.value   = d.url || '';
  if (dur)   dur.value   = (d.duration != null) ? d.duration : '';
  if (loop) {
    // Default loop value based on variant kind: stage = true, transition/overlay = false
    const defaultLoop = (kind === 'flower' && variant.startsWith('stage_'));
    const v = (d.loop != null) ? !!d.loop : defaultLoop;
    loop.value = v ? 'true' : 'false';
  }
  if (notes) notes.value = d.notes || '';
  adminBloomAnimUpdatePreview(d.url || '');
  const modal = document.getElementById('admin-bloom-anim-modal');
  if (modal) modal.hidden = false;
}

function adminBloomAnimCloseModal() {
  _bloomAnimEditing = null;
  const modal = document.getElementById('admin-bloom-anim-modal');
  if (modal) modal.hidden = true;
}

function adminBloomAnimUpdatePreview(url) {
  const prev = document.getElementById('admin-bloom-anim-preview');
  if (!prev) return;
  if (!url || !url.trim()) { prev.innerHTML = '<div class="admin-fof-anim-no-preview">No URL yet</div>'; return; }
  const u = url.trim();
  const lower = u.toLowerCase();
  if (lower.endsWith('.mp4') || lower.endsWith('.webm') || lower.endsWith('.mov')) {
    prev.innerHTML = `<video src="${u}" autoplay loop muted playsinline></video>`;
  } else if (lower.endsWith('.json')) {
    prev.innerHTML = `<div class="admin-fof-anim-preview-text">Lottie / JSON asset — preview not rendered here.</div>`;
  } else {
    prev.innerHTML = `<img src="${u}" alt="preview" onerror="this.replaceWith(Object.assign(document.createElement('div'),{className:'admin-fof-anim-no-preview',textContent:'Failed to load preview'}))">`;
  }
}

async function adminBloomAnimSave() {
  if (!_bloomAnimEditing) return;
  const { kind, subject, variant } = _bloomAnimEditing;
  const url     = document.getElementById('admin-bloom-anim-url')?.value.trim() || '';
  const durRaw  = document.getElementById('admin-bloom-anim-duration')?.value;
  const loopRaw = document.getElementById('admin-bloom-anim-loop')?.value;
  const notes   = document.getElementById('admin-bloom-anim-notes')?.value.trim() || '';
  const clip = { url };
  if (durRaw !== '' && durRaw != null && !Number.isNaN(Number(durRaw))) clip.duration = Number(durRaw);
  clip.loop = loopRaw === 'true';
  if (notes) clip.notes = notes;

  const status = document.getElementById('admin-bloom-anim-status');
  if (status) status.textContent = `Saving ${kind}/${subject}/${variant}…`;
  const { error } = await supabase
    .from('bloom_animations')
    .upsert(
      { kind, subject, variant, clip_data: clip, updated_at: new Date().toISOString() },
      { onConflict: 'kind,subject,variant' }
    );
  if (error) { if (status) status.textContent = `Save error: ${error.message}`; return; }
  // Reflect locally
  const existing = bloomAnimGet(kind, subject, variant);
  if (existing) existing.clip_data = clip;
  else _bloomAnimRows.push({ kind, subject, variant, clip_data: clip, updated_at: new Date().toISOString() });
  if (status) status.textContent = `Saved.`;
  adminBloomAnimCloseModal();
  renderBloomAnimsGrid();
}

async function adminBloomAnimClear() {
  if (!_bloomAnimEditing) return;
  const { kind, subject, variant } = _bloomAnimEditing;
  const status = document.getElementById('admin-bloom-anim-status');
  if (status) status.textContent = `Clearing…`;
  const { error } = await supabase
    .from('bloom_animations')
    .delete()
    .eq('kind', kind)
    .eq('subject', subject)
    .eq('variant', variant);
  if (error) { if (status) status.textContent = `Clear error: ${error.message}`; return; }
  _bloomAnimRows = _bloomAnimRows.filter(r =>
    !(r.kind === kind && r.subject === subject && r.variant === variant)
  );
  if (status) status.textContent = `Cleared.`;
  adminBloomAnimCloseModal();
  renderBloomAnimsGrid();
}
